create view aanwview
   (e_mandant,adr_gr,adr_nr,person_nr,
       obj_nr,ausg,anw_ref_nr,externe_nr,abostatus)
as
select a.e_mandant,a.adr_gr,a.adr_nr,a.person_nr, 
       s.obj_nr, s.ausg, a.anw_ref_nr,a.externe_nr,'xxxxxxxxx'
  from versges s, anwref a
where s.adr_gr    = a.adr_gr
   and s.adr_nr    = a.adr_nr
   and s.person_nr = a.person_nr
   and s.e_mandant = a.e_mandant

GO
create view [aboaview] (adr_gr, adr_nr, haupt_name, adr_nr_bv, land_code, inaus,
                      haupt_plz, haupt_ort, strasse,
                      hausnr, hausnr_zus, postfach, versand_adr,
                      datum_neu, datum_aend,
                      person_nr, a_typ, e_mandant,
                      obj_nr, ausg, abo_nr,
                      ber_menge,
                      vbeg_dat, vbeg_jahr, vbeg_heft,
                      vend_dat, vend_jahr, vend_heft,
                      preis_kat, waehrung, r_art,
                      r_beg_dat, r_beg_jahr, r_beg_hnr,
                      r_ende_dat, r_ende_jahr, r_ende_hnr,
                      abostatus, zeile1, zeile2, zeile3,
                      vorname, nachname, k_grund, status,
                      fakt_zr, r_grund, f_ende_dat_e,
                      kz_mahnung, rechkopien,
                      plz_wohn, wohnort, plz_post, postort,
                      plz_gk, gkort, b_id_aend,
                      person_nr_bv, abteilung,kz_storno,auftrags_nr,
                      spreis,ra_fakt,heft_anz,w_akt_id,w_uakt_id,
                      preis_kat_no,no_ende_dat,no_ende_jahr,no_ende_hnr,
                      stdb_bis,verlber_id,externe_nr,datum_neu_p,datum_aend_p,name1,name2,ANREDE_CODE,veranlasser,bestellg,EINDRUCK_NR,KZ_EINDRUCK,ASPERR_CODE,ABOSPERR_VON,ABOSPERR_BIS)
as
select a.adr_gr, a.adr_nr, a.haupt_name, b.adr_nr_bv, a.land_code,
       b.inaus,  a.haupt_plz, a.haupt_ort, a.strasse,
       a.hausnr, a.hausnr_zus, a.postfach, a.versand_adr,
       b.datum_neu, b.datum_aend, b.person_nr, p.a_typ, b.e_mandant,
       b.obj_nr, b.ausg, b.abo_nr,
       b.ber_menge,
       b.vbeg_dat, b.vbeg_jahr,
       b.vbeg_heft, b.vend_dat, b.vend_jahr, b.vend_heft,
       b.preis_kat,
       b.waehrung, b.r_art,
       b.r_beg_dat, b.r_beg_jahr, b.r_beg_hnr, b.r_ende_dat,
       b.r_ende_jahr, b.r_ende_hnr,
       b.abostatus, a.name1, a.name2, a.name3,
       p.vorname, p.nachname, b.k_grund, b.status,
       b.fakt_zr,b.r_grund,b.dat_fakt_von,
       b.kz_mahnung,b.rechkopien,
       a.plz_wohn,a.wohnort,
       a.plz_post,a.postort,
       a.plz_gk,a.gkort,
       b.b_id_aend, b.person_nr_bv, p.abteilung, b.kz_storno,
       b.auftrags_nr,b.spreis,b.ra_fakt,b.heft_anz,b.w_akt_id,b.w_uakt_id,
       b.preis_kat_no,b.no_ende_dat,b.no_ende_jahr,b.no_ende_hnr,
       p.stdb_bis,a.verlber_id, '               ', p.datum_neu,p.datum_aend,a.name1,a.name2,p.ANREDE_CODE,
       b.veranlasser,b.bestellg, b.EINDRUCK_NR,b.kz_eindruck, i.ASPERR_CODE,i.ABOSPERR_VON,i.ABOSPERR_BIS
from abostamm b
JOIN person p
    ON b.adr_gr = p.adr_gr
   AND b.adr_nr = p.adr_nr
   AND b.person_nr = p.person_nr
JOIN anschr a
    ON b.adr_gr = a.adr_gr
   AND b.adr_nr = a.adr_nr
LEFT JOIN ainfo i
    ON b.adr_gr = i.adr_gr
   AND b.adr_nr = i.adr_nr

GO
create view abokview (adr_gr, adr_nr, adr_nr_bv, inaus,
                      person_nr, e_mandant,
                      obj_nr, ausg, abo_nr,
                      ber_menge,
                      vbeg_dat, vbeg_jahr, vbeg_heft,
                      vend_dat, vend_jahr, vend_heft,
                      preis_kat, waehrung, r_art,
                      r_beg_dat, r_beg_jahr, r_beg_hnr,
                      r_ende_dat, r_ende_jahr, r_ende_hnr,
                      abostatus, k_grund, status,
                      fakt_zr, person_nr_bv,kz_storno,auftrags_nr,
                      spreis,ra_fakt,w_akt_id,w_uakt_id,
                      preis_kat_no,no_ende_dat,no_ende_jahr,no_ende_hnr,
                      best_datum, k_datum,
                      versand_soll_vbeg, versand_soll_vend,versand_soll_no,
                      VERSAND_SOLL_RBEG,VERSAND_SOLL_REND,LFD_NR,IVW_GRUPPE,LAND_CODE_LE, lfd_nr_aktvorb)
as
select                a.adr_gr, a.adr_nr, a.adr_nr_bv, a.inaus,
                      a.person_nr, a.e_mandant,
                      a.obj_nr, a.ausg, a.abo_nr,
                      a.ber_menge,
                      a.vbeg_dat, a.vbeg_jahr, a.vbeg_heft,
                      a.vend_dat, a.vend_jahr, a.vend_heft,
                      a.preis_kat, a.waehrung, a.r_art,
                      a.r_beg_dat, a.r_beg_jahr, a.r_beg_hnr,
                      a.r_ende_dat, a.r_ende_jahr, a.r_ende_hnr,
                      a.abostatus, a.k_grund, a.status,
                      a.fakt_zr, a.person_nr_bv,a.kz_storno,a.auftrags_nr,
                      a.spreis,a.ra_fakt,a.w_akt_id,a.w_uakt_id,
                      a.preis_kat_no,a.no_ende_dat,a.no_ende_jahr,a.no_ende_hnr,
                      a.best_datum, a.k_datum,
                      k.versand_soll, kk.versand_soll,null,
                      kkk.versand_soll, kkkk.versand_soll, a.LFD_NR, a.IVW_GRUPPE, s.land_code, a.lfd_nr_aktvorb
from abostamm a, kalender k, kalender kk, kalender kkk, kalender kkkk, anschr s
where k.e_mandant = a.e_mandant  
      and k.obj_nr    = a.obj_nr
      and k.ausg      = a.ausg
      and k.jahr      = a.vbeg_jahr
      and k.hnr       = a.vbeg_heft
      and kk.e_mandant = a.e_mandant
      and kk.obj_nr    = a.obj_nr
      and kk.ausg      = a.ausg
      and kk.jahr      = a.vend_jahr
      and kk.hnr       = a.vend_heft      
      and kkk.e_mandant = a.e_mandant
      and kkk.obj_nr    = a.obj_nr
      and kkk.ausg      = a.ausg
      and kkk.jahr      = a.r_beg_jahr
      and kkk.hnr       = a.r_beg_hnr      
      and kkkk.e_mandant = a.e_mandant
      and kkkk.obj_nr    = a.obj_nr
      and kkkk.ausg      = a.ausg
      and kkkk.jahr      = a.r_ende_jahr
      and kkkk.hnr       = a.r_ende_hnr      
      and a.vbeg_jahr is not null  
      and a.vend_jahr is not null
      and a.no_ende_jahr is null
      and a.r_beg_jahr is not null
      and a.vbeg_dat is null
      and s.adr_gr = a.adr_gr
      and s.adr_nr = a.adr_nr
union
select                a.adr_gr, a.adr_nr, a.adr_nr_bv, a.inaus,
                      a.person_nr, a.e_mandant,
                      a.obj_nr, a.ausg, a.abo_nr,
                      a.ber_menge,
                      a.vbeg_dat, a.vbeg_jahr, a.vbeg_heft,
                      a.vend_dat, a.vend_jahr, a.vend_heft,
                      a.preis_kat, a.waehrung, a.r_art,
                      a.r_beg_dat, a.r_beg_jahr, a.r_beg_hnr,
                      a.r_ende_dat, a.r_ende_jahr, a.r_ende_hnr,
                      a.abostatus, a.k_grund, a.status,
                      a.fakt_zr, a.person_nr_bv,a.kz_storno,a.auftrags_nr,
                      a.spreis,a.ra_fakt,a.w_akt_id,a.w_uakt_id,
                      a.preis_kat_no,a.no_ende_dat,a.no_ende_jahr,a.no_ende_hnr,
                      a.best_datum, a.k_datum,
                      k.versand_soll, null,null,
                      kk.versand_soll, null,a.LFD_NR,a.IVW_GRUPPE, s.land_code, a.lfd_nr_aktvorb
from abostamm a, kalender k, kalender kk, anschr s
where k.e_mandant = a.e_mandant  
      and k.obj_nr    = a.obj_nr
      and k.ausg      = a.ausg
      and k.jahr      = a.vbeg_jahr
      and k.hnr       = a.vbeg_heft
      and kk.e_mandant = a.e_mandant
      and kk.obj_nr    = a.obj_nr
      and kk.ausg      = a.ausg
