  from bufakst s, bufakupo u, buauftra a,
       bufakpos f LEFT OUTER JOIN bustaord o on
          f.staord_nr = o.staord_nr and
          o.l_ausg_nr_k != 1
  where s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and s.rech_nr      = f.rech_nr
  and s.rech_dat     = f.rech_dat
  and s.f_mandant    = f.f_mandant
  and f.rech_nr      = u.rech_nr
  and f.rech_dat     = u.rech_dat
  and f.f_mandant    = u.f_mandant
  and f.pos_nr       = u.pos_nr
  and s.rech_typ     = 'L'
  and s.rech_ref is null
  and u.e_mandant    = u.e_mandant
  and u.auft_nr      = a.auft_nr 
  and a.kz_kommission = 'F'
  and (not exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
       and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr) 
      or exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
         and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr and (u.bundle = 'F' or u.bundle = 'E')))
  group by u.e_mandant, u.l_ausg_nr, u.l_aufl_nr, u.artikel_nr, dbo.char2num(u.artikel_nr), s.rech_typ, u.rech_dat
union
  select u.e_mandant, u.l_ausg_nr, u.l_aufl_nr, u.artikel_nr, dbo.char2num(u.artikel_nr), s.rech_typ, u.rech_dat,
         0, isnull(sum(u.gelief_men),0), 0, 0
  from bufakst s, bufakupo u,
       bufakpos f LEFT OUTER JOIN bustaord o on
          f.staord_nr = o.staord_nr and
          o.l_ausg_nr_k != 1
  where s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and s.rech_nr      = f.rech_nr
  and s.rech_dat     = f.rech_dat
  and s.f_mandant    = f.f_mandant
  and f.rech_nr      = u.rech_nr
  and f.rech_dat     = u.rech_dat
  and f.f_mandant    = u.f_mandant
  and f.pos_nr       = u.pos_nr
  and s.rech_typ     = 'L'
  and s.rech_ref is null
  and u.e_mandant    = u.e_mandant
  and not exists (select * from buauftra a where 
      u.auft_nr      = a.auft_nr)
  and (not exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
       and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr) 
      or exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
         and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr and (u.bundle = 'F' or u.bundle = 'E')))
  group by u.e_mandant, u.l_ausg_nr, u.l_aufl_nr, u.artikel_nr, dbo.char2num(u.artikel_nr), s.rech_typ, u.rech_dat

GO
create view abslview (adr_gr, adr_nr, obj_nr, absl_nr, adr_nr_konz, konzern_id, 
        konzern_bez, e_mandant, abschl_von, abschl_bis, 
        hnr_num_von, hnr_num_bis, volumen_rabatt, abschl_text, 
	anz_seiten, anz_mm, anz_anzeigen, anz_umsatz, z_bed_id, verwend_typ)
as
select s.adr_gr, s.adr_nr, s.obj_nr, s.absl_nr, 0, '      ', '               ',
        s.e_mandant, s.abschl_von, s.abschl_bis, 
        s.hnr_num_von, s.hnr_num_bis, s.volumen_rabatt, s.abschl_text,
        s.anz_seiten, s.anz_mm, s.anz_anzeigen, s.anz_umsatz, s.z_bed_id, s.verwend_typ
from anschr a, auftabsl s
where
	a.adr_gr = s.adr_gr and
	a.adr_nr = s.adr_nr 
union
select s.adr_gr, a.adr_nr, s.obj_nr, s.absl_nr, k.adr_nr, k.konzern_id, k.syn, 
        s.e_mandant, s.abschl_von, s.abschl_bis, 
        s.hnr_num_von, s.hnr_num_bis, s.volumen_rabatt, s.abschl_text, 
        s.anz_seiten, s.anz_mm, s.anz_anzeigen, s.anz_umsatz, s.z_bed_id, s.verwend_typ
from auftabsl s, konzern k, anschr a
where
	k.adr_gr = a.adr_gr and
	k.konzern_id = a.konzern_id and 
	s.adr_gr = k.adr_gr and
	s.adr_nr = k.adr_nr

