create view absview
       (adr_gr, adr_nr, auft_nr, auft_hist_nr, dispo_nr, dispo_hist_nr,
        dispopos_nr, e_mandant, obj_nr, ausg, obj_nr_dispo, jahr, hnr, 
        hnr_num, status_dispopos, prodname, abw_prod_bez, motiv, 
	  motiv_folge, plaz_int, plaz_ext, seite,
	  anzart_id, datum_neu, datum_aend, anz_schaltung, farb_id, anz_si, anz_mm,
	  anz_eintrag, status, format_id,
	  volumen_fa, volumen_mm, netto_betrag, anzeigen_betrag, 
	  wa_prov_betrag, kombi_rabatt, sonder_rabatt, volumen_rabatt, 
        wa_prov_satz, anz_zeilen, anz_sp, anz_anzeigen, anz_seiten,
	  agv_nr, rech_nr, rech_nr_fakt, rech_datum, 
        haupt_name, abrech_id, bezirk_id, ums_ant_wt1, kz_loeschen,
        kz_einmal_kd, waehrung, produkt, verwend_typ, datum_neu_auft, datum_aend_auft, adr_nr_wa,
        datum_evt, z_bed_id)
  as
select p.adr_gr, p.adr_nr, p.auft_nr, p.auft_hist_nr, 
        p.dispo_nr, p.dispo_hist_nr, p.dispopos_nr, p.e_mandant, p.obj_nr,
        p.ausg, d.obj_nr, p.jahr, p.hnr, p.hnr_num, p.status, p.prodname, 
	  p.abw_prod_bez, p.motiv, p.motiv_folge, p.plaz_int, p.plaz_ext, p.seite, 
	  d.anzart_id, d.datum_neu, d.datum_aend, d.anz_schaltung, d.farb_id, d.anz_si, d.anz_mm, 
        d.anz_eintrag, d.status, d.format_id,
	  d.volumen_fa, d.volumen_mm, d.netto_betrag, d.anzeigen_betrag,
        d.wa_prov_betrag, d.kombi_rabatt, d.sonder_rabatt, d.volumen_rabatt, 
        d.wa_prov_satz, d.anz_zeilen, d.anz_sp, d.anz_anzeigen,d.anz_seiten, 
        d.agv_nr, d.rech_nr, d.rech_nr_fakt, d.rech_datum,
        a.haupt_name, d.abrech_id, b.bezirk_id, b.ums_anteil_proz, 
        e.kz_loeschen, e.kz_einmal_kd, g.waehrung, 
        p.produkt, g.verwend_typ, g.datum_neu, g.datum_aend, g.adr_nr_wa, k.datum_evt, d.z_bed_id
from   dispopos p LEFT OUTER JOIN kalendea k ON
       p.e_mandant = k.e_mandant and p.obj_nr = k.obj_nr and 
       p.ausg = k.ausg and p.jahr = k.jahr and p.hnr = k.hnr,
       dispo d, anschr a, adbezirk b, person e, auftrag g
where  
       p.auft_hist_nr = 0 and p.dispo_hist_nr = 0 and p.adr_gr = d.adr_gr and
       p.adr_nr = d.adr_nr and p.auft_nr = d.auft_nr and
       p.auft_hist_nr = d.auft_hist_nr and p.dispo_nr = d.dispo_nr and
       p.dispo_hist_nr = d.dispo_hist_nr and
       p.adr_gr = a.adr_gr and p.adr_nr = a.adr_nr and
       p.adr_gr = b.adr_gr and p.adr_nr = b.adr_nr and p.auft_nr = b.auft_nr and
       p.auft_hist_nr = b.auft_hist_nr and b.dispo_nr = 0 and p.dispo_hist_nr = b.dispo_hist_nr and
       b.f_typ_nr = 'WT1' and
       p.adr_gr = e.adr_gr and p.adr_nr = e.adr_nr and e.person_nr = 0 and
       p.adr_gr = g.adr_gr and p.adr_nr = g.adr_nr and p.auft_nr = g.auft_nr and
       p.auft_hist_nr = g.auft_hist_nr and g.kz_inaktiv='F'

