       (adr_gr, adr_nr_wa,adr_nr, auft_nr, auft_hist_nr, dispo_nr, dispo_hist_nr,
        dispopos_nr, e_mandant, obj_nr, ausg, obj_nr_dispo, jahr, hnr, 
        hnr_num, status_dispopos, anzart_id, datum_neu, datum_aend, anz_schaltung, 
        farb_id, anz_si, status, volumen_fa, volumen_mm, netto_betrag, 
        anzeigen_betrag, kombi_rabatt, sonder_rabatt, volumen_rabatt, 
        wa_prov_satz, anz_zeilen, anz_sp, anz_anzeigen, anz_seiten,
        haupt_name, haupt_ort, bezirk_id, abrech_id, kz_loeschen,
        kz_einmal_kd, waehrung, produkt, anz_mm, format_id,
	datum_neu_auft, datum_aend_auft, verwend_typ, motiv, motiv_folge, seite,
	prodname, abw_prod_bez, plaz_ext, plaz_int,
        anz_eintrag, rech_nr, rech_nr_fakt, agv_nr, rech_datum, datum_evt)
  as
select p.adr_gr, g.adr_nr_wa, p.adr_nr, p.auft_nr, p.auft_hist_nr, 
        p.dispo_nr, p.dispo_hist_nr, p.dispopos_nr, p.e_mandant, p.obj_nr,
        p.ausg, d.obj_nr, p.jahr, p.hnr, p.hnr_num, p.status, d.anzart_id, d.datum_neu, d.datum_aend,
        d.anz_schaltung, d.farb_id, d.anz_si, d.status, d.volumen_fa, d.volumen_mm,
        d.netto_betrag, d.anzeigen_betrag, d.kombi_rabatt, d.sonder_rabatt,
        d.volumen_rabatt, d.wa_prov_satz, d.anz_zeilen, d.anz_sp, d.anz_anzeigen,
        d.anz_seiten, a.haupt_name, a.haupt_ort, a.bezirk_id, d.abrech_id, e.kz_loeschen, 
        e.kz_einmal_kd, g.waehrung, p.produkt, d.anz_mm, d.format_id,
	g.datum_neu, g.datum_aend, g.verwend_typ, p.motiv, p.motiv_folge, p.seite,
	p.prodname, p.abw_prod_bez, p.plaz_ext, p.plaz_int,
	d.anz_eintrag, d.rech_nr, d.rech_nr_fakt, d.agv_nr, d.rech_datum, k.datum_evt  
