create view [dbo].[adrpbvie]
(adr_pool_nr, benutzer_id, pool_typ, adr_gr, adr_nr, person_nr, teil_pool_nr, 
status, erfasser_id, datum_akt, lfd_nr_bericht,
 e_mandant, akt_id, uakt_id, kz_marketing, gueltig_ab, gueltig_bis,
tp_benutzer_id, bengrp_id,
reg_id, reg_code)
as select
a.adr_pool_nr, a.benutzer_id, a.pool_typ, a.adr_gr, a.adr_nr, a.person_nr, a.teil_pool_nr, 
a.status, a.erfasser_id, a.datum_akt, a.lfd_nr_bericht,
b.e_mandant, b.akt_id, b.uakt_id, b.kz_marketing, b.gueltig_ab, b.gueltig_bis,
c.benutzer_id, c.bengrp_id,  
d.reg_id, d.reg_code
from adrpool a
   inner join adrpkopf b on
   b.adr_pool_nr = a.adr_pool_nr
   left outer join adrpben c on
   c.adr_pool_nr = a.adr_pool_nr and
   c.teil_pool_nr = a.teil_pool_nr
   inner join adrptp d on
   d.adr_pool_nr = a.adr_pool_nr and
   d.teil_pool_nr = a.teil_pool_nr 

GO
create view [dbo].[adrpkvie] (
	adr_pool_nr, adr_gr, e_mandant, benutzer_id, pool_typ,
	status, kurz_bez, bez, gueltig_ab, gueltig_bis, 
	teil_pool_nr, benutzer_id_tp, kurz_bez_tp, bez_tp)
as
select k.adr_pool_nr, k.adr_gr, k.e_mandant, k.benutzer_id,
	k.pool_typ, k.status, k.kurz_bez, k.bez, k.gueltig_ab, k.gueltig_bis,
	0, null, null, null
from ADRPKOPF k
union
select k.adr_pool_nr, k.adr_gr, k.e_mandant, k.benutzer_id,
	k.pool_typ, k.status, k.kurz_bez, k.bez, k.gueltig_ab, k.gueltig_bis,
	b.teil_pool_nr, rtrim(b.benutzer_id), rtrim(p.kurz_bez), rtrim(p.beschreibung)
from ADRPBEN b, ADRPTP p, ADRPKOPF k
where b.adr_pool_nr  = p.adr_pool_nr
and	b.teil_pool_nr = p.teil_pool_nr
and	b.adr_pool_nr  = k.adr_pool_nr
union
select k.adr_pool_nr, k.adr_gr, k.e_mandant, k.benutzer_id,
	k.pool_typ, k.status, k.kurz_bez, k.bez, k.gueltig_ab, k.gueltig_bis,
	b.teil_pool_nr, rtrim(b.benutzer_id), null, null
from ADRPBEN b, ADRPKOPF k
where b.teil_pool_nr = -1
and   b.adr_pool_nr  = k.adr_pool_nr
union
select k.adr_pool_nr, k.adr_gr, k.e_mandant, k.benutzer_id,
	k.pool_typ, k.status, k.kurz_bez, k.bez, k.gueltig_ab, k.gueltig_bis,
	b.teil_pool_nr, rtrim(b.benutzer_id), rtrim(p.kurz_bez), rtrim(p.beschreibung)
from ADRPBEN b, ADRPTP p, ADRPKOPF k
where b.adr_pool_nr  = p.adr_pool_nr
and	b.teil_pool_nr = p.teil_pool_nr
and	b.adr_pool_nr  = k.adr_pool_nr
and     b.bengrp_id  = '000'
union
select k.adr_pool_nr, k.adr_gr, k.e_mandant, k.benutzer_id,
	k.pool_typ, k.status, k.kurz_bez, k.bez, k.gueltig_ab, k.gueltig_bis,
	b.teil_pool_nr, rtrim(g.benutzer_id), rtrim(p.kurz_bez), rtrim(p.beschreibung)
from ADRPBEN b, ADRPTP p, ADRPKOPF k, BENGRPZU g
where b.adr_pool_nr  = p.adr_pool_nr
and	b.teil_pool_nr = p.teil_pool_nr
and	b.adr_pool_nr  = k.adr_pool_nr
and     b.bengrp_id    = g.bengrp_id
and     b.benutzer_id  = '000000'

GO
create view adrpview
	(adr_pool_nr, benutzer_id, pool_typ,
	e_mandant,
	adr_gr, adr_nr, person_nr, a_typ,
	quelle_nr, status, teil_pool_nr,
	haupt_name, land_code, haupt_ort, haupt_plz, medium,
	name1, name2, strasse, 
	kz_loeschen, nachname, vorname, titel_code, anrede_code,
	erfasser_id, datum_akt, lfd_nr_bericht, bezirk_id)
as 
select 
	a.adr_pool_nr, a.benutzer_id, a.pool_typ,
	k.e_mandant,
	a.adr_gr, a.adr_nr, a.person_nr, a.a_typ,
	a.quelle_nr, a.status, a.teil_pool_nr,
	b.haupt_name, b.land_code, b.haupt_ort, b.haupt_plz, c.medium,
	b.name1, b.name2, b.strasse, 
	p.kz_loeschen, p.nachname, p.vorname, p.titel_code, p.anrede_code,
	a.erfasser_id, a.datum_akt, a.lfd_nr_bericht, b.bezirk_id
from    adrpool a LEFT OUTER JOIN adrptp c  ON
        a.adr_pool_nr = c.adr_pool_nr and a.teil_pool_nr = c.teil_pool_nr 
                  LEFT OUTER JOIN adrpkopf k ON
        a.adr_pool_nr = k.adr_pool_nr,
        anschr b, person p
        where a.adr_gr = b.adr_gr 
	and a.adr_nr = b.adr_nr
	and p.adr_gr = a.adr_gr
	and p.adr_nr = a.adr_nr
	and p.person_nr = a.person_nr

