create view anprview 
       (anzart_id, beschreibung, verw_id, 
        e_mandant, obj_nr, ausg, jahr, hnr, waehrung)
as
select distinct a.anzart_id, a.beschreibung, a.verw_id, 
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung 
        from anzart a, preisefa p where a.anzart_id=p.anzart_id 
union
select distinct a.anzart_id, a.beschreibung, a.verw_id, 
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung 
        from anzart a, preisemm p where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.beschreibung, a.verw_id, 
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung 
        from anzart a, preiseonl p where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.beschreibung, a.verw_id, 
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung
        from anzart a, preisesi p where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.beschreibung, a.verw_id, 
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung
        from anzart a, preisete p where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.beschreibung, a.verw_id, 
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung
        from anzart a, preisezl p where a.anzart_id=p.anzart_id

GO
create view anvview
       (adr_gr, adr_nr, anv_nr, dispo_nr, dispopos_nr, person_nr,
        e_mandant, obj_nr, ausg, jahr, hnr, hnr_num,
        obj_nr_dispo, ausg_dispo, hnr_num_ab,
        auft_nr_ea, dispo_nr_ea, 
        status_dispo, produkt, abw_prod_bez, plazierungs_id, plaz_ext,
        anzart_id, anz_schaltung, farb_id, anz_si, anz_mm,
        anz_eintrag, format_id, volumen_fa, volumen_mm,
        netto_betrag, anzeigen_betrag, wa_prov_betrag, sonder_rabatt, volumen_rabatt, 
        wa_prov_satz, anz_zeilen, anz_sp, anz_anzeigen, anz_seiten,
        datum_neu, status, abrech_id, waehrung, verwend_typ, adr_nr_wa, person_nr_wa,
        hnr_ab, jahr_ab, heft_ab_num, hnr_bis, jahr_bis, heft_bis_num,
        haupt_name, kz_loeschen, kz_einmal_kd)
as
select d.adr_gr, d.adr_nr, d.anv_nr, d.dispo_nr, p.dispopos_nr, a.person_nr,
       d.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.hnr_num,
       d.obj_nr, d.ausg, d.hnr_num_ab,
       d.auft_nr_ea, d.dispo_nr_ea,
       d.status, p.produkt, p.abw_prod_bez, p.plazierungs_id, p.plaz_ext, 
       d.anzart_id, d.anz_schaltung, d.farb_id, d.anz_si, d.anz_mm,        
       d.anz_eintrag, d.format_id, d.volumen_fa, d.volumen_mm,
       d.netto_betrag, d.anzeigen_betrag, d.wa_prov_betrag, d.sonder_rabatt, d.volumen_rabatt,
       d.wa_prov_satz, d.anz_zeilen, d.anz_sp, d.anz_anzeigen, d.anz_seiten,
       a.datum_neu, a.status, a.abrech_id, a.waehrung, a.verwend_typ, a.adr_nr_wa, a.person_nr_wa,
       a.hnr_ab, a.jahr_ab, a.heft_ab_num, a.hnr_bis, a.jahr_bis, a.heft_bis_num,
       s.haupt_name, e.kz_loeschen, e.kz_einmal_kd
from   anvdpos p, anvdispo d, anvauftr a, anschr s, person e
where  p.adr_gr = d.adr_gr and p.adr_nr = d.adr_nr and p.anv_nr = d.anv_nr and 
       p.dispo_nr = d.dispo_nr and
       p.adr_gr = a.adr_gr and p.adr_nr = a.adr_nr and p.anv_nr = a.anv_nr and 
       p.adr_gr = s.adr_gr and p.adr_nr = s.adr_nr and       
       p.adr_gr = e.adr_gr and p.adr_nr = e.adr_nr and e.person_nr = 0

