CREATE VIEW atrview (
      adr_gr, adr_nr, konzern_id, konzern_name, haupt_name,
      name1, name2, name3,
      land_code, plz, ort, 
      nachname, vorname, person_nr,
      atr_auft_nr, status, atr_jahr, adr_nr_konzern)
AS SELECT
      a.adr_gr, a.adr_nr, a.konzern_id, k.syn, a.haupt_name, 
      a.name1, a.name2, a.name3, 
      a.land_code, a.haupt_plz, a.haupt_ort, 
      p.nachname, p.vorname, p.person_nr,
      atr.atr_auftr_nr, atr.status, atr_jahr, k.adr_nr
FROM
      anschr a
        LEFT OUTER JOIN atrauft atr ON
                           atr.adr_gr        = a.adr_gr      and
                           atr.adr_nr        = a.adr_nr
        LEFT OUTER JOIN person p ON
                           atr.adr_gr        = p.adr_gr      and
                           atr.adr_nr        = p.adr_nr      and
                           atr.person_nr     = p.person_nr
        LEFT OUTER JOIN konzern k ON
                           a.konzern_id      = k.konzern_id

GO
create view auftview 
       (adr_gr, adr_nr, auft_nr,
        volumen_fa, volumen_mm, anz_si, anz_dispos, status,
        anz_seiten, anz_gramm, netto_betrag)
  as
select adr_gr, adr_nr, auft_nr, 
          sum(volumen_fa), sum(volumen_mm), sum(anz_si), sum(anz_anzeigen), min(status), 
          sum(anz_seiten),sum(anz_gramm),sum(netto_betrag)
from   dispo
where  auft_hist_nr = 0 and dispo_hist_nr = 0 and
           (status<>'L' and status<>'S' and status<>'O')
group by adr_gr, adr_nr,auft_nr

