CREATE VIEW [dbo].[awaaview](adr_gr, adr_nr, person_nr, e_mandant, obj_nr, ausg, abo_nr,
					 akt_id, uakt_id, preis_kat, ber_menge, adr_nr_re, person_nr_re,
					 vbeg_dat, vend_dat, vbeg_heft, vend_heft, vbeg_jahr, vend_jahr, 
					 landart, preis_kat_no, k_grund, best_dat_abo, bestellg_abo,
					 vertreter_id, abo_kond, prov_status, kz_prov_schnorrer, prov_menge,
					 kgs, land_code, haupt_plz, plz_wohn, plz_post, plz_gk,
					 prov_kond, prov_std_aktion, kz_abw_prov, kz_prov_genehm,
					 datum_neu_abo, datum_aend_abo, no_ende_dat, no_ende_jahr, no_ende_hnr, k_datum,
					 kz_inaktiv_prov)
AS
SELECT 	a.adr_gr, a.adr_nr, a.person_nr, a.e_mandant, a.obj_nr, a.ausg, a.abo_nr, 
        a.w_akt_id, a.w_uakt_id, a.preis_kat, a.ber_menge, a.adr_nr_bv, a.person_nr_bv,
		a.vbeg_dat, a.vend_dat, a.vbeg_heft, a.vend_heft, a.vbeg_jahr, a.vend_jahr, 
		a.inaus, a.preis_kat_no, a.k_grund, a.best_datum, a.bestellg,
		w.vertreter_id, w.abo_kond, w.prov_status, w.kz_prov_schnorrer, prov_menge,
		i.kgs, 
		r.land_code, r.haupt_plz, r.plz_wohn, r.plz_post, r.plz_gk,
		m.prov_kond, m.prov_std_aktion, m.kz_abw_prov, m.kz_prov_genehm,
		a.datum_neu, a.datum_aend, a.no_ende_dat, a.no_ende_jahr, a.no_ende_hnr, a.k_datum,
		w.kz_inaktiv_prov
FROM   	anschr r,
        abostamm a LEFT OUTER JOIN ainfo i ON
		           a.adr_gr=i.adr_gr and
		           a.adr_nr=i.adr_nr 
		           LEFT OUTER JOIN werbepr w ON
		           a.adr_gr=w.adr_gr and
		           a.adr_nr=w.adr_nr and
		           a.person_nr=w.person_nr and
		           a.e_mandant=w.e_mandant and
		           a.obj_nr=w.obj_nr and
		           a.ausg=w.ausg and
	               a.abo_nr=w.abo_nr
				   LEFT OUTER JOIN mhaktion m ON
		           a.e_mandant = m.e_mandant and
		           a.w_akt_id  = m.akt_id
WHERE	a.adr_gr=r.adr_gr and
		a.adr_nr=r.adr_nr and
		a.datum_neu >= '01.04.2011' and
		w.vertreter_id is null and
		((w.prov_status='P') OR (w.prov_status='K') OR (w.prov_status='Z') OR (w.prov_status is NULL))

GO
create view [dbo].[benmanvi]
(e_mandant, e_anw, adr_gr, bklasse, benutzer_id, alias_name,bereich)
as select
ma.e_mandant, ma.e_anw, ab.adr_gr, ab.bklasse, be.benutzer_id, be.alias_name, an.bereich
from manan ma, adrber ab, benutzer be, anwend an
where
ma.adr_gr = ab.adr_gr and
ab.bklasse = be.bklasse and
an.e_anw = ma.e_anw and
(not exists (select * from manben mb where mb.benutzer_id = be.benutzer_id) or
exists (select * from manben mb where mb.benutzer_id = be.benutzer_id and mb.e_mandant = ma.e_mandant))

