create view beritbvi
(benutzer_id, tbau_id, verwend_typ, bez, text_nr, konto_id, text)
as select
a.benutzer_id, a.tbau_id, a.verwend_typ, a.bez, a.text_nr, a.konto_id, cast(b.text as varchar(400))
from beritbau a, texte b
where a.text_nr=b.text_nr

