CREATE VIEW bonview (
      bon_auftr_nr, beschreibung, bdatum, status, person_nr,
      adr_gr, adr_nr, haupt_name, haupt_plz, haupt_ort, name1, name2, 
      nachname, vorname, e_mandant)
AS SELECT
      g.bon_auftr_nr, g.beschreibung, g.bdatum, g.status, g.person_nr,
      a.adr_gr, a.adr_nr, a.haupt_name, a.haupt_plz, a.haupt_ort, a.name1, a.name2,
      p.nachname, p.vorname, g.e_mandant
FROM
      bonauftr g 
        LEFT OUTER JOIN anschr a ON
                           g.adr_gr        = a.adr_gr      and
                           g.adr_nr        = a.adr_nr
        LEFT OUTER JOIN person p ON
                           g.adr_gr        = p.adr_gr      and
                           g.adr_nr        = p.adr_nr      and
                           g.person_nr     = p.person_nr

