create view brieview (erfasser_id, datum_akt, lfd_nr, benutzer_id, n_art,
                      zeit_akt, adr_gr, adr_nr, person_nr, verfasser_id, 
                      adr_nr_wa, person_nr_wa, produkt_id, betreff, datum_bes,
                      g_art, datum_loe, kz_sperr, verteiler, vorname, nachname,
                      text_nr, datum_wv_verf, bebew_id, lfd_nr_anschr, verwend_typ,
                      bewert_id, text_nr_hist, text_nr_kurz, 
                      kz_erl, kz_gelesen, datum_wv, kz_aend, kz_wv_erl, zeit_wv,
                      key_num1, key_num2, key_char1)
as select s.erfasser_id, s.datum_akt, s.lfd_nr, s.benutzer_id, s.n_art,
          b.zeit_akt, b.adr_gr, b.adr_nr, b.person_nr, b.verfasser_id, 
          b.adr_nr_wa, b.person_nr_wa, b.produkt_id, b.betreff, b.datum_bes,
          b.g_art, b.datum_loe, b.kz_sperr, b.verteiler, b.vorname, b.nachname,
          b.text_nr, b.datum_wv_verf, b.bebew_id, b.lfd_nr_anschr, b.verwend_typ,
          b.bewert_id, b.text_nr_hist, b.text_nr_kurz, 
          s.kz_erl, s.kz_gelesen, s.datum_wv, s.kz_aend, s.kz_wv_erl, s.zeit_wv,
          s.key_num1, s.key_num2, s.key_char1      
from briefkas s, bericht b
where s.erfasser_id  = b.erfasser_id and
      s.datum_akt    = b.datum_akt and
      s.lfd_nr       = b.lfd_nr 

