create view brobview (erfasser_id, datum_akt, lfd_nr, e_mandant, obj_nr,
                      zeit_akt, adr_gr, adr_nr, person_nr, verfasser_id, 
                      adr_nr_wa, person_nr_wa, produkt_id, betreff, datum_bes,
                      g_art, datum_loe, kz_sperr, n_art, verteiler, vorname, nachname,
                      text_nr, datum_wv_verf, bebew_id, lfd_nr_anschr, verwend_typ,
                      bewert_id, text_nr_hist, text_nr_kurz) 
as select o.erfasser_id, o.datum_akt, o.lfd_nr, o.e_mandant, o.obj_nr,
          b.zeit_akt, b.adr_gr, b.adr_nr, b.person_nr, b.verfasser_id, 
          b.adr_nr_wa, b.person_nr_wa, b.produkt_id, b.betreff, b.datum_bes,
          b.g_art, b.datum_loe, b.kz_sperr, b.n_art, b.verteiler, b.vorname, b.nachname,
          b.text_nr, b.datum_wv_verf, b.bebew_id, b.lfd_nr_anschr, b.verwend_typ,
          b.bewert_id, b.text_nr_hist, b.text_nr_kurz 
from beriobj o, bericht b
where o.erfasser_id  = b.erfasser_id and
      o.datum_akt    = b.datum_akt and
      o.lfd_nr       = b.lfd_nr 

