create view [dbo].[bsumview]
	(auft_nr, anz_pos, ber_menge, frei_menge, preiskat,
	vers_ist_dat, l_ausg_nr)  
  as
select  s.auft_nr, count(*), sum(s.ber_menge), sum(s.frei_menge),
	min(s.preiskat), min(s.vers_ist_dat), min(s.l_ausg_nr)
from    buaufpos s
where s.l_ausg_nr > 0
group by auft_nr

GO
create view buaaview (e_mandant, auft_nr, auf_pos, 
       best_datum, l_vers_dat, fakt_soll_dat, akt_id, uakt_id,
       staord_nr, l_ausg_nr, artikel_nr, isbn, so_pos_id, status, auftrag_typ,
       rech_nr, rech_dat, auftrag_verw, pos_status, ber_menge, frei_menge, retour_menge, 
       l_aufl_nr, herkunft, pos_betrag, p_status_lief, f_mandant, rech_typ, r_art, rech_ref, vers_soll_dat,
       re_brutto, re_mwst, re_netto)
  as
select s.e_mandant, s.auft_nr, s.auf_pos, 
       a.best_datum, a.l_vers_dat, a.fakt_soll_dat, a.akt_id, a.uakt_id,
       a.staord_nr, s.l_ausg_nr, m.artikel_nr, b.isbn, o.so_pos_id, a.status, a.auftrag_typ,
       f.rech_nr, f.rech_dat, a.auftrag_verw, s.status, s.ber_menge, s.frei_menge, s.retour_menge,
       s.l_aufl_nr, a.herkunft, s.pos_betrag, f.p_status_lief,
       t.f_mandant, t.rech_typ, t.r_art, t.rech_ref, a.vers_soll_dat,
       t.re_brutto, t.re_mwst, t.re_netto
  from buauftra a, 
          buaufpos s LEFT OUTER JOIN bumanaus m ON
                   m.e_mandant = s.e_mandant and
                   m.l_ausg_nr  = s.l_ausg_nr 
              LEFT OUTER JOIN buausgab b ON
                   b.l_ausg_nr  = s.l_ausg_nr
              LEFT OUTER JOIN busopos o ON
                   o.so_pos_id  = s.so_pos_id 
              LEFT OUTER JOIN bufakupo f ON
                   f.auft_nr = s.auft_nr and
                   f.auf_pos = s.auf_pos
              LEFT OUTER JOIN bufakst t ON
                   t.rech_nr = f.rech_nr and
                   t.rech_dat = f.rech_dat and
                   t.f_mandant = f.f_mandant
 where a.auft_nr = s.auft_nr

