create view [dbo].[buabovie] (adr_gr, adr_nr, person_nr, e_mandant, obj_nr, ausg, abo_nr, adr_nr_bv, person_nr_bv, 
               abostatus, vbeg_dat, list_nr, bu_ra)
   as
select a.adr_gr, a.adr_nr, a.person_nr, a.e_mandant, a.obj_nr, a.ausg, a.abo_nr, a.adr_nr_bv, a.person_nr_bv,
       a.abostatus, k.versand_soll, NULL, p.bu_ra
from abostamm a, mobjtyp m, burabobj b, kalender k, burabatt p, preiskat v 
where a.e_mandant  = m.e_mandant and
      a.obj_nr     = m.obj_nr and
      m.kz_abrech  = 'H' and
      a.preis_kat  = v.preis_kat and
      v.berechnen != 'N' and
      a.e_mandant  = k.e_mandant and
      a.obj_nr     = k.obj_nr and
      a.ausg       = k.ausg and
      a.vbeg_heft  = k.hnr and
      a.vbeg_jahr  = k.jahr and  
      b.bu_ra      = p.bu_ra and
      a.e_mandant  = b.e_mandant and
      ((a.obj_nr   = b.obj_nr) or 
      (b.obj_nr    = '0'))
union
select a.adr_gr, a.adr_nr, a.person_nr, a.e_mandant, a.obj_nr, a.ausg, a.abo_nr, a.adr_nr_bv, a.person_nr_bv,
       a.abostatus, a.vbeg_dat, NULL, p.bu_ra
from abostamm a, mobjtyp m, burabobj b, burabatt p, preiskat v 
where a.e_mandant  = m.e_mandant and
      a.obj_nr     = m.obj_nr and
      m.kz_abrech  = 'Z' and
      a.preis_kat  = v.preis_kat and
      v.berechnen != 'N' and
      b.bu_ra      = p.bu_ra and
      a.e_mandant  = b.e_mandant and
      ((a.obj_nr   = b.obj_nr) or 
      (b.obj_nr    = '0'))
union
select a.adr_gr, a.adr_nr, a.person_nr, a.e_mandant, a.obj_nr, a.ausg, a.abo_nr, a.adr_nr_bv, a.person_nr_bv,
       a.abostatus, a.vbeg_dat, p.list_nr, NULL
from abostamm a, mobjtyp m, bupreobj b, buplist p, preiskat v 
where a.e_mandant  = m.e_mandant and
      a.obj_nr     = m.obj_nr and
      m.kz_abrech  = 'Z' and
      a.preis_kat  = v.preis_kat and
      v.berechnen != 'N' and
      b.list_nr    = p.list_nr and
      a.e_mandant  = b.e_mandant and
      ((a.obj_nr   = b.obj_nr) or 
      (b.obj_nr    = '0'))
union
select a.adr_gr, a.adr_nr, a.person_nr, a.e_mandant, a.obj_nr, a.ausg, a.abo_nr, a.adr_nr_bv, a.person_nr_bv,
       a.abostatus, k.versand_soll, p.list_nr, NULL
from abostamm a, mobjtyp m, bupreobj b, kalender k, buplist p, preiskat v 
where a.e_mandant  = m.e_mandant and
      a.obj_nr     = m.obj_nr and
      m.kz_abrech  = 'H' and
      a.preis_kat  = v.preis_kat and
      v.berechnen != 'N' and
      a.e_mandant  = k.e_mandant and
      a.obj_nr     = k.obj_nr and
      a.ausg       = k.ausg and
      a.vbeg_heft  = k.hnr and
      a.vbeg_jahr  = k.jahr and  
      b.list_nr    = p.list_nr and
      a.e_mandant  = b.e_mandant and
      ((a.obj_nr   = b.obj_nr) or 
      (b.obj_nr    = '0'))

