create view buabsvi1
       (e_mandant, l_ausg_nr, l_aufl_nr, artikel_nr, n_artikel_nr, prod_typ, kz_bod, format, sum_menge)
as
select a.e_mandant, a.l_ausg_nr, a.l_aufl_nr, a.artikel_nr, a.n_artikel_nr, b.prod_typ, b.kz_bod, h.format, 
sum(sum_ber_menge+sum_frei_ber- sum_gut_menge- sum_frei_gut) 
from absatzview a, 
     buausgab b LEFT OUTER JOIN buherste h on
          b.l_ausg_nr = h.l_ausg_nr
where a.l_ausg_nr=b.l_ausg_nr and 
      a.rech_dat>=DateAdd(year, -3,getDate())
group by a.e_mandant, a.l_ausg_nr, a.l_aufl_nr, a.artikel_nr, a.n_artikel_nr, b.prod_typ, b.kz_bod, h.format

