create view [dbo].[buaoview] (l_titel_nr, l_ausg_nr, titel_such,
                    titel1, sprach_code, orig_titel, org_spr_code, verlags_id, 
                    isbn, ean, prod_typ,  reihen_code, kombityp, issn, ausg_text,
                    e_mandant, artikel_nr, nachname, vorname, haupt_name,
                    sperr_grund, kz_loeschen, herkunft, grup_id)
  as
select a.l_titel_nr, b.l_ausg_nr,  t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id, 
           b.isbn, b.ean, b.prod_typ,  b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name,
           b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id
  from  butitel t, 
           buautor a LEFT OUTER JOIN buausgab b ON
                   b.l_titel_nr  = a.l_titel_nr 
                                  LEFT OUTER JOIN bumanaus m ON
                                         m.l_ausg_nr  = b.l_ausg_nr
 where t.l_titel_nr = a.l_titel_nr 

GO
create view buarview (l_titel_nr, l_ausg_nr, titel_such,
                    titel1, sprach_code, orig_titel, org_spr_code, verlags_id, 
                    isbn, ean, prod_typ,  reihen_code, kombityp, issn, ausg_text,
                    e_mandant, artikel_nr, nachname, vorname, haupt_name, autor_nr,
                    sperr_grund, kz_loeschen, herkunft, grup_id, b_id_aend, bu_la_id, kz_aufl_best)
  as
select t.l_titel_nr, m.l_ausg_nr,  t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id, 
           b.isbn, b.ean, b.prod_typ,  b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name, a.autor_nr,
           b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id, t.b_id_aend, b.bu_la_id, b.kz_aufl_best

  from  butitel t, bumanaus m, 
           buausgab b LEFT OUTER JOIN buautor a ON
                     b.l_titel_nr = a.l_titel_nr
 where b.l_ausg_nr = m.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            b.l_titel_nr > 0
union
  select b.l_titel_nr, m.l_ausg_nr,  b.ausg_text,
           s.artikel_bez, s.sprach_code, s.artikel_bez, s.sprach_code, b.verlags_id, 
           b.isbn, (case when c.ean is not null then c.ean else b.ean end), b.prod_typ,  
           b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name, a.bearb_nr,
           b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id, b.b_id_aend, b.bu_la_id, b.kz_aufl_best
  from bumanaus m, buausspr s, 
           buausgab b LEFT OUTER JOIN bubearb a ON
                     b.l_ausg_nr = a.l_ausg_nr
                  LEFT OUTER JOIN buaufl c ON
                     c.l_ausg_nr = b.l_ausg_nr and c.l_aufl_nr > 0
 where b.l_ausg_nr = m.l_ausg_nr and
            s.l_ausg_nr  = b.l_ausg_nr and
            b.l_titel_nr = 0

GO
create view [dbo].[buauslag] (lager_code, kz_aussen, l_ausg_nr, l_aufl_nr, auflage_nr, e_mandant, best_art, artikel_nr, lager_mandant, 
            l_titel_nr, titel_such, titel1, isbn, kz_bestand, kombityp, meld_nr, sum_menge)
  as
select l.lager_code, r.kz_aussen, l.l_ausg_nr, l.l_aufl_nr, a.auflage_nr, l.e_mandant, l.best_art, m.artikel_nr, m.lager_mandant, 
       b.l_titel_nr, t.titel_such, t.titel1, b.isbn, b.kz_bestand, b.kombityp, a.meld_nr, sum(l.menge)
  from bulagbes l, bumanaus m, bulagreg r, buaufl a, buausgab b, butitel t
  where r.lager_code = l.lager_code and
        r.regal_id   = l.regal_id and
        m.l_ausg_nr  = l.l_ausg_nr and
        m.e_mandant  = l.e_mandant and
        b.l_ausg_nr  = l.l_ausg_nr and
        t.l_titel_nr = b.l_titel_nr and
        a.l_ausg_nr  = l.l_ausg_nr and
        a.l_aufl_nr  = l.l_aufl_nr
  group by l.lager_code, r.kz_aussen, l.l_ausg_nr, l.l_aufl_nr, a.auflage_nr, l.e_mandant, l.best_art, m.artikel_nr, m.lager_mandant, 
       b.l_titel_nr, t.titel_such, t.titel1, b.isbn, b.kz_bestand, b.kombityp, a.meld_nr

