create view [dbo].[buauview] (e_mandant, auft_nr, adr_gr, adr_nr_best, person_nr_best,
       haupt_name_best, nachname_best, vorname_best, 
       adr_nr_re, person_nr_re, haupt_name_re, nachname_re, vorname_re, 
       adr_nr_le, person_nr_le, haupt_name_le, nachname_le, vorname_le,
       best_datum, l_vers_dat, fakt_soll_dat, akt_id, uakt_id, staord_nr, status, auftrag_typ, herkunft, r_art, kz_kommission)
  as
select b.e_mandant, b.auft_nr, b.adr_gr, b.adr_nr_best, b.person_nr_best,
       a1.haupt_name, p1.nachname, p1.vorname, 
       b.adr_nr_re, b.person_nr_re, a2.haupt_name, p2.nachname, p2.vorname, 
       b.adr_nr_le, b.person_nr_le, a3.haupt_name, p3.nachname, p3.vorname,
       b.best_datum, b.l_vers_dat, b.fakt_soll_dat, b.akt_id, b.uakt_id, b.staord_nr, b.status, 
       b.auftrag_typ, b.herkunft, b.r_art, b.kz_kommission
from buauftra b LEFT OUTER JOIN anschr a1 ON
              b.adr_gr  = a1.adr_gr and 
              b.adr_nr_best  = a1.adr_nr
           LEFT OUTER JOIN person p1 ON
              b.adr_gr  = p1.adr_gr and 
              b.adr_nr_best  = p1.adr_nr and 
              b.person_nr_best  =  p1.person_nr
           LEFT OUTER JOIN anschr a2 ON
              b.adr_gr  = a2.adr_gr and 
              b.adr_nr_re  = a2.adr_nr
           LEFT OUTER JOIN  person p2 ON
              b.adr_gr  = p2.adr_gr and 
              b.adr_nr_re  = p2.adr_nr and 
              b.person_nr_re  = p2.person_nr 
           LEFT OUTER JOIN anschr a3 ON
              b.adr_gr  = a3.adr_gr and 
              b.adr_nr_le  = a3.adr_nr
           LEFT OUTER JOIN person p3 ON
              b.adr_gr  = p3.adr_gr and 
              b.adr_nr_le  = p3.adr_nr and 
              b.person_nr_le  = p3.person_nr 

