create view [dbo].[bubewvie] (lager_code, regal_id, ebene_id, platz_id, l_ausg_nr, e_mandant, 
           best_art, l_aufl_nr, bew_menge, menge, artikel_nr, lager_mandant, l_titel_nr,
           titel_such, isbn, bew_art, bew_dat, bew_typ, bew_nr, umbuch_nr, ab_zu_buchung,
           auft_nr, auf_pos, b_id_aend, herkunft, n_artikel_nr, nummer1, kz_loeschen)
  as
select  w.lager_code, w.regal_id, w.ebene_id, w.platz_id, w.l_ausg_nr, w.e_mandant, 
           w.best_art, w.l_aufl_nr, w.bew_menge, l.menge, m.artikel_nr, m.lager_mandant, t.l_titel_nr,
           t.titel_such, b.isbn, w.bew_art, w.bew_dat, w.bew_typ, w.bew_nr, w.umbuch_nr, w.ab_zu_buchung,
           w.auft_nr,w.auf_pos, w.b_id_aend, b.herkunft, dbo.char2num(m.artikel_nr), w.nummer1, m.kz_loeschen
 from bumanaus m, buausgab b, butitel t, 
         bulagbew w LEFT OUTER JOIN bulagbes l ON
               l.lager_code = w.lager_code and
               l.regal_id = w.regal_id and 
               l.ebene_id  = w.ebene_id and 
               l.platz_id  = w.platz_id and
               l.l_ausg_nr = w.l_ausg_nr and
               l.l_aufl_nr  = w.l_aufl_nr and
               l.best_art  = w.best_art and
               l.e_mandant  = w.e_mandant 
 where  m.l_ausg_nr  = w.l_ausg_nr and
            m.e_mandant  = w.e_mandant and
            b.l_ausg_nr  = w.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr 

