                    verlags_id, best_menge, ek_preis, liefer_menge, ges_preis, pos_betrag, ber_menge,
                    frei_menge, adr_nr_re, person_nr_re, kz_storno_ek, kz_storno_pos, status_auf, status_pos,
                    waehrung, kz_bestaetigt, rab_proz, n_artikel_nr, mahn_dat, meld_nr, mahn_tage, erstmahn_tage,
                    kz_storno_intern, fax_nr, email, rech_nr, rech_dat, mahn_menge, rem_menge)
  as
select p.e_mandant, p.ek_nr, p.pos_nr, p.l_ausg_nr, p.l_aufl_nr, 
                    m.artikel_nr, b.isbn, l.auflage_nr, t.titel_such, b.ausg_text, p.best_art, p.lief_dat_soll, 
                    p.lief_dat_ist, p.k_woche, p.zustand_id, s.adr_gr_li, s.adr_nr_li, a.haupt_name, s.ek_best_nr, 
                    s.best_dat, s.verlags_id, p.best_menge, p.ek_preis, p.liefer_menge, p.ges_preis, p.pos_betrag, 
                    p.ber_menge, p.frei_menge, s.adr_nr_re, s.person_nr_re, s.kz_storno, p.kz_storno, 
                    s.status, p.status, s.waehrung, p.kz_bestaetigt, p.rab_proz, dbo.char2num(m.artikel_nr),
                    p.mahn_dat, l.meld_nr, e.mahn_tage, d.erstmahn_tage, p.kz_storno_intern, null, null, p.rech_nr, 
                    p.rech_dat, p.mahn_menge, p.rem_menge
  from buekpos p, buausgab b, bumanaus m, buaufl l, butitel t, bumeldnr e, land d, 
          buekstam s LEFT OUTER JOIN anschr a ON
               a.adr_gr = s.adr_gr_li and
               a.adr_nr = s.adr_nr_li 
 where s.e_mandant = p.e_mandant and
            s.ek_nr = p.ek_nr and 
            m.e_mandant = p.e_mandant and
            m.l_ausg_nr  = p.l_ausg_nr and
            b.l_ausg_nr  = p.l_ausg_nr and
            l.l_ausg_nr  = p.l_ausg_nr and
            l.l_aufl_nr  = p.l_aufl_nr and
            t.l_titel_nr = b.l_titel_nr and
            e.meld_nr = l.meld_nr and 
            d.land_code = a.land_code

GO
create view [dbo].[bufaklsv] (abruf_nr, rech_nr, rech_dat, e_mandant, rech_typ, auft_nr, ref_nr)		  
as
select  p.abruf_nr, p.rech_nr, p.rech_dat, p.e_mandant, s.rech_typ, p.auft_nr, p.lief_ref
from bufakpos p, bufakst s
where p.rech_nr    = s.rech_nr   and
      p.rech_dat   = s.rech_dat  and
      p.f_mandant  = s.f_mandant and
      p.rech_nr > 0  and
      p.lief_ref  is null and
      (s.rech_typ = 'LS' or s.rech_typ = 'L')

