create view bufaksev (rech_nr, rech_dat, f_mandant, adr_gr, adr_nr_e, person_nr_e, 
                      pos_nr, upos_nr, e_mandant, rech_typ, r_art, l_ausg_nr, l_aufl_nr, best_art, artikel_nr,
		      gewicht, ber_menge, kombityp, gelief_men, p_status_lief, so_pos_id, 
		      waehrung, auf_pos, auftrag_verw, land_e, preiskat, raproz,  staord_nr,
		      frei_menge, abruf_nr, r_formular, fd_id, obj_nr, kz_probeheft, kz_strecke, titel1,
		      akt_id, uakt_id, vertret_auft_typ, auft_nr, prov_grp, upos_sum_br, upos_sum_ne, kz_prov_erl,
		      vertreter_id, adr_nr_re, sortierung, upos_brutto, person_nr_re, LAGER_CODE, upos_netto, NACH_NR_LE, 
                      rech_ref, shop_id, herkunft, kz_kommission, auftrag_typ, kz_partie, kz_manuell, steuer_code, 
                      upos_ne_lief, kz_agentur, pos_gewicht, vers_weg, versart, LAND_GR_E, ZAHLBED, MWST_FREI, EG_ID,
                      E_PREIS_BR, UPOS_SUM_MW, MW_PROZ, VERTRETER_ID_UPOS, vg_menge, prod_typ, best_weg, best_datum, artikel_nr_set, bundle, set_nr)		
as
select  u.rech_nr, u.rech_dat, u.f_mandant, s.adr_gr, s.adr_nr_e, s.person_nr_e, 
        u.pos_nr, u.upos_nr, u.e_mandant, s.rech_typ, s.r_art, t.l_ausg_nr, t.l_aufl_nr, t.best_art, t.artikel_nr, 
	p.gewicht, t.ber_menge, u.kombityp, t.gelief_men, u.p_status_lief, u.so_pos_id,
	s.waehrung, u.auf_pos, a.auftrag_verw, s.land_e, u.preiskat, u.raproz, p.staord_nr,
	t.frei_menge, s.abruf_nr, s.r_formular, s.fd_id, u.obj_nr, u.kz_probeheft, u.kz_strecke, t.titel1,
        p.akt_id, p.uakt_id, p.vertret_auft_typ, u.auft_nr, u.prov_grp, t.upos_sum_br, t.upos_sum_ne, u.kz_prov_erl,
	s.vertreter_id, a.adr_nr_re, s.sortierung, t.upos_brutto, a.person_nr_re, u.LAGER_CODE, t.upos_netto, f.NACH_NR_LE, 
        s.rech_ref, u.shop_id, s.herkunft, a.kz_kommission, p.auftrag_typ, u.kz_partie, s.kz_manuell, t.steuer_code, 
        u.upos_ne_lief, s.kz_agentur, u.gewicht, s.vers_weg, s.versart, s.LAND_GR_E, s.ZAHLBED, s.MWST_FREI, s.EG_ID,
        t.E_PREIS_BR, t.UPOS_SUM_MW, t.MW_PROZ, u.VERTRETER_ID_UPOS, t.vg_menge, u.prod_typ, a.best_weg, p.best_datum, t.artikel_nr_set, u.bundle, t.set_nr
from bufakst s, bufakpos p, bufakset t,
     bufakupo u LEFT OUTER JOIN bufaktmp f on
        f.rech_nr    = u.rech_nr   and
        f.datum      = u.rech_dat   and
        f.auft_nr    = u.auft_nr   and
        f.auf_pos    = u.auf_pos   
     LEFT OUTER JOIN buauftra a on
         u.auft_nr    = a.auft_nr and 
         u.abruf_nr   >= 0
where u.rech_nr    = s.rech_nr   and
      u.rech_dat   = s.rech_dat  and
	u.f_mandant  = s.f_mandant and
	u.rech_nr    = p.rech_nr   and
	u.rech_dat   = p.rech_dat  and
	u.f_mandant  = p.f_mandant and
	u.pos_nr     = p.pos_nr and   
        u.rech_nr      = t.rech_nr and
        u.rech_dat     = t.rech_dat and
        u.f_mandant    = t.f_mandant and
        u.pos_nr       = t.pos_nr and
        u.upos_nr      = t.upos_nr

GO
create view [dbo].[bufakvie] (rech_nr, rech_dat, f_mandant, adr_gr, adr_nr_e, person_nr_e, 
                      pos_nr, upos_nr, e_mandant, rech_typ, r_art, l_ausg_nr, l_aufl_nr, best_art, artikel_nr,
		      gewicht, ber_menge, kombityp, gelief_men, p_status_lief, so_pos_id, 
		      waehrung, auf_pos, auftrag_verw, land_e, preiskat, raproz,  staord_nr,
		      frei_menge, abruf_nr, r_formular, fd_id, obj_nr, kz_probeheft, kz_strecke, titel1,
		      akt_id, uakt_id, vertret_auft_typ, auft_nr, prov_grp, upos_sum_br, upos_sum_ne, kz_prov_erl,
		      vertreter_id, adr_nr_re, sortierung, upos_brutto, person_nr_re, LAGER_CODE, upos_netto, NACH_NR_LE, 
                      rech_ref, shop_id, herkunft, kz_kommission, auftrag_typ, kz_partie, kz_manuell, steuer_code, 
                      upos_ne_lief, kz_agentur, pos_gewicht, vers_weg, versart, LAND_GR_E, ZAHLBED, MWST_FREI, EG_ID,
                      E_PREIS_BR, UPOS_SUM_MW, MW_PROZ, VERTRETER_ID_UPOS, vg_menge, prod_typ, best_weg, best_datum)		
as
select  u.rech_nr, u.rech_dat, u.f_mandant, s.adr_gr, s.adr_nr_e, s.person_nr_e, 
        u.pos_nr, u.upos_nr, u.e_mandant, s.rech_typ, s.r_art, u.l_ausg_nr, u.l_aufl_nr, u.best_art, u.artikel_nr, 
	p.gewicht, u.ber_menge, u.kombityp, u.gelief_men, u.p_status_lief, u.so_pos_id,
	s.waehrung, u.auf_pos, a.auftrag_verw, s.land_e, u.preiskat, u.raproz, p.staord_nr,
	u.frei_menge, s.abruf_nr, s.r_formular, s.fd_id, u.obj_nr, u.kz_probeheft, u.kz_strecke, u.titel1,
        p.akt_id, p.uakt_id, p.vertret_auft_typ, u.auft_nr, u.prov_grp, u.upos_sum_br, u.upos_sum_ne, u.kz_prov_erl,
	s.vertreter_id, a.adr_nr_re, s.sortierung, u.upos_brutto, a.person_nr_re, u.LAGER_CODE, u.upos_netto, f.NACH_NR_LE, 
        s.rech_ref, u.shop_id, s.herkunft, a.kz_kommission, p.auftrag_typ, u.kz_partie, s.kz_manuell, u.steuer_code, 
        u.upos_ne_lief, s.kz_agentur, u.gewicht, s.vers_weg, s.versart, s.LAND_GR_E, s.ZAHLBED, s.MWST_FREI, s.EG_ID,
        u.E_PREIS_BR, u.UPOS_SUM_MW, u.MW_PROZ, u.VERTRETER_ID_UPOS, u.vg_menge, u.prod_typ, a.best_weg, p.best_datum
from bufakst s, bufakpos p, 
     bufakupo u LEFT OUTER JOIN bufaktmp f on
        f.rech_nr    = u.rech_nr   and
        f.datum      = u.rech_dat   and
        f.auft_nr    = u.auft_nr   and
        f.auf_pos    = u.auf_pos   
     LEFT OUTER JOIN buauftra a on
         u.auft_nr    = a.auft_nr and 
         u.abruf_nr   >= 0
where u.rech_nr    = s.rech_nr   and
      u.rech_dat   = s.rech_dat  and
	u.f_mandant  = s.f_mandant and
	u.rech_nr    = p.rech_nr   and
	u.rech_dat   = p.rech_dat  and
	u.f_mandant  = p.f_mandant and
	u.pos_nr     = p.pos_nr    

GO
create view [dbo].[bufastvi] (rech_nr, rech_dat, f_mandant,adr_gr,adr_nr_e,person_nr_e, pos_nr, upos_nr, e_mandant, 
                      rech_typ, l_ausg_nr, l_aufl_nr, best_art, artikel_nr, gewicht, ber_menge, gelief_men, 
                      abruf_nr, land_code, staord_nr, r_artikel_nr, eti_1, eti_2, eti_3, eti_4, eti_5, eti_6,
                      eti_7, eti_8, eti_9, eti_10,vers_weg,versart)
as
select u.rech_nr, u.rech_dat, u.f_mandant, s.adr_gr,s.adr_nr_e,s.person_nr_e,u.pos_nr, u.upos_nr, u.e_mandant,
           s.rech_typ, u.l_ausg_nr, u.l_aufl_nr, u.best_art, u.artikel_nr, p.gewicht, u.ber_menge, u.gelief_men, 
           s.abruf_nr, s.land_e, p.staord_nr, m.artikel_nr, s.eti_1_e, s.eti_2_e, s.eti_3_e, s.eti_4_e, 
           s.eti_5_e, s.eti_6_e, s.eti_7_e, s.eti_8_e, s.eti_9_e, s.eti_10_e ,s.vers_weg,s.versart
from bufakupo u, bufakst s, bufakpos p, bustaord a, bumanaus m
where u.rech_nr = s.rech_nr and
      u.rech_dat = s.rech_dat and
      u.f_mandant = s.f_mandant and
      u.rech_nr = p.rech_nr and
      u.rech_dat = p.rech_dat and
      u.f_mandant = p.f_mandant and
      u.pos_nr = p.pos_nr and
      p.staord_nr = a.staord_nr  and
      a.e_mandant = m.e_mandant  and
      a.l_ausg_nr_k = m.l_ausg_nr

GO
create view [dbo].[bufoview] (e_mandant, staord_nr, adr_gr, adr_nr_re, person_nr_re, adr_nr_le, person_nr_le, 
       sto_beg, sto_end, l_ausg_nr_start, l_ausg_nr_k, ber_menge, frei_menge, kz_zus_band, storno, status,
       kz_basis_band, datum_von_inaktiv, datum_bis_inaktiv, u_ausg_nr, l_aufl_nr, menge, sto_datum, nov_dat,
       kz_zus_band_kombi, kz_basis_band_kombi, gueltig_bis_menge, ber_menge_2, frei_menge_2, anz_freilief, auftrag_typ)
  as
select b.e_mandant, b.staord_nr, b.adr_gr, b.adr_nr_re, b.person_nr_re, b.adr_nr_le, b.person_nr_le, 
       b.sto_beg, b.sto_end, b.l_ausg_nr_start, b.l_ausg_nr_k, b.ber_menge, b.frei_menge, b.kz_zus_band, 
       b.storno, b.status,b.kz_basis_band, b.datum_von_inaktiv, b.datum_bis_inaktiv, k.u_ausg_nr, k.l_aufl_nr,
       k.menge, m.sto_datum, m.nov_dat, a.kz_zus_band, a.kz_basis_band, b.gueltig_bis_menge, b.ber_menge_2, 
       b.frei_menge_2, b.anz_freilief, b.auftrag_typ
from bustaord b, bukombi k, bumanaus m, buausgab a
where k.l_ausg_nr = b.l_ausg_nr_k and 
      b.sto_beg is not null and
      m.e_mandant = b.e_mandant and
      m.l_ausg_nr = k.u_ausg_nr and
      a.l_ausg_nr = k.u_ausg_nr and
      k.kz_fortsetz = 'T' and
      (b.kz_zus_band = 'T' or a.kz_zus_band = 'F')
union
select b.e_mandant, b.staord_nr, b.adr_gr, b.adr_nr_re, b.person_nr_re, b.adr_nr_le, b.person_nr_le, 
       (select nov_dat from bumanaus m1 where m1.e_mandant = b.e_mandant and m1.l_ausg_nr = b.l_ausg_nr_start),
       b.sto_end, b.l_ausg_nr_start, b.l_ausg_nr_k, b.ber_menge, b.frei_menge, b.kz_zus_band, 
       b.storno, b.status,b.kz_basis_band, b.datum_von_inaktiv, b.datum_bis_inaktiv, k.u_ausg_nr, k.l_aufl_nr,
       k.menge, m.sto_datum, m.nov_dat, a.kz_zus_band, a.kz_basis_band, b.gueltig_bis_menge, b.ber_menge_2, 
       b.frei_menge_2, b.anz_freilief, b.auftrag_typ
from bustaord b, bukombi k, bumanaus m, buausgab a
where k.l_ausg_nr = b.l_ausg_nr_k and 
      b.sto_beg is null and
      b.l_ausg_nr_start is not null and
      m.e_mandant = b.e_mandant and
      m.l_ausg_nr = k.u_ausg_nr and
      a.l_ausg_nr = k.u_ausg_nr and
      k.kz_fortsetz = 'T'and
      (b.kz_zus_band = 'T' or a.kz_zus_band = 'F')

GO
create view bufreivi
       (e_mandant, rech_typ, datum, l_ausg_nr, l_aufl_nr, adr_gr, adr_nr, person_nr, artikel_nr, isbn, verlags_id, 
        n_artikel_nr, kurztitel, auflage_nr, frei_menge, veranlasser_id, auft_nr, auf_pos,
        kz_partie, herkunft, liz_typ, rech_nr, gelief_menge, retour_nr, ret_menge, ret_gr_id, ret_datum, zustand_id,
        adr_nr_verlag, adr_nr_lief, anz_ivwauf, akt_id, best_text)
  as
  select u.e_mandant, s.rech_typ, s.rech_dat, t.l_ausg_nr, t.l_aufl_nr, 
         s.adr_gr, s.adr_nr_e, s.person_nr_e, t.artikel_nr, b.isbn, b.verlags_id, dbo.char2num(t.artikel_nr),
         t.titel1, l.auflage_nr, t.frei_menge, a.veranlasser_id, u.auft_nr, u.auf_pos, u.kz_partie, s.herkunft, u.liz_typ, s.rech_nr,
         t.gelief_men, r.retour_nr, r.menge, r.ret_gr_id, r.ret_datum, r.zustand_id, v.adr_nr, v.adr_nr_li, 
         (select count(*) from buivwauf w where w.e_mandant=s.e_mandant and w.l_ausg_nr=t.l_ausg_nr and w.l_aufl_nr=t.l_aufl_nr), f.akt_id,
         f.best_text
from  bufakst s, buaufl l, buauftra a, bufakset t, bufakpos f,
         bufakupo u LEFT OUTER JOIN buretour r ON 
             u.auft_nr      = r.auft_nr 
             and u.auf_pos      = r.auf_pos, 
         buausgab b LEFT OUTER JOIN buverlag v ON 
                  b.verlags_id   = v.verlags_id
where s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and s.rech_typ     like 'R%'
  and (s.rech_typ != 'RS' or s.r_art != 'P' or u.p_status_lief != 'F')
  and (s.rech_typ != 'RO' or s.r_art != 'P')
  and s.rech_nr      = f.rech_nr
  and s.rech_dat     = f.rech_dat
  and s.f_mandant    = f.f_mandant
  and f.rech_nr      = u.rech_nr
  and f.rech_dat     = u.rech_dat
  and f.f_mandant    = u.f_mandant
  and f.pos_nr       = u.pos_nr
  and u.l_ausg_nr    = b.l_ausg_nr
  and u.l_ausg_nr    = l.l_ausg_nr
  and u.l_aufl_nr    = l.l_aufl_nr
  and u.auft_nr      = a.auft_nr
  and u.rech_nr      = t.rech_nr
  and u.rech_dat     = t.rech_dat
  and u.f_mandant    = t.f_mandant
  and u.pos_nr       = t.pos_nr
  and u.upos_nr      = t.upos_nr
  and ((u.bundle!='F' and u.bundle != 'E') or u.bundle is null)
  and ((u.preiskat != '$NU%' and u.preiskat != '$NU&') or u.preiskat is null)
union
  select u.e_mandant, s.rech_typ, s.rech_dat, u.l_ausg_nr, u.l_aufl_nr, 
         s.adr_gr, s.adr_nr_e, s.person_nr_e, u.artikel_nr, b.isbn, b.verlags_id, dbo.char2num(u.artikel_nr),
         u.titel1, l.auflage_nr, u.frei_menge, a.veranlasser_id, u.auft_nr, u.auf_pos, u.kz_partie, s.herkunft, u.liz_typ, s.rech_nr,
         u.gelief_men, r.retour_nr, r.menge, r.ret_gr_id, r.ret_datum, r.zustand_id, v.adr_nr, v.adr_nr_li, 
         (select count(*) from buivwauf w where w.e_mandant=s.e_mandant and w.l_ausg_nr=u.l_ausg_nr and w.l_aufl_nr=u.l_aufl_nr), f.akt_id,
         f.best_text
from  bufakst s, buaufl l, buauftra a, bufakpos f,
         bufakupo u LEFT OUTER JOIN buretour r ON 
             u.auft_nr      = r.auft_nr 
             and u.auf_pos      = r.auf_pos, 
         buausgab b LEFT OUTER JOIN buverlag v ON 
                  b.verlags_id   = v.verlags_id
where s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and s.rech_typ     like 'R%'
  and (s.rech_typ != 'RS' or s.r_art != 'P' or u.p_status_lief != 'F')
  and (s.rech_typ != 'RO' or s.r_art != 'P')
  and s.rech_nr      = f.rech_nr
  and s.rech_dat     = f.rech_dat
  and s.f_mandant    = f.f_mandant
  and f.rech_nr      = u.rech_nr
  and f.rech_dat     = u.rech_dat
  and f.f_mandant    = u.f_mandant
  and f.pos_nr       = u.pos_nr
  and u.l_ausg_nr    = b.l_ausg_nr
  and u.l_ausg_nr    = l.l_ausg_nr
  and u.l_aufl_nr    = l.l_aufl_nr
  and u.auft_nr      = a.auft_nr
  and (not exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
       and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr) 
      or exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
         and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr and (u.bundle = 'F' or u.bundle = 'E')))
  and ((u.preiskat != '$NU%' and u.preiskat != '$NU&') or u.preiskat is null)
union
  select u.e_mandant, s.rech_typ, s.rech_dat, t.l_ausg_nr, t.l_aufl_nr, 
         s.adr_gr, s.adr_nr_e, s.person_nr_e, t.artikel_nr, b.isbn, b.verlags_id, dbo.char2num(t.artikel_nr),
         t.titel1, l.auflage_nr, t.gelief_men, a.veranlasser_id, u.auft_nr, u.auf_pos, u.kz_partie, s.herkunft, u.liz_typ, s.rech_nr,
         t.gelief_men, r.retour_nr, r.menge, r.ret_gr_id, r.ret_datum, r.zustand_id, v.adr_nr, v.adr_nr_li, 
         (select count(*) from buivwauf w where w.e_mandant=s.e_mandant and w.l_ausg_nr=t.l_ausg_nr and w.l_aufl_nr=t.l_aufl_nr), f.akt_id,
         f.best_text
from  bufakst s, buaufl l, buauftra a, bufakset t, bufakpos f,
         bufakupo u LEFT OUTER JOIN buretour r ON 
             u.auft_nr      = r.auft_nr 
             and u.auf_pos      = r.auf_pos, 
         buausgab b LEFT OUTER JOIN buverlag v ON 
                  b.verlags_id   = v.verlags_id
where s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and s.rech_typ     like 'L%'
  and s.rech_ref is null
  and s.rech_nr      = f.rech_nr
  and s.rech_dat     = f.rech_dat
  and s.f_mandant    = f.f_mandant
  and f.rech_nr      = u.rech_nr
  and f.rech_dat     = u.rech_dat
  and f.f_mandant    = u.f_mandant
  and f.pos_nr       = u.pos_nr
  and u.l_ausg_nr    = b.l_ausg_nr
  and u.l_ausg_nr    = l.l_ausg_nr
  and u.l_aufl_nr    = l.l_aufl_nr
  and u.auft_nr      = a.auft_nr
  and a.kz_kommission = 'F'
  and u.rech_nr      = t.rech_nr
  and u.rech_dat     = t.rech_dat
  and u.f_mandant    = t.f_mandant
  and u.pos_nr       = t.pos_nr
  and u.upos_nr      = t.upos_nr
  and ((u.bundle!='F' and u.bundle != 'E') or u.bundle is null)
  and ((u.preiskat != '$NU%' and u.preiskat != '$NU&') or u.preiskat is null)
union
  select u.e_mandant, s.rech_typ, s.rech_dat, u.l_ausg_nr, u.l_aufl_nr, 
         s.adr_gr, s.adr_nr_e, s.person_nr_e, u.artikel_nr, b.isbn, b.verlags_id, dbo.char2num(u.artikel_nr),
         u.titel1, l.auflage_nr, u.gelief_men, a.veranlasser_id, u.auft_nr, u.auf_pos, u.kz_partie, s.herkunft, u.liz_typ, s.rech_nr,
         u.gelief_men, r.retour_nr, r.menge, r.ret_gr_id, r.ret_datum, r.zustand_id, v.adr_nr, v.adr_nr_li, 
         (select count(*) from buivwauf w where w.e_mandant=s.e_mandant and w.l_ausg_nr=u.l_ausg_nr and w.l_aufl_nr=u.l_aufl_nr), f.akt_id,
         f.best_text
from  bufakst s, buaufl l, buauftra a, bufakpos f,
         bufakupo u LEFT OUTER JOIN buretour r ON 
             u.auft_nr      = r.auft_nr 
             and u.auf_pos      = r.auf_pos, 
         buausgab b LEFT OUTER JOIN buverlag v ON 
                  b.verlags_id   = v.verlags_id
where s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and s.rech_typ     like 'L%'
  and s.rech_ref is null
  and not exists (select * from buauftra a1 where a1.auft_nr = f.auft_nr and a1.auftrag_typ = 'B' and a1.fakt_soll_dat > a1.vers_soll_dat)
  and s.rech_nr      = f.rech_nr
  and s.rech_dat     = f.rech_dat
  and s.f_mandant    = f.f_mandant
  and f.rech_nr      = u.rech_nr
  and f.rech_dat     = u.rech_dat
  and f.f_mandant    = u.f_mandant
  and f.pos_nr       = u.pos_nr
  and u.l_ausg_nr    = b.l_ausg_nr
  and u.l_ausg_nr    = l.l_ausg_nr
  and u.l_aufl_nr    = l.l_aufl_nr
  and u.auft_nr      = a.auft_nr
  and a.kz_kommission = 'F'
  and (not exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
       and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr) 
      or exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
         and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr and (u.bundle = 'F' or u.bundle = 'E')))
  and ((u.preiskat != '$NU%' and u.preiskat != '$NU&') or u.preiskat is null)

