create view [dbo].[bufrexvi] (l_ausg_nr, l_aufl_nr, adr_gr, adr_nr, person_nr,
       haupt_name, nachname, FREI_MENGE, AUFT_NR,  DATUM, KZ_ABGELEHNT, KZ_LIZENZ, KOMMENTAR, VERLAGS_ID)
  as
select b.l_ausg_nr, b.l_aufl_nr, b.adr_gr, b.adr_nr, b.person_nr,
       a1.haupt_name, p1.nachname, b.FREI_MENGE, b.AUFT_NR,  b.DATUM, b.KZ_ABGELEHNT, b.KZ_LIZENZ, b.KOMMENTAR, b.VERLAGS_ID
from bufreiex b LEFT OUTER JOIN person p1 ON 
                  p1.adr_gr    = b.adr_gr and
                  p1.adr_nr    = b.adr_nr and
                  p1.person_nr = b.person_nr
                LEFT OUTER JOIN anschr a1 ON
                  a1.adr_gr    = b.adr_gr and 
                  a1.adr_nr    = b.adr_nr

