create view bugsivie (datum_inv, l_ausg_nr, e_mandant, best_art, l_aufl_nr, l_aufl_nr_wert, ges_menge, artikel_nr, lager_mandant, 
            l_titel_nr, titel1, isbn, n_artikel_nr, grup_id, kz_bestand, herkunft, prod_typ, kz_loeschen, kz_aufl_best,
            kz_keine_inventu, kz_inv_bewert, aufl_status, gewicht, auflage_nr, aufl_dat_ist, steuer_code, l_ek_preis, ds_preis)
  as
select  l.datum_inv, l.l_ausg_nr, l.e_mandant, l.best_art, l.l_aufl_nr, w.l_aufl_nr, sum(l.ges_menge), m.artikel_nr, m.lager_mandant,
        t.l_titel_nr, t.titel1, b.isbn, dbo.char2num(m.artikel_nr), b.grup_id, b.kz_bestand, b.herkunft, b.prod_typ, m.kz_loeschen, b.kz_aufl_best,
        b.kz_keine_inventu, w.kz_inv_bewert, a.status, b.gewicht, a.auflage_nr, a.aufl_dat_ist, m.steuer_code, w.l_ek_preis, w.ds_preis
  from bulagsi l, bulawert w, bumanaus m, buaufl a, buausgab b, butitel t
  where w.l_ausg_nr = l.l_ausg_nr and
        w.best_art = l.best_art and
        w.e_mandant = l.e_mandant and
        m.l_ausg_nr = w.l_ausg_nr and
        m.e_mandant = w.e_mandant and
        a.l_ausg_nr = w.l_ausg_nr and
        a.l_aufl_nr = w.l_aufl_nr and
        b.l_ausg_nr = w.l_ausg_nr and
        t.l_titel_nr = b.l_titel_nr  
  group by l.datum_inv, l.l_ausg_nr, l.e_mandant, l.best_art, l.l_aufl_nr, w.l_aufl_nr, m.artikel_nr, m.lager_mandant,
        t.l_titel_nr, t.titel1, b.isbn, dbo.char2num(m.artikel_nr), b.grup_id, b.kz_bestand, b.herkunft, b.prod_typ, m.kz_loeschen, b.kz_aufl_best,
        b.kz_keine_inventu, w.kz_inv_bewert, a.status, b.gewicht, a.auflage_nr, a.aufl_dat_ist, m.steuer_code, w.l_ek_preis, w.ds_preis

