create view [dbo].[buinview] (lager_code, regal_id, ebene_id, platz_id, l_ausg_nr, e_mandant, 
                 best_art, l_aufl_nr, zaehl_menge, menge_alt, inventur_menge, inventur_nr, datum_inv, 
                 kz_uebernahme, kz_pruefen, artikel_nr, lager_mandant, l_titel_nr, titel_such, isbn, 
                 benutzer_id, menge_abw, proz_abw, n_artikel_nr, grup_id, herkunft, prod_typ, kz_keine_inventu, kz_inv_bewert,
                 grundpreis, preis, datum_zaehl)
  as
select  l.lager_code, l.regal_id, l.ebene_id, l.platz_id, l.l_ausg_nr, l.e_mandant, 
           l.best_art, l.l_aufl_nr, l.zaehl_menge, l.menge_alt, l.inventur_menge, l.inventur_nr, l.datum_inv, 
           l.kz_uebernahme, l.kz_pruefen, m.artikel_nr, m.lager_mandant, t.l_titel_nr, t.titel_such, b.isbn,
           l.benutzer_id, (l.zaehl_menge-l.menge_alt), 
           ((l.zaehl_menge-l.menge_alt)) * 100 /  (case when l.menge_alt=0 then 1 else l.menge_alt end),
           dbo.char2num(m.artikel_nr), l.grup_id, b.herkunft, l.prod_typ, b.kz_keine_inventu, w.kz_inv_bewert,
           l.grundpreis, l.preis, l.datum_zaehl 
  from  buinvpla l LEFT OUTER JOIN bulagbes g ON
                   l.lager_code  = g.lager_code  and
                   l.e_mandant   = g.e_mandant   and
                   l.l_ausg_nr   = g.l_ausg_nr  and
                   l.l_aufl_nr   = g.l_aufl_nr   and
                   l.best_art    = g.best_art   and 
                   l.regal_id    = g.regal_id    and 
                   l.ebene_id    = g.ebene_id    and 
                   l.platz_id    = g.platz_id    
               LEFT OUTER JOIN  bulawert w ON
                   l.l_ausg_nr = w.l_ausg_nr and
                   l.l_aufl_nr = w.l_aufl_nr and
                   l.best_art = w.best_art and
                   l.e_mandant = w.e_mandant 
               LEFT OUTER JOIN bumanaus m ON  
                   l.l_ausg_nr   = m.l_ausg_nr   and
                   l.e_mandant   = m.e_mandant   
               LEFT OUTER JOIN buausgab b ON
                   l.l_ausg_nr   = b.l_ausg_nr   
                         LEFT OUTER JOIN butitel t ON
                              b.l_titel_nr  = t.l_titel_nr 

