create view [dbo].[buistatv] 
       (e_mandant, jahr_monat, bu_la_id,
        land_code, istatwcode, waehrung,
        sum_geliefert,
        sum_rech_betr,
        ges_gewicht, buch_art)
 as
 select i.e_mandant, (year(i.datum) * 100 + month(i.datum)), 
        '08', i.land_code, o.istatwcode, f.waehrung, 
        sum(i.anzahl),
        sum(f.sum_betr),
        sum(i.gewicht / 1000), f.buch_art
 from   intrasta i, mobjtyp o, fakustat f
  where i.e_mandant = o.e_mandant
    and i.obj_nr    = o.obj_nr
    and o.istatwcode is not null
    and i.e_mandant = f.e_mandant
    and i.obj_nr    = f.obj_nr
    and i.ausg      = f.ausg
    and i.jahr      = f.jahr
    and i.hnr       = f.hnr
    and i.land_code = f.land_code_re
 group by i.e_mandant, i.datum,
          i.land_code , o.istatwcode, f.waehrung,f.buch_art
union
 select f.e_mandant, f.jahr_monat, b.bu_la_id, 
        f.land_code, p.istatwcode, f.waehrung,
        sum(f.sum_berechnet + f.sum_frei), sum(f.sum_netto_betr),
        sum((b.gewicht * (f.sum_berechnet + f.sum_frei)) / 1000), f.auftrag_typ
 from   bufaksum f, buausgab b, buprotyp p
 where f.l_ausg_nr     = b.l_ausg_nr
   and b.prod_typ      = p.prod_typ
   and p.istatwcode is not null
   and f.auftrag_typ   in ('B','L','E')
 group by f.e_mandant, f.jahr_monat, b.bu_la_id, 
          f.land_code, p.istatwcode, f.waehrung,f.auftrag_typ


