create view [dbo].[bukaview] (e_mandant, l_ausg_nr, l_aufl_nr, best_art, 
       l_ausg_nr_2, l_aufl_nr_2, best_art_2, anzahl, artikel_nr_2, 
       auflage_nr_2, lager_mandant, lager_code, ges_menge, kz_vorm_bar, 
       l_titel_nr, ausg_text, aufl_text) 
as 
