create view bukoview (l_ausg_nr, u_ausg_nr, l_aufl_nr, e_mandant, artikel_nr, sto_datum,
                                    nov_dat, isbn, titel_such, kz_fortsetz, titel1, kombityp, l_titel_nr, artikel_nr_k, l_titel_nr_k)
  as
select k.l_ausg_nr, k.u_ausg_nr, k.l_aufl_nr, b.e_mandant,
           b.artikel_nr, b.sto_datum, b.nov_dat, a.isbn, t.titel_such, k.kz_fortsetz, t.titel1, a2.kombityp, t.l_titel_nr, m.artikel_nr, a2.l_titel_nr
  from bukombi k, bumanaus b, buausgab a, butitel t, buausgab a2, bumanaus m
 where k.u_ausg_nr  = b.l_ausg_nr and
