create view [dbo].[buktrvie] (e_mandant, kst_traeger, l_titel_nr, obj_nr, l_ausg_nr)
as
select distinct man.e_mandant, rtrim(man.artikel_nr), aus.l_titel_nr, '    ', man.l_ausg_nr 
from bumanaus man, buausgab aus
   where man.artikel_nr is not null 
     and man.l_ausg_nr = aus.l_ausg_nr
	 and man.l_ausg_nr not in(select ivw.l_ausg_nr from buivwauf ivw, bumanaus man where man.e_mandant=ivw.e_mandant and man.l_ausg_nr=ivw.l_ausg_nr)
	 and aus.l_titel_nr > 0 
union
    select distinct erl.e_mandant, rtrim(erl.kst_traeger), aus.l_titel_nr, erl.obj_nr, man.l_ausg_nr 
	from erlkonto erl, bumanaus man, buivwauf ivw, buausgab aus
      where erl.kst_traeger is not null
        and erl.e_mandant = man.e_mandant
        and erl.kst_traeger <> man.artikel_nr
		and erl.obj_nr = ivw.obj_nr
		and man.e_mandant = ivw.e_mandant
		and man.l_ausg_nr = ivw.l_ausg_nr
        and man.l_ausg_nr = aus.l_ausg_nr
	    and aus.l_titel_nr > 0 
        and erl.ref_nr = 'BUCH'
union
    select distinct man.e_mandant, rtrim(art.qaus), aus.l_titel_nr, '    ', aus.l_ausg_nr 
	from bumanaus man, buausgab aus, buartqa art
      where aus.prod_typ = art.prod_typ
        and man.l_ausg_nr = aus.l_ausg_nr
		and aus.l_ausg_nr = art.l_ausg_nr
		and art.qm_id = 'KSTTRAEGER'
		and aus.l_titel_nr = 0
union
    select distinct erl.e_mandant, rtrim(erl.kst_traeger), aus.l_titel_nr, erl.obj_nr, man.l_ausg_nr 
	from erlkonto erl, bumanaus man, buausgab aus
      where erl.kst_traeger is not null
        and erl.e_mandant = man.e_mandant
        and erl.kst_traeger <> man.artikel_nr
	and erl.obj_nr = aus.prod_typ
        and man.l_ausg_nr = aus.l_ausg_nr
        and erl.ref_nr = 'BUCH'
		and aus.l_titel_nr = 0

GO
create view [dbo].[bulaaufl](e_mandant, lager_code, l_ausg_nr, l_aufl_nr, 
                     best_art, kombi_ausg_nr, ges_menge, anz_reserv, anz_vormerk, auflage_nr, faktor) 
as select
  l.e_mandant, l. lager_code, l.l_ausg_nr, l.l_aufl_nr, l.best_art, 0, 
  l.ges_menge, l.anz_reserv, l.anz_vormerk, a.auflage_nr, 1 
from bulagges l, buaufl a 
where
  l.l_ausg_nr = a.l_ausg_nr and
  l.l_aufl_nr = a.l_aufl_nr
union
select l.e_mandant, l. lager_code, k.u_ausg_nr, l.l_aufl_nr, l.best_art, 
  k.l_ausg_nr, l.ges_menge*k.menge, l.anz_reserv, l.anz_vormerk, a.auflage_nr, k.menge 
from bulagges l, bukombi k, buausgab b, buaufl a 
where
  l.l_ausg_nr = a.l_ausg_nr and
  l.l_aufl_nr = a.l_aufl_nr and
  l.l_ausg_nr = k.l_ausg_nr and
  l.l_aufl_nr = k.l_aufl_nr and
  l.l_ausg_nr = b.l_ausg_nr and
  (kombityp='V' or kombityp='Z')
union
select l.e_mandant, l. lager_code, k.u_ausg_nr, l.l_aufl_nr, l.best_art, 
  k1.l_ausg_nr, l.ges_menge*k.menge*k1.menge, l.anz_reserv, l.anz_vormerk, a.auflage_nr, k.menge*k1.menge 
from bulagges l, bukombi k, buausgab b, buaufl a, bukombi k1, buausgab b1 
where
  l.l_ausg_nr = a.l_ausg_nr and
  l.l_aufl_nr = a.l_aufl_nr and
  l.l_ausg_nr = k1.l_ausg_nr and
  l.l_aufl_nr = k1.l_aufl_nr and
  k.l_ausg_nr = b.l_ausg_nr and 
  b.kombityp='Z' and 
  k1.l_ausg_nr = b1.l_ausg_nr and 
  (b1.kombityp='Z' or b1.kombityp='V') and 
  k.l_ausg_nr=k1.u_ausg_nr

