create view [dbo].[bulagauf] (lager_code, e_mandant, l_ausg_nr, l_aufl_nr, 
                 best_art, ges_menge, artikel_nr, l_titel_nr, titel_such, isbn, auflage_nr,
                 meld_nr, kz_vorm_bar, anz_reserv)
  as
select  g.lager_code, m.lager_mandant, m.l_ausg_nr, a.l_aufl_nr, 
           g.best_art, g.ges_menge, m.artikel_nr, t.l_titel_nr, t.titel_such, b.isbn, a.auflage_nr,
           a.meld_nr, e.kz_vorm_bar, g.anz_reserv
  from  bumanaus m, buausgab b, butitel t, bumeldnr e, 
           buaufl a LEFT OUTER JOIN bulagges g ON
                 g.l_ausg_nr  = a.l_ausg_nr and
                 g.l_aufl_nr = a.l_aufl_nr 
 where  b.l_ausg_nr  = m.l_ausg_nr and
            t.l_titel_nr = b.l_titel_nr and
            a.l_ausg_nr = m.l_ausg_nr and
            e.meld_nr = a.meld_nr 

