create view [dbo].[bulaview] (lager_code, regal_id, ebene_id, platz_id, l_ausg_nr, e_mandant, 
            best_art, l_aufl_nr, menge, ges_menge, artikel_nr, lager_mandant, 
            l_titel_nr, titel_such, isbn, n_artikel_nr, grup_id, kz_bestand, herkunft, prod_typ, kz_loeschen, kz_aufl_best, platzart,
            kz_keine_inventu, kz_inv_bewert, aufl_status, gewicht)
  as
select  p.lager_code, p.regal_id, p.ebene_id, p.platz_id, l.l_ausg_nr, l.e_mandant, 
           l.best_art, l.l_aufl_nr, l.menge, g.ges_menge, m.artikel_nr, m.lager_mandant,
           t.l_titel_nr, t.titel_such, b.isbn, dbo.char2num(m.artikel_nr), b.grup_id, b.kz_bestand, b.herkunft,
           b.prod_typ, m.kz_loeschen, b.kz_aufl_best, p.platzart, b.kz_keine_inventu, w.kz_inv_bewert, a.status, b.gewicht
  from bulagpla p LEFT OUTER JOIN bulagbes l ON
                 l.lager_code  = p.lager_code and
                 l.regal_id = p.regal_id and 
                 l.ebene_id = p.ebene_id and 
                 l.platz_id = p.platz_id 
                      LEFT OUTER JOIN  bulagges g ON
                          g.lager_code = l.lager_code and
                          g.l_ausg_nr = l.l_ausg_nr and
                          g.l_aufl_nr = l.l_aufl_nr and
                          g.best_art = l.best_art and
                          g.e_mandant = l.e_mandant 
                      LEFT OUTER JOIN  bulawert w ON
                          w.l_ausg_nr = l.l_ausg_nr and
                          w.l_aufl_nr = l.l_aufl_nr and
                          w.best_art = l.best_art and
                          w.e_mandant = l.e_mandant 
                      LEFT OUTER JOIN bumanaus m ON
                          m.l_ausg_nr = l.l_ausg_nr and
                          m.e_mandant = l.e_mandant
                      LEFT OUTER JOIN buaufl a ON
                          a.l_ausg_nr = l.l_ausg_nr and
                          a.l_aufl_nr = l.l_aufl_nr
                      LEFT OUTER JOIN buausgab b ON
                          b.l_ausg_nr = l.l_ausg_nr 
                               LEFT OUTER JOIN butitel t ON
                                    t.l_titel_nr = b.l_titel_nr  

GO
create view [dbo].[bulfview] (e_mandant, adr_gr, adr_nr, person_nr, haupt_name, haupt_ort,
       nachname, vorname, adr_nr_re, person_nr_re, haupt_name_re, nachname_re, vorname_re, 
       l_ausg_nr, artikel_nr, isbn, l_aufl_nr, artikel_nr_li, auflage_nr_li, bezeichnung_li)
  as
select b.e_mandant, b.adr_gr, b.adr_nr, b.person_nr, a1.haupt_name, a1.haupt_ort,
       p1.nachname, p1.vorname, b.adr_nr_re, b.person_nr_re, a2.haupt_name, p2.nachname, 
       p2.vorname, s.l_ausg_nr, m.artikel_nr, a.isbn, s.l_aufl_nr, s.artikel_nr_li, s.auflage_nr_li, s.bezeichnung_li
from  buliesta b LEFT OUTER JOIN  person p1 ON
                  p1.adr_gr     = b.adr_gr and
                  p1.adr_nr      = b.adr_nr and
                  p1.person_nr   = b.person_nr 
              LEFT OUTER JOIN anschr a1 ON
                  a1.adr_gr   = b.adr_gr and 
                  a1.adr_nr      = b.adr_nr 
              LEFT OUTER JOIN person p2 ON
                  p2.adr_gr     = b.adr_gr and
                  p2.adr_nr     = b.adr_nr_re and
                  p2.person_nr  = b.person_nr_re 
              LEFT OUTER JOIN anschr a2 ON
                  a2.adr_gr      = b.adr_gr and 
                  a2.adr_nr    = b.adr_nr_re 
              LEFT OUTER JOIN bulieart s ON
                  s.adr_gr = b.adr_gr and
                  s.adr_nr      = b.adr_nr and
                  s.e_mandant    = b.e_mandant 
                        LEFT OUTER JOIN bumanaus m ON
                             m.e_mandant  = s.e_mandant and
                             m.l_ausg_nr  = s.l_ausg_nr
                        LEFT OUTER JOIN buausgab a ON 
                             a.l_ausg_nr  = s.l_ausg_nr 

GO
create view buliefersumview (e_mandant, jahr, land_e, artikel_nr, steuersatz, gelief_menge, gewicht)		
as
   select  t.e_mandant, year(s.rech_dat), s.land_e, t.artikel_nr, t.mw_proz, sum(t.gelief_men), sum(b.gewicht * t.gelief_men)
   from bufakst s, bufakpos p, bufakupo u, bufakset t, buausgab b, buprotyp o
   where u.rech_nr    = s.rech_nr   and
      u.rech_dat   = s.rech_dat  and
	u.f_mandant  = s.f_mandant and
	u.rech_nr    = p.rech_nr   and
	u.rech_dat   = p.rech_dat  and
	u.f_mandant  = p.f_mandant and
	u.pos_nr     = p.pos_nr and
        u.rech_nr    = t.rech_nr  and 
        u.rech_dat     = t.rech_dat and
        u.f_mandant    = t.f_mandant and 
        u.pos_nr       = t.pos_nr and 
        u.upos_nr      = t.upos_nr and
        s.rech_typ     like '%L%' and 
        t.l_ausg_nr = b.l_ausg_nr and
        b.prod_typ = o.prod_typ and
        o.kz_elektron = 'F'
   group by t.e_mandant, year(s.rech_dat), t.artikel_nr, s.land_e, t.mw_proz
union
   select  u.e_mandant, year(s.rech_dat), s.land_e, u.artikel_nr, u.mw_proz, sum(u.gelief_men), sum(b.gewicht * u.gelief_men)
   from bufakst s, bufakpos p, bufakupo u, buausgab b, buprotyp o
   where u.rech_nr    = s.rech_nr   and
      u.rech_dat   = s.rech_dat  and
	u.f_mandant  = s.f_mandant and
	u.rech_nr    = p.rech_nr   and
	u.rech_dat   = p.rech_dat  and
	u.f_mandant  = p.f_mandant and
	u.pos_nr     = p.pos_nr and
        s.rech_typ     like '%L%' and 
        u.l_ausg_nr = b.l_ausg_nr and
        b.prod_typ = o.prod_typ and
        o.kz_elektron = 'F'  and 
        (not exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
        and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr)) 
   group by u.e_mandant, year(s.rech_dat), u.artikel_nr, s.land_e, u.mw_proz

