create view [dbo].[bulivevw] (land_code, reg_id, reg_code, vers_weg, versart,
                      limit, waehrung, betrag, ext_code)
  as
select a.land_code, a.reg_id, a.reg_code, b.vers_weg, b.versart, c.limit, c.waehrung, c.betrag, c.ext_code
  from regland a, buverart b, buvakost c
 where a.reg_id = b.reg_id and
       a.reg_code = b.reg_code and
       b.vers_weg = c.vers_weg and
       b.versart = c.versart

