create view [dbo].[bulizvie] (lizenz_nr, e_mandant, l_ausg_nr, l_aufl_nr, adr_gr, adr_nr, person_nr,
       haupt_name, nachname, liz_typ, rhythmus, datum_ab, datum_bis, datum_vertrag, waehrung,
       preis, status, abteilung, verlags_id, isbn_liz, kz_ersch, kz_koprod, kz_eeu, kz_ang_gedruckt, kz_rechte_zurueck, 
       titel_such, titel1, l_titel_nr)
  as
select b.lizenz_nr, b.e_mandant, b.l_ausg_nr, b.l_aufl_nr, b.adr_gr, b.adr_nr, b.person_nr,
       a1.haupt_name, p1.nachname, b.liz_typ, b.rhythmus, b.datum_ab, b.datum_bis, b.datum_vertrag, 
       b.waehrung, b.preis, b.status, b.abteilung, b.verlags_id, b.isbn_liz, b.kz_ersch, b.kz_koprod, b.kz_eeu, b.kz_ang_gedruckt,
       b.kz_rechte_zurueck, t.titel_such, t.titel1, t.l_titel_nr
from butitel t, buausgab u, bulizenz b LEFT OUTER JOIN person p1 ON 
                  p1.adr_gr    = b.adr_gr and
                  p1.adr_nr    = b.adr_nr and
                  p1.person_nr = b.person_nr
                LEFT OUTER JOIN anschr a1 ON
                  a1.adr_gr    = b.adr_gr and 
                  a1.adr_nr    = b.adr_nr
where b.l_ausg_nr  = u.l_ausg_nr and
      t.l_titel_nr = u.l_titel_nr

GO
create view bulrview (e_mandant, auft_nr, auf_pos, adr_gr, adr_nr_best, 
       person_nr_best, adr_nr_re, person_nr_re, adr_nr_le, person_nr_le,
       akt_id, uakt_id, staord_nr, l_ausg_nr, artikel_nr, isbn, so_pos_id,
       auflage_nr, ber_menge, frei_menge, vormerk_menge, rab_proz,
       einzel_preis, ges_preis, pos_betrag, vers_weg, meld_nr, meld_text,
       status, brut_net, auftrag_typ, herkunft, reserviert_menge, l_titel_nr,
       lager_mandant, l_aufl_nr, lager_code, n_artikel_nr, best_datum, best_text,
       berechnen, grup_id, vertreter_id, kombi_artikel_nr, kombityp, kz_kommission, pos_typ, l_ek_preis, abweich_proz, storno,
       wb_id, hgrp_id, ugrp_id, produkt, prod_typ, datum_neu, z_bed, r_art, best_weg)
  as
select s.e_mandant, s.auft_nr, s.auf_pos, b.adr_gr, b.adr_nr_best, 
       b.person_nr_best, b.adr_nr_re, b.person_nr_re, b.adr_nr_le, b.person_nr_le,
       b.akt_id, b.uakt_id, b.staord_nr, s.l_ausg_nr, m.artikel_nr, a.isbn, o.so_pos_id,
       l.auflage_nr, s.ber_menge, s.frei_menge, s.vormerk_menge, s.rab_proz,
       s.einzel_preis, s.ges_preis, s.pos_betrag, b.vers_weg, l.meld_nr, e.meld_text,
       b.status, s.brut_net, b.auftrag_typ, b.herkunft, s.reserviert_menge, a.l_titel_nr,
       s.lager_mandant, s.l_aufl_nr, s.lager_code, dbo.char2num(m.artikel_nr),
       b.best_datum, b.best_text, p.berechnen, a.grup_id, b.vertreter_id, Null, a.kombityp, 
       b.kz_kommission, s.pos_typ, w.l_ek_preis, ((s.einzel_preis-w.l_ek_preis)) * 100 /  (case when w.l_ek_preis=0 then 1 else w.l_ek_preis end),
       s.storno, r.wb_id, r.hgrp_id, r.ugrp_id, r.produkt, a.prod_typ, b.datum_neu, b.z_bed, b.r_art, b.best_weg
from  buauftra b, 
         buaufpos s LEFT OUTER JOIN bumanaus m ON
                   m.e_mandant = s.e_mandant and
                   m.l_ausg_nr  = s.l_ausg_nr 
              LEFT OUTER JOIN buausgab a ON
                   a.l_ausg_nr  = s.l_ausg_nr 
              LEFT OUTER JOIN buartpro r ON
                   r.l_ausg_nr  = s.l_ausg_nr 
              LEFT OUTER JOIN busopos o ON
                   o.so_pos_id  = s.so_pos_id 
              LEFT OUTER JOIN buprkat p ON
                   p.preiskat  = s.preiskat 
              LEFT OUTER JOIN bulawert w ON
                   w.e_mandant = s.lager_mandant and
                   w.l_aufl_nr = s.l_aufl_nr and
                   w.l_ausg_nr = s.l_ausg_nr and
                   w.best_art = s.best_art 
              LEFT OUTER JOIN  buaufl l ON
                    l.l_ausg_nr  = s.l_ausg_nr and
                    l.l_aufl_nr  = s.l_aufl_nr 
                           LEFT OUTER JOIN bumeldnr e ON
                                  e.meld_nr  = l.meld_nr
where b.auft_nr = s.auft_nr 
union
select s.e_mandant, s.auft_nr, s.auf_pos, b.adr_gr, b.adr_nr_best, 
       b.person_nr_best, b.adr_nr_re, b.person_nr_re, b.adr_nr_le, b.person_nr_le,
       b.akt_id, b.uakt_id, b.staord_nr, s.l_ausg_nr, m2.artikel_nr, a.isbn, Null,
       l.auflage_nr, s.ber_menge, s.frei_menge, (s.vormerk_menge*k.menge), s.rab_proz,
       s.einzel_preis, s.ges_preis, s.pos_betrag, b.vers_weg, l.meld_nr, e.meld_text,
       b.status, s.brut_net, b.auftrag_typ, b.herkunft, s.reserviert_menge, a.l_titel_nr,
       s.lager_mandant, s.l_aufl_nr, s.lager_code, dbo.char2num(m2.artikel_nr),
       b.best_datum, b.best_text, p.berechnen, a.grup_id, b.vertreter_id, m.artikel_nr,
       a.kombityp, b.kz_kommission, s.pos_typ, NULL, NULL, s.storno, r.wb_id, r.hgrp_id, r.ugrp_id, r.produkt, 
       a.prod_typ, b.datum_neu, b.z_bed, b.r_art, b.best_weg
from  buauftra b, bumanaus m, buausgab a, bumanaus m2, 
         buaufpos s LEFT OUTER JOIN buprkat p ON
                   p.preiskat  = s.preiskat, 
         buaufl l LEFT OUTER JOIN bumeldnr e ON
                   e.meld_nr  = l.meld_nr,
         bukombi k LEFT OUTER JOIN buartpro r ON
                   r.l_ausg_nr  = k.u_ausg_nr
where b.auft_nr = s.auft_nr and
            k.l_ausg_nr     = s.l_ausg_nr and
            m2.e_mandant  = s.e_mandant and
            m2.l_ausg_nr  = k.u_ausg_nr and
            a.l_ausg_nr  = k.u_ausg_nr and
            m.e_mandant  = s.e_mandant and
            m.l_ausg_nr  = s.l_ausg_nr and
            l.l_ausg_nr  = k.u_ausg_nr and
            l.l_aufl_nr  = k.l_aufl_nr
union
select w.e_mandant, 0, 0, w.adr_gr, w.adr_nr, 
       w.person_nr, w.adr_nr, w.person_nr, w.adr_nr, w.person_nr,
       Null, Null, 0, r.l_ausg_nr, m.artikel_nr, a.isbn, Null,
       l.auflage_nr, 0, 0, 1, 0, 0, 0, 0, NULL, l.meld_nr, NULL,
       'X', NULL, NULL, NULL, 0, a.l_titel_nr,
       m.lager_mandant, r.l_aufl_nr, 'X§}', dbo.char2num(m.artikel_nr),
       NULL, NULL, NULL, a.grup_id, NULL, NULL, a.kombityp, 'F', NULL, NULL, NULL, 'F', p.wb_id, p.hgrp_id, p.ugrp_id, p.produkt, 
       a.prod_typ, NULL, NULL, NULL, NULL
from werbepr w, bumanaus m, buausgab a, buaufl l,
         werbepra r LEFT OUTER JOIN buartpro p ON
                   p.l_ausg_nr  = r.l_ausg_nr 
where       r.adr_gr    = w.adr_gr    and 
            r.adr_nr    = w.adr_nr    and 
            r.person_nr = w.person_nr and 
            r.e_mandant = w.e_mandant and 
            r.obj_nr    = w.obj_nr    and 
            r.ausg      = w.ausg      and 
            r.abo_nr    = w.abo_nr    and 
            w.kz_sperren='F'          and 
            r.v_datum is null         and
            a.l_ausg_nr  = r.l_ausg_nr and
            m.e_mandant = r.e_mandant and
            m.l_ausg_nr  = r.l_ausg_nr and
            l.l_ausg_nr  = r.l_ausg_nr and
            l.l_aufl_nr  = r.l_aufl_nr
union
select w.e_mandant, 0, 0, w.adr_gr, w.adr_nr, 
       w.person_nr, w.adr_nr, w.person_nr, w.adr_nr, w.person_nr,
       Null, Null, 0, r.l_ausg_nr, m.artikel_nr, a.isbn, Null,
       l.auflage_nr, 0, 0, 1, 0, 0, 0, 0, NULL, l.meld_nr, NULL,
       'X', NULL, NULL, NULL, 0, a.l_titel_nr,
       m.lager_mandant, r.l_aufl_nr, 'X§}', dbo.char2num(m.artikel_nr),
       NULL, NULL, NULL, a.grup_id, NULL, NULL, a.kombityp, 'F', NULL, NULL, NULL, 'F', o.wb_id, o.hgrp_id, o.ugrp_id, o.produkt, 
       a.prod_typ, NULL, NULL, NULL, NULL
from werbepr w, bumanaus m, buausgab a, buaufl l, buaufpos p,
         werbepra r LEFT OUTER JOIN buartpro o ON
                   o.l_ausg_nr  = r.l_ausg_nr 
where       r.adr_gr    = w.adr_gr    and 
            r.adr_nr    = w.adr_nr    and 
            r.person_nr = w.person_nr and 
            r.e_mandant = w.e_mandant and 
            r.obj_nr    = w.obj_nr    and 
            r.ausg      = w.ausg      and 
            r.abo_nr    = w.abo_nr    and 
            w.kz_sperren='F'          and 
            r.v_datum is not null     and
            a.l_ausg_nr  = r.l_ausg_nr and
            m.e_mandant = r.e_mandant and
            m.l_ausg_nr  = r.l_ausg_nr and
            l.l_ausg_nr  = r.l_ausg_nr and
            l.l_aufl_nr  = r.l_aufl_nr and
            r.adr_nr    = p.adr_nr_abo and 
            r.person_nr = p.person_nr_abo and 
            r.e_mandant = p.e_mandant and 
            r.obj_nr    = p.obj_nr and 
            r.ausg      = p.ausg and 
            r.abo_nr    = p.abo_nr and 
            r.pos_nr    = p.pos_nr_werbepra and 
            p.reserviert_menge = 0 and 
            r.l_ausg_nr = p.l_ausg_nr and 
            r.l_aufl_nr = p.l_aufl_nr and 
            p.status='O'

GO
create view [dbo].[bumravie] (bu_ra, bez, berechnung, kz_fuer, rab_proz, akt_id, m_preis_grp,  
                      e_mandant, l_ausg_nr, best_art)
  as
select r.bu_ra, r.bez, r.berechnung, r.kz_fuer, r.rab_proz, r.akt_id, r.m_preis_grp,  
       m.e_mandant, m.l_ausg_nr, m.best_art
from  burabatt r, bumprzu m 
where m.m_preis_grp  = r.m_preis_grp
union
select r.bu_ra, r.bez, r.berechnung, r.kz_fuer, r.rab_proz, r.akt_id, r.m_preis_grp,  
       '  ', 0, '   '
from  burabatt r 
where r.m_preis_grp is null

GO
create view [dbo].[buobview] (l_titel_nr, l_ausg_nr, titel_such,
                    titel1, sprach_code, orig_titel, org_spr_code, verlags_id, 
                    isbn, ean, prod_typ,  reihen_code, kombityp, issn, ausg_text,
                    e_mandant, artikel_nr, nachname, vorname, haupt_name)
  as
select t.l_titel_nr, b.l_ausg_nr,  t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id, 
           b.isbn, b.ean, b.prod_typ,  b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name
  from butitel t, 
          buausgab b LEFT OUTER JOIN buautor a ON
                       a.l_titel_nr = b.l_titel_nr
                 LEFT OUTER JOIN bumanaus m ON
                      m.l_ausg_nr  = b.l_ausg_nr 
 where t.l_titel_nr  = b.l_titel_nr 

GO
create view [dbo].[buoptvie] (vers_weg, versart, land_code, reg_id, reg_code, tara,
           land_code_man, kz_auto_aus, kz_auto_in, max_gew_aus, max_gew_in,
           prio_aus, prio_in, kz_verw_aus, kz_verw_in, steuer_code,
           land_code_reg, plz_von, plz_bis, wohnort, limit, tara_buvakost,
           bu_send_typ, breite, hoehe, dicke)
  as
select b.vers_weg, b.versart, b.land_code, b.reg_id, b.reg_code, b.tara,
           l.land_code, l.kz_auto_aus, l.kz_auto_in, l.max_gew_aus, l.max_gew_in,
           l.prio_aus, l.prio_in, l.kz_verw_aus, l.kz_verw_in, l.steuer_code,
           a.land_code, p.plz_von, p.plz_bis, o.wohnort, v.limit, v.tara, b.bu_send_typ, v.breite, v.hoehe, v.dicke
  from bulanver l, 
           buverart b LEFT OUTER JOIN buvakost v ON
                      b.vers_weg = v.vers_weg and
                      b.versart = v.versart 
                LEFT OUTER JOIN regland a ON
                      b.reg_id = a.reg_id  and
                      b.reg_code = a.reg_code  
                           LEFT OUTER JOIN regplz p ON
                                 a.land_code = p.land_code  and
                                 a.reg_id = p.reg_id  and
                                 a.reg_code = p.reg_code  
                           LEFT OUTER JOIN regort o ON 
                                 a.land_code = o.land_code  and
                                 a.reg_id = o.reg_id  and
                                 a.reg_code = o.reg_code 
 where b.vers_weg = l.vers_weg and
       b.versart = l.versart 

GO
create view [dbo].[buorview] (l_ausg_nr, u_ausg_nr, l_aufl_nr, menge, e_mandant, 
                      sto_datum, nov_dat, kz_loeschen, kz_loeschen_ausgab,
                      sperr_grund, kz_zus_band, kz_fortsetz, kz_basis_band)
as select k.l_ausg_nr, k.u_ausg_nr, k.l_aufl_nr, k.menge, m.e_mandant,
       m.sto_datum, m.nov_dat, m.kz_loeschen, a.kz_loeschen,
       a.sperr_grund, a.kz_zus_band, k.kz_fortsetz, a.kz_basis_band
   from  bukombi k, bumanaus m, buausgab a 
   where m.l_ausg_nr = k.u_ausg_nr  and
         a.l_ausg_nr = k.u_ausg_nr and 
         a.kz_aufl_best = 'F'
union
   select k.l_ausg_nr, k.u_ausg_nr, k.l_aufl_nr, k.menge, m.e_mandant,
       l.sto_datum, l.aufl_dat_ist, m.kz_loeschen, a.kz_loeschen,
       l.sperr_grund, a.kz_zus_band, k.kz_fortsetz, a.kz_basis_band
   from  bukombi k, bumanaus m, buausgab a, buaufl l
   where m.l_ausg_nr = k.u_ausg_nr  and
         a.l_ausg_nr = k.u_ausg_nr and 
         a.kz_aufl_best = 'T' and
         k.u_ausg_nr = l.l_ausg_nr and
         k.l_aufl_nr = l.l_aufl_nr

