create view [dbo].[bupkview] (list_nr, e_mandant, l_ausg_nr, best_art, preiskat, waehrung, 
                                    gueltig_ab, l_aufl_nr, akt_id, subs_dat1, berechnen, kz_kugru, prioritaet)
  as
select l.list_nr, l.e_mandant, l.l_ausg_nr, l.best_art, l.preiskat, l.waehrung, 
               l.gueltig_ab, l.l_aufl_nr, l.akt_id, l.subs_dat1, k.berechnen, k.kz_kugru, k.prioritaet
from buplist l, buprkat k
where k.preiskat  = l.preiskat

GO
create view bupoview (e_mandant, auft_nr, auf_pos, adr_gr, adr_nr_best, 
       person_nr_best, haupt_name_best, nachname_best, vorname_best, 
       adr_nr_re, person_nr_re, haupt_name_re, nachname_re, vorname_re, 
       adr_nr_le, person_nr_le, haupt_name_le, nachname_le, vorname_le,
       best_datum, l_vers_dat, fakt_soll_dat, akt_id, uakt_id, staord_nr, 
       l_ausg_nr, artikel_nr, isbn, so_pos_id, status, status_pos, storno_pos, auftrag_typ,
       rech_nr, rech_dat, l_aufl_nr, herkunft, prio, ber_menge, frei_menge, gelief_men, 
       vertreter_id, obj_nr, preiskat_abo, grup_id, bew_art, 
       ausg, abo_nr, adr_nr_abo, person_nr_abo, liefer_menge_abo, eindr_art, best_text, ref_auft_nr, r_art, kz_kommission, b_id_neu, datum_neu)
  as
select s.e_mandant, s.auft_nr, s.auf_pos, b.adr_gr, b.adr_nr_best, 
       b.person_nr_best, a1.haupt_name, p1.nachname, p1.vorname, 
       b.adr_nr_re, b.person_nr_re, a2.haupt_name, p2.nachname, p2.vorname, 
       b.adr_nr_le, b.person_nr_le, a3.haupt_name, p3.nachname, p3.vorname,
       b.best_datum, b.l_vers_dat, b.fakt_soll_dat, b.akt_id, b.uakt_id, b.staord_nr, 
       s.l_ausg_nr, m.artikel_nr, a.isbn, o.so_pos_id, b.status, s.status, s.storno,
       b.auftrag_typ, f.rech_nr, f.rech_dat, s.l_aufl_nr, b.herkunft, b.prioritaet,
       s.ber_menge, s.frei_menge, s.gelief_menge, b.vertreter_id, s.obj_nr, s.preiskat_abo, a.grup_id, w.bew_art, 
       s.ausg, s.abo_nr, s.adr_nr_abo, s.person_nr_abo, s.liefer_menge_abo, s.eindr_art, b.best_text, r.ref_auft_nr,
       b.r_art, b.kz_kommission, b.b_id_neu, b.datum_neu
from  buaufpos s LEFT OUTER JOIN bumanaus m ON
                   m.e_mandant  = s.e_mandant and
                   m.l_ausg_nr  = s.l_ausg_nr 
              LEFT OUTER JOIN buausgab a ON
                   a.l_ausg_nr  = s.l_ausg_nr 
              LEFT OUTER JOIN buaufref r ON
                   r.auft_nr = s.auft_nr
              LEFT OUTER JOIN bufakupo f ON
                   f.auft_nr = s.auft_nr and
                   f.auf_pos = s.auf_pos
                       LEFT OUTER JOIN bulagbew w ON
                            w.auft_nr = f.auft_nr and
                            w.auf_pos = f.auf_pos
              LEFT OUTER JOIN  busopos o ON
                   o.so_pos_id   = s.so_pos_id, 
          buauftra b LEFT OUTER JOIN person p1 ON
                   p1.adr_gr     =b.adr_gr and
                   p1.adr_nr    = b.adr_nr_best and
                   p1.person_nr    = b.person_nr_best 
              LEFT OUTER JOIN  anschr a1 ON
                   a1.adr_gr    = b.adr_gr and 
                   a1.adr_nr     = b.adr_nr_best 
              LEFT OUTER JOIN  person p2 ON
                   p2.adr_gr   = b.adr_gr and
                   p2.adr_nr    = b.adr_nr_re and
                   p2.person_nr  = b.person_nr_re 
              LEFT OUTER JOIN  anschr a2 ON
                   a2.adr_gr     = b.adr_gr and 
                   a2.adr_nr   = b.adr_nr_re 
              LEFT OUTER JOIN person p3 ON
                   p3.adr_gr  = b.adr_gr and
                   p3.adr_nr   = b.adr_nr_le and
                   p3.person_nr  = b.person_nr_le 
              LEFT OUTER JOIN anschr a3 ON
                   a3.adr_gr    = b.adr_gr and 
                   a3.adr_nr    = b.adr_nr_le 
where b.auft_nr = s.auft_nr 

GO
create view [dbo].[buprhivi]
  as
select distinct h.key_num_1, h.key_num_2, h.key_char_1, h.datim, h.entitaet, h.lfd_nr_hist,
          p.l_ausg_nr, p.e_mandant, b.isbn, b.ean, b.preisbind, b.reihen_code, m.artikel_nr, h.feldname, 
          p.preiskat, p.gueltig_ab, p.waehrung, p.list_nr, s.menge, s.preis, b.kz_bestand
  from historie h, buausgab b, bumanaus m, buplist p, bumpreis s
 where p.l_ausg_nr  = h.key_num_1 and
            p.e_mandant = h.key_char_1 and
            p.list_nr = h.key_num_2 and
            p.l_aufl_nr = 0 and
            b.l_ausg_nr = p.l_ausg_nr and 
            m.l_ausg_nr = p.l_ausg_nr and 
            m.e_mandant = p.e_mandant and
            s.list_nr = p.list_nr  and 
            h.feldname != 'PREISELOE'

GO
create view [dbo].[buprovie] (rech_nr, rech_dat, pos_nr, upos_nr, e_mandant, f_mandant,
                      l_ausg_nr, l_aufl_nr, best_art, artikel_nr, prov_bet_net,
                      ber_menge, kombityp, gelief_men, p_status_lief, so_pos_id, waehrung)
as
select s.rech_nr, s.rech_dat, s.rech_pos_nr, s.rech_upos_nr, s.e_mandant, u.f_mandant,
           u.l_ausg_nr, u.l_aufl_nr, u.best_art, u.artikel_nr, s.prov_bet_net,
           u.ber_menge, u.kombityp, u.gelief_men, u.p_status_lief, u.so_pos_id, s.waehrung
from bufakupo u, buveprov s
where u.rech_nr = s.rech_nr and
      u.rech_dat = s.rech_dat and
      u.e_mandant = s.e_mandant and
      u.pos_nr = s.rech_pos_nr and
      u.upos_nr = s.rech_upos_nr

GO
CREATE VIEW buqagvie
AS SELECT w.adr_gr, w.adr_nr, w.person_nr, w.a_typ, w.q_code, w.q_ausp_code, a.grup_id, a.e_mandant
FROM qwerte w, buqstagr a
WHERE w.adr_gr = a.adr_gr and
              w.a_typ = a.a_typ and
              w.q_code = a.q_code and
              w.q_ausp_code = a.q_ausp_code

GO
create view buqmview (l_ausg_nr, prod_typ,  qm_id, qaus_id, l_titel_nr, titel_such,
                    titel1, sprach_code, orig_titel, org_spr_code, verlags_id, 
                    isbn, ean, reihen_code, kombityp, issn, ausg_text,
                    e_mandant, artikel_nr, nachname, vorname, haupt_name,
                    sperr_grund, kz_loeschen, herkunft, grup_id, kz_aufl_best, b_id_aend)
as
  select  q.l_ausg_nr, q.prod_typ, q.qm_id, q.qaus, t.l_titel_nr, t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id, 
           b.isbn, b.ean, b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name,
           b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id, b.kz_aufl_best, t.b_id_aend
  from butitel t, 
          buartqa q LEFT OUTER JOIN bumanaus m ON
               m.l_ausg_nr = q.l_ausg_nr , 
          buausgab b LEFT OUTER JOIN buautor a ON
               a.l_titel_nr = b.l_titel_nr
  where b.l_ausg_nr = q.l_ausg_nr and
       b.prod_typ = q.prod_typ   and
       t.l_titel_nr  = b.l_titel_nr and
       b.l_titel_nr > 0
union
  select  b.l_ausg_nr, q.prod_typ, q.qm_id, q.qaus, t.l_titel_nr, t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id, 
           b.isbn, b.ean, b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name,
           b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id, b.kz_aufl_best, t.b_id_aend
  from butitel t, butitqa q,
       buausgab b LEFT OUTER JOIN buautor a ON
                      a.l_titel_nr = b.l_titel_nr
                  LEFT OUTER JOIN bumanaus m ON
                      m.l_ausg_nr = b.l_ausg_nr
  where t.l_titel_nr = q.l_titel_nr and
       t.l_titel_nr  = b.l_titel_nr and
       b.l_titel_nr > 0
union
  select  q.l_ausg_nr, q.prod_typ, q.qm_id, q.qaus, b.l_titel_nr, b.ausg_text,
           s.artikel_bez, s.sprach_code, s.artikel_bez, s.sprach_code, b.verlags_id, 
           b.isbn, (case when c.ean is not null then c.ean else b.ean end), b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name,
           b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id, b.kz_aufl_best, b.b_id_aend
  from buausspr s, 
          buartqa q LEFT OUTER JOIN bumanaus m ON
               m.l_ausg_nr = q.l_ausg_nr , 
           buausgab b LEFT OUTER JOIN bubearb a ON
                     b.l_ausg_nr = a.l_ausg_nr
                  LEFT OUTER JOIN buaufl c ON
                     c.l_ausg_nr = b.l_ausg_nr and c.l_aufl_nr > 0
  where b.l_ausg_nr = q.l_ausg_nr and
       b.prod_typ = q.prod_typ   and
       s.l_ausg_nr  = b.l_ausg_nr and
       b.l_titel_nr = 0

GO
