create view [dbo].[buremvie] (ek_nr, pos_nr, bew_nr, verlags_id, artikel_nr, auflage_nr, titel1, artikel_bez, aufl_text, ges_menge, liefertermin,
                      rem_ende_dat, tage_rem_ende, e_mandant, adr_gr, adr_nr_li, l_ausg_nr, l_aufl_nr, isbn, status_pos, rem_menge,
                      rem_dat, liefer_menge, lager_code)
  as
select p.ek_nr, p.pos_nr, w.bew_nr, s.verlags_id, dbo.char2num(m.artikel_nr),
       l.auflage_nr, t.titel1, a.artikel_bez, l.aufl_text, g.ges_menge, w.bew_dat, (w.bew_dat+p.rr_frist), 
       datediff(day,getdate(),(w.bew_dat+p.rr_frist)), s.e_mandant, s.adr_gr_li, s.adr_nr_li, p.l_ausg_nr, p.l_aufl_nr, b.isbn, 
       p.status, p.rem_menge, p.rem_dat, w.bew_menge, g.lager_code
 from buekstam s, bumanaus m, buaufl l, bulagbew w, butitel t, buausgab b, bulagges g, 
          buekpos p LEFT OUTER JOIN buausspr a ON
              a.l_ausg_nr = p.l_ausg_nr
 where s.e_mandant = p.e_mandant and
            s.ek_nr = p.ek_nr and 
            m.e_mandant = p.e_mandant and
            m.l_ausg_nr  = p.l_ausg_nr and
            l.l_ausg_nr  = p.l_ausg_nr and
            l.l_aufl_nr  = p.l_aufl_nr and

            b.l_ausg_nr  = p.l_ausg_nr and
            t.l_titel_nr = b.l_titel_nr and
            g.e_mandant  = p.e_mandant and
            g.l_ausg_nr  = p.l_ausg_nr and
            g.l_aufl_nr  = p.l_aufl_nr and
            g.lager_code = 'HLA' and
            g.best_art   = '1' and
            w.e_mandant  = p.e_mandant and
            w.l_ausg_nr  = p.l_ausg_nr and
            w.l_aufl_nr  = p.l_aufl_nr and
            w.ek_nr      = p.ek_nr and
            w.ek_pos_nr     = p.pos_nr and
            p.kz_storno = 'F' and
            p.rem_recht  = 'J' and
            p.rr_frist   > 0 and 
            (w.bew_dat+p.rr_frist) > getdate()

GO
create view buresuch (rech_nr, rech_dat, f_mandant, pos_nr, upos_nr, e_mandant, 
                      rech_typ, r_art, adr_gr, adr_nr_e, person_nr_e, 
       	              haupt_name, eti_1_e, eti_2_e, eti_3_e, eti_4_e, eti_5_e,
                      eti_6_e, eti_7_e, eti_8_e, eti_9_e, eti_10_e, waehrung, re_netto,
                      re_zus_ne, re_zus_mw, re_zus_br, re_rab, re_mwst, re_brutto, zahlbed,
                      auftrag_typ, auft_nr, best_datum, adr_nr_a, person_nr_a, 
                      pos_netto, pos_zus_ne, pos_zus_mw, pos_zus_br, pos_rab, 
                      pos_mwst, pos_brutto, auf_pos, l_ausg_nr, l_aufl_nr, artikel_nr,
                      titel_kurz, e_preis_net, e_preis_br, ber_menge, 
                      upos_sum_ne, upos_rab, upos_sum_mw, upos_sum_br, kombityp,
                      gelief_men,vm_menge,p_status_lief,kz_best_erl, herkunft, vg_menge, liz_typ, best_text, staord_nr,
                      vertreter_id, vertret_auft_typ, grup_id, land_e, isbn, kz_manuell, mw_proz, adr_nr_b, person_nr_b)
as
   select u.rech_nr, u.rech_dat, u.f_mandant, u.pos_nr, u.upos_nr, u.e_mandant,
   s.rech_typ, s.r_art, s.adr_gr, s.adr_nr_e, s.person_nr_e, a.haupt_name, 
   s.eti_1_e, s.eti_2_e, s.eti_3_e, s.eti_4_e, s.eti_5_e, s.eti_6_e, s.eti_7_e,
   s.eti_8_e, s.eti_9_e, s.eti_10_e, s.waehrung, s.re_netto, 
   s.re_zus_ne, s.re_zus_mw, s.re_zus_br, s.re_rab, s.re_mwst, s.re_brutto, s.zahlbed,
   p.auftrag_typ, p.auft_nr, p.best_datum, p.adr_nr_a, p.person_nr_a, p.pos_netto,
   p.pos_zus_ne, p.pos_zus_mw, p.pos_zus_br, p.pos_rab, p.pos_mwst, p.pos_brutto,
   u.auf_pos, u.l_ausg_nr, u.l_aufl_nr, u.artikel_nr, u.titel_kurz, u.e_preis_net, u.e_preis_br, u.ber_menge, u.upos_sum_ne, u.upos_rab, u.upos_sum_mw, u.upos_sum_br, u.kombityp, u.gelief_men, 
   u.vm_menge, u.p_status_lief, u.kz_best_erl, p.herkunft, u.vg_menge, u.liz_typ, p.best_text, p.staord_nr, s.vertreter_id, p.vertret_auft_typ, b.grup_id, s.land_e, u.isbn, s.kz_manuell, u.mw_proz, 
   p.adr_nr_b, p.person_nr_b
 from bufakpos p, 
         bufakupo u LEFT OUTER JOIN buausgab b ON 
              u.l_ausg_nr    = b.l_ausg_nr, 
         bufakst s LEFT OUTER JOIN anschr a ON 
              s.adr_gr       = a.adr_gr
              and s.adr_nr_e     = a.adr_nr
where u.rech_nr = s.rech_nr and
      u.rech_dat = s.rech_dat and
      u.f_mandant = s.f_mandant and
      u.rech_nr = p.rech_nr and
      u.rech_dat = p.rech_dat and
      u.f_mandant = p.f_mandant and
      u.pos_nr = p.pos_nr and
      (u.kombityp != 'X' or u.kombityp is null)
union
   select u.rech_nr, u.rech_dat, u.f_mandant, u.pos_nr, u.upos_nr, u.e_mandant,
   s.rech_typ, s.r_art, s.adr_gr, r.adr_nr, r.person_nr, a.haupt_name, 
   s.eti_1_e, s.eti_2_e, s.eti_3_e, s.eti_4_e, s.eti_5_e, s.eti_6_e, s.eti_7_e,
   s.eti_8_e, s.eti_9_e, s.eti_10_e, s.waehrung, s.re_netto,
   s.re_zus_ne, s.re_zus_mw, s.re_zus_br, s.re_rab, s.re_mwst, s.re_brutto, s.zahlbed,
   p.auftrag_typ, p.auft_nr, p.best_datum, p.adr_nr_a, p.person_nr_a, p.pos_netto,
   p.pos_zus_ne, p.pos_zus_mw, p.pos_zus_br, p.pos_rab, p.pos_mwst, p.pos_brutto,
   u.auf_pos, u.l_ausg_nr, u.l_aufl_nr, u.artikel_nr, u.titel_kurz, u.e_preis_net, u.e_preis_br, u.ber_menge, u.upos_sum_ne, u.upos_rab,
   u.upos_sum_mw, u.upos_sum_br, u.kombityp, u.gelief_men, u.vm_menge, u.p_status_lief, u.kz_best_erl, p.herkunft, u.vg_menge, u.liz_typ,
   p.best_text, p.staord_nr, s.vertreter_id, p.vertret_auft_typ, b.grup_id, s.land_e, u.isbn, s.kz_manuell, u.mw_proz, p.adr_nr_b, p.person_nr_b
 from bufakpos p, bufakst s, 
      bufakupo u LEFT OUTER JOIN buausgab b ON 
              u.l_ausg_nr    = b.l_ausg_nr, 
      adrrech r LEFT OUTER JOIN anschr a ON 
              r.adr_gr       = a.adr_gr
              and r.adr_nr     = a.adr_nr
where r.rech_nr = s.rech_nr and
      r.rech_dat = s.rech_dat and
      r.f_mandant = s.f_mandant and
      u.rech_nr = s.rech_nr and
      u.rech_dat = s.rech_dat and
      u.f_mandant = s.f_mandant and
      u.rech_nr = p.rech_nr and
      u.rech_dat = p.rech_dat and
      u.f_mandant = p.f_mandant and
      u.pos_nr = p.pos_nr and
      (u.kombityp != 'X' or u.kombityp is null)

GO
create view [dbo].[bureview] (e_mandant, retour_nr, l_ausg_nr, l_aufl_nr, l_titel_nr,
                    artikel_nr, isbn, titel_such, best_art, adr_nr_best, adr_nr_le,
                    zustand_id, adr_gr, haupt_name_best, haupt_name_lief, best_datum, 
                    auftrag_typ, ret_datum, ret_gr_id, auft_nr, rech_nr, rech_dat)
  as
select r.e_mandant, r.retour_nr, r.l_ausg_nr, r.l_aufl_nr, b.l_titel_nr,
                    m.artikel_nr, b.isbn, t.titel_such, r.best_art, au.adr_nr_best, au.adr_nr_le,
                    r.zustand_id, r.adr_gr, a1.haupt_name, a2.haupt_name, au.best_datum, au.auftrag_typ, 
                    r.ret_datum, r.ret_gr_id, r.auft_nr, f.rech_nr, f.rech_dat
  from buretour r, buausgab b, bumanaus m, butitel t, anschr a2, bufakupo f, 
       buauftra au LEFT OUTER JOIN anschr a1 ON
            a1.adr_gr = au.adr_gr and
            a1.adr_nr = au.adr_nr_best
 where m.e_mandant = r.e_mandant and
            m.l_ausg_nr  = r.l_ausg_nr and
            au.auft_nr = r.auft_nr and
            (au.auftrag_typ = 'B' or au.auftrag_typ = 'L' or au.auftrag_typ = 'E') and
            a2.adr_gr = au.adr_gr and
            a2.adr_nr = au.adr_nr_le and
            b.l_ausg_nr  = r.l_ausg_nr and
            t.l_titel_nr = b.l_titel_nr and
            f.auft_nr = r.auft_nr and
            f.auf_pos = r.auf_pos and
            f.rech_nr = r.rech_nr

GO
create view [dbo].[burezvie] 
       (e_mandant, l_ausg_nr, l_aufl_nr, artikel_nr, n_artikel_nr, kurztitel, 
        auflage_nr, adr_gr, adr_nr, person_nr, rez_dat, bew_id, text_nr,
        sum_punkte_titel, sum_punkte_rez, sum_menge, einzel_preis, pos_betrag, verw_typ, sel_id, benutzer_id, lfd_nr, auft_nr)
  as
 select m.e_mandant, f.l_ausg_nr, f.l_aufl_nr, m.artikel_nr, 
        dbo.char2num(m.artikel_nr),
        t.titel_such, l.auflage_nr, f.adr_gr, f.adr_nr, f.person_nr, f.rez_dat, f.bew_id, f.text_nr,
        (select sum(cast(bew_id as int)) from burezens k
         where f.l_ausg_nr   = k.l_ausg_nr  
           and f.l_aufl_nr   = k.l_aufl_nr),
        (select sum(cast(bew_id as int)) from burezens i
         where f.adr_gr    = i.adr_gr
           and f.adr_nr   = i.adr_nr  
           and f.person_nr   = i.person_nr),
        (case when f.auft_nr = 9999999999 then 1 else (select sum(ber_menge + frei_menge) from buaufpos p
         where f.auft_nr    = p.auft_nr
           and f.auf_pos   = p.auf_pos) end),
        (select einzel_preis from buaufpos p
         where f.auft_nr    = p.auft_nr
           and f.auf_pos   = p.auf_pos),
        (select pos_betrag from buaufpos p
         where f.auft_nr    = p.auft_nr
           and f.auf_pos   = p.auf_pos), f.verw_typ, (case when o.sel_id is Null then 999999 else o.sel_id end),
        (case when o.benutzer_id is Null then '&$§&$§' else o.benutzer_id end), f.lfd_nr, f.auft_nr
from   bumanaus m, butitel t, buaufl l, 
       burezens f LEFT OUTER JOIN (select o1.benutzer_id, o1.sel_id, o1.adr_gr, o1.adr_nr, o1.person_nr, o1.a_typ from selpool o1 
		                   group by o1.benutzer_id, o1.sel_id, o1.adr_gr, o1.adr_nr, o1.person_nr, o1.a_typ) o ON 
		               f.adr_gr = o.adr_gr
                           and f.adr_nr = o.adr_nr
                           and f.person_nr = o.person_nr
where f.l_ausg_nr     = m.l_ausg_nr
  and f.l_titel_nr    = t.l_titel_nr 
  and f.l_ausg_nr     = l.l_ausg_nr
  and f.l_aufl_nr     = l.l_aufl_nr

GO
create view burfview (l_ausg_nr, ref_id, ref_art_nr, l_titel_nr, titel_such,
                    titel1, sprach_code, orig_titel, org_spr_code, verlags_id, 
                    isbn, ean, prod_typ,  reihen_code, kombityp, issn, ausg_text,
                    e_mandant, artikel_nr, nachname, vorname, haupt_name,
                    sperr_grund, kz_loeschen, herkunft, grup_id, kz_aufl_best, b_id_aend)
  as
select  r.l_ausg_nr,  r.ref_id, r.ref_art_nr, t.l_titel_nr, t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id, 
           b.isbn, b.ean, b.prod_typ,  b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name,
           b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id, b.kz_aufl_best, t.b_id_aend
  from butitel t, 
          buausgab b LEFT OUTER JOIN buautor a ON
                 a.l_titel_nr = b.l_titel_nr , 
          buartref r LEFT OUTER JOIN bumanaus m ON
                m.l_ausg_nr   = r.l_ausg_nr 
 where b.l_ausg_nr = r.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            b.l_titel_nr > 0 
union
select  r.l_ausg_nr,  r.ref_id, r.ref_art_nr, b.l_titel_nr, b.ausg_text,
           s.artikel_bez, s.sprach_code, s.artikel_bez, s.sprach_code, b.verlags_id, 
           b.isbn, (case when c.ean is not null then c.ean else b.ean end), b.prod_typ,  
           b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name,
           b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id, b.kz_aufl_best, b.b_id_aend
  from buausspr s, 
          buartref r LEFT OUTER JOIN bumanaus m ON
                m.l_ausg_nr   = r.l_ausg_nr, 
           buausgab b LEFT OUTER JOIN bubearb a ON
                     b.l_ausg_nr = a.l_ausg_nr
                  LEFT OUTER JOIN buaufl c ON
                     c.l_ausg_nr = b.l_ausg_nr and c.l_aufl_nr > 0
 where b.l_ausg_nr = r.l_ausg_nr and
            s.l_ausg_nr  = b.l_ausg_nr and
            b.l_titel_nr = 0 

GO
create view [dbo].[burgview] (e_mandant, retour_nr, l_ausg_nr, l_aufl_nr, 
                    artikel_nr, best_art, auft_nr_gut, lager_mandant, menge, 
                    mangel_menge, auft_nr, adr_gr, adr_nr, person_nr, rech_nr, rech_dat, preiskat, auf_pos)
  as
select r.e_mandant, r.retour_nr, r.l_ausg_nr, r.l_aufl_nr, 
                    m.artikel_nr, r.best_art, r.auft_nr_gut, m.lager_mandant, r.menge, 
                    r.mangel_menge, r.auft_nr, r.adr_gr, r.adr_nr, r.person_nr, f.rech_nr, f.rech_dat, f.preiskat, r.auf_pos
  from buretour r, bumanaus m, bufakupo f
 where m.e_mandant = r.e_mandant and
            m.l_ausg_nr  = r.l_ausg_nr and
            f.auft_nr = r.auft_nr_gut and
            f.auf_pos = r.auf_pos

GO
create view [dbo].[burtview] (e_mandant, auft_nr, auf_pos, l_ausg_nr, l_aufl_nr, l_titel_nr,
                    artikel_nr, isbn, titel_such, best_art, adr_nr_best, adr_nr_le,
                    adr_gr, haupt_name_best, haupt_name_lief, best_datum, auftrag_typ, 
                    gelief_menge, retour_menge, rech_nr, rech_dat, rech_nr_abw, kombityp, abruf_nr, lager_mandant)
  as
select au.e_mandant, au.auft_nr, p.auf_pos, p.l_ausg_nr, p.l_aufl_nr, b.l_titel_nr,
                    m.artikel_nr, b.isbn, t.titel_such, p.best_art, au.adr_nr_best, au.adr_nr_le,
                    au.adr_gr, a1.haupt_name, a2.haupt_name, au.best_datum, au.auftrag_typ, 
                    f.gelief_men, p.retour_menge, f.rech_nr, f.rech_dat, s.rech_ref, b.kombityp, f.abruf_nr, m.lager_mandant
from buaufpos p, anschr a2, buausgab b, bumanaus m, butitel t, bufakupo f, bufakst s, buauftra au LEFT OUTER JOIN anschr a1 ON
            a1.adr_gr = au.adr_gr and
            a1.adr_nr = au.adr_nr_best
where  p.auft_nr  = au.auft_nr and
            m.e_mandant = p.e_mandant and
            m.l_ausg_nr  = p.l_ausg_nr and
            a2.adr_gr = au.adr_gr and
            a2.adr_nr = au.adr_nr_le and
            b.l_ausg_nr  = p.l_ausg_nr and
            t.l_titel_nr = b.l_titel_nr and
            (au.auftrag_typ = 'B' or au.auftrag_typ = 'L' or au.auftrag_typ = 'E') and
            f.gelief_men > 0 and
            f.auft_nr = p.auft_nr and
            f.auf_pos = p.auf_pos and
            p.kz_best_unabh != 'T' and
            s.rech_nr = f.rech_nr and 
            s.rech_dat = f.rech_dat and 
            s.f_mandant = f.f_mandant and
            s.rech_typ != 'R' and s.rech_typ != 'RS'

GO
create view busgview (l_titel_nr, l_ausg_nr, l_aufl_nr, titel_such,
                    titel1, sprach_code, orig_titel, org_spr_code, verlags_id, 
                    isbn, ean, prod_typ,  reihen_code, kombityp, issn, ausg_text,
                    e_mandant, artikel_nr, nachname, vorname, haupt_name, adr_gr_aut, adr_nr_aut, person_nr_aut, sach_grp,
                    stichwort, sperr_grund, kz_loeschen, herkunft, adr_gr, adr_nr, grup_id, lektor_id, honart_id, meld_nr, 
                    seggrup_id, kz_vorm_bar, bu_la_id, aufl_dat_ist, ideen_nr, aufl_dat_soll, waehrung, kz_aufl_best, autor_typ, b_id_aend)
  as
select t.l_titel_nr, b.l_ausg_nr,  u.l_aufl_nr,  t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id, 
           b.isbn, b.ean, b.prod_typ,  b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name, a.adr_gr, a.adr_nr_aut, a.person_nr_aut,
	   g.sach_grp, s.stichwort, b.sperr_grund, m.kz_loeschen, b.herkunft, l.adr_gr, l.adr_nr, b.grup_id, k.lektor_id, h.honart_id,
           u.meld_nr, e.seggrup_id, c.kz_vorm_bar, b.bu_la_id, u.aufl_dat_ist, b.ideen_nr, u.aufl_dat_soll, u.waehrung, b.kz_aufl_best, a.autor_typ, t.b_id_aend
  from  butitel t LEFT OUTER JOIN  buautor a ON
                      a.l_titel_nr = t.l_titel_nr       
                             LEFT OUTER JOIN hoautor h ON
                                    h.l_titel_nr = a.l_titel_nr and
                                    h.autor_nr = a.autor_nr 
                LEFT OUTER JOIN bugruppe g ON
                      g.l_titel_nr   = t.l_titel_nr
                LEFT OUTER JOIN butitlek k ON
                      k.l_titel_nr   = t.l_titel_nr
                LEFT OUTER JOIN bustichw s ON
                      s.l_titel_nr  = t.l_titel_nr 
                LEFT OUTER JOIN buausgab b ON
                      b.l_titel_nr = t.l_titel_nr 
                             LEFT OUTER JOIN bumanaus m ON
                                    m.l_ausg_nr   = b.l_ausg_nr 
                             LEFT OUTER JOIN buliefer l ON
                                    l.l_ausg_nr   = b.l_ausg_nr 
                             LEFT OUTER JOIN busegagr e ON
                                    e.grup_id   = b.grup_id 
                             LEFT OUTER JOIN buaufl u ON
                                    u.l_ausg_nr   = b.l_ausg_nr 
                                        LEFT OUTER JOIN bumeldnr c ON
                                             c.meld_nr = u.meld_nr 
   where t.l_titel_nr > 0
union
  select b.l_titel_nr, b.l_ausg_nr,  u.l_aufl_nr, b.ausg_text,
           t.artikel_bez, t.sprach_code, t.artikel_bez, t.sprach_code, b.verlags_id, 
           b.isbn, (case when u.ean is not null then u.ean else b.ean end), b.prod_typ,  b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name, a.adr_gr, a.adr_nr, a.person_nr,
           g.sach_grp, s.stichwort, b.sperr_grund, m.kz_loeschen, b.herkunft, l.adr_gr, l.adr_nr, b.grup_id, k.lektor_id, h.honart_id,
           u.meld_nr, e.seggrup_id, c.kz_vorm_bar, b.bu_la_id, u.aufl_dat_ist, b.ideen_nr, u.aufl_dat_soll, u.waehrung, b.kz_aufl_best, a.autor_typ, b.b_id_aend
  from  buausspr t, buausgab b 
                LEFT OUTER JOIN bugruppe g ON
                      g.l_titel_nr   = b.l_titel_nr
                LEFT OUTER JOIN butitlek k ON
                      k.l_titel_nr   = b.l_titel_nr
                LEFT OUTER JOIN bustichw s ON
                      s.l_titel_nr  = b.l_titel_nr 
                LEFT OUTER JOIN bumanaus m ON
                      m.l_ausg_nr   = b.l_ausg_nr 
                LEFT OUTER JOIN buliefer l ON
                      l.l_ausg_nr   = b.l_ausg_nr 
                LEFT OUTER JOIN busegagr e ON
                      e.grup_id   = b.grup_id 
                LEFT OUTER JOIN  bubearb a ON
                      a.l_ausg_nr = b.l_ausg_nr       
                             LEFT OUTER JOIN hoautor h ON
                                    h.l_ausg_nr = a.l_ausg_nr and
                                    h.autor_nr = a.bearb_nr
                LEFT OUTER JOIN buaufl u ON
                      u.l_ausg_nr   = b.l_ausg_nr 
                           LEFT OUTER JOIN bumeldnr c ON
                                c.meld_nr = u.meld_nr 
   where b.l_ausg_nr = t.l_ausg_nr and
         b.l_titel_nr = 0

GO
create view [dbo].[busoview] (l_titel_nr, l_ausg_nr, ausg_text, verlags_id, 
                    prod_typ, benutzer_ek, e_mandant, artikel_nr, 
                    sprach_code, artikel_bez, qm_id, qaus_id, sperr_grund, kz_loeschen, 
                    kombityp, grup_id,ean)
  as
select b.l_titel_nr, m.l_ausg_nr, b.ausg_text, b.verlags_id, 
                    b.prod_typ, b.benutzer_ek, m.e_mandant, m.artikel_nr, 
                    s.sprach_code, s.artikel_bez, q.qm_id, q.qaus,
                    b.sperr_grund, m.kz_loeschen, b.kombityp, b.grup_id,
                    (case when c.ean is not null
                          then c.ean
			  else b.ean
                     end)
  from buausgab b, 
          bumanaus m LEFT OUTER JOIN buausspr s ON
                     s.l_ausg_nr   = m.l_ausg_nr  
                LEFT OUTER JOIN buartqa q ON
                     q.l_ausg_nr  = m.l_ausg_nr 
                LEFT OUTER JOIN buaufl c ON
                     c.l_ausg_nr = m.l_ausg_nr and c.l_aufl_nr > 0
 where b.l_titel_nr = 0 and
           b.l_ausg_nr  = m.l_ausg_nr 

GO
create view [dbo].[bustview] (e_mandant, staord_nr, adr_gr, adr_nr_best, person_nr_best,
       haupt_name_best, nachname_best, vorname_best, 
       adr_nr_re, person_nr_re, haupt_name_re, nachname_re, vorname_re, 
       adr_nr_le, person_nr_le, haupt_name_le, nachname_le, vorname_le,
       best_datum, akt_id, uakt_id, status, l_ausg_nr_k, kz_alle, sach_grp, r_artikel_nr, 
       reihen_code, ber_menge, frei_menge, plz_wohn_best, plz_wohn_re, plz_wohn_le, sto_end, best_text, l_ausg_nr_start, sto_beg,
       datum_von_inaktiv, datum_bis_inaktiv, gueltig_bis_menge, ber_menge_2, frei_menge_2, preiskat, preiskat_2, gueltig_bis)
  as
select b.e_mandant, b.staord_nr, b.adr_gr, b.adr_nr_best, b.person_nr_best,
       a1.haupt_name, p1.nachname, p1.vorname, 
       b.adr_nr_re, b.person_nr_re, a2.haupt_name, p2.nachname, p2.vorname, 
       b.adr_nr_le, b.person_nr_le, a3.haupt_name, p3.nachname, p3.vorname,
       b.best_datum, b.akt_id, b.uakt_id, b.status, b.l_ausg_nr_k, b.kz_alle, 
       b.sach_grp, r.artikel_nr, c.reihen_code, b.ber_menge, b.frei_menge, a1.plz_wohn, a2.plz_wohn, a3.plz_wohn, b.sto_end, 
       b.best_text, b.l_ausg_nr_start, b.sto_beg, b.datum_von_inaktiv, b.datum_bis_inaktiv, b.gueltig_bis_menge, b.ber_menge_2, 
       b.frei_menge_2, b.preiskat, b.preiskat_2, b.gueltig_bis
from bustaord b, person p1, anschr a1, person p2, anschr a2, person p3, anschr a3, bumanaus r,
     buausgab c
where a1.adr_gr    = b.adr_gr and 
           a1.adr_nr    = b.adr_nr_best and
           p1.adr_gr    =b.adr_gr and
           p1.adr_nr    = b.adr_nr_best and
           p1.person_nr = b.person_nr_best and
           a2.adr_gr    = b.adr_gr and 
           a2.adr_nr    = b.adr_nr_re and
           p2.adr_gr    = b.adr_gr and
           p2.adr_nr    = b.adr_nr_re and
           p2.person_nr = b.person_nr_re and
           a3.adr_gr    = b.adr_gr and 
           a3.adr_nr    = b.adr_nr_le and
           p3.adr_gr    = b.adr_gr and
           p3.adr_nr    = b.adr_nr_le and
           p3.person_nr = b.person_nr_le and
           r.e_mandant  = b.e_mandant and
           r.l_ausg_nr  = b.l_ausg_nr_k and
           c.l_ausg_nr  = b.l_ausg_nr_k

GO
create view [dbo].[buswview] (l_titel_nr, l_ausg_nr, titel_such,
                    titel1, sprach_code, orig_titel, org_spr_code, verlags_id, 
                    isbn, ean, prod_typ,  reihen_code, kombityp, issn, ausg_text,
                    e_mandant, artikel_nr, stichwort, sperr_grund, kz_loeschen, herkunft, grup_id)
  as
select s.l_titel_nr, b.l_ausg_nr,  t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id, 
           b.isbn, b.ean, b.prod_typ,  b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, s.stichwort, b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id
  from  butitel t, 
           bustichw s LEFT OUTER JOIN buausgab b ON 
                 b.l_titel_nr  = s.l_titel_nr 
                        LEFT OUTER JOIN bumanaus m ON 
                                m.l_ausg_nr   = b.l_ausg_nr
 where t.l_titel_nr = s.l_titel_nr 

GO
create view [dbo].[butervie] 
       (e_mandant, l_ausg_nr, l_aufl_nr, artikel_nr, n_artikel_nr, kurztitel, 
        auflage_nr, herkunft, ausg_text, aufl_text, aufg_id, abteilung, 
        prioritaet, ben_zust, termin_soll, termin_ist, status)
  as
 select m.e_mandant, t.l_ausg_nr, t.l_aufl_nr, m.artikel_nr, 
        dbo.char2num(m.artikel_nr),
        i.titel_such, l.auflage_nr, b.herkunft, b.ausg_text, l.aufl_text, t.aufg_id, t.abteilung, 
        t.prioritaet, t.ben_zust, t.termin_soll, t.termin_ist, t.status
from   buaufter t, bumanaus m, butitel i, buaufl l, buausgab b
where t.l_ausg_nr     = m.l_ausg_nr
  and t.l_ausg_nr     = l.l_ausg_nr
  and t.l_aufl_nr     = l.l_aufl_nr
  and t.l_ausg_nr     = b.l_ausg_nr
  and b.l_titel_nr    = i.l_titel_nr 

GO
create view [dbo].[butexvie] (l_ausg_nr, l_aufl_nr, e_mandant, verw_typ, auflage_nr, aufl_text, sprach_code, typ)
  as
select  a.l_ausg_nr, a.l_aufl_nr, t.e_mandant, t.verw_typ, a.auflage_nr, a.aufl_text, t.sprach_code, t.typ
  from buaufl a LEFT OUTER JOIN buauftxt t ON  
       t.l_ausg_nr = a.l_ausg_nr and
       t.l_aufl_nr  = a.l_aufl_nr 

GO
create view [dbo].[butihivi]
  as
select distinct h.key_num_1, h.key_num_2, h.key_char_1,  h.datim, h.entitaet, h.lfd_nr_hist,
          m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such, t.titel1,  b.isbn,  b.ean, b.verlags_id, b.kz_eigen,
          b.aend_datum, m.artikel_nr, m.steuer_code, b.sperr_grund, h.feldname, a.meld_nr, b.ausg_text, b.kz_bestand,
          b.bu_send, b.prod_typ, b.grup_id, b.band_nr, a.aufl_dat_ist, a.aufl_text, t.titel_unter
  from historie h, buausgab b, bumanaus m, butitel t, buaufl a
 where b.l_ausg_nr  = h.key_num_1 and
            m.l_ausg_nr = b.l_ausg_nr and 
            a.l_ausg_nr = b.l_ausg_nr and 
            a.l_aufl_nr = 0 and
            t.l_titel_nr = b.l_titel_nr and 
            entitaet = 'BUAUSGAB'
union
select distinct h.key_num_1, h.key_num_2, h.key_char_1,  h.datim, h.entitaet, h.lfd_nr_hist,
          m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such, t.titel1,  b.isbn,  b.ean, b.verlags_id, b.kz_eigen,
          b.aend_datum, m.artikel_nr, m.steuer_code, b.sperr_grund, h.feldname, a.meld_nr, b.ausg_text, b.kz_bestand,
          b.bu_send, b.prod_typ, b.grup_id, b.band_nr, a.aufl_dat_ist, a.aufl_text, t.titel_unter
  from historie h, butitel t, buausgab b, bumanaus m, buaufl a
 where  t.l_titel_nr  = h.key_num_1 and
            m.l_ausg_nr = b.l_ausg_nr and 
            a.l_ausg_nr = b.l_ausg_nr and 
            a.l_aufl_nr = 0 and
            b.l_titel_nr = t.l_titel_nr and
            entitaet = 'BUTITEL'  and 
            (feldname = 'TITEL_SUCH' or feldname = 'TITEL1' or feldname = 'TITEL_UNTER' or  feldname = 'NEUANLAGE')
union
select distinct h.key_num_1, h.key_num_2, h.key_char_1,  h.datim, h.entitaet, h.lfd_nr_hist,
          m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such, t.titel1,  b.isbn,  b.ean, b.verlags_id, b.kz_eigen,
          b.aend_datum, m.artikel_nr, m.steuer_code, b.sperr_grund, h.feldname, a.meld_nr, b.ausg_text, b.kz_bestand,
          b.bu_send, b.prod_typ, b.grup_id, b.band_nr, a.aufl_dat_ist, a.aufl_text, t.titel_unter
  from historie h, buausgab b, bumanaus m, butitel t, buaufl a
 where m.l_ausg_nr  = h.key_num_1 and
            m.e_mandant = h.key_char_1 and 
            b.l_ausg_nr = m.l_ausg_nr and 
            a.l_ausg_nr = b.l_ausg_nr and 
            a.l_aufl_nr = 0 and
            t.l_titel_nr = b.l_titel_nr and 
            entitaet = 'BUMANAUS' and
            (feldname = 'STEUER_CODE' or feldname = 'ARTIKEL_NR')
union
select distinct h.key_num_1, h.key_num_2, h.key_char_1,  h.datim, h.entitaet, h.lfd_nr_hist,
          m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such, t.titel1,  b.isbn,  b.ean, b.verlags_id, b.kz_eigen,
          b.aend_datum, m.artikel_nr, m.steuer_code, b.sperr_grund, h.feldname, a.meld_nr, b.ausg_text, b.kz_bestand,
          b.bu_send, b.prod_typ, b.grup_id, b.band_nr, a.aufl_dat_ist, a.aufl_text, t.titel_unter
  from historie h, butitel t, buausgab b, bumanaus m, buaufl a
 where  a.l_ausg_nr  = h.key_num_1 and
            a.l_aufl_nr = h.key_num_2 and
            h.key_num_2 = 0 and
            m.l_ausg_nr = a.l_ausg_nr and 
            b.l_ausg_nr = a.l_ausg_nr and 
            a.l_aufl_nr = 0 and
            t.l_titel_nr = b.l_titel_nr and
            entitaet = 'BUAUFL'   and
            (feldname = 'MELD_NR' or feldname = 'AUFL_DAT_IST' or feldname = 'AUFL_TEXT')

