create view butiview (l_titel_nr, l_ausg_nr, titel_such,
                    titel1, sprach_code, orig_titel, org_spr_code, verlags_id, 
                    isbn, ean, prod_typ,  reihen_code, kombityp, issn, ausg_text,
                    e_mandant, artikel_nr, sperr_grund, kz_loeschen, l_aufl_nr,
                    auflage_nr, meld_nr, herkunft, kz_aufl_best, n_artikel_nr,
                    aufl_dat_ist, aufl_dat_soll, aufl_hoehe, breite, hoehe, grup_id, titel_unter, 
                    waehrung, lager_mandant, bu_la_id, bu_send, kz_basis_band, anz_beitrag, aufl_status, bestuhlung, b_id_aend)
  as
select t.l_titel_nr, b.l_ausg_nr,  t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id, 
           b.isbn, b.ean, b.prod_typ,  b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, b.sperr_grund, m.kz_loeschen, 
           l.l_aufl_nr, l.auflage_nr, l.meld_nr, b.herkunft, b.kz_aufl_best, isnull(dbo.char2num(m.artikel_nr),0),
           l.aufl_dat_ist, l.aufl_dat_soll, l.aufl_hoehe, b.breite, b.hoehe, b.grup_id, t.titel_unter, 
           l.waehrung, m.lager_mandant, b.bu_la_id, b.bu_send, b.kz_basis_band,
           (select count(*) from bubeitra e where e.l_ausg_nr=b.l_ausg_nr and e.l_ausg_nr_beitr>0), 
           l.status, l.bestuhlung, (case when b.l_titel_nr=0 then b.b_id_aend else t.b_id_aend end)
  from  butitel t LEFT OUTER JOIN buausgab b ON 
                   b.l_titel_nr   = t.l_titel_nr
                        LEFT OUTER JOIN bumanaus m ON
                              m.l_ausg_nr   = b.l_ausg_nr
                        LEFT OUTER JOIN buaufl l ON
                               l.l_ausg_nr = b.l_ausg_nr

