create view buumprvi
  as
select p.list_nr, s.menge, p.e_mandant, p.l_ausg_nr, p.best_art, p.preiskat, p.waehrung, p.gueltig_ab, p.l_aufl_nr, m.steuer_code,
       s.preis, s.b_id_aend, b.l_titel_nr, b.prod_typ, p.subs_dat1, p.subs_dat2
from bumanaus m, buplist p, bumpreis s, buausgab b
where  m.l_ausg_nr = p.l_ausg_nr and 
       m.e_mandant = p.e_mandant and
       s.list_nr = p.list_nr and
       b.l_ausg_nr = p.l_ausg_nr and
       p.l_ausg_nr is not null and
       p.l_aufl_nr is not null
union
select p.list_nr, s.menge, z.e_mandant, z.l_ausg_nr, z.best_art, p.preiskat, p.waehrung, p.gueltig_ab, z.l_aufl_nr, m.steuer_code,
       s.preis, s.b_id_aend, b.l_titel_nr, b.prod_typ, p.subs_dat1, p.subs_dat2
from bumanaus m, buplist p, bumpreis s, buausgab b, bumprzu z
where  s.list_nr = p.list_nr and
       b.l_ausg_nr = z.l_ausg_nr and
       p.l_ausg_nr is null and
       p.l_aufl_nr is null and
       m.l_ausg_nr = z.l_ausg_nr and 
       m.e_mandant = z.e_mandant and
       z.m_preis_grp  = p.m_preis_grp and
       z.e_mandant  = p.e_mandant and 
       z.best_art = p.best_art

