create view buumsakt 
       (e_mandant, rech_typ, datum, l_ausg_nr, l_aufl_nr, artikel_nr, 
        n_artikel_nr, such_titel, kurztitel, auflage_nr, waehrung,
        sum_berechnet, sum_netto_betr, sum_brutto_betr, sum_frei_expl,
        akt_id,uakt_id, herkunft, kz_probeheft, obj_nr, auft_nr, auf_pos, auf_pos_zu, kz_praemie, kz_loeschen)
  as
  select t.e_mandant, s.rech_typ, t.rech_dat, t.l_ausg_nr,
         t.l_aufl_nr, t.artikel_nr, dbo.char2num(t.artikel_nr), t.titel_kurz,
         t.titel1,l.auflage_nr, s.waehrung, sum(t.ber_menge), sum(t.upos_sum_ne),
         sum(t.upos_sum_br), sum(t.frei_menge), o.akt_id, o.uakt_id, s.herkunft, u.kz_probeheft, u.obj_nr,
	 u.auft_nr, u.auf_pos, u.auf_pos_zu, u.kz_praemie, m.kz_loeschen
from  bufakst s, bufakpos o, buaufl l, bufakset t, bufakupo u, bumanaus m
where (s.rech_typ     like 'R%'
  or     s.rech_typ like 'G%' or (s.rech_typ like 'L%' and s.rech_ref is null))
  and (s.rech_typ != 'RO' or s.r_art != 'P')
  and (s.rech_typ != 'RS' or s.r_art != 'P' or u.p_status_lief != 'F')
  and s.rech_nr      = o.rech_nr
  and s.rech_dat     = o.rech_dat
  and s.f_mandant    = o.f_mandant
  and s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and o.pos_nr       = u.pos_nr
  and u.rech_nr      = t.rech_nr
  and u.rech_dat     = t.rech_dat
  and u.f_mandant    = t.f_mandant
  and u.pos_nr       = t.pos_nr
  and u.upos_nr      = t.upos_nr
  and o.akt_id       is not null
  and t.l_ausg_nr    = l.l_ausg_nr
  and t.l_aufl_nr    = l.l_aufl_nr
  and t.l_ausg_nr    = m.l_ausg_nr
  and t.e_mandant    = m.e_mandant
  and ((u.bundle!='F' and u.bundle != 'E') or u.bundle is null)
  and ((u.preiskat != '$NU%' and u.preiskat != '$NU&') or u.preiskat is null)
  group by t.e_mandant, s.rech_typ, t.rech_dat, t.l_ausg_nr,
         t.l_aufl_nr, t.artikel_nr, dbo.char2num(t.artikel_nr),
         t.titel_kurz, t.titel1,l.auflage_nr, s.waehrung, o.akt_id, o.uakt_id, s.herkunft, u.kz_probeheft, u.obj_nr,
	 u.auft_nr, u.auf_pos, u.auf_pos_zu, u.kz_praemie, m.kz_loeschen
union
  select u.e_mandant, s.rech_typ, u.rech_dat, u.l_ausg_nr,
         u.l_aufl_nr, u.artikel_nr, dbo.char2num(u.artikel_nr), u.titel_kurz,
         u.titel1,l.auflage_nr, s.waehrung, sum(u.ber_menge), sum(u.upos_sum_ne),
         sum(u.upos_sum_br), sum(u.frei_menge), o.akt_id, o.uakt_id, s.herkunft, u.kz_probeheft, u.obj_nr,
	 u.auft_nr, u.auf_pos, u.auf_pos_zu, u.kz_praemie, m.kz_loeschen
from  bufakst s, bufakpos o,  buaufl l, bufakupo u, bumanaus m
where (s.rech_typ     like 'R%'
  or     s.rech_typ like 'G%' or (s.rech_typ like 'L%' and s.rech_ref is null))
  and (s.rech_typ != 'RO' or s.r_art != 'P')
  and (s.rech_typ != 'RS' or s.r_art != 'P' or u.p_status_lief != 'F')
  and s.rech_nr      = o.rech_nr
  and s.rech_dat     = o.rech_dat
  and s.f_mandant    = o.f_mandant
  and s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and o.pos_nr       = u.pos_nr
  and o.akt_id       is not null
  and u.l_ausg_nr    = l.l_ausg_nr
  and u.l_aufl_nr    = l.l_aufl_nr
  and (not exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
       and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr) 
      or exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
         and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr and (u.bundle = 'F' or u.bundle = 'E')))
  and u.l_ausg_nr    = m.l_ausg_nr
  and u.e_mandant    = m.e_mandant
  and ((u.preiskat != '$NU%' and u.preiskat != '$NU&') or u.preiskat is null)
  group by u.e_mandant, s.rech_typ, u.rech_dat, u.l_ausg_nr,
