create view [dbo].[buvglvie] (stichtag, lager_code, regal_id, ebene_id, platz_id, e_mandant, l_ausg_nr,
           l_aufl_nr, best_art, bes_menge, artikel_nr, auflage_nr, l_titel_nr,
           titel_such, isbn, bsi_menge, bew_nr)
  as
select  s.stichtag, w.lager_code, w.regal_id, w.ebene_id, w.platz_id, w.e_mandant, w.l_ausg_nr,
           w.l_aufl_nr, w.best_art, w.menge, m.artikel_nr, a.auflage_nr, t.l_titel_nr,
           t.titel_such, b.isbn, s.menge, s.bew_nr
 from bulagbes w, bumanaus m, buausgab b, butitel t, buaufl a, bulagbsi s 
 where  m.l_ausg_nr  = w.l_ausg_nr and
            m.e_mandant  = w.e_mandant and
            b.l_ausg_nr  = w.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            a.l_ausg_nr  = w.l_ausg_nr and
            a.l_aufl_nr  = w.l_aufl_nr and
            s.e_mandant = w.e_mandant and
            s.l_ausg_nr = w.l_ausg_nr and
            s.l_aufl_nr = w.l_aufl_nr and
            s.lager_code = w.lager_code and
            s.regal_id = w.regal_id and
            s.ebene_id = w.ebene_id and
            s.platz_id = w.platz_id and
            s.menge != w.menge

