create view [dbo].[buwaview] (l_ausg_nr, e_mandant, l_titel_nr, titel_such, isbn, prod_typ, 
                 artikel_nr, meld_best, min_best, lager_code, preiskat,
                 best_art, gueltig_ab, l_aufl_nr, waehrung, list_nr, ges_menge, waehrung_man,
                 verlags_id, lager_mandant, titel1, gewicht, anz_vormerk, kz_hauptlager, regal_id,
                 ebene_id, platz_id, best_art_lager, kz_aufl_best, kz_aufl_preis, anz_reserv, 
                 n_artikel_nr, herkunft, grup_id, kz_loeschen, aufl_dat_soll, aufl_waehrung, kz_beobacht, aufl_dat_ist, 
                 kz_eigen, status, meld_nr)
  as
select distinct m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such,  b.isbn, b.prod_typ,  
           m.artikel_nr, l.meld_best, l.min_best, l.lager_code, p.preiskat,
           p.best_art, p.gueltig_ab, a.l_aufl_nr, p.waehrung, p.list_nr, isnull(g.ges_menge,0),
           ma.waehrung, b.verlags_id, m.lager_mandant, t.titel1, b.gewicht,isnull(g.anz_vormerk,0),
           l.kz_hauptlager, l.regal_id, l.ebene_id, l.platz_id,g.best_art, b.kz_aufl_best, b.kz_aufl_preis, isnull(g.anz_reserv,0), 
           dbo.char2num(m.artikel_nr), b.herkunft, b.grup_id, m.kz_loeschen, a.aufl_dat_soll, a.waehrung, m.kz_beobacht,
           a.aufl_dat_ist, b.kz_eigen, a.status, a.meld_nr
  from bumanaus m, butitel t, bmandant ma, buaufl a, buplist p, buausgab b ,
          bulagmin l LEFT OUTER JOIN bulagges g ON
               g.l_ausg_nr = l.l_ausg_nr and
               g.l_aufl_nr = l.l_aufl_nr and
               g.lager_code = l.lager_code and
               g.e_mandant = l.e_mandant
 where b.l_ausg_nr = m.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            a.l_ausg_nr  = m.l_ausg_nr and 
            p.e_mandant  = m.e_mandant and
            p.l_ausg_nr = m.l_ausg_nr and
            b.kz_aufl_preis ='F' and
            l.e_mandant  = m.lager_mandant and 
            l.l_ausg_nr  = a.l_ausg_nr and 
            l.l_aufl_nr  = a.l_aufl_nr and 
            ma.e_mandant = m.e_mandant
union
select distinct m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such,  b.isbn, b.prod_typ,  
           m.artikel_nr, l.meld_best, l.min_best, l.lager_code, p.preiskat,
           p.best_art, p.gueltig_ab, a.l_aufl_nr, p.waehrung, p.list_nr, isnull(g.ges_menge,0),
           ma.waehrung, b.verlags_id, m.lager_mandant, t.titel1, b.gewicht,isnull(g.anz_vormerk,0),
           l.kz_hauptlager, l.regal_id, l.ebene_id, l.platz_id,g.best_art, b.kz_aufl_best, b.kz_aufl_preis, isnull(g.anz_reserv,0), 
           dbo.char2num(m.artikel_nr), b.herkunft, b.grup_id, m.kz_loeschen, a.aufl_dat_soll, a.waehrung, m.kz_beobacht,
           a.aufl_dat_ist, b.kz_eigen, a.status, a.meld_nr
  from bumanaus m, butitel t, bmandant ma, buaufl a, buplist p, buausgab b,
          bulagmin l LEFT OUTER JOIN bulagges g ON
               g.l_ausg_nr = l.l_ausg_nr and
               g.l_aufl_nr = l.l_aufl_nr and
               g.lager_code = l.lager_code and
               g.e_mandant = l.e_mandant
 where b.l_ausg_nr = m.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            a.l_ausg_nr  = m.l_ausg_nr and 
            p.e_mandant  = m.e_mandant and
            p.l_ausg_nr = m.l_ausg_nr and
            p.l_aufl_nr = a.l_aufl_nr and
            b.kz_aufl_preis ='T' and
            l.e_mandant  = m.lager_mandant and 
            l.l_ausg_nr  = a.l_ausg_nr and 
            l.l_aufl_nr  = a.l_aufl_nr and 
            ma.e_mandant = m.e_mandant
union
select distinct m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such,  b.isbn, b.prod_typ,  
           m.artikel_nr, l.meld_best, l.min_best, l.lager_code, '    ', x.best_art ,
           '01.01.2099', a.l_aufl_nr, '   ', 0, isnull(g.ges_menge,0),
           ma.waehrung, b.verlags_id, m.lager_mandant, t.titel1, b.gewicht,isnull(g.anz_vormerk,0),
           l.kz_hauptlager, l.regal_id, l.ebene_id, l.platz_id,g.best_art, b.kz_aufl_best, b.kz_aufl_preis, isnull(g.anz_reserv,0), 
          dbo.char2num(m.artikel_nr), b.herkunft, b.grup_id, m.kz_loeschen, a.aufl_dat_soll, a.waehrung, m.kz_beobacht,
           a.aufl_dat_ist, b.kz_eigen, a.status, a.meld_nr
from bumanaus m, butitel t, bmandant ma, buaufl a, bestart x , buausgab b,
          bulagmin l LEFT OUTER JOIN bulagges g ON
               g.l_ausg_nr = l.l_ausg_nr and
               g.l_aufl_nr = l.l_aufl_nr and
               g.lager_code = l.lager_code and
               g.e_mandant = l.e_mandant
 where b.l_ausg_nr = m.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            a.l_ausg_nr  = m.l_ausg_nr and 
            x.kz_standard = 'T' and 
            not exists (select * from buplist p where
            p.e_mandant  = m.e_mandant and
            p.l_ausg_nr = m.l_ausg_nr) and
            l.e_mandant  = m.lager_mandant and 
            l.l_ausg_nr  = a.l_ausg_nr and 
            l.l_aufl_nr  = a.l_aufl_nr and 
            ma.e_mandant = m.e_mandant
union
select distinct m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such,  b.isbn, b.prod_typ,  
           m.artikel_nr, l.meld_best, l.min_best, l.lager_code, '    ', g.best_art ,
           '01.01.2099', a.l_aufl_nr, '   ', 0, isnull(g.ges_menge,0),
           ma.waehrung, b.verlags_id, m.lager_mandant, t.titel1, b.gewicht,isnull(g.anz_vormerk,0),
           l.kz_hauptlager, l.regal_id, l.ebene_id, l.platz_id,g.best_art, b.kz_aufl_best, b.kz_aufl_preis, isnull(g.anz_reserv,0), 
          dbo.char2num(m.artikel_nr), b.herkunft, b.grup_id, m.kz_loeschen, a.aufl_dat_soll, a.waehrung, m.kz_beobacht,
           a.aufl_dat_ist, b.kz_eigen, a.status, a.meld_nr
from bumanaus m, butitel t, bmandant ma, buaufl a, bestart x , buausgab b,
          bulagmin l LEFT OUTER JOIN bulagges g ON
               g.l_ausg_nr = l.l_ausg_nr and
               g.l_aufl_nr = l.l_aufl_nr and
               g.lager_code = l.lager_code and
               g.e_mandant = l.e_mandant 
 where b.l_ausg_nr = m.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            a.l_ausg_nr  = m.l_ausg_nr and 
            x.kz_standard = 'F' and 
            l.e_mandant  = m.lager_mandant and 
            l.l_ausg_nr  = a.l_ausg_nr and 
            l.l_aufl_nr  = a.l_aufl_nr and 
            g.best_art = x.best_art and
            ma.e_mandant = m.e_mandant

