CREATE VIEW CRM_SELIMPORTV (mandant,aktion_id,unteraktion_id,unteraktion_bez,sel_benutzer_id,sel_id,sel_bez)
as
SELECT m.e_mandant,m.akt_id,m.uakt_id,m.b_uaktid,m.benutzer_id,m.sel_id,v.bez
FROM
    muaktion m
    JOIN selverwa v ON (m.benutzer_id=v.benutzer_id and m.sel_id=v.sel_id and v.sel_form = 'S'
    AND NOT EXISTS (select * from svorschr r where r.benutzer_id=v.benutzer_id and r.sel_id=v.sel_id))        

GO
create VIEW dokbview
