create view dplaview
       (adr_gr, adr_nr, auft_nr, auft_hist_nr, dispo_nr, dispo_hist_nr,
        dispopos_nr, e_mandant, obj_nr, ausg, obj_nr_dispo, jahr, hnr, 
        hnr_num, status_dispopos, produkt, prodname, abw_prod_bez, motiv, 
	motiv_folge, plaz_int, plaz_ext, seite,
	anzart_id, datum_neu, anz_schaltung, farb_id, anz_si, anz_mm,
	anz_eintrag, status, format_id,
	volumen_fa, volumen_mm, netto_betrag, anzeigen_betrag, 
	wa_prov_betrag, kombi_rabatt, sonder_rabatt, volumen_rabatt, 
        wa_prov_satz, anz_zeilen, anz_sp, anz_anzeigen, anz_seiten,
	agv_nr, rech_nr, rech_nr_fakt, rech_datum, 
        haupt_name, abrech_id, bezirk_id, ums_ant_wt1,
        waehrung, verwend_typ, datum_evt,
        plazierungs_id,rubrik_id,rubrik_bez,anz_rubrik,ressort_id)
  as
select p.adr_gr, p.adr_nr, p.auft_nr, p.auft_hist_nr, 
       p.dispo_nr, p.dispo_hist_nr, p.dispopos_nr, p.e_mandant, p.obj_nr,
       p.ausg, d.obj_nr, p.jahr, p.hnr, p.hnr_num, p.status, p.produkt, p.prodname, 
       p.abw_prod_bez, p.motiv, p.motiv_folge, p.plaz_int, p.plaz_ext, p.seite, 
       d.anzart_id, d.datum_neu, d.anz_schaltung, d.farb_id, d.anz_si, d.anz_mm, 
       d.anz_eintrag, d.status, d.format_id,
       d.volumen_fa, d.volumen_mm, d.netto_betrag, d.anzeigen_betrag,
        d.wa_prov_betrag, d.kombi_rabatt, d.sonder_rabatt,
        d.volumen_rabatt, d.wa_prov_satz, d.anz_zeilen, d.anz_sp, d.anz_anzeigen,
        d.anz_seiten, d.agv_nr, d.rech_nr, d.rech_nr_fakt, d.rech_datum,
	a.haupt_name, d.abrech_id, b.bezirk_id, 
        b.ums_anteil_proz, g.waehrung, 
        g.verwend_typ, k.datum_evt, p.plazierungs_id, r.rubrik_id, r.bezeichnung,
        r.anz_belegung,z.ressort_id
from   dispopos p LEFT OUTER JOIN kalendea k ON
       p.e_mandant = k.e_mandant and p.obj_nr = k.obj_nr and 
       p.ausg = k.ausg and p.jahr = k.jahr and p.hnr = k.hnr 
                  LEFT OUTER JOIN drubrik r ON
       p.adr_gr = r.adr_gr  and p.adr_nr = r.adr_nr  and p.auft_nr = r.auft_nr 
       and p.auft_hist_nr = r.auft_hist_nr  and p.dispo_nr = r.dispo_nr  and 
       p.dispo_hist_nr = r.dispo_hist_nr  and p.dispopos_nr = r.dispopos_nr
                  LEFT OUTER JOIN dispplaz z ON
       p.adr_gr = z.adr_gr  and p.adr_nr = z.adr_nr  and p.auft_nr = z.auft_nr and
       p.auft_hist_nr = z.auft_hist_nr  and p.dispo_nr = z.dispo_nr  and 
       p.dispo_hist_nr = z.dispo_hist_nr  and p.dispopos_nr = z.dispopos_nr ,
       dispo d, anschr a, adbezirk b, auftrag g
where  p.auft_hist_nr = 0 and p.dispo_hist_nr = 0 and 
       p.adr_gr = d.adr_gr and p.adr_nr = d.adr_nr and p.auft_nr = d.auft_nr and
       p.auft_hist_nr = d.auft_hist_nr and p.dispo_nr = d.dispo_nr and
       p.dispo_hist_nr = d.dispo_hist_nr and
       p.adr_gr = a.adr_gr and p.adr_nr = a.adr_nr and
       p.adr_gr = b.adr_gr and p.adr_nr = b.adr_nr and p.auft_nr = b.auft_nr and
       b.auft_hist_nr = 0 and b.dispo_nr = 0 and b.dispo_hist_nr = 0 and
       b.f_typ_nr = 'WT1' and
       p.adr_gr = g.adr_gr and p.adr_nr = g.adr_nr and p.auft_nr = g.auft_nr and
       g.auft_hist_nr = 0 and g.kz_inaktiv='F'

GO
CREATE VIEW dwc_v_abo_einzelheft
   ( adr_gr, adr_nr, person_nr, e_mandant, obj_nr, ausg, abo_nr, adresse, adresse_mit_plz, adr_nr_re, objekt, heftnummer, lfd_heftnummer
   , aktion, bewegungsart, preiskategorie, ivw_gruppe, ivw_gruppe_orig, ivw_gruppe_temp, fakturazeitraum, status
   , evt_dat, heft_vers_ist, heft_vers_soll, best_datum, k_datum
   , abobeginn, abobeginn_lfd_hnr, temp_ende, temp_ende_lfd_hnr, kz_temp_phase_beendet
   , aboende, aboende_lfd_hnr, rechnungsbeginn, rechnungsbeginn_lfd_hnr
   , bestellweg, bestellgrund, aboendeweg, aboendegrund, kz_storno
   , rabatt_sum, rabatt_sum_temp, praemienartikel, praemienartikel2, praemienartikel3, praemienartikel4, praemienanteil
   , plz, kreis, datum_neu, datum_aend
   , zusatzfeld1, zusatzfeld2, zusatzfeld3, zusatzfeld4, zusatzfeld5
   , jahr, preiskat_norm, preiskat_temp, preiskat_akt, kz_spreis, ber_menge, liefer_menge )
AS 
-----------------------------------------------------------------------------------------
( SELECT 
  s.adr_gr
, adr_nr
, person_nr
, s.e_mandant
, s.obj_nr
, s.ausg
, abo_nr
-----------------------------------------------------------------------------------------
, adresse
, adresse_mit_plz
, adr_nr_re
-----------------------------------------------------------------------------------------
, s.objekt
, k.heftnummer
, k.lfd_heftnummer
, aktion
-- Bewegungsart wenn Heftnummern gleich (ohne lfd. Nummern)
, CASE WHEN (   heftnummer = abobeginn       AND
              ( abobeginn  = frei_ende       OR
                abobeginn  = temp_ende       OR
                abobeginn  = aboende         ) )
            OR
            (   heftnummer = rechnungsbeginn AND
              ( rechnungsbeginn = temp_ende  OR
                rechnungsbeginn = aboende    ) )
            OR
            (   heftnummer = norm_abo_beginn AND
                norm_abo_beginn = aboende      )
       THEN 'Zu- und Abgang'
       ELSE CASE WHEN ( heftnummer = abobeginn       OR
                        heftnummer = rechnungsbeginn OR
                        heftnummer = norm_abo_beginn )
                 THEN 'Zugang'
                 ELSE CASE WHEN ( heftnummer = frei_ende OR
                                  heftnummer = temp_ende OR
                                  heftnummer = aboende   )
                           THEN 'Abgang'
                           ELSE 'Bestand'
                           END
                 END
       END																				bewegungsart
-- Preiskategorie über lfd. Nummern da >=
, CASE WHEN ( lfd_heftnummer >= norm_abo_beginn_lfd_hnr ) OR
            ( lfd_heftnummer >= rechnungsbeginn_lfd_hnr   AND
              temp_ende_lfd_hnr IS NULL                 )
       THEN preiskat_norm
       ELSE CASE WHEN lfd_heftnummer >= rechnungsbeginn_lfd_hnr AND
                      temp_ende_lfd_hnr IS NOT NULL
                 THEN preiskat_temp
                 ELSE 'FREI'
                 END
       END																				preiskategorie
-- IVW-Gruppe über lfd. Nummer da >=
, CASE WHEN ( lfd_heftnummer >= norm_abo_beginn_lfd_hnr ) OR
            ( lfd_heftnummer >= rechnungsbeginn_lfd_hnr   AND
              temp_ende_lfd_hnr IS NULL                 )
       THEN ivw_gruppe
       ELSE CASE WHEN lfd_heftnummer >= rechnungsbeginn_lfd_hnr AND
                      temp_ende_lfd_hnr IS NOT NULL
                 THEN ivw_gruppe_temp
                 ELSE '23'
                 END
       END																				ivw_gruppe
, ivw_gruppe																			ivw_gruppe_orig
, ivw_gruppe_temp
-- Fakturazeitraum über lfd. Nummern da >=
, CASE WHEN ( lfd_heftnummer >= norm_abo_beginn_lfd_hnr ) OR
            ( lfd_heftnummer >= rechnungsbeginn_lfd_hnr   AND
              temp_ende_lfd_hnr IS NULL                 )
       THEN fakturazeitraum
       ELSE CASE WHEN lfd_heftnummer >= rechnungsbeginn_lfd_hnr AND
                      temp_ende_lfd_hnr IS NOT NULL
                 THEN fakturazeitraum_temp
                 ELSE 'FREI'
                 END
       END																				fakturazeitraum
-- Status über lfd. Nummer da >=
, CASE WHEN temp_ende IS NULL
       THEN CASE WHEN lfd_heftnummer >= rechnungsbeginn_lfd_hnr
                 THEN 'normal'
                 ELSE 'unberechnete Phase'
                 END
       ELSE CASE WHEN temp_ende_lfd_hnr >= lfd_heftnummer
                 THEN 
                     CASE WHEN preiskat_norm = preiskat_temp AND kz_spreis != 'T'
                          THEN 'Temp-Phase, gleicher Preis'
                          ELSE 'Temp-Phase'
                          END
                 ELSE 'normal' 
                 END
       END																				status
, COALESCE(k.evt_dat, k.versand_soll)													evt_dat
, k.versand_ist																			heft_vers_ist
, k.versand_soll																		heft_vers_soll
, best_datum
, k_datum
, abobeginn
, abobeginn_lfd_hnr
, temp_ende
, temp_ende_lfd_hnr
, kz_temp_phase_beendet
, aboende
, aboende_lfd_hnr
, rechnungsbeginn
, rechnungsbeginn_lfd_hnr
, bestellweg
, bestellgrund
, aboendeweg
, aboendegrund
, kz_storno
, rabatt_sum
, rabatt_sum_temp
, praemienartikel
, praemienartikel2
, praemienartikel3
, praemienartikel4
, praemienanteil
, plz
, kreis
, datum_neu
, datum_aend
, zusatzfeld1
, zusatzfeld2
, zusatzfeld3
, zusatzfeld4
, zusatzfeld5
, k.jahr
-----------------------------------------------------------------------------------------
-- Info Originalfelder
, preiskat_norm
, preiskat_temp
, preiskat_akt
, kz_spreis
-----------------------------------------------------------------------------------------
, ber_menge
, liefer_menge
-----------------------------------------------------------------------------------------
-- Tabellen, Filter und Referenzierungen ------------------------------------------------
FROM dwc_t_abo_stamm s, dwc_t_abo_kalender k, mobjtyp o
-- Kalenderjoin Einzelheft
WHERE s.objekt  =  k.objekt
AND abobeginn_lfd_hnr  <= k.lfd_heftnummer		-- neuer Join über lfd_heftnummer
AND aboende_lfd_hnr    >= k.lfd_heftnummer		-- neuer Join über lfd_heftnummer
AND s.e_mandant = o.e_mandant
AND s.obj_nr    = o.obj_nr
AND o.status    = 'N'				-- nur Objekte, die nicht zur Löschung markiert sind
-----------------------------------------------------------------------------------------
/*
   ##### Hier die View ggf. anpassen, um mehr Jahre zu schreiben #####
   MSSQL: Join über jahr_num
*/
AND k.jahr_num > DATEPART(yyyy,dateadd(month, -36, GETDATE())) -- letzte 3 Kalenderjahre
AND k.jahr_num <= DATEPART(yyyy,dateadd(month, 12, GETDATE())) -- nächstes Kalenderjahr
-----------------------------------------------------------------------------------------
) 
;
GO
CREATE VIEW dwc_v_abo_ivwstath
   (e_mandant, obj_nr, ausg, jahr, hnr, abrnr, ivw_list, datum
   , objekt, heftnummer, quartal, menge_in, menge_aus, beschreibung, nummer)
AS 
--------------------------------------------------------------------------------------------------------------------
(SELECT 
  e_mandant
, obj_nr
, ausg
, jahr
, hnr
, abrnr
, ivw_list
, datum
--------------------------------------------------------------------------------------------------------------------
-- DW-Felder
, RTRIM(e_mandant) + '/' + RTRIM(obj_nr) + '/' + RTRIM(ausg)										objekt
-- Heftnummer wird zuerst aus DWC_V_ABO_KALENDER gelesen und wenn n.v. nach alter Variante geglättet
, COALESCE((SELECT heftnummer FROM dwc_v_abo_kalender k 
                     WHERE k.e_mandant = i.e_mandant AND k.obj_nr = i.obj_nr AND k.ausg = i.ausg
                     AND   k.jahr = i.jahr AND k.hnr = i.hnr),RTRIM(jahr) + '/' + 
                           RIGHT('0' + RTRIM(LEFT(hnr, PATINDEX('%[^0-9]%', hnr + 'x') - 1)),2) + 
                           SUBSTRING(RTRIM(hnr), PATINDEX('%[^0-9-]%', hnr + 'x' ),1))				heftnummer
, RTRIM(DATEPART(yyyy,datum)) + '-Q' + RTRIM(DATEPART(q,datum))										quartal 
--------------------------------------------------------------------------------------------------------------------
, COALESCE(menge_in, 0)																				menge_in
, COALESCE(menge_aus, 0)																			menge_aus
, beschreibung
, nummer
--------------------------------------------------------------------------------------------------------------------
FROM ivwstath i
-- u.U. filtern (nur wenn alle Jahre im Kalender numerisch sind)
-- WHERE jahr > DATEPART(yyyy,DATEADD(month, -120, GETDATE()))
--------------------------------------------------------------------------------------------------------------------
) 
;
GO
CREATE VIEW dwc_v_abo_kalender
  (objekt, heftnummer, versanddatum, erscheinungsdatum, faktura_datum, versand_datum,  
   evt_datum, hbk_ref_datum, lfd_monatsnummer, auflage, abwicklungsart,
   hnr, monat, jahr, jahrzehnt, ausgaben_jahr, abgang_aus_heft, edat_letztes_heft, jahr_num,
   e_mandant, obj_nr, ausg, edat_soll, edat_ist, versand_soll, versand_ist, anz_schluss, evt_dat)
AS 
--------------------------------------------------------------------------------------------------------------------------------------------------
-- Vorselektion mit Berechnung des häufig benötigten Feldes hnr2
WITH kalview AS
 ( 
   SELECT k.e_mandant, k.obj_nr, k.ausg, jahr, hnr, edat_soll, edat_ist, versand_soll, versand_ist
        , anz_schluss, bemerkungen, anzahl_abo, exem_vers, va_ist, dauflage, vauflage, heft_gew
        , kz_nicht_ivw, kz_nicht_fakt, rtext_von, rtext_bis, evt_dat
        , CASE WHEN LEN(RTRIM(hnr)) = 2
               THEN RTRIM(hnr)
               ELSE RIGHT('0' + RTRIM(LEFT(hnr, PATINDEX('%[^0-9]%', hnr + 'x') - 1)),2) + 
                    SUBSTRING(RTRIM(hnr), PATINDEX('%[^0-9-]%', hnr + 'x' ),1)
               END																								hnr2
   FROM  kalender k, mobstamm s, mobjtyp t
   WHERE k.e_mandant COLLATE DATABASE_DEFAULT = s.e_mandant COLLATE DATABASE_DEFAULT
   AND   k.obj_nr    COLLATE DATABASE_DEFAULT = s.obj_nr    COLLATE DATABASE_DEFAULT
   AND   k.ausg      COLLATE DATABASE_DEFAULT = s.ausg      COLLATE DATABASE_DEFAULT
   AND   s.e_mandant COLLATE DATABASE_DEFAULT = t.e_mandant COLLATE DATABASE_DEFAULT
   AND   s.obj_nr    COLLATE DATABASE_DEFAULT = t.obj_nr    COLLATE DATABASE_DEFAULT
   AND   kz_abrech = 'H'
   AND   t.status = 'N'
   AND   k.jahr <> 'XXX'
 )
--------------------------------------------------------------------------------------------------------------------------------------------------
  SELECT (RTRIM(k.e_mandant)) + '/' + (RTRIM(k.obj_nr) + '/' + RTRIM(k.ausg))									objekt
, CASE WHEN LEN(RTRIM(hnr2)) = 2 AND (LEN(RTRIM(hnr)) < 3 OR hnr LIKE '%-%')  -- 24.1.2024: 2. Bedingung in Klammern
       THEN RTRIM(jahr) + '/' + hnr2
       ELSE CASE WHEN hnr2 > '99'
                 THEN RTRIM(jahr) + '/99'
                 ELSE RTRIM(jahr) + '/' + hnr  -- 24.1.2024: hnr statt hnr2
                 END
       END																										heftnummer
, COALESCE(versand_ist,versand_soll)																			versanddatum
, COALESCE(evt_dat,versand_ist,versand_soll,edat_ist,edat_soll)													erscheinungsdatum
--------------------------------------------------------------------------------------------------------------------------------------------------
-- einige Originaldaten
, edat_soll																										faktura_datum
, versand_soll																									versand_datum
, evt_dat																										evt_datum
--------------------------------------------------------------------------------------------------------------------------------------------------
-- kundenspezifisch je nach Erfassung: LFD_MONATSNUMMER für Berechnung HBK und HBK_REF_DATUM als Info
-- Kandidaten für diese Berechnung: anz_schluss (IVW-Dat), evt_dat, edat_soll, versand_soll
, COALESCE(anz_schluss,edat_soll,evt_dat,versand_soll)															hbk_ref_datum  
, DATEDIFF(mm, '01.01.1900', COALESCE(anz_schluss,edat_soll,evt_dat,versand_soll))								lfd_monatsnummer
--------------------------------------------------------------------------------------------------------------------------------------------------
, dauflage
, 'H'																											abwicklungsart
, k.hnr
, DATENAME(month, COALESCE(evt_dat,versand_ist,versand_soll,edat_ist,edat_soll))								monat
, jahr
, LEFT(jahr, 3)+ '0er'																							jahrzehnt
, (SELECT MAX(CASE WHEN '0' + hnr2 > '099'
                   THEN '99'
                   ELSE RIGHT('0' + RTRIM(LEFT(hnr, PATINDEX('%[^0-9]%', hnr + 'x') - 1)),2)
                   END) 
   FROM kalview k1
   WHERE k1.jahr=k.jahr AND k1.e_mandant=k.e_mandant AND k1.obj_nr=k.obj_nr and k1.ausg=k.ausg)					Ausgaben_Jahr
, CASE WHEN hnr2 ='01' AND jahr < '9999' -- Jahr=Text abfangen
       THEN 
            CASE WHEN EXISTS (SELECT * FROM kalview k1 WHERE k1.jahr=(k.jahr-1) AND k1.e_mandant=k.e_mandant 
                                                       AND   k1.obj_nr=k.obj_nr AND k1.ausg=k.ausg)
                 THEN
                      CONVERT(char(4),jahr-1) + '/' + (SELECT MAX(hnr2)
                                                    FROM  kalview k1
                                                    WHERE k1.jahr=(k.jahr-1) AND k1.e_mandant=k.e_mandant 
                                                    AND   k1.obj_nr=k.obj_nr AND k1.ausg=k.ausg)
-- wenn Vorjahr im Kalender nicht existiert, dann max. Heftnummer aus aktuellem Jahr nehmen:
                 ELSE
                      CONVERT(char(4),jahr-1) + '/' + (SELECT MAX(hnr2) 
                                                    FROM  kalview k1
                                                    WHERE k1.jahr=k.jahr AND k1.e_mandant=k.e_mandant 
                                                    AND   k1.obj_nr=k.obj_nr AND k1.ausg=k.ausg)
                 END
       ELSE           RTRIM(jahr) + '/' + RTRIM((SELECT MAX(hnr2) 
                                                 FROM  kalview k1
                                                 WHERE k1.jahr=k.jahr AND k1.e_mandant=k.e_mandant 
                                                 AND   k1.obj_nr=k.obj_nr AND k1.ausg=k.ausg
                                                 AND   k1.hnr2<k.hnr2))
       END																										abgang_aus_heft
, COALESCE(edat_ist,evt_dat,edat_soll)																			edat_letztes_heft
, CASE WHEN jahr > '9999'
       THEN 0
       ELSE CONVERT(int, jahr)
       END																										jahr_num
--------------------------------------------------------------------------------------------------------------------------------------------------
-- weitere COVER-Felder
, k.e_mandant, k.obj_nr, k.ausg, edat_soll, edat_ist, versand_soll, versand_ist, anz_schluss, evt_dat
FROM  kalview k 
--------------------------------------------------------------------------------------------------------------------------------------------------
UNION SELECT
  RTRIM(s.e_mandant) + '/' + (RTRIM(s.obj_nr) + '/' + RTRIM(s.ausg))											objekt
, RTRIM(jahr + '/' + mtext)																						heftnummer
, CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)														versanddatum
, CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)														erscheinungsdatum
, CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)														faktura_datum
, CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)														versand_datum
, CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)														evt_datum
, CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)														hbk_ref_datum
, DATEDIFF(mm, '01.01.1900', CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104))							lfd_monatsnummer
, null
, 'Z'																											abwicklungsart
, mtext																											hnr
, mbez																											monat
, jahr
, SUBSTRING(jahr,1,3) + '0er'																					jahrzehnt
, 12																											ausgaben_jahr
, CASE WHEN mtext='01'
       THEN RTRIM(jahr-1) + '/12' 
       ELSE RTRIM(jahr + '/' + RIGHT( '0' + RTRIM(mtext-1),2))
       END																										abgang_aus_heft
, CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)														edat_letztes_heft
, CONVERT(int, jahr)																							jahr_num
, s.e_mandant, s.obj_nr, s.ausg
, CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)														edat_soll
, NULL
, CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)														versand_soll
, CASE WHEN CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104) > GETDATE()
       THEN NULL
       ELSE CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)	
       END																										versand_ist
, NULL
, CONVERT(datetime, '01.' + mtext + '.' + RTRIM(jahr), 104)														evt_dat
FROM  mobstamm s, mobjtyp t, dwc_t_crm_monat, dwc_t_crm_jahr
-- WHERE s.e_mandant COLLATE DATABASE_DEFAULT = t.e_mandant COLLATE DATABASE_DEFAULT -- bei Sortierproblemen
-- AND   s.obj_nr    COLLATE DATABASE_DEFAULT = t.obj_nr    COLLATE DATABASE_DEFAULT -- bei Sortierproblemen
WHERE s.e_mandant = t.e_mandant
AND   s.obj_nr    = t.obj_nr
AND   kz_abrech   = 'Z'
AND   t.status    = 'N'
AND   CONVERT(int, jahr) < DATEPART(yyyy, GETDATE() + 1096)
AND   CONVERT(int, jahr) > 1900
;
GO
CREATE VIEW dwc_v_abo_mobplist
   ( e_mandant, obj_nr, ausg, objekt, list_nr, gueltig_ab, gueltig_bis, rabatt, kz_pauschal, menge1, prozent1
   , waehrung, fakt_zr, preis_kat, inaus, land_code, preis_m1, ek_preis, kiosk_preis, prov_preis )
AS 
WITH x AS (
SELECT e_mandant, obj_nr, MAX(gueltig_ab) max_gueltig_ab
FROM  mobplnr
WHERE gueltig_ab <= GETDATE()
GROUP BY e_mandant, obj_nr )
SELECT m.e_mandant, m.obj_nr, l.ausg
, RTRIM(m.e_mandant) + '/' + RTRIM(m.obj_nr) + '/' + RTRIM(l.ausg) objekt
, m.list_nr, m.gueltig_ab, m.gueltig_bis, m_rabatt, kz_pauschal, menge1, prozent1
, waehrung, fakt_zr, preis_kat, inaus, land_code, preis_m1, ek_preis, kiosk_preis, prov_preis
FROM  mobplnr m, x, mobplist l
WHERE m.e_mandant = x.e_mandant
AND   m.obj_nr = x.obj_nr
AND   m.gueltig_ab = x.max_gueltig_ab
AND   m.e_mandant = l.e_mandant
AND   m.obj_nr = l.obj_nr
AND   m.list_nr = l.list_nr
---------------------------------------------------------------------------------------------------
;
GO
CREATE VIEW dwc_v_abo_praemienartikel
   (adr_gr, adr_nr, person_nr, e_mandant, obj_nr, ausg, abo_nr, pos_nr
   , l_ausg_nr, l_aufl_nr, artikel_nr, artikelauflage, w_adr_nr, w_person_nr
   , preiskat, einzel_preis, list_nr, preislistenpreis
   , kz_liefer_nach_zahl, liefer_datum, liefer_tage_nach_zahl
   , kz_schnupperabo, kz_kein_buauft, kz_abozus, kz_sperren, kz_ersatz, kz_lager_reserv
   , datum_neu, b_id_neu, datum_aend, b_id_aend
   , l_menge)
AS 
SELECT adr_gr, adr_nr, person_nr, w.e_mandant, obj_nr, ausg, abo_nr, pos_nr
   , w.l_ausg_nr, w.l_aufl_nr, artikel_nr, artikelauflage, w_adr_nr, w_person_nr
   , preiskat, einzel_preis, list_nr
   , (SELECT MAX(preis) FROM bumpreis p WHERE p.list_nr = w.list_nr) preislistenpreis
   , v_nach, v_datum, v_nach_tage
   , kz_schnupperabo, kz_kein_buauft, kz_abozus, kz_sperren, kz_ersatz, kz_lager_reserv
   , datum_neu, b_id_neu, datum_aend, b_id_aend
   , l_menge
FROM werbepra w, dwc_v_wws_artikel a
WHERE w.e_mandant = a.e_mandant
AND   w.l_ausg_nr = a.l_ausg_nr
AND   ((w.l_aufl_nr = a.l_aufl_nr) OR (w.l_aufl_nr IS NULL AND a.l_aufl_nr = 0))
------------------------------------------------------------------------
AND   w.kz_sperren = 'F'
;
GO
CREATE VIEW dwc_v_abo_preiskat
            (preis_kat, bezeichnung, ivw_gruppe, rabatt_ab, rabatt_bis)
AS (
SELECT       RTRIM(preis_kat)
           , RTRIM(bezeichnung)
           , ivw1
           , 0
           , CASE WHEN max_ivw1 IS NULL
                  THEN 100
                  ELSE max_ivw1 
                  END
             FROM preiskat
UNION SELECT RTRIM(preis_kat)
           , RTRIM(bezeichnung) + ' (rabattiert)'
           , ivw2
           , max_ivw1 + 1
           , 100
             FROM preiskat 
             WHERE max_ivw1 IS NOT NULL )
;
GO
CREATE VIEW dwc_v_abo_rechnung
   (adr_gr, adr_nr, person_nr, e_mandant, obj_nr, ausg, abo_nr, rechnungsdatum, adresse, adresse_index, adresse_rech
   , objekt, u_objekt, heftnummer, jahr, hnr, land_code, land_code_re, preiskat, fakturazeitraum
   , eg_kz_re, heft_wert, buch_jahr, buch_monat, buchm_wert, buchungsmonat
   , buch_art, rech_nr, re_dat, abruf_nr, posnr, uposnr, u_obj_nr, u_ausg, waehrung, waehrungskurs
   , netto_gesamtsumme, netto_zuschlagsbetrag, netto_abobetrag, mwst_betrag, mwst_satz
   , r_art, fakt_art, adr_nr_re, person_nr_re)
AS 
----------------------------------------------------------------------------------------------------------------------------
( SELECT
  adr_gr, adr_nr, person_nr, f.e_mandant, f.obj_nr, ausg, abo_nr
, REPLACE(CONVERT(char(10), re_dat, 111),'/','-')												rechnungsdatum
, RTRIM(adr_gr) + '/' + RTRIM(land_code_he)														adresse        -- Lieferempfänger
, RTRIM(adr_gr) + '/' + LTRIM(adr_nr) + '/' + LTRIM(person_nr)									adresse_index  -- für MSSQL-PK
, RTRIM(adr_gr) + '/' + RTRIM(land_code_re)														adresse_rech
, RTRIM(f.e_mandant) + '/' + RTRIM(f.obj_nr) + '/' + RTRIM(ausg)								objekt
, RTRIM(f.e_mandant) + '/' + RTRIM(u_obj_nr) + '/' + RTRIM(u_ausg)								u_objekt
, RTRIM(jahr) + '/' + 
        RIGHT('0' + RTRIM(LEFT(hnr, PATINDEX('%[^0-9]%', hnr + 'x') - 1)),2) + 
        SUBSTRING(RTRIM(hnr), PATINDEX('%[^0-9]%', hnr + 'x' ),1)								heftnummer
, jahr, hnr
, land_code_he																					land_code
, land_code_re
, f.preis_kat																					preiskat
, f.fakt_zr																						fakturazeitraum
, eg_kz_re, heft_wert, buch_jahr, buch_monat, buchm_wert
, LTRIM(STR(buch_jahr)) + '-' + SUBSTRING(LTRIM(STR(buchm_wert)),5,2)							buchungsmonat
, buch_art, rech_nr, re_dat, abruf_nr, posnr, uposnr, u_obj_nr, u_ausg, f.waehrung
, CASE WHEN f.waehrung = 'EUR'
       THEN 1
       ELSE COALESCE((SELECT kurs FROM dwc_v_crm_waehkurs k 
                      WHERE f.waehrung=k.waehrung AND k.ziel_waehr='EUR'
                      AND f.re_dat>=k.datum_von AND f.re_dat<=k.datum_bis),1)
       END																						waehrungskurs
, CASE WHEN buch_art='S' 
       THEN sum_betr 
       ELSE sum_betr * (-1)
       END																						netto_gesamtsumme
, CASE WHEN buch_art='S' 
       THEN zusbetr 
       ELSE zusbetr * (-1)
       END																						netto_zuschlagsbetrag
, CASE WHEN buch_art='S' 
       THEN sum_betr - zusbetr 
       ELSE (sum_betr - zusbetr) * (-1)
       END																						netto_abobetrag
, CASE WHEN buch_art='S' 
       THEN mwst_betr 
       ELSE mwst_betr * (-1)
       END																						mwst_betrag
, mwst_satz																						mwst_satz
, RTRIM(r_art)																					r_art
, fakt_art																						fakt_art
, adr_nr_bv																						adr_nr_re
, person_nr_bv																					person_nr_re
FROM fakustat f, mobjtyp o
WHERE re_dat >= CONVERT(date,'01.01.' + CONVERT(char(10),DATEPART(yyyy, DATEADD(month, -60, GETDATE()))))
AND   f.e_mandant=o.e_mandant
AND   f.obj_nr=o.obj_nr
AND   o.status='N'                 -- nur Objekte, die nicht zur Löschung markiert sind
) 
;
GO
CREATE VIEW dwc_v_abo_stamm_h
   ( adr_gr, adr_nr, person_nr, e_mandant, obj_nr, ausg, abo_nr
   , adresse, objekt, aktion, lfd_nr_aktvorb, preiskat_norm, preiskat_temp, preiskat_akt, ivw_gruppe
   , fakturazeitraum, fakturazeitraum_temp
   , bestellweg, bestellgrund, aboendeweg, aboendegrund
   , abobeginn, abobeginn_hnr, aboende, aboende_hnr, rechnungsbeginn, rechnungsbeginn_hnr, temp_ende, temp_ende_hnr
   , best_datum, bestelldatum, k_datum
   , verband, adr_nr_re, person_nr_re, kz_storno, abostatus, aboart, inaus, waehrung, kz_spreis
   , zahlart, r_art, satz_nr, kz_r_druck, kz_gutschrift
   , datum_neu, datum_aend, b_id_neu, b_id_aend, veranlasser
   , objektart, kz_abrech, steuer_code
   , ber_menge )
AS 
( SELECT s.adr_gr
, s.adr_nr
, s.person_nr
, s.e_mandant	--kein TRIM, da PK
, s.obj_nr		--kein TRIM, da PK
, s.ausg		--kein TRIM, da PK
, s.abo_nr
, RTRIM(s.adr_gr) + '/---'																				adresse
, RTRIM(s.e_mandant) + '/' + RTRIM(s.obj_nr) + '/' + RTRIM(s.ausg)										objekt
, CASE WHEN s.w_akt_id IS NULL
       THEN RTRIM(s.e_mandant) + '/[---]'
       ELSE RTRIM(s.e_mandant) + '/' + RTRIM(s.w_akt_id) + '/' + COALESCE(RTRIM(s.w_uakt_id),'-')
       END																								aktion
, lfd_nr_aktvorb
, RTRIM(s.preis_kat)																					preiskat_norm
, RTRIM(COALESCE(s.preis_kat_no,'---'))																	preiskat_temp
, RTRIM(s.preis_kat_akt)																				preiskat_akt
, LTRIM(COALESCE(str(s.ivw_gruppe),'---'))																ivw_gruppe
, RTRIM(COALESCE(s.fakt_zr,'---'))																		fakturazeitraum
, RTRIM(COALESCE(s.fakt_zr_no,'---'))																	fakturazeitraum_temp
, s.best_weg																							bestellweg
, RTRIM(COALESCE(s.bestellg,'---'))																		bestellgrund
, s.kuend_weg																							aboendeweg
, RTRIM(COALESCE(s.k_grund,'---'))																		aboendegrund
, CASE WHEN LEN(RTRIM(s.vbeg_heft)) = 2
       THEN RTRIM(s.vbeg_jahr) + '/' + RTRIM(s.vbeg_heft)
       ELSE CASE WHEN REPLACE(s.vbeg_heft,'/','-') LIKE '%-%'
                 THEN RTRIM(s.vbeg_jahr) + '/' + RIGHT('0' + 
                      LEFT(s.vbeg_heft,CHARINDEX('-',REPLACE(s.vbeg_heft,'/','-'))-1),2)
                 ELSE RTRIM(s.vbeg_jahr) + '/' 
                      + RIGHT('0' + RTRIM(LEFT(vbeg_heft, patindex('%[^0-9]%', vbeg_heft + 'x') - 1)),2)
                      + SUBSTRING(RTRIM(vbeg_heft), patindex('%[^0-9-]%', vbeg_heft + 'x' ),1)
                 END
       END																								abobeginn
, RTRIM(s.vbeg_jahr) + '/' + RTRIM(s.vbeg_heft)															abobeginn_hnr
, CASE WHEN s.vend_jahr IS NULL
       THEN 'ZZZZ/ZZ'
       ELSE CASE WHEN LEN(RTRIM(s.vend_heft)) = 2
                 THEN RTRIM(s.vend_jahr) + '/' + RTRIM(s.vend_heft)
                 ELSE CASE WHEN REPLACE(s.vend_heft,'/','-') LIKE '%-%'
                           THEN RTRIM(s.vend_jahr) + '/' + RIGHT('0' + 
                                LEFT(s.vend_heft,CHARINDEX('-',REPLACE(s.vend_heft,'/','-'))-1),2)
                           ELSE RTRIM(s.vend_jahr) + '/' 
                                + RIGHT('0' + RTRIM(LEFT(vend_heft, patindex('%[^0-9]%', vend_heft + 'x') - 1)),2)
                                + SUBSTRING(RTRIM(vend_heft), patindex('%[^0-9-]%', vend_heft + 'x' ),1)
                           END
                 END
       END																								aboende
, CASE WHEN s.vend_jahr IS NULL
       THEN 'ZZZZ/ZZ'
       ELSE RTRIM(s.vend_jahr) + '/' + RTRIM(s.vend_heft)
       END																								aboende_hnr
, CASE WHEN len(RTRIM(s.r_beg_hnr)) = 2
       THEN RTRIM(s.r_beg_jahr) + '/' + RTRIM(s.r_beg_hnr)
       ELSE CASE WHEN s.r_beg_jahr IS NULL
                 THEN NULL
                 ELSE CASE WHEN replace(s.r_beg_hnr,'/','-') LIKE '%-%'
                           THEN RTRIM(s.r_beg_jahr) + '/' + RIGHT('0' + 
                                left(s.r_beg_hnr,CHARINDEX('-',REPLACE(s.r_beg_hnr,'/','-'))-1),2)
                           ELSE RTRIM(s.r_beg_jahr) + '/' 
                                + RIGHT('0' + RTRIM(left(s.r_beg_hnr, patindex('%[^0-9]%', s.r_beg_hnr + 'x') - 1)),2)
                                + SUBSTRING(RTRIM(s.r_beg_hnr), patindex('%[^0-9-]%', s.r_beg_hnr + 'x' ),1)
                           END
                 END
       END																								rechnungsbeginn
, CASE WHEN s.r_beg_jahr IS NULL
       THEN NULL
       ELSE RTRIM(s.r_beg_jahr) + '/' + RTRIM(s.r_beg_hnr)
       END																								rechnungsbeginn_hnr
-- FREI_ENDE wird später geschrieben
, CASE WHEN len(RTRIM(s.no_ende_hnr)) = 2
       THEN RTRIM(s.no_ende_jahr) + '/' + RTRIM(s.no_ende_hnr)
       ELSE CASE WHEN s.no_ende_jahr IS NULL
                 THEN NULL
                 ELSE CASE WHEN REPLACE(s.no_ende_hnr,'/','-') LIKE '%-%'
                           THEN RTRIM(s.no_ende_jahr) + '/' + RIGHT('0' + 
                                left(s.no_ende_hnr,CHARINDEX('-',REPLACE(s.no_ende_hnr,'/','-'))-1),2)
                           ELSE RTRIM(s.no_ende_jahr) + '/' 
                                + RIGHT('0' + RTRIM(LEFT(s.no_ende_hnr, patindex('%[^0-9]%', s.no_ende_hnr + 'x') - 1)),2)
                                + SUBSTRING(RTRIM(s.no_ende_hnr), patindex('%[^0-9-]%', s.no_ende_hnr + 'x' ),1)
                           END
                 END
       END																								temp_ende
, CASE WHEN s.no_ende_jahr IS NULL
       THEN NULL
       ELSE RTRIM(s.no_ende_jahr) + '/' + RTRIM(s.no_ende_hnr)
       END																								temp_ende_hnr
-- NORM_ABO_BEGINN wird später geschrieben
, COALESCE(REPLACE(CONVERT(CHAR(10), s.best_datum, 111),'/','-'),'---')									best_datum
, REPLACE(CONVERT(CHAR(7), s.best_datum, 111),'/','-')													bestelldatum
, COALESCE(REPLACE(CONVERT(CHAR(10), s.k_datum, 111),'/','-'),'---')									k_datum
, CASE WHEN s.verb_code IS NULL
       THEN NULL 
       ELSE RTRIM(s.verb_code) + '/' + RTRIM(s.uverb_code) 
       END																								verband
, s.adr_nr_bv																							adr_nr_re
, s.person_nr_bv																						person_nr_re
, kz_storno																								kz_storno
, RTRIM(COALESCE(s.abostatus,'~'))																		abostatus
, RTRIM(s.aboart)																						aboart
, s.inaus
, RTRIM(s.waehrung)																						waehrung
, s.kz_spreis
, COALESCE(RTRIM(s.e_mandant) + '/' + RTRIM(s.z_bed),'---')												zahlart
, RTRIM(s.r_art)																						r_art
, s.satz_nr
, s.kz_r_druck
, s.kz_gutschrift
, COALESCE(REPLACE(CONVERT(CHAR(10), s.datum_neu, 111),'/','-'),'---')									datum_neu
, COALESCE(REPLACE(CONVERT(CHAR(10), s.datum_aend, 111),'/','-'),'---')									datum_aend
, RTRIM(s.b_id_neu)																						b_id_neu
, RTRIM(s.b_id_aend)																					b_id_aend
, RTRIM(s.veranlasser)																					veranlasser
, o.objektart
, o.kz_abrech
, RTRIM(o.steuer_code)																					steuer_code
-- Adress- und Zusatzfelder werden später geschrieben
, ber_menge
FROM abostamm s, mobjtyp o
WHERE s.e_mandant=o.e_mandant
AND   s.obj_nr=o.obj_nr
AND   o.kz_abrech='H'                      -- nur heftbezogene Abos
AND   o.status='N'                         -- nur Objekte, die nicht zur Löschung markiert sind
AND   s.vbeg_heft IS NOT NULL              -- nur heftbezogene Abos: vbeg_heft muss auch gefüllt sein
---------------------------------------------------------------------------------------------------------
AND   s.kz_storno='F'                      -- allgemeine Variante ohne Einschränkung auf Kündigungsgrund
---------------------------------------------------------------------------------------------------------
)
;
GO
CREATE VIEW dwc_v_abo_stamm_z
   ( adr_gr, adr_nr, person_nr, e_mandant, obj_nr, ausg, abo_nr
   , adresse, objekt, aktion, lfd_nr_aktvorb, preiskat_norm, preiskat_temp, preiskat_akt, ivw_gruppe
   , fakturazeitraum, fakturazeitraum_temp
   , bestellweg, bestellgrund, aboendeweg, aboendegrund
   , abobeginn, abobeginn_lfd_hnr, aboende, aboende_lfd_hnr, rechnungsbeginn, rechnungsbeginn_lfd_hnr, temp_ende, temp_ende_lfd_hnr
   , best_datum, bestelldatum, k_datum
   , verband, adr_nr_re, person_nr_re, kz_storno, abostatus, aboart, inaus, waehrung, kz_spreis
   , zahlart, r_art, satz_nr, kz_r_druck, kz_gutschrift
   , datum_neu, datum_aend, b_id_neu, b_id_aend, veranlasser
   , objektart, kz_abrech, steuer_code
   , ber_menge )
AS
(SELECT s.adr_gr
, s.adr_nr
, s.person_nr
, s.e_mandant   --kein TRIM, da PK
, s.obj_nr      --kein TRIM, da PK
, s.ausg        --kein TRIM, da PK
, s.abo_nr
, RTRIM(s.adr_gr) + '/---'																				adresse
, RTRIM(s.e_mandant) + '/' + RTRIM(s.obj_nr) + '/' + RTRIM(s.ausg)										objekt
, CASE WHEN s.w_akt_id IS NULL
       THEN RTRIM(s.e_mandant) + '/[---]'
       ELSE RTRIM(s.e_mandant) + '/' + RTRIM(s.w_akt_id) + '/' + COALESCE(RTRIM(s.w_uakt_id),'-')
       END																								aktion
, lfd_nr_aktvorb
, RTRIM(s.preis_kat)																					preiskat_norm
, RTRIM(COALESCE(s.preis_kat_no,'---'))																	preiskat_temp
, RTRIM(s.preis_kat_akt)																				preiskat_akt
, LTRIM(COALESCE(str(s.ivw_gruppe),'---'))																ivw_gruppe
, RTRIM(COALESCE(s.fakt_zr,'---'))																		fakturazeitraum
, RTRIM(COALESCE(s.fakt_zr_no,'---'))																	fakturazeitraum_temp
, s.best_weg																							bestellweg
, RTRIM(COALESCE(s.bestellg,'---'))																		bestellgrund
, s.kuend_weg																							aboendeweg
, RTRIM(COALESCE(s.k_grund,'---'))																		aboendegrund
, CONVERT(CHAR(7), vbeg_dat, 111)																		abobeginn
, CONVERT(CHAR(6), vbeg_dat, 112) 																		abobeginn_lfd_hnr
, CASE WHEN vend_dat IS NULL
       THEN 'ZZZZ/ZZ'
       ELSE CONVERT(CHAR(7), vend_dat, 111) 
       END																								aboende
, CASE WHEN vend_dat IS NULL
       THEN 999999999
       ELSE CONVERT(CHAR(6), vend_dat, 112) 
       END																								aboende_lfd_hnr
, CASE WHEN r_beg_dat IS NULL
       THEN NULL
       ELSE CONVERT(CHAR(7), r_beg_dat, 111) 
       END																								rechnungsbeginn
, CASE WHEN r_beg_dat IS NULL
       THEN NULL
       ELSE CONVERT(CHAR(6), r_beg_dat, 112) 
       END																								rechnungsbeginn_lfd_hnr
-- FREI_ENDE wird später geschrieben
, CASE WHEN s.no_ende_dat IS NULL
       THEN NULL
       ELSE CONVERT(CHAR(7), s.no_ende_dat, 111)
       END																								temp_ende
, CASE WHEN s.no_ende_dat IS NULL
       THEN NULL
       ELSE CONVERT(CHAR(6), s.no_ende_dat, 112)
       END																								temp_ende_lfd_hnr
-- NORM_ABO_BEGINN wird später geschrieben
, COALESCE(REPLACE(CONVERT(CHAR(10), s.best_datum, 111),'/','-'),'---')									best_datum
, REPLACE(CONVERT(CHAR(7), s.best_datum, 111),'/','-')													bestelldatum
, COALESCE(REPLACE(CONVERT(CHAR(10), s.k_datum, 111),'/','-'),'---')									k_datum
, CASE WHEN s.verb_code IS NULL
       THEN NULL 
       ELSE RTRIM(s.verb_code) + '/' + RTRIM(s.uverb_code) 
       END																								verband
, s.adr_nr_bv																							adr_nr_re
, s.person_nr_bv																						person_nr_re
, kz_storno																								kz_storno
, RTRIM(COALESCE(s.abostatus,'~'))																		abostatus
, RTRIM(s.aboart)																						aboart
, s.inaus
, RTRIM(s.waehrung)																						waehrung
, s.kz_spreis
, COALESCE(RTRIM(s.e_mandant) + '/' + RTRIM(s.z_bed),'---')												zahlart
, RTRIM(s.r_art)																						r_art
, s.satz_nr
, s.kz_r_druck
, s.kz_gutschrift
, COALESCE(REPLACE(CONVERT(CHAR(10), s.datum_neu, 111),'/','-'),'---')									datum_neu
, COALESCE(REPLACE(CONVERT(CHAR(10), s.datum_aend, 111),'/','-'),'---')									datum_aend
, RTRIM(s.b_id_neu)																						b_id_neu
, RTRIM(s.b_id_aend)																					b_id_aend
, RTRIM(s.veranlasser)																					veranlasser
, o.objektart
, o.kz_abrech
, RTRIM(o.steuer_code)																					steuer_code
-- Adress- und Zusatzfelder werden später geschrieben
, ber_menge
FROM abostamm s, mobjtyp o
WHERE s.e_mandant=o.e_mandant
AND   s.obj_nr=o.obj_nr
AND   o.kz_abrech='Z'         -- nur zeitraumbezogene Abos
AND   o.status='N'            -- nur Objekte, die nicht zur Löschung markiert sind
AND   s.vbeg_dat IS NOT NULL  -- nur zeitraumbezogene Abos: vbeg_dat muss auch gefüllt sein
---------------------------------------------------------------------------------------------------------
AND   s.kz_storno='F'         -- allgemeine Variante ohne Einschränkung auf Kündigungsgrund
---------------------------------------------------------------------------------------------------------
)
;
--------------------------------------------------------------------------------------------------------------------------------------------------------

GO
CREATE VIEW dwc_v_anz_advert_umsanteil
( adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
, status
, f_typ_nr
, vertreter_id
, provision
, provision_berechnet
, um_ant_proz
, umsatzanteil_berechnet
, adresse
, objektausgabe
, heftnummer
, auft_dispo_nr
, ref )
AS 
--------------------------------------------------------------------------------------------------------------------------------
-- dispobezogene Vertreter
SELECT d.adr_gr, d.adr_nr, d.auft_nr, d.dispo_nr, p.dispopos_nr
, CASE d.STATUS
       WHEN 'A' THEN 'offen'
       WHEN 'F' THEN 'fakturiert'
       WHEN 'Z' THEN 'fakturiert'
       WHEN 'E' THEN 'Eigenanzeige'
       WHEN 'R' THEN 'reserviert'
       WHEN 'O' THEN 'angeboten'
       ELSE '---'
       END																									status
, f_typ_nr
, vertreter_id
, provision
, provision * (COALESCE(um_ant_proz,100)) /
              (SELECT SUM(COALESCE(um_ant_proz,100)) FROM advert x 
               WHERE v.adr_gr=x.adr_gr AND v.adr_nr=x.adr_nr AND v.auft_nr=x.auft_nr 
               AND v.dispo_nr=x.dispo_nr AND v.auft_hist_nr=0 AND x.auft_hist_nr=0
               AND v.dispo_hist_nr=0 AND x.dispo_hist_nr=0)													provision_berechnet
, COALESCE(um_ant_proz,100)
, 100 * (COALESCE(um_ant_proz,100)) /
        (SELECT SUM(COALESCE(um_ant_proz,100)) FROM advert x 
         WHERE v.adr_gr=x.adr_gr AND v.adr_nr=x.adr_nr AND v.auft_nr=x.auft_nr 
         AND v.dispo_nr=x.dispo_nr AND v.auft_hist_nr=0 AND x.auft_hist_nr=0 
         AND v.dispo_hist_nr=0 AND x.dispo_hist_nr=0)														umsatzanteil_berechnet
, RTRIM(v.adr_gr) + '/' + LTRIM(v.adr_nr)																	adresse
, RTRIM(d.e_mandant) + '/' + RTRIM(d.obj_nr)  + '/' + RTRIM(d.ausg)											objektausgabe
, jahr + '/' + CASE WHEN hnr < 10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END						heftnummer
, SUBSTRING(LTRIM(p.auft_nr) +'/'+ LTRIM(p.dispo_nr) +'/'+ LTRIM(p.dispopos_nr),1,10)						auft_dispo_nr  
, 'DISPO'																									ref
FROM advert v, dispo d, dispopos p
WHERE v.dispo_nr>0
AND v.auft_hist_nr=0 AND v.dispo_hist_nr=0
AND d.auft_hist_nr=0 AND d.dispo_hist_nr=0
AND p.auft_hist_nr=0 AND p.dispo_hist_nr=0
AND v.adr_gr=d.adr_gr AND v.adr_nr=d.adr_nr AND v.auft_nr=d.auft_nr AND v.dispo_nr=d.dispo_nr
AND d.adr_gr=p.adr_gr AND d.adr_nr=p.adr_nr AND d.auft_nr=p.auft_nr AND d.dispo_nr=p.dispo_nr
AND jahr IS NOT NULL
--------------------------------------------------------------------------------------------------------------------------------
-- auftragsübergreifende Vertreter
UNION SELECT d.adr_gr, d.adr_nr, d.auft_nr, d.dispo_nr, p.dispopos_nr
, CASE d.STATUS
       WHEN 'A' THEN 'offen'
       WHEN 'F' THEN 'fakturiert'
       WHEN 'Z' THEN 'fakturiert'
       WHEN 'E' THEN 'Eigenanzeige'
       WHEN 'R' THEN 'reserviert'
       WHEN 'O' THEN 'angeboten'
       ELSE '---'
       END																									status
, f_typ_nr
, vertreter_id
, provision
, provision * (COALESCE(um_ant_proz,100)) /
              (SELECT SUM(COALESCE(um_ant_proz,100)) FROM advert x 
               WHERE v.adr_gr=x.adr_gr AND v.adr_nr=x.adr_nr AND v.auft_nr=x.auft_nr 
               AND v.dispo_nr=x.dispo_nr AND v.auft_hist_nr=0 AND x.auft_hist_nr=0 
               AND v.dispo_hist_nr=0 AND x.dispo_hist_nr=0)													provision_berechnet
, COALESCE(um_ant_proz,100)
, 100 * (COALESCE(um_ant_proz,100)) /
        (SELECT SUM(COALESCE(um_ant_proz,100)) FROM advert x 
         WHERE v.adr_gr=x.adr_gr AND v.adr_nr=x.adr_nr AND v.auft_nr=x.auft_nr 
         AND v.dispo_nr=x.dispo_nr AND v.auft_hist_nr=0 AND x.auft_hist_nr=0 
         AND v.dispo_hist_nr=0 AND x.dispo_hist_nr=0)														umsatzanteil_berechnet
, RTRIM(v.adr_gr) + '/' + LTRIM(v.adr_nr)																	adresse
, RTRIM(d.e_mandant) + '/' + RTRIM(d.obj_nr)  + '/' + RTRIM(d.ausg)											objektausgabe
, jahr + '/' + CASE WHEN hnr < 10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END						heftnummer
, SUBSTRING(LTRIM(p.auft_nr) +'/'+ LTRIM(p.dispo_nr) +'/'+ LTRIM(p.dispopos_nr),1,10)						auft_dispo_nr  
, 'AUFTRAG'																									ref
FROM advert v, dispo d, dispopos p
WHERE v.dispo_nr=0
AND v.auft_hist_nr=0 AND v.dispo_hist_nr=0
AND d.auft_hist_nr=0 AND d.dispo_hist_nr=0
AND p.auft_hist_nr=0 AND p.dispo_hist_nr=0
AND v.adr_gr=d.adr_gr AND v.adr_nr=d.adr_nr AND v.auft_nr=d.auft_nr -- keine Dispozuordnung
AND d.adr_gr=p.adr_gr AND d.adr_nr=p.adr_nr AND d.auft_nr=p.auft_nr AND d.dispo_nr=p.dispo_nr
AND jahr IS NOT NULL
--------------------------------------------------------------------------------------------------------------------------------
-- Ausfiltern dispobezogene Vertreter
AND NOT EXISTS
(
SELECT * FROM advert v2
WHERE v2.dispo_nr>0
AND v2.auft_hist_nr=0 AND v2.dispo_hist_nr=0
AND d.auft_hist_nr=0 AND d.dispo_hist_nr=0
AND p.auft_hist_nr=0 AND p.dispo_hist_nr=0
AND v2.adr_gr=d.adr_gr AND v2.adr_nr=d.adr_nr AND v2.auft_nr=d.auft_nr AND v2.dispo_nr=d.dispo_nr
AND d.adr_gr=p.adr_gr AND d.adr_nr=p.adr_nr AND d.auft_nr=p.auft_nr AND d.dispo_nr=p.dispo_nr
AND jahr IS NOT NULL
)
;
GO
CREATE VIEW dwc_v_anz_auftvert_ae
( adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
-----------------------------------------------------------------------------------------------------------------
-- DW
, kunde
, agentur
, objektausgabe
, heftnummer
, datum
, anzeigenart
, platzierung
, abrechnungsart
, status
, auft_dispo_nr
, vert_prov_betrag)
AS 
-----------------------------------------------------------------------------------------------------------------
SELECT a.adr_gr, a.adr_nr, a.auft_nr, v.dispo_nr, v.dispopos_nr,
  RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr) Kunde
, CASE WHEN a.adr_nr_wa IS NULL
       THEN '---'
       ELSE RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr_wa) 
       END Agentur
, RTRIM(v.e_mandant) + '/' + RTRIM(v.obj_nr)  + '/' + RTRIM(v.ausg) Objektausgabe
, jahr + '/' + CASE WHEN hnr < 10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END Heftnummer
, COALESCE((SELECT CASE WHEN datum_evt IS NULL
                   THEN v.jahr + '-01-01'
                   ELSE COALESCE(REPLACE(CONVERT(char(10), datum_evt, 111),'/','-'),v.jahr)
                   END
            FROM kalendea k
            WHERE v.e_mandant = k.e_mandant AND v.obj_nr = k.obj_nr
            AND v.ausg = k.ausg AND v.jahr = k.jahr 
            AND v.hnr = k.hnr),v.jahr + '-01-01') Datum
, CASE RTRIM(COALESCE(
            (SELECT d.format_id FROM dispo d 
             WHERE v.adr_gr = d.adr_gr AND v.adr_nr = d.adr_nr 
             AND v.auft_nr = d.auft_nr AND v.dispo_nr = d.dispo_nr
             AND d.auft_hist_nr = 0 and d.dispo_hist_nr = 0),'---')) 
       WHEN '---' THEN  RTRIM(COALESCE((SELECT anzart_id FROM dispo d WHERE v.adr_gr = d.adr_gr AND v.adr_nr = d.adr_nr 
                        AND v.auft_nr = d.auft_nr AND v.dispo_nr = d.dispo_nr
                        AND d.auft_hist_nr = 0 and d.dispo_hist_nr = 0),'---'))    
       ELSE 
                        RTRIM((SELECT anzart_id FROM dispo d WHERE v.adr_gr = d.adr_gr AND v.adr_nr = d.adr_nr 
                        AND v.auft_nr = d.auft_nr AND v.dispo_nr = d.dispo_nr
                        AND d.auft_hist_nr = 0 
                        AND d.dispo_hist_nr = 0)) + '/' + 
                        RTRIM((SELECT format_id FROM dispo d WHERE v.adr_gr = d.adr_gr AND v.adr_nr = d.adr_nr 
                        AND v.auft_nr = d.auft_nr AND v.dispo_nr = d.dispo_nr
                        AND d.auft_hist_nr = 0 AND d.dispo_hist_nr = 0))
       END Anzeigenart -- aus dispopos wenn möglich
, RTRIM(COALESCE(
       (SELECT plazierungs_id FROM dispopos p 
        WHERE v.adr_gr = p.adr_gr AND v.adr_nr = p.adr_nr 
        AND v.auft_nr = p.auft_nr AND v.dispo_nr = p.dispo_nr AND v.dispopos_nr = p.dispopos_nr
        AND p.auft_hist_nr = 0 and p.dispo_hist_nr = 0),'---')) Platzierung -- aus dispopos wenn möglich
, RTRIM(a.abrech_id) Abrechnungsart  -- hier kann nur die AbrechId aus dem Auftrag genommen werden
-- Vertreter
, CASE (SELECT status FROM dispopos p WHERE v.adr_gr = p.adr_gr AND v.adr_nr = p.adr_nr 
           AND v.auft_nr = p.auft_nr AND v.dispo_nr = p.dispo_nr AND v.dispopos_nr = p.dispopos_nr
           AND p.auft_hist_nr = 0 AND p.dispo_hist_nr = 0)
        WHEN 'A' THEN 'offen'
        WHEN 'F' THEN 'fakturiert'
        WHEN 'Z' THEN 'fakturiert'
        WHEN 'E' THEN 'Eigenanzeige'
        WHEN 'R' THEN 'reserviert'
        WHEN 'O' THEN 'angeboten'
        ELSE 'fakturiert'
        END  Status
, SUBSTRING(LTRIM(a.auft_nr) +'/'+ LTRIM(v.dispo_nr) +'/'+ LTRIM(v.dispopos_nr),1,10) Auft_Dispo_nr  
, vert_prov_betrag
-----------------------------------------------------------------------------------------------------------------
FROM auftrag a, vertbuch v, eobjtyp t
WHERE a.adr_gr = v.adr_gr AND a.adr_nr = v.adr_nr 
AND a.auft_nr = v.auft_nr 
AND a.auft_hist_nr = 0
AND a.e_mandant = v.e_mandant
AND v.jahr is not null
AND a.e_mandant = t.e_mandant
AND a.obj_nr = t.obj_nr
AND (t.istatwcode != 'SPERR' OR t.istatwcode IS NULL)
;
GO
CREATE VIEW dwc_v_anz_bezirkssplit
( adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
-------------------------------------------------------------------------------------------------------------
-- DW
, kunde
, agentur
, objektausgabe
, heftnummer
, anzeigenart
, farbe
, platzierung
, abrechnungsart
, produkt
-------------------------------------------------------------------------------------------------------------
, auftragstyp
, objekttyp
, objekt_auftrag
, objekt_dispo
, status
, auft_dispo_nr
, stichtag
-------------------------------------------------------------------------------------------------------------
, bezirk
, anteil
-------------------------------------------------------------------------------------------------------------
-- kennzahlen
, anzeigenpreis_gesamt
, anzeigenpreis_bezirk
, nettobetrag_gesamt
, nettobetrag_bezirk
, volumen_gesamt
, volumen_bezirk)
AS 
-----------------------------------------------------------------------------------------------------------------
SELECT 
  a.adr_gr
, a.adr_nr
, a.auft_nr
, a.dispo_nr
, a.dispopos_nr
-------------------------------------------------------------------------------------------------------------
-- DW
, kunde
, agentur
, objektausgabe
, heftnummer
, anzeigenart
, farbe
, platzierung
, abrechnungsart
, produkt
-------------------------------------------------------------------------------------------------------------
, auftragstyp
, objekttyp
, objekt_auftrag
, objekt_dispo
, status
, auft_dispo_nr
, stichtag
-------------------------------------------------------------------------------------------------------------
, SUBSTRING(f_typ_nr,1,2) + '/' + RTRIM(bezirk_id)  BEZIRK
, ums_anteil_proz          ANTEIL
-------------------------------------------------------------------------------------------------------------
-- Kennzahlen
, anzeigenpreis												anzeigenpreis_gesamt
, ROUND(anzeigenpreis / 100 * ums_anteil_proz,2)			anzeigenpreis_bezirk
, nettobetrag												nettobetrag_gesamt
, ROUND(nettobetrag / 100 * ums_anteil_proz,2)				nettobetrag_bezirk
, volumen													volumen_gesamt
, ROUND(volumen / 100 * ums_anteil_proz,2)					volumen_bezirk
FROM dwc_v_anz_schaltung_ae a, adbezirk b
WHERE a.adr_gr=b.adr_gr 
  AND a.adr_nr=b.adr_nr
  AND a.auft_nr=b.auft_nr
  AND b.auft_hist_nr=0
  AND b.dispo_nr=0
  AND b.dispo_hist_nr=0
;
GO
CREATE VIEW dwc_v_anz_dispplaz_ae
( adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
, lfd_nr
, anz_belegung
, rubgrp_id
, rubrik_id_ober
, rubrik_id
, bezeichnung
-------------------------------------------------------------------------------------------------------------------------------
-- dispo
, netto_betrag
, anz_schaltung
, anz_anzeigen
-------------------------------------------------------------------------------------------------------------------------------
-- DW
, kunde
, agentur
, objektausgabe
, heftnummer
, datum
, abrechnungsart
, status
, auft_dispo_nr
, anzeigenart
, rubrik
, anzahl_rubriken
, nettobetrag_berechnet
, sonderrabattbetrag
, volumenrabattbetrag
, kombirabattbetrag
, zusatzrabattbetrag
, grundpreisnachlass
, rabattbetrag
, agenturprovisionsbasis
, agenturprovision
, zuschlagsbetrag )
AS 
-------------------------------------------------------------------------------------------------------------------------------
SELECT r.adr_gr, r.adr_nr, r.auft_nr, r.dispo_nr, r.dispopos_nr, lfd_nr, 1
, rubgrp_id, NULL
, RTRIM(COALESCE(ressort_id,'---'))																					rubrik_id
, RTRIM(r.plaz_ext)																									bezeichnung
, d.netto_betrag, d.anz_schaltung, d.anz_anzeigen
, RTRIM(r.adr_gr) + '/' + LTRIM(r.adr_nr)																			kunde
, CASE WHEN a.adr_nr_wa IS NULL
       THEN '---'
       ELSE RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr_wa)
       END																											agentur
, RTRIM(s.e_mandant) + '/' + RTRIM(s.obj_nr)  + '/' + RTRIM(s.ausg)													objektausgabe
, jahr + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END									heftnummer
, COALESCE((SELECT CASE WHEN datum_evt IS NULL
                   THEN p.jahr + '-01-01'
                   ELSE COALESCE(REPLACE(CONVERT(char(10), datum_evt, 111),'/','-'),p.jahr)
                   END
            FROM kalendea k
            WHERE p.e_mandant = k.e_mandant AND p.obj_nr = k.obj_nr
            AND p.ausg = k.ausg AND p.jahr = k.jahr 
            AND p.hnr = k.hnr),p.jahr + '-01-01')																	datum
, RTRIM(d.abrech_id)																								abrechnungsart
, CASE d.status
       WHEN 'A' THEN 'offen'
       WHEN 'F' THEN 'fakturiert'
       WHEN 'Z' THEN 'fakturiert'
       WHEN 'E' THEN 'Eigenanzeige'
       WHEN 'R' THEN 'reserviert'
       WHEN 'O' THEN 'angeboten'
       ELSE '---'
       END																											status
, SUBSTRING(LTRIM(r.auft_nr) +'/'+ LTRIM(r.dispo_nr) +'/'+ LTRIM(r.dispopos_nr),1,10)								auft_dispo_nr  
, CASE WHEN format_id IS NULL 
       THEN RTRIM(anzart_id) 
       ELSE RTRIM(anzart_id) + '/' + RTRIM(format_id) 
       END																											anzeigenart
, '[RGR:' + RTRIM(rubgrp_id) + ']/' + RTRIM(COALESCE(ressort_id,'---'))												Rubrik
, 1																													anzahlrubriken
-------------------------------------------------------------------------------------------------------------------------------
-- im folgenden Betrag wird der Nettobetrag durch Anzahl Anzeigen (Rubriken) geteilt und mal Anzahl Schaltungen 
-- multipliziert weil bei z.B. 4 Dispopos-Sätzen mit je 1 Rubrik Anzahl Anzeigen auch =4 ist. 
-- Das Ergebnis wird gemäß eobjstru verteilt.
, ROUND(netto_betrag / d.anz_anzeigen * d.anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM eobjstru u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg),100),2) - COALESCE(mwst_anteil,0)											nettobetrag_berechnet
-- bei den folgenden Beträgen müsste eigentlich auch MwSt rausgerechnet werden, ist in COVER aber auch nicht...
, ROUND(sondrab_betrag / d.anz_anzeigen * d.anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		sonderrabattbetrag
, ROUND(volrab_betrag / d.anz_anzeigen * d.anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		volumenrabattbetrag
, ROUND(kombirab_betrag / d.anz_anzeigen * d.anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		kombirabattbetrag
, ROUND((COALESCE((SELECT SUM(k.betrag) FROM dsokost k 
                  WHERE betrag<0 AND d.adr_gr = k.adr_gr AND d.adr_nr = k.adr_nr AND d.auft_nr = k.auft_nr 
                  AND d.dispo_nr = k.dispo_nr AND k.auft_hist_nr = 0 and k.dispo_hist_nr = 0),0)) / 
                  d.anz_anzeigen * d.anz_schaltung / 100 * (-1) *
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		zusatzrabattbetrag
, ROUND((COALESCE(anzeigen_betrag_preis,anzeigen_betrag) - anzeigen_betrag) / 
             d.anz_anzeigen * d.anz_schaltung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		grundpreisnachlass
, ROUND((sondrab_betrag + volrab_betrag + kombirab_betrag + 
        (COALESCE(anzeigen_betrag_preis,anzeigen_betrag) - anzeigen_betrag) -
         COALESCE((SELECT SUM(k.betrag) FROM dsokost k 
                  WHERE betrag<0 AND d.adr_gr = k.adr_gr AND d.adr_nr = k.adr_nr AND d.auft_nr = k.auft_nr 
                  AND d.dispo_nr = k.dispo_nr AND k.auft_hist_nr = 0 and k.dispo_hist_nr = 0),0)) / 
                  d.anz_anzeigen * d.anz_schaltung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                   WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                   AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		rabattbetrag
, ROUND(wa_prov_basis / d.anz_anzeigen * d.anz_schaltung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		agenturprovisionsbasis
, ROUND(wa_prov_betrag / d.anz_anzeigen * d.anz_schaltung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		agenturprovision
, ROUND(COALESCE((SELECT SUM(k.betrag) FROM dsokost k 
                  WHERE betrag>0 AND d.adr_gr = k.adr_gr AND d.adr_nr = k.adr_nr AND d.auft_nr = k.auft_nr 
                  AND d.dispo_nr = k.dispo_nr AND k.auft_hist_nr = 0 and k.dispo_hist_nr = 0),0) / 
                 d.anz_anzeigen * d.anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		zuschlagsbetrag
--------------------------------------------------------------------------------------------------------------------------------------------
FROM auftrag a, dispplaz r, dispopos p, dispo d, eobstamm s, eobjtyp t
WHERE a.adr_gr = d.adr_gr AND a.adr_nr = d.adr_nr AND a.auft_nr = d.auft_nr AND a.auft_hist_nr = d.auft_hist_nr
  AND d.adr_gr = p.adr_gr AND d.adr_nr = p.adr_nr AND d.auft_nr = p.auft_nr AND d.dispo_nr = p.dispo_nr
  AND r.adr_gr = p.adr_gr AND r.adr_nr = p.adr_nr AND r.auft_nr = p.auft_nr AND r.dispo_nr = p.dispo_nr AND r.dispopos_nr = p.dispopos_nr
  AND p.e_mandant = s.e_mandant AND p.obj_nr = s.obj_nr AND p.ausg = s.ausg
  AND r.auft_hist_nr = 0 AND r.dispo_hist_nr = 0
  AND p.auft_hist_nr = 0 AND p.dispo_hist_nr = 0
  AND d.auft_hist_nr = 0 AND d.dispo_hist_nr = 0
  AND p.status not in ('L','S')
  AND s.e_mandant = t.e_mandant
  AND s.obj_nr = t.obj_nr
  AND (t.istatwcode != 'SPERR' OR t.istatwcode IS NULL)
;
GO
CREATE VIEW dwc_v_anz_drubrik_ae
( adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
, lfd_nr
, anz_belegung
, rubgrp_id
, rubrik_id_ober
, rubrik_id
, bezeichnung
-------------------------------------------------------------------------------------------------------------------------------
-- dispo
, netto_betrag
, anz_schaltung
, anz_anzeigen
-------------------------------------------------------------------------------------------------------------------------------
-- DW
, kunde
, agentur
, objektausgabe
, heftnummer
, datum
, abrechnungsart
, status
, auft_dispo_nr
, anzeigenart
, rubrik
, anzahl_rubriken
, nettobetrag_berechnet
, sonderrabattbetrag
, volumenrabattbetrag
, kombirabattbetrag
, zusatzrabattbetrag
, grundpreisnachlass
, rabattbetrag
, agenturprovisionsbasis
, agenturprovision
, zuschlagsbetrag )
AS 
-------------------------------------------------------------------------------------------------------------------------------
SELECT r.adr_gr, r.adr_nr, r.auft_nr, r.dispo_nr, r.dispopos_nr, lfd_nr, r.anz_belegung
, rubgrp_id, rubrik_id_ober
, RTRIM(COALESCE(rubrik_id,'---'))																					rubrik_id
, RTRIM(bezeichnung)																								bezeichnung
, d.netto_betrag, d.anz_schaltung, d.anz_anzeigen
, RTRIM(r.adr_gr) + '/' + LTRIM(r.adr_nr)																			kunde
, CASE WHEN a.adr_nr_wa IS NULL
       THEN '---'
       ELSE RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr_wa)
       END																											agentur
, RTRIM(s.e_mandant) + '/' + RTRIM(s.obj_nr)  + '/' + RTRIM(s.ausg)													objektausgabe
, jahr + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END									heftnummer
, COALESCE((SELECT CASE WHEN datum_evt IS NULL
                   THEN p.jahr + '-01-01'
                   ELSE COALESCE(REPLACE(CONVERT(char(10), datum_evt, 111),'/','-'),p.jahr)
                   END
            FROM kalendea k
            WHERE p.e_mandant = k.e_mandant AND p.obj_nr = k.obj_nr
            AND p.ausg = k.ausg AND p.jahr = k.jahr 
            AND p.hnr = k.hnr),p.jahr + '-01-01')																	datum
, RTRIM(d.abrech_id)																								abrechnungsart
, CASE d.status
       WHEN 'A' THEN 'offen'
       WHEN 'F' THEN 'fakturiert'
       WHEN 'Z' THEN 'fakturiert'
       WHEN 'E' THEN 'Eigenanzeige'
       WHEN 'R' THEN 'reserviert'
       WHEN 'O' THEN 'angeboten'
       ELSE '---'
       END																											status
, SUBSTRING(LTRIM(r.auft_nr) +'/'+ LTRIM(r.dispo_nr) +'/'+ LTRIM(r.dispopos_nr),1,10)								auft_dispo_nr  
, CASE WHEN format_id IS NULL 
       THEN RTRIM(anzart_id) 
       ELSE RTRIM(anzart_id) + '/' + RTRIM(format_id) 
       END																											anzeigenart
, '[RGR:' + RTRIM(rubgrp_id) + ']/' + RTRIM(COALESCE(rubrik_id,'---'))												Rubrik
, 1																													anzahlrubriken
-------------------------------------------------------------------------------------------------------------------------------
-- im folgenden Betrag wird der Nettobetrag durch Anzahl Anzeigen (Rubriken) geteilt und mal Anzahl Schaltungen 
-- multipliziert weil bei z.B. 4 Dispopos-Sätzen mit je 1 Rubrik Anzahl Anzeigen auch =4 ist. 
-- Das Ergebnis wird gemäß eobjstru verteilt.
, ROUND(netto_betrag / d.anz_anzeigen * d.anz_schaltung * r.anz_belegung / 100 * 
        COALESCE((SELECT erloes_ant FROM eobjstru u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg),100),2) - COALESCE(mwst_anteil,0)											nettobetrag_berechnet
-- bei den folgenden Beträgen müsste eigentlich auch MwSt rausgerechnet werden, ist in COVER aber auch nicht...
, ROUND(sondrab_betrag / d.anz_anzeigen * d.anz_schaltung * r.anz_belegung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		sonderrabattbetrag
, ROUND(volrab_betrag / d.anz_anzeigen * d.anz_schaltung * r.anz_belegung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		volumenrabattbetrag
, ROUND(kombirab_betrag / d.anz_anzeigen * d.anz_schaltung * r.anz_belegung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		kombirabattbetrag
, ROUND((COALESCE((SELECT SUM(k.betrag) FROM dsokost k 
                  WHERE betrag<0 AND d.adr_gr = k.adr_gr AND d.adr_nr = k.adr_nr AND d.auft_nr = k.auft_nr 
                  AND d.dispo_nr = k.dispo_nr AND k.auft_hist_nr = 0 and k.dispo_hist_nr = 0),0)) / 
                  d.anz_anzeigen * d.anz_schaltung * r.anz_belegung / 100 * (-1) *
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		zusatzrabattbetrag
, ROUND((COALESCE(anzeigen_betrag_preis,anzeigen_betrag) - anzeigen_betrag) / 
             d.anz_anzeigen * d.anz_schaltung * r.anz_belegung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >=  u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		grundpreisnachlass
, ROUND((sondrab_betrag + volrab_betrag + kombirab_betrag + 
        (COALESCE(anzeigen_betrag_preis,anzeigen_betrag) - anzeigen_betrag) -
         COALESCE((SELECT SUM(k.betrag) FROM dsokost k 
                  WHERE betrag<0 AND d.adr_gr = k.adr_gr AND d.adr_nr = k.adr_nr AND d.auft_nr = k.auft_nr 
                  AND d.dispo_nr = k.dispo_nr AND k.auft_hist_nr = 0 and k.dispo_hist_nr = 0),0)) / 
                  d.anz_anzeigen * d.anz_schaltung * r.anz_belegung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                   WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                   AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		rabattbetrag
, ROUND(wa_prov_basis / d.anz_anzeigen * d.anz_schaltung * r.anz_belegung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		agenturprovisionsbasis
, ROUND(wa_prov_betrag / d.anz_anzeigen * d.anz_schaltung * r.anz_belegung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		agenturprovision
, ROUND(COALESCE((SELECT SUM(k.betrag) FROM dsokost k 
                  WHERE betrag>0 AND d.adr_gr = k.adr_gr AND d.adr_nr = k.adr_nr AND d.auft_nr = k.auft_nr 
                  AND d.dispo_nr = k.dispo_nr AND k.auft_hist_nr = 0 and k.dispo_hist_nr = 0),0) / 
                 d.anz_anzeigen * d.anz_schaltung * r.anz_belegung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant = u.e_mandant AND d.obj_nr = u.obj_nr AND p.obj_nr = u_obj_nr 
                  AND p.ausg = u.ausg AND p.hnr_num >= u.hnr_num_von AND p.hnr_num <= u.hnr_num_bis),100),2)		zuschlagsbetrag
--------------------------------------------------------------------------------------------------------------------------------------------
FROM auftrag a, drubrik r, dispopos p, dispo d, eobstamm s, eobjtyp t
WHERE a.adr_gr = d.adr_gr AND a.adr_nr = d.adr_nr AND a.auft_nr = d.auft_nr AND a.auft_hist_nr = d.auft_hist_nr
  AND d.adr_gr = p.adr_gr AND d.adr_nr = p.adr_nr AND d.auft_nr = p.auft_nr AND d.dispo_nr = p.dispo_nr
  AND r.adr_gr = p.adr_gr AND r.adr_nr = p.adr_nr AND r.auft_nr = p.auft_nr AND r.dispo_nr = p.dispo_nr AND r.dispopos_nr = p.dispopos_nr
  AND p.e_mandant = s.e_mandant AND p.obj_nr = s.obj_nr AND p.ausg = s.ausg
  AND r.auft_hist_nr = 0 AND r.dispo_hist_nr = 0
  AND p.auft_hist_nr = 0 AND p.dispo_hist_nr = 0
  AND d.auft_hist_nr = 0 AND d.dispo_hist_nr = 0
  AND p.status not in ('L','S')
  AND s.e_mandant = t.e_mandant
  AND s.obj_nr = t.obj_nr
  AND (t.istatwcode != 'SPERR' OR t.istatwcode IS NULL)
;
GO
CREATE VIEW dwc_v_anz_dsokost AS
WITH zusk AS (
SELECT 
  k.adr_gr
, k.adr_nr
, k.auft_nr
, k.auft_hist_nr
, k.dispo_nr
, k.zuschl_id
, k.soko_id
, CASE WHEN k.soko_id IS NULL
       THEN 'ZU_' + k.zuschl_id
       ELSE 'SK_' + k.soko_id
       END zuschl_soko_id
, k.kz_rabatt
, k.kz_wa_prov
, COALESCE((SELECT kz_abs FROM dwc_v_anz_zuschl_sk j
            WHERE j.zuschl_id = k.zuschl_id),'F') kz_abs1
, COALESCE((SELECT kz_abs FROM dwc_v_anz_zuschl_sk j
            WHERE j.soko_id = k.soko_id),'F') kz_abs2
, k.menge
, k.satz
, k.betrag
, CASE WHEN k.kz_rabatt = 'T'
       THEN (100 - d.volumen_rabatt) / 100
       ELSE 1
       END vr_multi
, CASE WHEN k.kz_rabatt = 'T'
       THEN (100 - d.sonder_rabatt) / 100
       ELSE 1
       END sr_multi
, CASE WHEN k.kz_wa_prov = 'T'
       THEN (100 - d.wa_prov_satz) / 100
       ELSE 1
       END waprov_multi
FROM dsokost k, dispo d
WHERE k.adr_gr = d.adr_gr
AND k.adr_nr = d.adr_nr
AND k.auft_nr = d.auft_nr
AND k.dispo_nr = d.dispo_nr
AND k.auft_hist_nr = 0 
AND d.auft_hist_nr = 0 
AND k.dispo_hist_nr = 0
AND d.dispo_hist_nr = 0)
SELECT 
  adr_gr
, adr_nr
, auft_nr
, auft_hist_nr
, dispo_nr
, zuschl_id
, soko_id
, zuschl_soko_id
, kz_rabatt
, kz_wa_prov
, CASE WHEN kz_abs1 = 'F' AND kz_abs2 = 'F'
       THEN 'F'
       ELSE 'T'
       END kz_abs
, COALESCE(menge,1) menge
, satz
, vr_multi
, sr_multi
, waprov_multi
, betrag
, (betrag * vr_multi * sr_multi * waprov_multi) betrag_berech
, CASE WHEN kz_abs1 = 'F' AND kz_abs2 = 'F'
       THEN 0
       ELSE betrag
       END betrag_abs
, CASE WHEN kz_abs1 = 'F' AND kz_abs2 = 'F'
       THEN 0
       ELSE (betrag * vr_multi * sr_multi * waprov_multi)
       END betrag_abs_berech
FROM zusk
;
GO
CREATE VIEW dwc_v_anz_eastatfc
( adr_gr
, adr_nr
-------------------------------------------------------------------------------------------------------------
-- DW
, kunde
, agentur
, objektausgabe
, heftnummer
, datum
, check_datum
, vert_bez_anzart
, version
, nettobetrag
, volumen)
AS 
SELECT 
  adr_gr
, adr_nr
, RTRIM(adr_gr) + '/' + LTRIM(adr_nr)														kunde
, '---' Agentur
, RTRIM(e.e_mandant) + '/' + RTRIM(e.obj_nr)  + '/' + RTRIM(e.ausg)							objektausgabe
, CASE WHEN e.hnr=0
       THEN e.jahr + '/99'
       ELSE CASE WHEN datum_evt IS NULL
                 THEN e.jahr + '/99'
                 ELSE e.jahr + '/' + CASE WHEN e.hnr<10 
                                          THEN '0' + LTRIM(STR(e.hnr)) 
                                          ELSE LTRIM(STR(e.hnr)) 
                                          END
                 END
       END																					heftnummer
, CASE WHEN e.hnr=0
       THEN e.jahr + '-01-01'
       ELSE CASE WHEN datum_evt IS NULL
                 THEN e.jahr + '-01-01'
                 ELSE COALESCE(REPLACE(CONVERT(char(10), datum_evt, 111),'/','-'),e.jahr)
                 END
       END																					datum
, CASE WHEN e.hnr=0
       THEN 'Planzahl nur auf Jahr gebucht'
       ELSE CASE WHEN datum_evt IS NULL
                 THEN 'Hefttermin fehlt im Kalender'
                 ELSE 'ok'
                 END
       END																					check_datum
, CASE WHEN vertreter_bez='000'
       THEN '---'
       ELSE CASE WHEN vertreter_bez = 'FA'
                 THEN 'FA/---'
                 ELSE COALESCE(vertreter_bez,'---')
                 END
       END																					vert_bez_anzart
, 'Plan'																					version
, COALESCE(soll_netto,0)																	nettobetrag
, COALESCE(soll_volumen,0)																	volumen
FROM eastatfc e
LEFT JOIN kalendea k ON e.e_mandant=k.e_mandant
AND e.obj_nr=k.obj_nr
AND e.ausg=k.ausg
AND e.jahr=k.jahr
AND e.hnr=k.hnr
;
GO
CREATE VIEW dwc_v_anz_eobjstrukr AS
WITH p AS
(SELECT e_mandant, obj_nr, u_obj_nr, ausg, 1900001 hnr_num_von, erloes_ant 
 FROM eobjstru
 UNION SELECT e_mandant, obj_nr, u_obj_nr, ausg
 , CONVERT(int,jahr + RIGHT('000' + LTRIM(hnr),3)) hnr_num_von
 , erloes_ant 
 FROM eobjstkr)
SELECT e_mandant, obj_nr, u_obj_nr, ausg, hnr_num_von
, COALESCE((SELECT MIN(hnr_num_von)-1 
  FROM p p2 
  WHERE p2.e_mandant=p.e_mandant AND p2.obj_nr=p.obj_nr AND p2.u_obj_nr=p.u_obj_nr AND p2.ausg=p.ausg 
  AND p2.hnr_num_von>p.hnr_num_von),9999999) hnr_num_bis
, COALESCE(erloes_ant,100) erloes_ant
FROM  p
;
GO
CREATE VIEW dwc_v_anz_eobsteauft AS
WITH p AS
(
SELECT e_mandant, obj_nr, ausg, u_obj_nr
, u_ausg_nr																u_ausg
, CONVERT(int, RTRIM(jahr_ab) + RIGHT('000' + LTRIM(hnr_ab),3))			hnr_num_von
, RTRIM(e_mandant) + '/' + RTRIM(obj_nr)   + '/' + RTRIM(ausg)			objekt
, RTRIM(e_mandant) + '/' + RTRIM(u_obj_nr) + '/' + RTRIM(u_ausg_nr)		unterobjekt
, RTRIM(jahr_ab) + '/'   + RIGHT('00' + LTRIM(hnr_ab),2)				heftnummer
, erloes_ant 
FROM eobsteauft
)
SELECT e_mandant, obj_nr, ausg, u_obj_nr, u_ausg, hnr_num_von
, COALESCE((SELECT MIN(hnr_num_von)-1 
  FROM p p2 
  WHERE p2.e_mandant=p.e_mandant AND p2.obj_nr=p.obj_nr AND p2.ausg=p.ausg AND p2.u_obj_nr=p.u_obj_nr AND p2.u_ausg=p.u_ausg 
  AND p2.hnr_num_von>p.hnr_num_von),9999999) hnr_num_bis
, objekt
, unterobjekt
, heftnummer heftnummer_von
, REPLACE(CONVERT(numeric(7,3),COALESCE((SELECT (MIN(hnr_num_von)-1)
  FROM p p2 
  WHERE p2.e_mandant=p.e_mandant AND p2.obj_nr=p.obj_nr AND p2.ausg=p.ausg AND p2.u_obj_nr=p.u_obj_nr AND p2.u_ausg=p.u_ausg 
  AND p2.hnr_num_von>p.hnr_num_von),9999001)/1000),'.','/') heftnummer_bis
, erloes_ant
FROM p
;
GO
CREATE VIEW dwc_v_anz_eobsteauft_objekt 
( E_MANDANT
, OBJEKT
, UNTEROBJEKT
, HEFTNUMMER_AB
, ERLOES_ANTEIL
)
AS
SELECT e_mandant
, RTRIM(e_mandant) + '/' + RTRIM(obj_nr) + '/'   + RTRIM(ausg)			OBJEKT
, RTRIM(e_mandant) + '/' + RTRIM(u_obj_nr) + '/' + RTRIM(u_ausg_nr)		UNTEROBJEKT
, RTRIM(jahr_ab) + '/'   + RIGHT('00' + LTRIM(hnr_ab),2)				HEFTNUMMER_AB
, erloes_ant
FROM eobsteauft
;

GO
CREATE VIEW dwc_v_anz_kadispo
( obj_nr
, ausg
, jahr
, hnr
, dispo_nr
-------------------------------------------------------------------------------------------------------------
, adr_gr
, adr_nr
, anzart_id
, format_id
, farb_id
, plazierungs_id
, produkt
-------------------------------------------------------------------------------------------------------------
-- DW
, kunde
, konkurrenzobjekt
, heftnummer
, datum
, stichtag
, anzeigenart
, farbe
, platzierung
, anzeigenpreis
, anzschaltung
, volumen)
AS 
-----------------------------------------------------------------------------------------------------------------
SELECT d.obj_nr, d.ausg, d.jahr, d.hnr, d.dispo_nr, d.adr_gr, d.adr_nr
, d.anzart_id, d.format_id, d.farb_id, d.plazierungs_id 
, COALESCE(RTRIM(d.produkt),'---')
-- in kadispo keine Unterscheidung mehr zwischen Kunde und Agentur (2021/11)
, RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)													Kunde
, '[KON]/' + RTRIM(d.obj_nr)  + '/' + RTRIM(d.ausg)											Konkurrenzobjekt
, jahr + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END			Heftnummer
, COALESCE((SELECT CASE WHEN datum_evt IS NULL
               THEN d.jahr + '-01-01'
               ELSE COALESCE(REPLACE(CONVERT(char(10), datum_evt, 111),'/','-'),d.jahr)
               END
            FROM kalendka k
            WHERE d.obj_nr=k.obj_nr AND d.ausg=k.ausg 
            AND d.jahr=k.jahr AND d.hnr=k.hnr),d.jahr + '-01-01')							Datum
, REPLACE(CONVERT(char(10), d.datum_neu, 111),'/','-')										Stichtag
, CASE WHEN format_id IS NULL 
       THEN '[KON]/' + RTRIM(anzart_id) 
       ELSE '[KON]/' + RTRIM(anzart_id) + '/' + RTRIM(format_id) 
       END																					Anzeigenart
, '[KON]/' + RTRIM(farb_id)																	Farbe
, '[KON]/' + COALESCE(RTRIM(plazierungs_id),'---')											Platzierung
, anzeigen_preis																			Anzeigenpreis
, 1																							AnzSchaltung
, volumen																					Volumen
FROM anschr a, kadispo d, kaobstam o
WHERE a.adr_gr=d.adr_gr
AND a.adr_nr=d.adr_nr
AND d.obj_nr=o.obj_nr 
AND d.ausg=o.ausg 
GO
CREATE VIEW dwc_v_anz_kalendea AS
WITH Kalenderdaten AS (
SELECT DISTINCT 
  s.e_mandant
, s.obj_nr
, s.ausg
, jahr
, hnr
, heft_name
-----------------------------------------------------------------------------------------------------------------------------------------
-- DW
, RTRIM(s.e_mandant) + '/' + RTRIM(s.obj_nr)  + '/' + RTRIM(s.ausg)										Objektausgabe
, jahr + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END						Heftnummer
-----------------------------------------------------------------------------------------------------------------------------------------
, CONVERT(CHAR(10), datum_evt, 104)																		EVT
, 'Q' + LTRIM(STR(DATEPART(q,datum_evt),2)) + '/' + CONVERT(CHAR(4), datum_evt, 111)					Erscheinungsquartal
, REPLACE(CONVERT(CHAR(7), datum_evt, 111),'/','-')														Erscheinungsmonat
, CONVERT(CHAR(4), datum_evt, 111) + '/' + REPLACE(STR(DATEPART(ww, datum_evt),2),' ','0')				Erscheinungswoche
, CONVERT(CHAR(4), datum_evt, 111) + '/' + REPLACE(STR(DATEPART(ISO_WEEK, datum_evt),2),' ','0')		Erscheinungs_KW
, REPLACE(CONVERT(CHAR(10), datum_evt, 111),'/','-')													Erscheinungstag
-----------------------------------------------------------------------------------------------------------------------------------------
, CONVERT(CHAR(10), datum_fakt, 104)																	Fakturadatum
, 'Q' + LTRIM(STR(DATEPART(q,datum_fakt),2)) + '/' + CONVERT(CHAR(4), datum_fakt, 111)					Fakturaquartal
, REPLACE(CONVERT(CHAR(7), datum_fakt, 111),'/','-')													Fakturamonat
, CONVERT(CHAR(4), datum_fakt, 111) + '/' + REPLACE(STR(DATEPART(ww, datum_fakt),2),' ','0')			Fakturawoche
, CONVERT(CHAR(4), datum_fakt, 111) + '/' + REPLACE(STR(DATEPART(ISO_WEEK, datum_fakt),2),' ','0')		Faktura_KW
, REPLACE(CONVERT(CHAR(10), datum_fakt, 111),'/','-')													Fakturatag
-----------------------------------------------------------------------------------------------------------------------------------------
, (SELECT MAX(hnr) FROM kalendea k2 WHERE k2.jahr=k.jahr AND k2.e_mandant=k.e_mandant 
                                    AND k2.obj_nr=k.obj_nr AND k2.ausg=k.ausg)							Max_Hnr
-----------------------------------------------------------------------------------------------------------------------------------------
, jahr - 1																								Vorjahr
, jahr - 2																								Vorvorjahr
, jahr + 1																								Folgejahr
, STR(jahr - 1) + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END			Heftnummer_Vorjahr
, STR(jahr - 2) + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END			Heftnummer_Vorvorjahr
, STR(jahr + 1) + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END			Heftnummer_Folgejahr
, jahr + REPLACE(STR(hnr,3),' ','0')																	Hnr_Num
, CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END									HNR2
-----------------------------------------------------------------------------------------------------------------------------------------
, CONVERT(CHAR(10), k.datum_4cse, 104)																	Anzeigenschluss
, CONVERT(CHAR(10), k.datum_du4c, 104)																	DU_Schluss
, REPLACE(CONVERT(CHAR(7), k.datum_4cse, 111),'/','-')													Anzeigenschlussmonat
, REPLACE(CONVERT(CHAR(7), k.datum_du4c, 111),'/','-')													DU_Schluss_Monat
, REPLACE(CONVERT(CHAR(10), k.datum_4cse, 111),'/','-')													Anzeigenschlusstag
, REPLACE(CONVERT(CHAR(10), k.datum_du4c, 111),'/','-')													DU_Schluss_Tag
, heftumfang
, CASE WHEN k.kz_loeschen = 'T'
       THEN 'ja'
       ELSE 'nein'
       END																								Auftragssperre
-----------------------------------------------------------------------------------------------------------------------------------------
FROM  eobjtyp o, eobstamm s, kalendea k
WHERE o.e_mandant = s.e_mandant
AND   s.e_mandant = k.e_mandant
AND   o.obj_nr = s.obj_nr
AND   s.obj_nr = k.obj_nr
AND   s.ausg = k.ausg
AND   (istatwcode != 'SPERR' OR istatwcode IS NULL)
)
SELECT 
  Objektausgabe
, Heftnummer
, heft_name
, EVT
, Erscheinungsquartal
, Erscheinungsmonat
, Erscheinungswoche
, Erscheinungs_KW
, Erscheinungstag
, Fakturadatum
, Fakturaquartal
, Fakturamonat
, Fakturawoche
, Faktura_KW
, Fakturatag
, Jahr
, HNR
, HNR2
, Hnr_Num
, Folgejahr
, Vorjahr
, Vorvorjahr
, Heftnummer_Folgejahr
, Heftnummer_Vorjahr 
, Heftnummer_Vorvorjahr
, Anzeigenschluss
, DU_Schluss
, Anzeigenschlussmonat
, DU_Schluss_Monat
, Anzeigenschlusstag
, DU_Schluss_Tag
, heftumfang
, Auftragssperre
, CASE WHEN Max_Hnr<10 THEN '0' + LTRIM(STR(Max_Hnr)) ELSE LTRIM(STR(Max_Hnr)) END Max_HNR_Jahr
, jahr + '/' + CASE WHEN Max_Hnr<10 THEN '0' + LTRIM(STR(Max_Hnr)) ELSE LTRIM(STR(Max_Hnr)) END Max_Heftnummer_Jahr
FROM Kalenderdaten
;
GO
CREATE VIEW dwc_v_anz_schaltung_ae
( adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
----------------------------------------------------------------------------------------------------------------------------
-- DW
, auftragskey  -- DW-Dimension: Anzeigenauftrag
, kunde
, agentur
, objektausgabe
, heftnummer
, datum
, anzeigenart
, farbe
, platzierung
, abrechnungsart
, produkt
--, kundenvertreter        -- aktivieren falls verwendet
--, auftragsvertreter_wt1  -- aktivieren falls verwendet
--, auftragsvertreter_wa1  -- aktivieren falls verwendet
, herkunft
--, aktion                 -- aktivieren falls verwendet
----------------------------------------------------------------------------------------------------------------------------
, auftragstyp
, objekttyp
, paketobjekt
, objekt_auftrag
, objekt_dispo
, status
, auft_dispo_nr
--, auft_bez_wt1
--, auft_bez_wa1
, stichtag
, waehrung
----------------------------------------------------------------------------------------------------------------------------
-- Zusatzfelder für Auftragskey-Dimension "Anzeigenauftrag"
, motiv
, schalt_von
, schalt_bis
, schalt_von_monat
, schalt_bis_monat
, laufzeit_tage
, laufzeit_monate
, laufzeit
, rechnungsnummer
----------------------------------------------------------------------------------------------------------------------------
-- kennzahlen
, anzeigenpreis
, nettobetrag
, sonderrabattbetrag
, volumenrabattbetrag
, kombirabattbetrag
, zusatzrabattbetrag
, grundpreisnachlass
, rabattbetrag
, agenturprovisionsbasisbetrag
, agenturprovision
, zuschlagsbetrag
, anzschaltung
, volumen)
AS 
----------------------------------------------------------------------------------------------------------------------------
SELECT p.adr_gr
, p.adr_nr
, p.auft_nr
, p.dispo_nr
, p.dispopos_nr
, RTRIM(p.adr_gr) + '/' + LTRIM(p.adr_nr) + '/' + LTRIM(p.auft_nr) + '/' 
                        + LTRIM(p.dispo_nr) + '/' + LTRIM(p.dispopos_nr)					auftragskey
, RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)													kunde
, CASE WHEN a.adr_nr_wa IS NULL
       THEN '---'
       ELSE RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr_wa) 
       END																					agentur
, RTRIM(p.e_mandant) + '/' + RTRIM(p.obj_nr)  + '/' + RTRIM(p.ausg)							objektausgabe
, jahr + '/' 
       + CASE WHEN hnr < 10 
              THEN '0' + LTRIM(STR(hnr)) 
              ELSE LTRIM(STR(hnr)) 
              END																			heftnummer
, COALESCE((SELECT CASE WHEN datum_evt IS NULL
                   THEN p.jahr + '-01-01'
                   ELSE COALESCE(REPLACE(CONVERT(char(10), datum_evt, 111),'/','-'),p.jahr)
                   END
            FROM kalendea k
            WHERE p.e_mandant=k.e_mandant AND p.obj_nr=k.obj_nr
            AND p.ausg=k.ausg AND p.jahr=k.jahr 
            AND p.hnr=k.hnr),p.jahr + '-01-01')												datum
, CASE WHEN format_id IS NULL 
       THEN RTRIM(anzart_id) 
       ELSE RTRIM(anzart_id) + '/' + RTRIM(format_id) 
       END																					anzeigenart
, COALESCE(RTRIM(farb_id),'---')															farbe
, COALESCE(RTRIM(plazierungs_id),'---')														platzierung
, RTRIM(d.abrech_id)																		abrechnungsart
, COALESCE(RTRIM(produkt),'---')															produkt
/*
-- aktivieren falls verwendet
-- Vertreter (Kunden-Vertreter)
, COALESCE((SELECT MIN(v.vertreter_id) FROM adrverzu v 
   WHERE a.adr_gr=v.adr_gr AND a.adr_nr=v.adr_nr),'---')									Kundenvertreter
, COALESCE((SELECT MIN(v.vertreter_id) FROM advert v 
   WHERE a.adr_gr=v.adr_gr AND a.adr_nr=v.adr_nr 
   AND a.auft_nr=v.auft_nr
   AND v.auft_hist_nr=0
   AND f_typ_nr='WT1'),'---')																Auftragsvertreter_WT1
, COALESCE((SELECT MIN(v.vertreter_id) FROM advert v 
   WHERE a.adr_gr=v.adr_gr AND a.adr_nr=v.adr_nr
   AND a.auft_nr=v.auft_nr
   AND v.auft_hist_nr=0   
   AND f_typ_nr='WA1'),'---')																Auftragsvertreter_WA1
*/
, COALESCE(RTRIM(herkunft_id),'---')														herkunft
/*
-- aktivieren falls verwendet
, COALESCE((SELECT MAX(akt_id) FROM adaktion w 
            WHERE w.adr_gr=d.adr_gr AND w.adr_nr=d.adr_nr 
            AND w.auft_nr=d.auft_nr AND w.auft_hist_nr=d.auft_hist_nr
            AND w.dispo_nr=d.dispo_nr AND w.dispo_hist_nr=d.dispo_hist_nr 
            AND w.obj_nr IS NOT NULL),'---')												aktion
*/
----------------------------------------------------------------------------------------------------------------------------
, CASE a.verwend_typ
       WHEN 'N' THEN 'Normaler Auftrag'
       WHEN 'P' THEN 'Paket-Auftrag'
       WHEN 'K' THEN 'Kleinauftrag'
       WHEN 'G' THEN 'Gelegenheitsanzeige'
       WHEN 'B' THEN 'BQN-Auftrag'
       ELSE '---'
       END																					auftragstyp
, CASE t.objekttyp
       WHEN 'N' THEN 'Normal'
       WHEN 'O' THEN 'Onlineobjekt'
       WHEN 'P' THEN 'Paketobjekt'
       WHEN 'K' THEN 'Kombiobjekt'
       ELSE '---'
       END																					objekttyp
, CASE WHEN a.verwend_typ = 'P' OR t.objekttyp = 'K'
       THEN RTRIM(a.e_mandant) + '/' + RTRIM(a.obj_nr)  
                               + '/' + RTRIM(a.ausg)
       ELSE RTRIM(a.e_mandant) + '/kein Paket'
       END																					Paketobjekt
, RTRIM(a.e_mandant) + '/' + RTRIM(a.obj_nr)  + '/' + RTRIM(a.ausg)							objekt_auftrag
, RTRIM(d.e_mandant) + '/' + RTRIM(d.obj_nr)  + '/' + RTRIM(d.ausg)							objekt_dispo
, CASE d.STATUS
       WHEN 'A' THEN 'offen'
       WHEN 'F' THEN 'fakturiert'
       WHEN 'Z' THEN 'fakturiert'
       WHEN 'E' THEN 'Eigenanzeige'
       WHEN 'R' THEN 'reserviert'
       WHEN 'O' THEN 'angeboten'
       ELSE '---'
       END																					status
, SUBSTRING(LTRIM(a.auft_nr) +'/'+ LTRIM(d.dispo_nr) +'/'+ LTRIM(p.dispopos_nr),1,10)		auft_dispo_nr
/*
-- aktivieren falls verwendet (Auftragsbezirk)
, 'WT/' + COALESCE((SELECT RTRIM(bezirk_id) FROM adbezirk b 
                     WHERE a.adr_gr=b.adr_gr AND a.adr_nr=b.adr_nr
                     AND a.auft_nr=b.auft_nr AND b.auft_hist_nr=0
                     AND f_typ_nr='WT1'),'---')												auft_bez_wt1
, 'WA/' + COALESCE((SELECT RTRIM(bezirk_id) FROM adbezirk b 
                     WHERE a.adr_gr=b.adr_gr AND a.adr_nr=b.adr_nr
                     AND a.auft_nr=b.auft_nr AND b.auft_hist_nr=0
                     AND f_typ_nr='WA1'),'---')												auft_bez_wa1
*/
, REPLACE(CONVERT(char(10), d.datum_neu, 111),'/','-')										stichtag
, waehrung
----------------------------------------------------------------------------------------------------------------------------
-- Zusatzfelder für Auftragskey-Dimension "Anzeigenauftrag"
, p.motiv																					Motiv
, p.schalt_von
, p.schalt_bis
, CONVERT(char(7),CONVERT(date, schalt_von, 111))											Schalt_von_Monat
, CONVERT(char(7),CONVERT(date, schalt_bis, 111))											Schalt_bis_Monat
, CASE WHEN p.schalt_von IS NULL
       THEN NULL
       ELSE CONVERT(int, COALESCE(p.schalt_bis,GETDATE())) - CONVERT(int, p.schalt_von) + 1
       END																					Laufzeit_Tage
, CASE WHEN p.schalt_von IS NULL
       THEN NULL
       ELSE (DATEPART(yyyy,COALESCE(p.schalt_bis,GETDATE())) -
             DATEPART(yyyy,p.schalt_von)) * 12 + 
             DATEPART(mm,COALESCE(p.schalt_bis,GETDATE())) - 
             DATEPART(mm,p.schalt_von) + 1
       END																					Laufzeit_Monate
, CASE WHEN p.schalt_von IS NULL
       THEN NULL
       ELSE CONVERT(char(10),p.schalt_von,104) + '-' + CONVERT(char(10),p.schalt_bis,104)
       END																					Laufzeit
, d.rech_nr																					Rechnungsnummer
----------------------------------------------------------------------------------------------------------------------------
-- in den folgenden Beträgen werden Anzahl Schaltungen herausgerechnet und der Umsatz gemäß DWC_V_ANZ_EOBJSTRUKR verteilt
, ROUND(anzeigen_betrag / anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr AND p.obj_nr=u_obj_nr
                  AND p.ausg=u.ausg AND p.hnr_num>=u.hnr_num_von 
                  AND p.hnr_num<=u.hnr_num_bis),100),2) - COALESCE(mwst_anteil,0)			anzeigenpreis
, ROUND(netto_betrag / anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr AND p.obj_nr=u_obj_nr
                  AND p.ausg=u.ausg AND p.hnr_num>=u.hnr_num_von 
                  AND p.hnr_num<=u.hnr_num_bis),100),2) - COALESCE(mwst_anteil,0)			nettobetrag
-- bei den folgenden Beträgen müsste eigentlich auch MwSt rausgerechnet werden, ist in COVER aber auch nicht...
, ROUND(sondrab_betrag / anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr AND p.obj_nr=u_obj_nr
                  AND p.ausg=u.ausg AND p.hnr_num>=u.hnr_num_von 
                  AND p.hnr_num<=u.hnr_num_bis),100),2)										sonderrabattbetrag
, ROUND(volrab_betrag / anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr AND p.obj_nr=u_obj_nr 
                  AND p.ausg=u.ausg AND p.hnr_num>=u.hnr_num_von 
                  AND p.hnr_num<=u.hnr_num_bis),100),2)										volumenrabattbetrag
, ROUND(kombirab_betrag / anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr AND p.obj_nr=u_obj_nr
                  AND p.ausg=u.ausg AND p.hnr_num>=u.hnr_num_von 
                  AND p.hnr_num<=u.hnr_num_bis),100),2)										kombirabattbetrag
, ROUND((COALESCE((SELECT SUM(k.betrag) FROM dsokost k 
                   WHERE betrag<0 AND d.adr_gr=k.adr_gr AND d.adr_nr=k.adr_nr 
                   AND d.auft_nr=k.auft_nr AND d.dispo_nr=k.dispo_nr AND k.auft_hist_nr=0
                   AND k.dispo_hist_nr=0),0)) / anz_schaltung / 100 * (-1) *
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                   WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr AND p.obj_nr=u_obj_nr
                   AND p.ausg=u.ausg AND p.hnr_num>=u.hnr_num_von 
                   AND p.hnr_num<=u.hnr_num_bis),100),2)									zusatzrabattbetrag
, ROUND((COALESCE(anzeigen_betrag_preis,anzeigen_betrag) - 
                  anzeigen_betrag) / anz_schaltung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                   WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr 
                   AND p.obj_nr=u_obj_nr AND p.ausg=u.ausg 
                   AND p.hnr_num>=u.hnr_num_von AND p.hnr_num<=u.hnr_num_bis),100),2)		grundpreisnachlass
, ROUND((sondrab_betrag + volrab_betrag + kombirab_betrag +
        (COALESCE(anzeigen_betrag_preis,anzeigen_betrag) - anzeigen_betrag) -
         COALESCE((SELECT SUM(k.betrag) FROM dsokost k 
                   WHERE betrag<0 AND d.adr_gr=k.adr_gr AND d.adr_nr=k.adr_nr 
                   AND d.auft_nr=k.auft_nr AND d.dispo_nr=k.dispo_nr
                   AND k.auft_hist_nr=0 and k.dispo_hist_nr=0),0)) / anz_schaltung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                   WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr 
                   AND p.obj_nr=u_obj_nr AND p.ausg=u.ausg 
                   AND p.hnr_num>=u.hnr_num_von AND p.hnr_num<=u.hnr_num_bis),100),2)		rabattbetrag
, ROUND(wa_prov_basis / anz_schaltung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                   WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr 
                   AND p.obj_nr=u_obj_nr AND p.ausg=u.ausg 
                   AND p.hnr_num>=u.hnr_num_von AND p.hnr_num<=u.hnr_num_bis),100),2)		agenturprovisionsbasisbetrag
, ROUND(wa_prov_betrag / anz_schaltung / 100 * 
         COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                   WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr 
                   AND p.obj_nr=u_obj_nr AND p.ausg=u.ausg 
                   AND p.hnr_num>=u.hnr_num_von AND p.hnr_num<=u.hnr_num_bis),100),2)		agenturprovision
, ROUND(COALESCE((SELECT SUM(k.betrag) FROM dsokost k 
                  WHERE betrag>0 AND d.adr_gr=k.adr_gr AND d.adr_nr=k.adr_nr
                  AND d.auft_nr=k.auft_nr AND d.dispo_nr=k.dispo_nr AND k.auft_hist_nr=0 
                  AND k.dispo_hist_nr=0),0) / anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr 
                  AND p.obj_nr=u_obj_nr AND p.ausg=u.ausg 
                  AND p.hnr_num>=u.hnr_num_von AND p.hnr_num<=u.hnr_num_bis),100),2)		zuschlagsbetrag
, 1																							anzschaltung
, COALESCE(volumen_fa + (volumen_mm / 
        COALESCE((SELECT mm_seite FROM eobstamm e 
                  WHERE p.e_mandant=e.e_mandant AND p.obj_nr=e.obj_nr 
                  AND p.ausg=e.ausg),1000)),0) / anz_schaltung								volumen
----------------------------------------------------------------------------------------------------------------------------
FROM auftrag a, dispo d, dispopos p, eobstamm s, eobjtyp t
WHERE a.adr_gr=d.adr_gr AND d.adr_gr=p.adr_gr
  AND a.adr_nr=d.adr_nr AND d.adr_nr=p.adr_nr
  AND a.auft_nr=d.auft_nr AND d.auft_nr=p.auft_nr
  AND d.dispo_nr=p.dispo_nr
  AND a.auft_hist_nr=0 AND d.auft_hist_nr=0 AND p.auft_hist_nr=0
  AND d.dispo_hist_nr=0 AND p.dispo_hist_nr=0
  AND d.e_mandant=s.e_mandant
  AND d.obj_nr=s.obj_nr
  AND d.ausg=s.ausg
  AND p.status not in ('L','S')
  AND p.jahr is not null
  AND s.e_mandant=t.e_mandant
  AND s.obj_nr=t.obj_nr
  AND (t.istatwcode != 'SPERR' OR t.istatwcode IS NULL)
----------------------------------------------------------------------------------------------------------------------------
;
GO
CREATE VIEW dwc_v_anz_schaltung_konkurrenz
( adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
--------------------------------------------------------------------------------------------------------------------------------------------------------
-- DW
, auftragskey  -- DW-Dimension: Anzeigenauftrag
, kunde
, objektausgabe
, heftnummer
, datum
, anzeigenart
, farbe
, platzierung
, abrechnungsart
, produkt
, stichtag
--------------------------------------------------------------------------------------------------------------------------------------------------------
-- Kennzahlen
, anzeigenpreis
, nettobetrag
, anzschaltung
, volumen)
AS 
--------------------------------------------------------------------------------------------------------------------------------------------------------
SELECT p.adr_gr
, p.adr_nr
, p.auft_nr
, p.dispo_nr
, p.dispopos_nr
, RTRIM(p.adr_gr) + '/' + LTRIM(p.adr_nr) + '/' + LTRIM(p.auft_nr) + '/' + LTRIM(p.dispo_nr) + '/' + LTRIM(p.dispopos_nr)				auftragskey
, RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)																								kunde
, RTRIM(p.e_mandant) + '/' + RTRIM(p.obj_nr)  + '/' + RTRIM(p.ausg)																		objektausgabe
, jahr + '/' 
       + CASE WHEN hnr < 10 
              THEN '0' + LTRIM(STR(hnr)) 
              ELSE LTRIM(STR(hnr)) 
              END																														heftnummer
, COALESCE((SELECT CASE WHEN datum_evt IS NULL
                   THEN p.jahr + '-01-01'
                   ELSE COALESCE(REPLACE(CONVERT(char(10), datum_evt, 111),'/','-'),p.jahr)
                   END
            FROM kalendea k
            WHERE p.e_mandant=k.e_mandant AND p.obj_nr=k.obj_nr
            AND p.ausg=k.ausg AND p.jahr=k.jahr 
            AND p.hnr=k.hnr),p.jahr + '-01-01')																							datum
--------------------------------------------------------------------------------------------------------------------------------------------------------
-- EA-Schnittstellen: kassaart, kassform, kassfarb, kassplaz
, CASE WHEN format_id IS NULL 
       THEN CASE WHEN (SELECT 1 FROM kassaart x WHERE d.e_mandant=x.e_mandant AND d.anzart_id=x.kaanza_ssc AND x.anw_ref_nr='EA') = 1
                 THEN '[KON]/' + (SELECT RTRIM(anzart_id) FROM kassaart x WHERE d.e_mandant=x.e_mandant 
                                                                          AND d.anzart_id=x.kaanza_ssc AND x.anw_ref_nr='EA')
                 ELSE '[KON]/' + RTRIM(anzart_id) -- wird unter Standardelement angelegt
                 END
       ELSE CASE WHEN (SELECT 1 FROM kassaart x WHERE d.e_mandant=x.e_mandant AND d.anzart_id=x.kaanza_ssc AND x.anw_ref_nr='EA') = 1
                  AND (SELECT 1 FROM kassform x WHERE d.e_mandant=x.e_mandant AND d.format_id=x.kaform_ssc AND x.anw_ref_nr='EA') = 1
                 THEN '[KON]/' + (SELECT RTRIM(anzart_id) FROM kassaart x WHERE d.e_mandant=x.e_mandant 
                                                                          AND d.anzart_id=x.kaanza_ssc AND x.anw_ref_nr='EA')
                         + '/' + (SELECT RTRIM(format_id) FROM kassform x WHERE d.e_mandant=x.e_mandant 
                                                                          AND d.format_id=x.kaform_ssc AND x.anw_ref_nr='EA')
                 ELSE '[KON]/' + RTRIM(anzart_id) + '/' + RTRIM(format_id) -- wird unter Standardelement angelegt
                 END
       END																																anzeigenart
, CASE WHEN (SELECT 1 FROM kassfarb x WHERE d.e_mandant=x.e_mandant AND d.farb_id=x.kafarb_ssc AND x.anw_ref_nr='EA') = 1
       THEN '[KON]/' + (SELECT RTRIM(farb_id) FROM kassfarb x WHERE d.e_mandant=x.e_mandant 
                                                              AND d.farb_id=x.kafarb_ssc AND x.anw_ref_nr='EA')
       ELSE '[KON]/' + COALESCE(RTRIM(farb_id),'---') -- wird unter Standardelement angelegt
       END																																farbe
, CASE WHEN (SELECT 1 FROM kassplaz x WHERE p.e_mandant=x.e_mandant AND p.plazierungs_id=x.kaplaz_ssc AND x.anw_ref_nr='EA') = 1
       THEN '[KON]/' + (SELECT RTRIM(plazierungs_id) FROM kassplaz x WHERE p.e_mandant=x.e_mandant 
                                                                     AND p.plazierungs_id=x.kaplaz_ssc AND x.anw_ref_nr='EA')
       ELSE '[KON]/' + COALESCE(RTRIM(plazierungs_id),'---') -- wird unter Standardelement angelegt
       END																																platzierung
, RTRIM(d.abrech_id)																													abrechnungsart
, COALESCE(RTRIM(produkt),'---')																										produkt
, REPLACE(CONVERT(char(10), d.datum_neu, 111),'/','-')																					stichtag
--------------------------------------------------------------------------------------------------------------------------------------------------------
-- in den folgenden Beträgen werden Anzahl Schaltungen herausgerechnet und der Umsatz gemäß DWC_V_ANZ_EOBJSTRUKR verteilt
, ROUND(anzeigen_betrag / anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr AND p.obj_nr=u_obj_nr
                  AND p.ausg=u.ausg AND p.hnr_num>=u.hnr_num_von 
                  AND p.hnr_num<=u.hnr_num_bis),100),2) - COALESCE(mwst_anteil,0)														anzeigenpreis
, ROUND(netto_betrag / anz_schaltung / 100 * 
        COALESCE((SELECT erloes_ant FROM dwc_v_anz_eobjstrukr u 
                  WHERE d.e_mandant=u.e_mandant AND d.obj_nr=u.obj_nr AND p.obj_nr=u_obj_nr
                  AND p.ausg=u.ausg AND p.hnr_num>=u.hnr_num_von 
                  AND p.hnr_num<=u.hnr_num_bis),100),2) - COALESCE(mwst_anteil,0)														nettobetrag
, 1																																		anzschaltung
, COALESCE(volumen_fa + (volumen_mm / 
        COALESCE((SELECT mm_seite FROM eobstamm e 
                  WHERE p.e_mandant=e.e_mandant AND p.obj_nr=e.obj_nr 
                  AND p.ausg=e.ausg),1000)),0)																							volumen
--------------------------------------------------------------------------------------------------------------------------------------------------------
FROM auftrag a, dispo d, dispopos p, kassobj k
WHERE a.adr_gr=d.adr_gr AND d.adr_gr=p.adr_gr
  AND a.adr_nr=d.adr_nr AND d.adr_nr=p.adr_nr
  AND a.auft_nr=d.auft_nr AND d.auft_nr=p.auft_nr
  AND d.dispo_nr=p.dispo_nr
  AND a.auft_hist_nr=0 AND d.auft_hist_nr=0 AND p.auft_hist_nr=0
  AND d.dispo_hist_nr=0 AND p.dispo_hist_nr=0
  AND p.status not in ('L','S','R','O')
  AND p.jahr is not null
  AND p.e_mandant=k.e_mandant
  AND p.obj_nr=k.obj_nr         -- nur Objekte, die in der KA-Schnittstelle eingetragen sind
  AND p.ausg=k.ausg
--------------------------------------------------------------------------------------------------------------------------------------------------------
;

GO
CREATE VIEW dwc_v_anz_schaltung_monatssplit
( adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
----------------------------------------------------------------------------------------------------------------------------
-- DW
, auftragskey           -- DW-Dimension: Anzeigenauftrag
, status
, kunde
, agentur
, objektausgabe
, heftnummer
, datum                 -- Originaldatum
, anzeigenart
, farbe
, platzierung
, abrechnungsart
----------------------------------------------------------------------------------------------------------------------------
, stichtag
, waehrung
----------------------------------------------------------------------------------------------------------------------------
-- Zusatzfelder für Auftragskey-Dimension "Anzeigenauftrag"
, motiv
, schalt_von
, schalt_bis
, schalt_von_monat
, schalt_bis_monat
, laufzeit_tage         -- Anzahl Tage innerhalb der Laufzeit
, laufzeit_monate       -- Anzahl der Kalendermonate innerhalb der Laufzeit
, laufzeit              -- Laufzeittext (Info Laufzeit von-bis)
, rechnungsnummer
----------------------------------------------------------------------------------------------------------------------------
-- Kennzahlen aus DWC_V_ANZ_SCHALTUNG_AE
, nettobetrag_auftrag   -- Info Gesamtsumme
----------------------------------------------------------------------------------------------------------------------------
-- Aufteilung
, jahr_monat            -- Buchungsmonat
, kalendertage          -- Kalendertage im Buchungsmonat
, tage_anteil           -- anteilige Anzahl der Tage im Buchungsmonat
, datum_anteil          -- Datum der Verteilung (Startdatum im 1. Monat, 1. in Zwischenmonaten, Enddatum im letzten Monat)
, nettobetrag_anteil    -- anteiliger Betragswert (innerhalb des Buchungsmonats)
)
AS
----------------------------------------------------------------------------------------------------------------------------
-- Pre-Select Monate und Tage
WITH kalview AS (
SELECT jahr
, tage_februar
, monat
, maxtag
FROM dwc_t_crm_jahr, dwc_t_crm_monat
), monview AS (
SELECT TOP 100 PERCENT
  jahr
, monat
, jahr + '-' + REPLACE(STR(monat,2),' ','0') jahr_monat
, CASE WHEN monat = 2
       THEN tage_februar
       ELSE maxtag
       END kalendertage
FROM kalview
WHERE jahr > 2010
ORDER BY jahr, monat)
----------------------------------------------------------------------------------------------------------------------------
SELECT 
  adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
, auftragskey
, status
, kunde
, agentur
, objektausgabe
, heftnummer
, datum
, anzeigenart
, farbe
, platzierung
, abrechnungsart
, stichtag
, waehrung
, motiv
, schalt_von
, schalt_bis
, schalt_von_monat
, schalt_bis_monat
, laufzeit_tage
, laufzeit_monate
, laufzeit
, rechnungsnummer
----------------------------------------------------------------------------------------------------------------------------
-- Kennzahlen aus dwc_v_ANZ_SCHALTUNG_AE
, nettobetrag																	nettobetrag_auftrag
----------------------------------------------------------------------------------------------------------------------------
-- Aufteilung
, jahr_monat
, kalendertage
, CASE WHEN laufzeit_monate = 1
       THEN laufzeit_tage
       ELSE CASE WHEN m.jahr_monat = schalt_von_monat
                 THEN kalendertage - SUBSTRING(CONVERT(char(10), schalt_von, 104),1,2) + 1
                 ELSE CASE WHEN m.jahr_monat = schalt_bis_monat
                           THEN SUBSTRING(CONVERT(char(10), schalt_bis, 104),1,2)
                           ELSE kalendertage
                           END
                 END 
       END																		tage_anteil
, CASE WHEN schalt_von_monat = jahr_monat
       THEN REPLACE(CONVERT(char(10), schalt_von, 111),'/','-')
       ELSE CASE WHEN schalt_bis_monat = jahr_monat
                 THEN REPLACE(CONVERT(char(10), schalt_bis, 111),'/','-')
                 ELSE jahr_monat + '-01'
                 END
       END																		datum_anteil
, ROUND((
  CASE WHEN laufzeit_monate = 1
       THEN nettobetrag
       ELSE CASE WHEN m.jahr_monat = schalt_von_monat
                 THEN nettobetrag / laufzeit_tage * (kalendertage - SUBSTRING(CONVERT(char(10), schalt_von, 104),1,2) + 1)
                 ELSE CASE WHEN m.jahr_monat = schalt_bis_monat
                           THEN nettobetrag / laufzeit_tage * SUBSTRING(CONVERT(char(10), schalt_bis, 104),1,2)
                           ELSE nettobetrag / laufzeit_tage * kalendertage
                           END
                 END
       END),2)																	nettobetrag_anteil
FROM dwc_v_anz_schaltung_ae j, monview m
WHERE schalt_von_monat <= m.jahr_monat 
AND   schalt_bis_monat >= m.jahr_monat
-------------------------------------------------------------------------------------------------------------
UNION SELECT 
  adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
, auftragskey
, status
, kunde
, agentur
, objektausgabe
, heftnummer
, datum
, anzeigenart
, farbe
, platzierung
, abrechnungsart
, stichtag
, waehrung
, motiv
, schalt_von
, schalt_bis
, schalt_von_monat
, schalt_bis_monat
, laufzeit_tage
, laufzeit_monate
, laufzeit
, rechnungsnummer
----------------------------------------------------------------------------------------------------------------------------
-- Kennzahlen aus dwc_v_ANZ_SCHALTUNG_AE
, nettobetrag																	nettobetrag_auftrag
----------------------------------------------------------------------------------------------------------------------------
-- hier keine Aufteilung
, SUBSTRING(datum,1,7)															jahr_monat
, 0																				kalendertage
, 0																				tage_anteil
, datum																			datum_anteil
, nettobetrag																	nettobetrag_anteil
FROM dwc_v_anz_schaltung_ae j
WHERE schalt_von IS NULL OR schalt_bis IS NULL
----------------------------------------------------------------------------------------------------------------------------
;
GO
CREATE VIEW dwc_v_anz_sorech
( lfd_nr
, adr_gr
, adr_nr
----------------------------------------------------------------------------------------------------------------------------------
-- DW
, kunde
, agentur
, objektausgabe
, heftnummer
, datum
, anzeigenart
, platzierung
, abrechnungsart
, status
, stichtag
, waehrung
, anzeigenpreis
, nettobetrag
, agenturprovisionsbasisbetrag
, agenturprovision
, anzschaltung
, volumen)
AS 
----------------------------------------------------------------------------------------------------------------------------------
-- SELECT Teil Kombiobjekte mit Erlösaufteilung
SELECT s.lfd_nr, a.adr_gr, a.adr_nr
, CASE WHEN a.f_typ='WT'
       THEN RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)
       ELSE '---'
       END																							kunde
, CASE WHEN a.f_typ='WT'
       THEN '---'
       ELSE RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)
       END																							agentur
, RTRIM(s.e_mandant) + '/' + RTRIM(u.u_obj_nr)  + '/' + RTRIM(u.ausg)								objektausgabe
, jahr + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END					heftnummer
, COALESCE((SELECT CASE WHEN datum_evt IS NULL
                        THEN s.jahr + '-01-01'
                        ELSE COALESCE(REPLACE(CONVERT(char(10), datum_evt, 111),'/','-'),s.jahr)
                        END
            FROM kalendea k
            WHERE s.e_mandant=k.e_mandant AND u.u_obj_nr=k.obj_nr
            AND u.ausg=k.ausg AND s.jahr=k.jahr 
            AND s.hnr=k.hnr),s.jahr + '-01-01')														datum
, 'Sonderrechnung'																					anzeigenart
, '---'																								platzierung
, CASE WHEN a.f_typ='WT'
       THEN '01'
       ELSE '02'
       END																							abrechnungsart
-- Vertreter
, CASE WHEN s.fakt_datum IS NULL
       THEN 'offen'
       ELSE 'fakturiert'
       END																							status
, REPLACE(CONVERT(char(10), s.datum_neu, 111),'/','-') Stichtag
, waehrung
-- in den folgenden Beträgen wird der Umsatz gemäß DWC_V_ANZ_EOBJSTRUKR verteilt
, ROUND(wt_netto_betrag / 100 * COALESCE(erloes_ant,100),2) * 
        CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END												anzeigenpreis
, ROUND(wa_netto_betrag / 100 * COALESCE(erloes_ant,100),2) * 
        CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END												nettobetrag
, ROUND(wt_netto_betrag / 100 * COALESCE(erloes_ant,100),2) * 
        CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END												agenturprovisionsbasisbetrag
, (ROUND(wt_netto_betrag / 100 * COALESCE(erloes_ant,100),2) -
   ROUND(wa_netto_betrag / 100 * COALESCE(erloes_ant,100),2)) * 
        CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END												agenturprovision
, CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END														anzschaltung
, 0																									volumen
FROM anschr a, sorechn s, eobstamm e, eobjtyp t, sorekat k, dwc_v_anz_eobjstrukr u
WHERE a.adr_gr=s.adr_gr
AND a.adr_nr=s.rech_empf
AND s.e_mandant=u.e_mandant AND s.obj_nr=u.obj_nr AND s.ausg=u.ausg 
AND (s.jahr + '0' + s.hnr)>=u.hnr_num_von AND (s.jahr + '0' + s.hnr)<=u.hnr_num_bis
AND s.e_mandant=e.e_mandant
AND s.obj_nr=e.obj_nr
AND s.ausg=e.ausg
------------------------------------------------
-- Filter auf Sorekat und Abrech
AND s.kategorie=k.kategorie
------------------------------------------------
AND s.jahr is not null
AND e.e_mandant=t.e_mandant
AND e.obj_nr=t.obj_nr
AND (t.istatwcode != 'SPERR' OR t.istatwcode IS NULL)
-- Kombiobjekte
AND t.objekttyp = 'K'
----------------------------------------------------------------------------------------------------------------------------------
-- UNION Teil ohne Kombiobjekte
UNION SELECT s.lfd_nr, a.adr_gr, a.adr_nr
, CASE WHEN a.f_typ='WT'
       THEN RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)
       ELSE '---'
       END																							kunde
, CASE WHEN a.f_typ='WT'
       THEN '---'
       ELSE RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)
       END																							agentur
, RTRIM(s.e_mandant) + '/' + RTRIM(s.obj_nr)  + '/' + RTRIM(s.ausg)									objektausgabe
, jahr + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END					heftnummer
, COALESCE((SELECT CASE WHEN datum_evt IS NULL
                        THEN s.jahr + '-01-01'
                        ELSE COALESCE(REPLACE(CONVERT(char(10), datum_evt, 111),'/','-'),s.jahr)
                        END
            FROM kalendea k
            WHERE s.e_mandant=k.e_mandant AND s.obj_nr=k.obj_nr
            AND s.ausg=k.ausg AND s.jahr=k.jahr 
            AND s.hnr=k.hnr),s.jahr + '-01-01')														datum
, 'Sonderrechnung'																					anzeigenart
, '---' Platzierung
, CASE WHEN a.f_typ='WT'
       THEN '01'
       ELSE '02'
       END																							abrechnungsart
-- Vertreter
, CASE WHEN s.fakt_datum IS NULL
       THEN 'offen'
       ELSE 'fakturiert'
       END																							status
, REPLACE(CONVERT(char(10), s.datum_neu, 111),'/','-')												stichtag
, waehrung
, wt_netto_betrag * CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END									anzeigenpreis   -- geändert 16.10.2018
, wa_netto_betrag * CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END									nettobetrag
, wt_netto_betrag * CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END									agenturprovisionsbasisbetrag
, (wt_netto_betrag - wa_netto_betrag) * CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END				agenturprovision
, CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END														anzschaltung
, 0																									volumen
FROM anschr a, sorechn s, eobstamm e, eobjtyp t, sorekat k
WHERE a.adr_gr=s.adr_gr
AND a.adr_nr=s.rech_empf
AND s.e_mandant=e.e_mandant
AND s.obj_nr=e.obj_nr
AND s.ausg=e.ausg
------------------------------------------------
-- Filter auf Sorekat und Abrech
AND s.kategorie=k.kategorie
------------------------------------------------
AND s.jahr is not null
AND e.e_mandant=t.e_mandant
AND e.obj_nr=t.obj_nr
AND (t.istatwcode != 'SPERR' OR t.istatwcode IS NULL)
-- keine Kombiobjekte
AND t.objekttyp != 'K'
;
GO
CREATE VIEW dwc_v_anz_sorechn
( lfd_nr
, adr_gr
, adr_nr
-------------------------------------------------------------------------------------------------------------
-- originalfelder
, e_mandant
, obj_nr
, ausg
, jahr
, hnr
, rech_art
, kategorie
, kz_wam
, waehrung
, steuer_code
, wa_netto_betrag
, rech_betrag
, rech_nr
, betreff
-------------------------------------------------------------------------------------------------------------
-- DW
, kunde
, agentur
, objektausgabe
, heftnummer
, abrechnungsart
, status
, stichtag
, nettobetrag
, agenturprovisionsbasisbetrag
, agenturprovision
, menge)
AS 
-----------------------------------------------------------------------------------------------------------------
-- SELECT Teil Kombiobjekte mit Erlösaufteilung
SELECT s.lfd_nr, a.adr_gr, a.adr_nr
, s.e_mandant, s.obj_nr, s.ausg
, jahr, hnr
, rech_art
, RTRIM(s.kategorie) Kategorie
, kz_wam, waehrung, steuer_code, wa_netto_betrag, rech_betrag, rech_nr
, RTRIM(betreff)
-------------------------------------------------------------------------------------------------------------
, CASE WHEN a.f_typ='WT'
       THEN RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)
       ELSE '---'
       END Kunde
, CASE WHEN a.f_typ='WT'
       THEN '---'
       ELSE RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)
       END Agentur
, RTRIM(s.e_mandant) + '/' + RTRIM(u.u_obj_nr)  + '/' + RTRIM(u.ausg) Objektausgabe
, jahr + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END Heftnummer
, CASE WHEN a.f_typ='WT'
       THEN '01'
       ELSE '02'
       END Abrechnungsart
-- Vertreter
, CASE WHEN s.fakt_datum IS NULL
       THEN 'offen'
       ELSE 'fakturiert'
       END Status
, REPLACE(CONVERT(char(10), s.datum_neu, 111),'/','-') Stichtag
-- in den folgenden Beträgen wird der Umsatz gemäß DWC_V_ANZ_EOBJSTRUKR verteilt
, ROUND(wa_netto_betrag / 100 * COALESCE(erloes_ant,100),2) * CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END Nettobetrag
, ROUND(wt_netto_betrag / 100 * COALESCE(erloes_ant,100),2) * CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END Agenturprovisionsbasisbetrag
, (ROUND(wt_netto_betrag / 100 * COALESCE(erloes_ant,100),2) -
   ROUND(wa_netto_betrag / 100 * COALESCE(erloes_ant,100),2)) * CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END Agenturprovision
, CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END Menge
FROM anschr a, sorechn s, eobstamm e, eobjtyp t, sorekat k, dwc_v_anz_eobjstrukr u
WHERE a.adr_gr=s.adr_gr
AND a.adr_nr=s.rech_empf
AND s.e_mandant=u.e_mandant AND s.obj_nr=u.obj_nr AND s.ausg=u.ausg 
AND (s.jahr + '0' + s.hnr)>=u.hnr_num_von AND (s.jahr + '0' + s.hnr)<=u.hnr_num_bis
AND s.e_mandant=e.e_mandant
AND s.obj_nr=e.obj_nr
AND s.ausg=e.ausg
------------------------------------------------
-- Filter auf Sorekat und Abrech
AND s.kategorie=k.kategorie
------------------------------------------------
AND s.jahr is not null
AND e.e_mandant=t.e_mandant
AND e.obj_nr=t.obj_nr
AND (t.istatwcode != 'SPERR' OR t.istatwcode IS NULL)
-- Kombiobjekte
AND t.objekttyp = 'K'
-----------------------------------------------------------------------------------------------------------------
-- UNION Teil ohne Kombiobjekte
UNION SELECT s.lfd_nr, a.adr_gr, a.adr_nr
, s.e_mandant, s.obj_nr, s.ausg
, jahr, hnr
, rech_art
, RTRIM(s.kategorie) Kategorie
, kz_wam, waehrung, steuer_code, wa_netto_betrag, rech_betrag, rech_nr
, RTRIM(betreff)
, CASE WHEN a.f_typ='WT'
       THEN RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)
       ELSE '---'
       END Kunde
, CASE WHEN a.f_typ='WT'
       THEN '---'
       ELSE RTRIM(a.adr_gr) + '/' + LTRIM(a.adr_nr)
       END Agentur
, RTRIM(s.e_mandant) + '/' + RTRIM(s.obj_nr)  + '/' + RTRIM(s.ausg) Objektausgabe
, jahr + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END Heftnummer
, CASE WHEN a.f_typ='WT'
       THEN '01'
       ELSE '02'
       END Abrechnungsart
-- Vertreter
, CASE WHEN s.fakt_datum IS NULL
       THEN 'offen'
       ELSE 'fakturiert'
       END Status
, REPLACE(CONVERT(char(10), s.datum_neu, 111),'/','-') Stichtag
, wa_netto_betrag * CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END Nettobetrag
, wt_netto_betrag * CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END Agenturprovisionsbasisbetrag
, (wt_netto_betrag - wa_netto_betrag) * CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END Agenturprovision
, CASE WHEN s.rech_art='SG' THEN -1 ELSE 1 END  Menge
FROM anschr a, sorechn s, eobstamm e, eobjtyp t, sorekat k
WHERE a.adr_gr=s.adr_gr
AND a.adr_nr=s.rech_empf
AND s.e_mandant=e.e_mandant
AND s.obj_nr=e.obj_nr
AND s.ausg=e.ausg
------------------------------------------------
-- Filter auf Sorekat und Abrech
AND s.kategorie=k.kategorie
------------------------------------------------
AND s.jahr is not null
AND e.e_mandant=t.e_mandant
AND e.obj_nr=t.obj_nr
AND (t.istatwcode != 'SPERR' OR t.istatwcode IS NULL)
-- keine Kombiobjekte
AND t.objekttyp != 'K'
;
GO
CREATE VIEW dwc_v_anz_vertbuch_ae
( adr_gr
, adr_nr
, auft_nr
, dispo_nr
, dispopos_nr
-------------------------------------------------------------------------------------------------------------
-- DW
, kunde
, agentur
, objektausgabe
, heftnummer
, datum
, abrechnungsart
, vertreter
, auft_dispo_nr
, vert_netto_betrag
, vert_prov_basis
, vert_prov_betrag)
AS 
-----------------------------------------------------------------------------------------------------------------
-- Selects aus auftrag nur per Unter-Selektion, da vertbuch auch alleine dastehen kann
SELECT adr_gr, adr_nr, auft_nr, dispo_nr, dispopos_nr,
  RTRIM(adr_gr) + '/' + LTRIM(adr_nr)																kunde
, REPLACE(RTRIM(adr_gr) + '/' +
          COALESCE((SELECT LTRIM(STR(adr_nr_wa)) FROM auftrag a
                    WHERE a.adr_gr=v.adr_gr AND a.adr_nr=v.adr_nr 
                    AND a.auft_nr=v.auft_nr AND a.auft_hist_nr=0 
                    AND a.e_mandant=v.e_mandant),'---'),RTRIM(adr_gr) + '/---','---')				agentur -- wenn keine AE dann nur drei Striche
, RTRIM(e_mandant) + '/' + RTRIM(obj_nr)  + '/' + RTRIM(ausg)										objektausgabe
, jahr + '/' + CASE WHEN hnr<10 THEN '0' + LTRIM(STR(hnr)) ELSE LTRIM(STR(hnr)) END					heftnummer
, COALESCE((SELECT CASE WHEN datum_evt IS NULL
                   THEN v.jahr + '-01-01'
                   ELSE COALESCE(REPLACE(CONVERT(char(10), datum_evt, 111),'/','-'),v.jahr)
                   END
            FROM kalendea k
            WHERE v.e_mandant=k.e_mandant AND v.obj_nr=k.obj_nr
            AND v.ausg=k.ausg AND v.jahr=k.jahr 
            AND v.hnr=k.hnr),v.jahr + '-01-01')														datum
, COALESCE((SELECT RTRIM(abrech_id) FROM auftrag a
            WHERE a.adr_gr=v.adr_gr AND a.adr_nr=v.adr_nr AND a.auft_nr=v.auft_nr 
            AND a.auft_hist_nr=0 AND a.e_mandant=v.e_mandant),'01')									abrechnungsart
, RTRIM(vertreter_id)																				vertreter
, SUBSTRING(LTRIM(auft_nr) +'/'+ LTRIM(dispo_nr) +'/'+ LTRIM(dispopos_nr),1,10)						auft_dispo_nr 
, vert_netto_betrag
, vert_prov_basis
, vert_prov_betrag
FROM vertbuch v
WHERE jahr is not null
;
GO
CREATE VIEW dwc_v_anz_zuschl_sk
( zusk_id
, zuschl_id
, soko_id
, beschreibung
, kz_wa_prov
, kz_rabatt
, kz_abs
, ist_rabatt)
AS
SELECT 
  'ZU_' + zuschl_id,zuschl_id,NULL,beschreibung,kz_wa_prov,kz_rabatt,kz_statistik2 kz_abs,kz_zuschl_rab ist_rabatt
  FROM zuschlag
UNION SELECT
  'SK_' + soko_id,NULL,soko_id,beschreibung,kz_wa_prov,kz_rabatt,kz_wam kz_abs,'F' ist_rabatt
  FROM sondkost
;
GO
CREATE VIEW dwc_v_crm_adresse
( adressgruppe
, adresse
----------------------------------------------------------------------------
, land
, hauptname
, name_komplett
, ort
, adresse_komplett
----------------------------------------------------------------------------
, bereich
, generalfilter
, firmentyp
, konzern
, bundesland
, bezirk
, adresstyp)
AS
----------------------------------------------------------------------------------------------------------------------------------
WITH Adressen AS (
SELECT RTRIM(a.adr_gr)										Adressgruppe
, RTRIM(a.adr_gr) + '/' + LTRIM(STR(a.adr_nr))				Adresse
----------------------------------------------------------------------------
, (SELECT land FROM land l where l.land_code=a.land_code)	Land
, RTRIM(haupt_name)											Hauptname
, CASE WHEN name1 IS NULL 
       THEN RTRIM(RTRIM(vorname) + ' ' + RTRIM(nachname))
       ELSE RTRIM(name1) + ' ' + RTRIM(name2) 
	   END													Name_komplett
, CASE land_code
      WHEN 'D' THEN ''
      ELSE RTRIM(land_code) + '-'
      END
      +
      RTRIM(haupt_plz) + ' ' + RTRIM(haupt_ort) 			Ort
----------------------------------------------------------------------------
, verlber_id
, genfilt_id
, f_typ
, konzern_id
, kgs_bl
, bezirk_id
, a_typ
FROM anschr a, person p
WHERE a.adr_gr=p.adr_gr
  AND a.adr_nr=p.adr_nr
  AND person_nr=0
)
-----------------------------------------------------------------------------------------------------------------
SELECT
  Adressgruppe
, Adresse
----------------------------------------------------------------------------
, Land
, Hauptname
, Name_komplett
, Ort
, RTRIM(Name_komplett) + ', ' + RTRIM(Ort) AdresseKomplett
----------------------------------------------------------------------------
, verlber_id
, genfilt_id
, f_typ
, konzern_id
, kgs_bl
, bezirk_id
, a_typ
FROM Adressen
;
GO
CREATE VIEW dwc_v_crm_aktion
  (e_mandant, mandant_bez, mandant_codebez, akt_code, akt_code_bez, akt_code_codebez, akt_id, akt_id_bez, akt_id_codebez
  , uakt_id, aktion, aktions_bez, aktions_codebez, soll_beginn, soll_ende, ist_ende, ist_kosten, soll_kosten, plan_kosten
  , ist_erloes, soll_erloes, plan_erloes, modul, union_part)
AS
(   SELECT h.e_mandant
    , (SELECT RTRIM(m_name) FROM mandant m WHERE m.e_mandant = h.e_mandant)					mandant_bez
    , (SELECT RTRIM(e_mandant) + ' - ' + RTRIM(m_name)
       FROM mandant m WHERE m.e_mandant = h.e_mandant)										mandant_codebez
    , RTRIM(h.e_mandant) + '/' + COALESCE(RTRIM(a.akt_code),'---')							akt_code
    , COALESCE(a.bez,'kein Code')															akt_code_bez
    , CASE WHEN a.akt_code IS NULL
           then 'kein Code'
           ELSE RTRIM(a.akt_code) + ' - ' + RTRIM(a.bez) 
      END																					akt_code_codebez
      -- AKT_ID: der Slash am Ende ist Absicht, zur sicheren Unterscheidung von akt_code
    , RTRIM(h.e_mandant) + '/' + RTRIM(h.akt_id) + '/'										akt_id
    , COALESCE(RTRIM(h.b_aktid),'-')														akt_id_bez
    , RTRIM(h.akt_id) + ' - ' + COALESCE(RTRIM(h.b_aktid),'-')								akt_id_codebez
    , RTRIM(u.uakt_id)																		uakt_id
    , RTRIM(h.e_mandant) + '/' + RTRIM(h.akt_id) + '/' + RTRIM(u.uakt_id)					aktion
    , CASE WHEN u.b_uaktid IS NULL
           then COALESCE(RTRIM(h.b_aktid),'-')
           ELSE COALESCE(RTRIM(h.b_aktid),'-') + ' (' + RTRIM(u.b_uaktid) + ')' 
           END																				aktions_bez
    , CASE WHEN u.b_uaktid IS NULL
           then RTRIM(h.akt_id) + '/' + RTRIM(u.uakt_id)  + ' - ' 
                                + COALESCE(RTRIM(h.b_aktid),'-')
           ELSE RTRIM(h.akt_id) + '/' + RTRIM(u.uakt_id) + ' - ' 
                                + COALESCE(RTRIM(h.b_aktid),'-') 
                                + ' (' + RTRIM(u.b_uaktid) + ')' 
           END																				aktions_codebez
    , h.soll_beg																			soll_beginn
    , h.soll_ende																			soll_ende
    , h.ist_ende																			ist_ende
    -- Kosten und Erlöse nur im Abschnitt "leere Unteraktion"
    , NULL																					ist_kosten
    , NULL																					soll_kosten
    , NULL																					plan_kosten
    , NULL																					ist_erloes
    , NULL																					soll_erloes
    , NULL																					plan_erloes
    , CASE h.modul
           WHEN 'VZ' then 'Abo'
           WHEN 'BU' then 'Buch'
           ELSE 'global'
           END																				modul
    , 1																						union_part
    FROM mhaktion h 
         INNER JOIN muaktion u ON h.e_mandant = u.e_mandant AND h.akt_id = u.akt_id
         LEFT JOIN maktion a ON h.akt_code = a.akt_code
    WHERE u.uakt_id IS NOT NULL
    ---------------------------------------------------------------------------------------------------------------------------------
    -- Abschnitt fuer leere Unteraktion 
    UNION SELECT h.e_mandant
    , (SELECT RTRIM(m_name) FROM mandant m WHERE m.e_mandant = h.e_mandant)					mandant_bez
    , (SELECT RTRIM(e_mandant) + ' - ' + RTRIM(m_name)
       FROM mandant m WHERE m.e_mandant = h.e_mandant)										mandant_codebez
    , RTRIM(h.e_mandant) + '/' + COALESCE(RTRIM(a.akt_code),'---')							akt_code
    , COALESCE(a.bez,'kein Code')															akt_code_bez
    , CASE WHEN a.akt_code IS NULL
           then 'kein Code'
           ELSE RTRIM(a.akt_code) + ' - ' + RTRIM(a.bez) 
           END																				akt_code_codebez
      -- AKT_ID: der Slash am Ende ist Absicht, zur sicheren Unterscheidung von akt_code
    , RTRIM(h.e_mandant) + '/' + RTRIM(h.akt_id) + '/'										akt_id
    , COALESCE(RTRIM(h.b_aktid),'-')														akt_id_bez
    , RTRIM(h.akt_id) + ' - ' + COALESCE(RTRIM(h.b_aktid),'-')								akt_id_codebez
    , '-'																					uakt_id
    , RTRIM(h.e_mandant) + '/' + RTRIM(h.akt_id) + '/-'										aktion
    , COALESCE(RTRIM(h.b_aktid),'-')														aktions_bez
    , RTRIM(h.akt_id)  + ' - ' + COALESCE(RTRIM(h.b_aktid),'-')								aktions_codebez
    , h.soll_beg																			soll_beginn
    , h.soll_ende																			soll_ende
    , h.ist_ende																			ist_ende
    , h.ist_kost																			ist_kosten
    , h.soll_kost																			soll_kosten
    , h.plan_kost																			plan_kosten
    , h.ist_erloes																			ist_erloes
    , h.soll_erloes																			soll_erloes
    , h.plan_erloes																			plan_erloes
    , CASE h.modul
           WHEN 'VZ' then 'Abo'
           WHEN 'BU' then 'Buch'
           ELSE 'global'
           END																				modul
    , 2																						union_part
    FROM mhaktion h LEFT JOIN maktion a ON h.akt_code = a.akt_code
    -- AND (h.soll_ende > getdate()-730 or h.soll_ende IS NULL)                             -- letzte 2 jahre (wird nicht mehr verwendet)
    ---------------------------------------------------------------------------------------------------------------------------------
    -- Abschnitt fuer komplett leere Aktion
    UNION SELECT e_mandant
    , RTRIM(m_name)																			mandant_bez
    , RTRIM(e_mandant) + ' - ' + RTRIM(m_name)												mandant_codebez
    , RTRIM(e_mandant) + '/---'																akt_code
    , 'keine Aktion'																		akt_code_bez
    , 'keine Aktion'																		akt_code_codebez
      -- AKT_ID: der Slash am Ende ist Absicht, zur sicheren Unterscheidung von akt_code
    , RTRIM(e_mandant) + '/[---]/'															akt_id
    , 'keine Aktion'																		akt_id_bez
    , 'keine Aktion'																		akt_id_codebez
    , '-'																					uakt_id
    , RTRIM(e_mandant) + '/[---]'															aktion
    , '-'																					aktions_bez
    , RTRIM(e_mandant) + '/[---] - keine Aktion'											aktions_codebez
    , NULL																					soll_beginn
    , NULL																					soll_ende
    , NULL																					ist_ende
    , NULL																					ist_kosten
    , NULL																					soll_kosten
    , NULL																					plan_kosten
    , NULL																					ist_erloes
    , NULL																					soll_erloes
    , NULL																					plan_erloes
    , 'global'																				modul
    , 3																						union_part
    FROM mandant
    ---------------------------------------------------------------------------------------------------------------------------------
    -- Abschnitt fuer nicht (mehr) existierende Aktion
    UNION SELECT e_mandant
    , RTRIM(m_name)																			mandant_bez
    , RTRIM(e_mandant) + ' - ' + RTRIM(m_name)												mandant_codebez
    , RTRIM(e_mandant) + '/---'																akt_code
    , 'keine Aktion'																		akt_code_bez
    , 'keine Aktion'																		akt_code_codebez
      -- AKT_ID: der Slash am Ende ist Absicht, zur sicheren Unterscheidung von akt_code
    , RTRIM(e_mandant) + '/[ALT]/'															akt_id
    , '[nicht (mehr) existente Aktion]'														akt_id_bez
    , '[nicht (mehr) existente Aktion]'														akt_id_codebez
    , RTRIM(e_mandant) + '/[ALT]'															uakt_id
    , RTRIM(e_mandant) + '/[ALT]'															aktion
    , '[nicht (mehr) existente Aktion]'														aktions_bez
    , RTRIM(e_mandant) + '/[ALT] - [nicht (mehr) existente Aktion]'							aktions_codebez
    , NULL																					soll_beginn
    , NULL																					soll_ende
    , NULL																					ist_ende
    , NULL																					ist_kosten
    , NULL																					soll_kosten
    , NULL																					plan_kosten
    , NULL																					ist_erloes
    , NULL																					soll_erloes
    , NULL																					plan_erloes
    , 'global'																				modul
    , 4																						union_part
    FROM mandant
)
;
GO
CREATE VIEW dwc_v_crm_jobtab AS
SELECT 
  jobnr
, vorjob
, folgejob
, jobtyp
, prio
, hostname
, benutzer_id
, esname
, (SELECT beschreibung FROM eszuordn z WHERE z.esname=jobtab.esname) bezeichnung
, jobstatus
, startzeit
, jobstart
, jobende
-- berechnete Felder verzug (verspäteter Start) und aktuelle_laufzeit (Laufzeit des aktuell laufenden Jobs) in Sekunden
, CASE WHEN jobstart is null
       THEN CASE WHEN CONVERT(float, GETDATE() - startzeit) < 0 
                 THEN 0
                 ELSE CONVERT(float, GETDATE() - startzeit) * 24 * 60 * 60  -- Sekunden
                 END
       ELSE 0
       END verzug
, CASE WHEN jobstart is not null AND jobende IS NULL
       THEN CONVERT(float, GETDATE() - jobstart) * 24 * 60 * 60  -- Sekunden
       ELSE 0
       END aktuelle_laufzeit
FROM jobtab
WHERE startzeit > GETDATE()-1
;
GO
CREATE VIEW dwc_v_crm_kunden
(ADR_GR, ADR_NR) AS
(SELECT adr_gr, adr_nr FROM abostamm
UNION SELECT adr_gr, adr_nr_bv FROM abostamm
UNION SELECT adr_gr, adr_nr_le FROM bustaord
UNION SELECT adr_gr, adr_nr_re FROM bustaord
UNION SELECT adr_gr, adr_nr_le FROM buauftra
UNION SELECT adr_gr, adr_nr_re FROM buauftra
UNION SELECT adr_gr, adr_nr FROM auftrag
UNION SELECT adr_gr, rech_empf FROM sorechn)
;
GO
CREATE VIEW dwc_v_crm_monate
( jahr
, monat
, anz_tage
, jahr_monat
, monatserster
, monatsletzter
, monatserster_datum
, monatsletzter_datum
)
AS
--------------------------------------------------------------------------------------------------------------------------------
SELECT jahr
, monat
, CASE WHEN monat = 2
       THEN tage_februar
       ELSE maxtag
       END											anz_tage
, jahr + '-' + mtext								jahr_monat
, jahr + '-' + mtext + '-01'						monatserster
, jahr + '-' + mtext 
       + '-' + LTRIM(STR(
       CASE WHEN monat = 2
            THEN tage_februar
            ELSE maxtag
            END ))									monatsletzter
, '01.' + mtext + '.' + jahr						monatserster_datum
, LTRIM(STR(CASE WHEN monat = 2
               THEN tage_februar
               ELSE maxtag
               END)) + '.' + mtext
                     + '.' + jahr					monatsletzter_datum
FROM dwc_t_crm_monat m, dwc_t_crm_jahr j
WHERE jahr>LTRIM(STR(datepart(yyyy,dateadd(month, -60, getdate()))))
;
GO
CREATE VIEW dwc_v_crm_produkt
( wb_id
, hgrp_id
, ugrp_id
, branche
, hauptgruppe
, untergruppe
, produkt
, branchenbezeichnung
, branchencodebezeichnung
, hauptgruppenbezeichnung
, hauptgruppencodebezeichnung
, untergruppenbezeichnung
, untergruppencodebezeichnung
, produktbezeichnung
, produktcodebezeichnung
, branchenverwendung
, untergruppentyp)
AS
(SELECT w.wb_id
, h.hgrp_id
, u.ugrp_id
, '[BR:' + RTRIM(w.wb_id) + ']'												Branche
, RTRIM(w.wb_id) + '/' + RTRIM(h.hgrp_id)									Hauptgruppe
, RTRIM(w.wb_id) + '/' + RTRIM(h.hgrp_id) + '/' + RTRIM(u.ugrp_id)			Untergruppe
, RTRIM(p.produkt)															Produkt
, RTRIM(w.bez)																Branchenbezeichnung
, RTRIM(w.wb_id) + ' - ' + RTRIM(w.bez)										BranchenCodeBezeichnung
, RTRIM(h.bez)																Hauptgruppenbezeichnung
, RTRIM(h.hgrp_id) + ' - ' + RTRIM(h.bez)									HauptgruppenCodebezeichnung
, RTRIM(u.bez)																Untergruppenbezeichnung
, RTRIM(u.ugrp_id) + ' - ' + RTRIM(u.bez)									UntergruppenCodebezeichnung
, RTRIM(p.bez)																Produktbezeichnung
, RTRIM(p.produkt) + ' - ' + RTRIM(p.bez)									ProduktCodeBezeichnung
, CASE WHEN w.verwend_typ='WEB' 
       THEN 'Webshop'
       ELSE 'Cover'
  END																		Branchenverwendung
, CASE WHEN u.verwend_typ='E' 
       THEN 'eindeutig'
       ELSE 'mehrfach'
  END																		Untergruppentyp
FROM  wbereich w, hauptgrp h, ugruppe u, produkt p
WHERE p.wb_id=u.wb_id AND p.hgrp_id=u.hgrp_id AND p.ugrp_id=u.ugrp_id
AND   u.wb_id=h.wb_id AND u.hgrp_id=h.hgrp_id
AND   h.wb_id=w.wb_id
)
;
GO
CREATE VIEW dwc_v_crm_steuersatz AS
WITH p AS
(
SELECT m.land_code, m.steuer_code, bezeichnung, datum_ab, steuersatz 
       FROM  steuer m, stsatz s
       WHERE m.steuer_code=s.steuer_code
       AND   m.land_code=s.land_code
)
SELECT land_code, steuer_code, bezeichnung, datum_ab
,  COALESCE((SELECT MIN(datum_ab)-1 
   FROM p p2 
   WHERE p2.land_code=p.land_code AND p2.steuer_code=p.steuer_code  
   AND p2.datum_ab>p.datum_ab),'31.12.2999') datum_bis
, steuersatz
, (steuersatz + 100) /100 multi
FROM  p
;
GO
CREATE VIEW dwc_v_crm_verlber
( verlber_id
, verlber_bez
, verlber_codebez
, bezeichnung
, vb_sort)
AS
SELECT 
  verlber_id
, beschreibung
, RTRIM(verlber_id) + ' - ' + RTRIM(beschreibung)
, CASE verlber_id
          WHEN 'VER' THEN 'Verlage'
          WHEN 'VEH' THEN 'Hotels'
          ELSE 'Sonstige'
          END 
, CASE verlber_id
          WHEN 'VER' THEN '1'
          WHEN 'VEH' THEN '2'
          ELSE '3'
          END 
FROM verlber
UNION SELECT 
  '---'
, 'ohne Branchenzuordnung'
, '--- (ohne Branchenzuordnung)'
, 'Sonstige'
, '3'
FROM af
;
GO
CREATE VIEW dwc_v_crm_waehkurs AS
WITH p AS
(
SELECT waehrung, ziel_waehr, stichtag, kurs
       FROM  waehkurs
)
SELECT waehrung, ziel_waehr, kurs
,  stichtag datum_von
,  COALESCE((SELECT MIN(stichtag)-1 
   FROM p p2 
   WHERE p2.waehrung=p.waehrung AND p2.ziel_waehr=p.ziel_waehr  
   AND p2.stichtag>p.stichtag),'31.12.2999') datum_bis
FROM  p
;
GO
CREATE VIEW dwc_v_wws_artikel AS
WITH Artikel AS (
-- Pre-Select
    SELECT
      t.l_titel_nr
    , a.l_ausg_nr
    , l.l_aufl_nr
    , RTRIM(m.e_mandant)														e_mandant
    , RTRIM(m.artikel_nr)														artikel_nr
    , RTRIM(l.auflage_nr)														auflage_nr
---------------------------------------------------------------------------------------------------------------------
    , RTRIM(SUBSTRING(t.titel_such,1,50))										titel_such
    , RTRIM(SUBSTRING(t.titel1,1,50))											titel1
    , RTRIM(a.ausg_text)														ausg_text
    , RTRIM(SUBSTRING(l.aufl_text,1,50))										aufl_text
    , a.isbn
    , a.ean
    , a.prod_typ
    , a.grup_id
    , a.kombityp
    , a.reihen_code
    , a.verlags_id
    , a.sperr_grund
    , a.kz_bod																	pod
    , a.kz_export
    , a.bundle
    , a.doi
    , a.link
    , m.brut_net
    , m.kz_fortsetz
    , m.rab_grp
    , m.steuer_code
    , m.kz_loeschen
    , l.status
    , CONVERT(date, l.aufl_dat_soll)											evt_soll
    , CONVERT(date, l.aufl_dat_ist)												erscheinungstermin
    , l.gewicht
    , l.meld_nr																	meldenummer
    , p.istatwcode
    , p.kz_elektron
    , p.ean_laenge
-----------------------------------------------------------------------------------------------------------------------------------------
    , RTRIM(b.m_name)															mandantenbezeichnung
    , RTRIM(m.e_mandant) + '/' + REPLACE(RTRIM(m.artikel_nr),' ','_')			artikel
    , RTRIM(m.e_mandant) + '/' + REPLACE(RTRIM(m.artikel_nr),' ','_') 
                         + '/' + COALESCE(RTRIM(l.auflage_nr),'0')				artikelauflage
    , CASE WHEN a.l_titel_nr=0
           THEN RTRIM(a.ausg_text)
           ELSE RTRIM(SUBSTRING(t.titel1,1,50))
           END 																	artikelbezeichnung
    , CASE WHEN a.ausg_text IS NULL
               THEN CASE WHEN l.auflage_nr ='0'
                         THEN '(Standardauflage)'
                         ELSE RTRIM(aufl_text) 
                         END
               ELSE RTRIM(a.ausg_text) + ' (' + RTRIM(aufl_text) + ')'
               END																auflagenbezeichnung
    , CASE p.ean_laenge
           WHEN 0 THEN 'Buch/Veranstaltung'
           WHEN 1 THEN 'Buch'
           WHEN 2 THEN 'Veranstaltung'
           END 																	produkttypherkunft
    , CASE a.herkunft
           WHEN 'VA' THEN 'Veranstaltung'
           ELSE 'Buch'
           END 																	modul
    , '[TYP:' + COALESCE(RTRIM(a.prod_typ),'---') + ']'							produkttypknoten
    , RTRIM(p.bez)																produkttypbezeichnung
    , '[GR:' + COALESCE(RTRIM(a.grup_id),'---') + ']'							artikelgruppenknoten
    , COALESCE((SELECT RTRIM(bez) FROM buartgru g 
                WHERE g.grup_id = a.grup_id),'---')								artikelgruppenbezeichnung
    , COALESCE((SELECT MIN(sach_grp) FROM bugruppe g 
                WHERE a.l_titel_nr=g.l_titel_nr),'---')							sach_grp
-----------------------------------------------------------------------------------------------------------------------------------------
    -- Tabellen, Filter und Referenzierungen -------------------
    FROM buausgab a
         LEFT JOIN butitel t  ON a.l_titel_nr = t.l_titel_nr
         LEFT JOIN bumanaus m ON a.l_ausg_nr  = m.l_ausg_nr
         LEFT JOIN bmandant b ON m.e_mandant  = b.e_mandant
         LEFT JOIN buaufl l   ON a.l_ausg_nr  = l.l_ausg_nr
         LEFT JOIN buprotyp p ON a.prod_typ   = p.prod_typ
-----------------------------------------------------------------------------------------------------------------------------------------
)
-- Ausgabe
SELECT 
  l_titel_nr
, l_ausg_nr
, l_aufl_nr
, e_mandant
, artikel_nr
, auflage_nr
---------------------------------------------------------------------------------------------------------------------
, titel_such, titel1, ausg_text, aufl_text
, isbn, ean
, prod_typ, grup_id, kombityp, reihen_code
, verlags_id, sperr_grund
, pod, kz_export, bundle
, doi, link
, brut_net, kz_fortsetz, rab_grp, steuer_code, kz_loeschen
, status, evt_soll
, erscheinungstermin, gewicht, meldenummer
, istatwcode, kz_elektron, ean_laenge
---------------------------------------------------------------------------------------------------------------------
, (SELECT ds_preis FROM bulawert w 
   WHERE a.e_mandant=w.e_mandant 
   AND a.l_ausg_nr=w.l_ausg_nr 
   AND a.l_aufl_nr=w.l_aufl_nr AND w.best_art='1')								ds_preis
, (SELECT SUM(aufl_hoehe_ist) FROM buaufdru d 
   WHERE a.l_ausg_nr=d.l_ausg_nr 
   AND a.l_aufl_nr=d.l_aufl_nr)													auflagenhoehe
--   GROUP BY a.l_ausg_nr,a.l_aufl_nr)											auflagenhoehe
---------------------------------------------------------------------------------------------------------------------
, mandantenbezeichnung
, e_mandant + ' - ' + mandantenbezeichnung										mandantencodebezeichnung
, artikel
, artikelauflage
, artikelbezeichnung
, artikel_nr + ' - ' + artikelbezeichnung										artikelcodebezeichnung
, auflagenbezeichnung
, auflage_nr + ' - ' + auflagenbezeichnung										auflagencodebezeichnung
, CASE WHEN l_titel_nr=0
       THEN auflagenbezeichnung
       ELSE titel1 + ' - ' + auflagenbezeichnung
       END																		artikelauflagenbezeichnung
, CASE WHEN l_titel_nr=0
       THEN artikel_nr + '/' + auflage_nr + ' - ' + auflagenbezeichnung
       ELSE artikel_nr + '/' + auflage_nr 
            + ' - ' + titel1 + ' - ' + auflagenbezeichnung
       END																		artikelauflagencodebezeichnung
, produkttypherkunft
, modul
, produkttypknoten
, produkttypbezeichnung
, rtrim(prod_typ) + ' - ' + produkttypbezeichnung								produkttypcodebezeichnung
, artikelgruppenknoten
, artikelgruppenbezeichnung
, CASE WHEN grup_id IS NULL
       THEN '--- (keine Artikelgruppe)'
       ELSE RTRIM(grup_id) + ' - ' + artikelgruppenbezeichnung
       END																		artikelgruppencodebezeichnung
, '[SG:' + RTRIM(sach_grp) + ']'												sachgruppenknoten
, RTRIM(sach_grp)																sachgruppe
, COALESCE((SELECT RTRIM(bez) FROM sachgrup s 
            WHERE s.sach_grp=a.sach_grp),'keine Sachgruppe')					sachgruppenbezeichnung
FROM artikel a
WHERE artikelauflage NOT LIKE '//%'
--  AND kz_loeschen != 'T'  -- optional
;
GO
CREATE VIEW dwc_v_wws_artikelpreise
   ( e_mandant, l_ausg_nr, l_aufl_nr, artikel_nr, Artikel, Artikelauflage, list_nr, preiskat, waehrung, gueltig_ab
   , akt_id, m_preis_grp, subs_dat1, subs_dat2, anzahl, menge, preis )
AS
(SELECT 
  l.e_mandant
, l.l_ausg_nr
, l.l_aufl_nr
, artikel_nr
, RTRIM(m.e_mandant) + '/' + REPLACE(RTRIM(m.artikel_nr),' ','_')			Artikel
, RTRIM(m.e_mandant) + '/' + REPLACE(RTRIM(m.artikel_nr),' ','_') + '/0'	Artikelauflage
, l.list_nr
, preiskat
, waehrung
, gueltig_ab
, akt_id
, m_preis_grp
, subs_dat1
, subs_dat2
, anzahl
, menge
, preis
FROM buplist l, bumpreis p, bumanaus m
WHERE l.list_nr=p.list_nr
AND   m.e_mandant=l.e_mandant
AND   m.l_ausg_nr=l.l_ausg_nr
AND   l.l_aufl_nr=0
UNION SELECT 
  l.e_mandant
, l.l_ausg_nr
, l.l_aufl_nr
, artikel_nr
, RTRIM(m.e_mandant) + '/' + REPLACE(RTRIM(m.artikel_nr),' ','_')			Artikel
, RTRIM(m.e_mandant) + '/' + REPLACE(RTRIM(m.artikel_nr),' ','_') 
                     + '/' + COALESCE(RTRIM(a.auflage_nr),'0')				Artikelauflage
, l.list_nr
, preiskat
, l.waehrung
, gueltig_ab
, akt_id
, m_preis_grp
, subs_dat1
, subs_dat2
, anzahl
, menge
, preis
FROM buplist l, bumpreis p, bumanaus m, buaufl a
WHERE l.list_nr = p.list_nr
AND   m.e_mandant = l.e_mandant
AND   m.l_ausg_nr = l.l_ausg_nr
AND   l.l_aufl_nr <> 0
AND   l.l_ausg_nr = a.l_ausg_nr
AND   l.l_aufl_nr = a.l_aufl_nr )
;
GO
CREATE VIEW dwc_v_wws_auftrag_kopf
( e_mandant
, auft_nr
, posz
----------------------------------------------------------------------------------
, adr_gr
, adr_nr_best
, person_nr_best
, adr_nr_lief
, person_nr_lief
, adr_nr_rech
, person_nr_rech
----------------------------------------------------------------------------------
, auftrag_typ
, staord_nr
, vers_soll_dat
, fakt_soll_dat
, fakt_ist_dat
, l_vers_dat
, datum_neu
, datum_aend
, best_datum
, best_weg
, vers_weg
, versart
, prioritaet
, status
, bu_ra
, rab_proz
, waehrung
, betrag_br
, betrag_ne
, vertreter_id
-------------------------------------------------------------------------------------------------------------
-- DW und berechnete Felder
, lieferadresse
, rechnungsadresse
, besteller
, aktion
, bestelldatum
, bestellweg
, modul
, anzahl_positionen
)
AS 
SELECT e_mandant
, auft_nr
, posz
, adr_gr
, adr_nr_best
, person_nr_best
, adr_nr_le
, person_nr_le
, adr_nr_re
, person_nr_re
, auftrag_typ
, staord_nr
, vers_soll_dat
, fakt_soll_dat
, fakt_ist_dat
, l_vers_dat
, datum_neu
, datum_aend
, best_datum
, best_weg
, vers_weg
, versart
, prioritaet
, status
, bu_ra
, rab_proz
, waehrung
, betrag_br
, betrag_ne
, vertreter_id
----------------------------------------------------------------------------------------------------------
-- DW
, RTRIM(adr_gr) + '/' + LTRIM(STR(adr_nr_le))								lieferadresse
, RTRIM(adr_gr) + '/' + LTRIM(STR(adr_nr_re))								rechnungsadresse
, RTRIM(adr_gr) + '/' + LTRIM(STR(adr_nr_best))								besteller
, RTRIM(b.e_mandant) + '/' + RTRIM(COALESCE(b.akt_id,'-')) 
                     + '/' + RTRIM(COALESCE(LTRIM(STR(b.uakt_id)),'-'))		aktion
, REPLACE(CONVERT(char(10), best_datum, 111),'/','-')						bestelldatum
, RTRIM(best_weg)															bestellweg
, CASE herkunft WHEN 'VA' THEN 'Veranstaltungen'
                ELSE 'Buch' 
                END 														modul
, (SELECT COUNT(*) FROM buaufpos p WHERE p.auft_nr=b.auft_nr)				anzahl_positionen
FROM buauftra b
WHERE b.storno = 'F'
;
GO
CREATE VIEW dwc_v_wws_auftrag_position
( e_mandant
, auft_nr
, auf_pos
, l_ausg_nr
, l_aufl_nr
, best_art
, vers_ist_dat
, fakt_ist_dat
, datum_neu
, datum_aend
, status
, bu_ra
, rab_proz
, brut_net
, steuer_code
, ber_menge
, frei_menge
, gelief_menge
, fakt_menge
, vormerk_menge
, reserviert_menge
, vergriff_menge
, gut_menge
, retour_menge
, preiskat
, list_nr
, einzel_preis
, ges_preis
, pos_betrag
, obj_nr
, ausg
, abo_nr
, adr_nr_abo
, liefer_menge_abo
, preiskat_abo
, lager_mandant
, lager_code
, regal_id
, ebene_id
, platz_id
, kz_praemie
, kz_geliefert
, kz_partie
, kz_vormerker
, kz_liefersperre
, vertreter_id
-------------------------------------------------------------------------------------------------------------
-- DW und berechnete Felder
, artikelauflage
, bestellprodukttyp
, aktion
)
AS 
SELECT p.e_mandant
, p.auft_nr
, p.auf_pos
, p.l_ausg_nr
, p.l_aufl_nr
, p.best_art
, p.vers_ist_dat
, p.fakt_ist_dat
, p.datum_neu
, p.datum_aend
, p.status
, p.bu_ra
, p.rab_proz
, p.brut_net
, p.steuer_code
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.ber_menge * (-1)
                                  ELSE p.ber_menge
                                  END
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.frei_menge * (-1)
                                  ELSE p.frei_menge
                                  END
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.gelief_menge * (-1)
                                  ELSE p.gelief_menge
                                  END
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.fakt_menge * (-1)
                                  ELSE p.fakt_menge
                                  END
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.vormerk_menge * (-1)
                                  ELSE p.vormerk_menge
                                  END
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.reserviert_menge * (-1)
                                  ELSE p.reserviert_menge
                                  END
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.vergriff_menge * (-1)
                                  ELSE p.vergriff_menge
                                  END
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.gut_menge * (-1)
                                  ELSE p.gut_menge
                                  END
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.retour_menge * (-1)
                                  ELSE p.retour_menge
                                  END
, p.preiskat
, p.list_nr
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.einzel_preis * (-1)
                                  ELSE p.einzel_preis
                                  END
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.ges_preis * (-1)
                                  ELSE p.ges_preis
                                  END
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.pos_betrag * (-1)
                                  ELSE p.pos_betrag
                                  END
, p.obj_nr
, p.ausg
, p.abo_nr
, p.adr_nr_abo
, CASE SUBSTRING(auftrag_typ,1,1) WHEN 'G' 
                                  THEN p.liefer_menge_abo * (-1)
                                  ELSE p.liefer_menge_abo
                                  END
, p.preiskat_abo
, p.lager_mandant
, p.lager_code
, p.regal_id
, p.ebene_id
, p.platz_id
, p.kz_praemie
, p.kz_geliefert
, p.kz_partie
, p.kz_vormerker
, p.kz_liefersperre
, p.vertreter_id
----------------------------------------------------------------------------------------------------------
-- DW
, j.artikelauflage
, CASE WHEN j.kz_elektron = 'T'
       THEN 'digital'
       ELSE 'physisch'
       END																	bestellprodukttyp
, RTRIM(p.e_mandant) + '/' + RTRIM(COALESCE(p.akt_id,'-')) 
                     + '/' + RTRIM(COALESCE(LTRIM(STR(p.uakt_id)),'-'))		aktion
----------------------------------------------------------------------------------------------------------
FROM buauftra a, buaufpos p
LEFT JOIN dwc_v_wws_artikel j 
       ON p.l_ausg_nr=j.l_ausg_nr 
      AND p.e_mandant=j.e_mandant AND j.l_aufl_nr=0
WHERE a.auft_nr = p.auft_nr
AND a.storno = 'F'
AND p.storno = 'F'
;
GO
CREATE VIEW dwc_v_wws_faktura
( rech_dat
, rech_nr
, pos_nr
, upos_nr
, f_mandant
------------------------------------------------------------------------------------------------
, rech_typ
, r_art
, rech_ref
, auftrag_verw
------------------------------------------------------------------------------------------------
-- wird später aus auftrag_verw berechnet 
, rech_verw
------------------------------------------------------------------------------------------------
-- weitere Originalfelder
, adr_gr
, adr_nr_rech
, person_nr_rech
, adr_nr_lief
, person_nr_lief
, adr_nr_best
, person_nr_best
, auft_nr
, auf_pos
, waehrung
, preiskat
, shop_id
, staord_nr
, artikel_nr
, titel1
, kz_praemie
, kombityp
, steuer_code
------------------------------------------------------------------------------------------------
-- berechnete und formatierte Felder
, best_dat_text
, rech_dat_text
, lieferadresse
, rechnungsadresse
, rechnungsadresse_top
, l_ausg_nr
, artikelauflage
, rechnungstyp
, aktion
, lager
, vertreter
, quelle
, modul
------------------------------------------------------------------------------------------------
-- Abo-Felder
, adr_nr_abo
, person_nr_abo
, objekt
, abo_nr
----------------------------------------------------------------------------------
-- weitere UPOS-Wertfelder
, raproz
, upos_rab
, upos_netto
, upos_brutto
, mw_proz
, gewicht
------------------------------------------------------------------------------------------------
-- mengen
, berechnete_menge
, frei_menge
, liefer_menge
, vormerk_menge
, vergriffen_menge
, nettobetrag
, bruttobetrag
, ges_zuschlag_rech
, ges_rabatt_betrag_rech
, upos_rabatt_betrag_netto )
AS
------------------------------------------------------------------------------------------------
(
SELECT
-- PK
  s.rech_dat
, s.rech_nr
, p.pos_nr
, u.upos_nr
, s.f_mandant
------------------------------------------------------------------------------------------------
, s.rech_typ
, s.r_art
, s.rech_ref
, COALESCE(p.auftrag_verw,0)
, NULL
------------------------------------------------------------------------------------------------
-- weitere Originalfelder
, s.adr_gr																	adr_gr
, s.adr_nr_e																adr_nr_rech
, s.person_nr_e																person_nr_rech
, p.adr_nr_a																adr_nr_lief
, p.person_nr_a																person_nr_lief
, p.adr_nr_b																adr_nr_best
, p.person_nr_b																person_nr_best
, u.auft_nr																	auft_nr
, u.auf_pos																	auf_pos
, RTRIM(s.waehrung)															waehrung
, RTRIM(u.preiskat)															preiskat
, RTRIM(u.shop_id)															shop_id
, p.staord_nr																staord_nr
, u.artikel_nr																artikel_nr
, u.titel1																	titel1
, u.kz_praemie																kz_praemie
, u.kombityp																kombityp
, u.steuer_code																steuer_code
------------------------------------------------------------------------------------------------
-- berechnete und formatierte Felder
, CONVERT(date, p.best_datum)												best_dat_text
, CONVERT(date, s.rech_dat)													rech_dat_text
, RTRIM(p.adr_gr_a) + '/---'												lieferadresse
, RTRIM(s.adr_gr) + '/' + LTRIM(STR(s.adr_nr_e))							rechnungsadresse      -- muss wegen späterer Updates so bleiben
, RTRIM(s.adr_gr) + '/---' 													rechnungsadresse_top
, u.l_ausg_nr																l_ausg_nr
, CASE WHEN u.artikel_nr IS NULL
       THEN '---'
       ELSE RTRIM(u.e_mandant) + '/' + 
            REPLACE(RTRIM(u.artikel_nr),' ','_') + '/' +
            COALESCE(RTRIM(u.auflage_nr),'0')
       END																	artikelauflage
, CASE SUBSTRING(rech_typ,1,1) WHEN 'G' 
                               THEN 'Gutschrift' 
                               ELSE 'Rechnung' 
                               END											rechnungstyp
, RTRIM(u.e_mandant) + '/' + COALESCE(RTRIM(p.akt_id),'-') 
                     + '/' + COALESCE(RTRIM(p.uakt_id),'-') 				aktion
, COALESCE(RTRIM(u.lager_code),'HLA')										lager
, CASE WHEN u.vertreter_id_upos IS NULL 
       THEN s.vertreter_id 
       ELSE u.vertreter_id_upos 
       END																	vertreter
, CASE WHEN p.staord_nr IS NULL 
       THEN 'Auftrag' 
       ELSE 'Standing Order' 
       END 																	quelle
, CASE p.herkunft WHEN 'VA' THEN 'Veranstaltungen'
                  ELSE 'Buch' 
                  END 														modul
------------------------------------------------------------------------------------------------
-- Abo-Felder
, u.adr_nr_abo
, u.person_nr_abo
, RTRIM(u.e_mandant) + '/' + RTRIM(u.obj_nr) + '/' + RTRIM(u.ausg)			objekt
, u.abo_nr																	abo_nr
----------------------------------------------------------------------------------
-- weitere UPOS-Wertfelder
, u.raproz
, u.upos_rab
, u.upos_netto
, u.upos_brutto
, u.mw_proz
, u.gewicht
------------------------------------------------------------------------------------------------
-- Mengen
, CASE SUBSTRING(rech_typ,1,1) WHEN 'G' 
                               THEN ABS(u.ber_menge) * (-1)
                               ELSE u.ber_menge
                               END											berechnete_menge
, CASE SUBSTRING(rech_typ,1,1) WHEN 'G' 
                               THEN ABS(u.frei_menge) * (-1)
                               ELSE u.frei_menge
                               END											frei_menge
, CASE SUBSTRING(rech_typ,1,1) WHEN 'G' 
                               THEN ABS(u.gelief_men) * (-1)
                               ELSE u.gelief_men
                               END											liefer_menge
, u.vm_menge																vormerk_menge
, u.vg_menge																vergriffen_menge
, CASE SUBSTRING(rech_typ,1,1) WHEN 'G' 
                               THEN ABS(u.upos_sum_ne) * (-1)
                               ELSE u.upos_sum_ne
                               END											nettobetrag
, CASE SUBSTRING(rech_typ,1,1) WHEN 'G'
                               THEN ABS(u.upos_sum_br) * (-1)
                               ELSE u.upos_sum_br
                               END											bruttobetrag
, CASE WHEN u.pos_nr = 1 AND u.upos_nr = 1
       THEN CASE SUBSTRING(rech_typ,1,1) WHEN 'G' 
                                         THEN COALESCE(s.re_zus_ne,0) * (-1)
                                         ELSE COALESCE(s.re_zus_ne,0)
                                         END
       ELSE 0
       END																	ges_zuschlag_rech
, CASE WHEN u.pos_nr = 1 AND u.upos_nr = 1
       THEN CASE SUBSTRING(rech_typ,1,1) WHEN 'G' 
                                         THEN COALESCE(s.re_rab,0) * (-1)
                                         ELSE COALESCE(s.re_rab,0)
                                         END
       ELSE 0
       END																	ges_rabatt_betrag_rech
, CASE SUBSTRING(rech_typ,1,1) WHEN 'G' 
                               THEN (u.upos_netto - u.upos_sum_ne) * (-1)
                               ELSE (u.upos_netto - u.upos_sum_ne)
                               END											upos_rabatt_betrag_netto
------------------------------------------------------------------------------------------------
FROM bufakst s, bufakpos p, bufakupo u
WHERE s.rech_nr=p.rech_nr
  AND s.rech_dat=p.rech_dat
  AND s.f_mandant=p.f_mandant
  AND p.rech_nr=u.rech_nr
  AND p.rech_dat=u.rech_dat
  AND p.pos_nr=u.pos_nr
  AND p.f_mandant=u.f_mandant
  AND (s.rech_typ != 'RS' OR s.r_art != 'P' OR u.p_status_lief != 'F')
  AND (s.rech_typ != 'RO' OR s.r_art != 'P')
)
----------------------------------------------------------------------------------------------------------------------------------
;
GO
