CREATE VIEW dwc_v_wws_lager AS
SELECT 
-- Originalfelder
  l.lager_code
, l.lager_name
, l.e_mandant
, l.adr_gr_lag
, l.adr_nr_lag
, l.kz_packlager
, l.kz_reservier
, l.kz_strecke
, l.kz_komm_lager
---------------------------------------------------------------------------------------------------------------------
, r.regal_id
, r.kz_aussen
---------------------------------------------------------------------------------------------------------------------
, p.ebene_id
, p.platz_id
, p.platzart
---------------------------------------------------------------------------------------------------------------------
-- DW-Felder
, RTRIM(l.lager_code)										Lager
, RTRIM(l.lager_name)										Lager_Bezeichnung
, RTRIM(l.lager_code) + ' - ' + RTRIM(l.lager_name)			Lager_Codebezeichnung
, RTRIM(l.lager_code) + '/' + RTRIM(r.regal_id)				Lagerregal
, RTRIM(l.lager_code) + '/' + RTRIM(r.regal_id) + '/' 
                            + RTRIM(p.ebene_id)				Lagerebene
, RTRIM(l.lager_code) + '/' + RTRIM(r.regal_id) + '/' 
  + RTRIM(p.ebene_id) + '/' + RTRIM(p.platz_id)				Lagerplatz
, CASE p.platzart WHEN 1 THEN 'Normalplatz'
                  WHEN 2 THEN 'Mittelplatz'
                  WHEN 3 THEN 'Kleinplatz'
                  WHEN 4 THEN 'ohne Sperre'
                  WHEN 9 THEN 'Inventursperre'
                  ELSE 'Sonstiger Platz'
                  END										Platzartbezeichnung
, CASE WHEN l.kz_packlager = 'T'
       THEN 'ja'
       ELSE 'nein'
       END													Packlager
, CASE WHEN l.kz_reservier = 'T'
       THEN 'ja'
       ELSE 'nein'
       END													Vormerker
, CASE WHEN l.kz_reservier = 'T'
       THEN 'ja'
       ELSE 'nein'
       END													Streckengeschaeftslager
, CASE WHEN l.kz_komm_lager = 'T'
       THEN 'ja'
       ELSE 'nein'
       END													Kommissionslager
, CASE WHEN l.adr_nr_lag IS NULL
       THEN '---'
       ELSE RTRIM(l.adr_gr_lag) + '/' + STR(l.adr_nr_lag)
       END 													Lager_Adressnummer
---------------------------------------------------------------------------------------------------------------------
FROM bulager l, bulagreg r, bulagpla p
WHERE l.lager_code = r.lager_code
AND   r.lager_code = p.lager_code
AND   r.regal_id   = p.regal_id
;
GO
CREATE VIEW dwc_v_wws_lagerbestand AS
SELECT 
-- DW-Felder normalisiert
  RTRIM(m.e_mandant) + '/' + REPLACE(RTRIM(m.artikel_nr),' ','_')			Artikel
, RTRIM(m.e_mandant) + '/' + REPLACE(RTRIM(m.artikel_nr),' ','_') 
                     + '/' + COALESCE(RTRIM(a.auflage_nr),'0')				Artikelauflage
, RTRIM(b.lager_code) + '/' + RTRIM(b.regal_id) + '/' 
  + RTRIM(b.ebene_id) + '/' + RTRIM(b.platz_id)								Lagerplatz
, CASE s.herkunft
       WHEN 'VA' THEN 'Veranstaltung'
       ELSE 'Buch'
       END 																	Modul
---------------------------------------------------------------------------------------------------------------------
-- Mengen
, b.menge
, g.ges_menge
, g.anz_reserv
, g.anz_vormerk
, n.reserve
, COALESCE(n.meld_best,0)													meld_best
, COALESCE(n.min_best,0)													min_best
, n.max_best   -- Veranstaltungen
---------------------------------------------------------------------------------------------------------------------
, m.artikel_nr
, m.lager_mandant
, m.kz_loeschen
, s.kz_bestand
, s.herkunft
, s.kz_aufl_best
, s.kz_keine_inventu
, a.status
, a.aufl_text
, s.ausg_text
, t.titel_such
---------------------------------------------------------------------------------------------------------------------
, b.lager_code
, b.regal_id
, b.ebene_id
, b.platz_id
, b.e_mandant
, b.l_ausg_nr
, b.l_aufl_nr
, b.best_art
, COALESCE(CONVERT(char(4), b.prod_jahr, 111),'---')						prod_jahr
---------------------------------------------------------------------------------------------------------------------
FROM bulagbes b
LEFT JOIN bulagges g ON b.e_mandant = g.e_mandant AND b.best_art = g.best_art AND b.l_aufl_nr = g.l_aufl_nr AND b.l_ausg_nr = g.l_ausg_nr AND b.lager_code = g.lager_code 
LEFT JOIN bumanaus m ON b.e_mandant = m.e_mandant AND b.l_ausg_nr = m.l_ausg_nr 
LEFT JOIN buausgab s ON b.l_ausg_nr = s.l_ausg_nr 
LEFT JOIN butitel t  ON s.l_titel_nr = t.l_titel_nr 
LEFT JOIN buaufl a   ON b.l_aufl_nr = a.l_aufl_nr AND b.l_ausg_nr = a.l_ausg_nr 
LEFT JOIN bulagmin n ON b.l_aufl_nr = n.l_aufl_nr AND b.l_ausg_nr = n.l_ausg_nr AND b.e_mandant = n.e_mandant AND b.lager_code = n.lager_code
;
GO
CREATE VIEW dwc_v_wws_lagerbestand_stichtag AS
SELECT 
-- DW-Felder normalisiert
  RTRIM(m.e_mandant) + '/' + REPLACE(RTRIM(m.artikel_nr),' ','_')			Artikel
, RTRIM(m.e_mandant) + '/' + REPLACE(RTRIM(m.artikel_nr),' ','_') 
                     + '/' + COALESCE(RTRIM(a.auflage_nr),'0')				Artikelauflage
, RTRIM(b.lager_code) + '/' + RTRIM(b.regal_id) + '/' 
  + RTRIM(b.ebene_id) + '/' + RTRIM(b.platz_id)								Lagerplatz
, CASE s.herkunft
       WHEN 'VA' THEN 'Veranstaltung'
       ELSE 'Buch'
       END 																	Modul
, REPLACE(CONVERT(char(10), b.stichtag, 111),'/','-')						Stichtag
---------------------------------------------------------------------------------------------------------------------
-- Menge
, b.menge
---------------------------------------------------------------------------------------------------------------------
, m.artikel_nr
, m.lager_mandant
, m.kz_loeschen
, s.kz_bestand
, s.herkunft
, s.kz_aufl_best
, s.kz_keine_inventu
, a.status
, a.aufl_text
, s.ausg_text
, t.titel_such
---------------------------------------------------------------------------------------------------------------------
, b.lager_code
, b.regal_id
, b.ebene_id
, b.platz_id
, b.e_mandant
, b.l_ausg_nr
, b.l_aufl_nr
, b.best_art
---------------------------------------------------------------------------------------------------------------------
FROM bulagbsi b
LEFT JOIN bumanaus m ON b.e_mandant = m.e_mandant AND b.l_ausg_nr = m.l_ausg_nr 
LEFT JOIN buausgab s ON b.l_ausg_nr = s.l_ausg_nr 
LEFT JOIN butitel t  ON s.l_titel_nr = t.l_titel_nr 
LEFT JOIN buaufl a   ON b.l_aufl_nr = a.l_aufl_nr AND b.l_ausg_nr = a.l_ausg_nr 
LEFT JOIN bulagmin n ON b.l_aufl_nr = n.l_aufl_nr AND b.l_ausg_nr = n.l_ausg_nr AND b.e_mandant = n.e_mandant AND b.lager_code = n.lager_code
;
GO
CREATE VIEW dwc_v_wws_standing_order
( e_mandant
, staord_nr
, l_ausg_nr_k
, l_ausg_nr_start
, adr_gr
, adr_nr_best
, adr_nr_le
, adr_nr_re
, sto_beg
, sto_end
, status
, best_datum
, ber_menge
, frei_menge
, preiskat
, bu_ra
, rab_proz
, zus_kat
, vertreter_id
-------------------------------------------------------------------------------------------------------------
-- DW und berechnete Felder
, lieferadresse
, rechnungsadresse
, besteller
, bula_lieferadresse
, bula_rechnungsadresse
, reihe
, aktion
, rechnungsart
, versandweg
, bestellweg
, bestelldatum
, startdatum
, endedatum
, stichtag
, liefermenge)
AS 
WITH Adresse AS
(SELECT adr_gr
 , adr_nr
 , RTRIM(haupt_name)												hauptname
 , RTRIM(haupt_ort)													hauptort
 , RTRIM(haupt_plz) + ' ' + RTRIM(haupt_ort)						plz_ort
 , RTRIM(land_code)													land
 , RTRIM(kgs_bl)													bundesland
 , RTRIM(bezirk_id)													bezirk
 , RTRIM(adr_gr) + '/' + RTRIM(COALESCE(land_code,'---'))  
                 + CASE WHEN land_code = 'D'                        -- Länderliste ggf. anpassen, z.B. auch A/CH
                        THEN '/' + RTRIM(COALESCE(kgs_bl,'---'))
                        ELSE ''
                        END											land_bula
 FROM anschr a 
 WHERE EXISTS
 (SELECT 1 FROM bustaord b
  WHERE a.adr_gr = b.adr_gr
  AND (a.adr_nr = b.adr_nr_le OR a.adr_nr=b.adr_nr_re))
)
SELECT e_mandant
, staord_nr
, l_ausg_nr_k
, l_ausg_nr_start
, adr_gr
, adr_nr_best
, adr_nr_le
, adr_nr_re
, sto_beg
, sto_end
, status
, best_datum
, ber_menge
, frei_menge
, preiskat
, bu_ra
, rab_proz
, zus_kat
, vertreter_id
----------------------------------------------------------------------------------------------------------
-- DW
, RTRIM(adr_gr) + '/' + LTRIM(STR(adr_nr_le))						lieferadresse
, RTRIM(adr_gr) + '/' + LTRIM(STR(adr_nr_re))						rechnungsadresse
, RTRIM(adr_gr) + '/' + LTRIM(STR(adr_nr_best))						besteller
, (SELECT Land_Bula
   FROM Adresse a
   WHERE a.adr_gr = s.adr_gr
   AND a.adr_nr = s.adr_nr_le)										bula_lieferadresse
, (SELECT Land_Bula
   FROM Adresse a
   WHERE a.adr_gr = s.adr_gr
   AND a.adr_nr = s.adr_nr_re)										bula_rechnungsadresse
, (SELECT Artikelauflage FROM dwc_v_wws_artikel j 
                         WHERE s.l_ausg_nr_k=j.l_ausg_nr
                         AND s.e_mandant=j.e_mandant
                         AND j.l_aufl_nr=0)							reihe
, RTRIM(e_mandant) + '/' + RTRIM(COALESCE(akt_id,'-')) 
                  + '/' + RTRIM(COALESCE(LTRIM(STR(uakt_id)),'-'))	aktion
, RTRIM(r_art)                    Rechnungsart
, RTRIM(vers_weg)                   Versandweg
, RTRIM(best_weg)                   Bestellweg
, REPLACE(CONVERT(char(10), best_datum, 111),'/','-')				bestelldatum
, REPLACE(CONVERT(char(10), sto_beg, 111),'/','-')					startdatum
, REPLACE(CONVERT(char(10), sto_end, 111),'/','-')					endedatum
, monatsletzter														stichtag
, ber_menge + COALESCE(frei_menge, 0)								liefermenge
FROM bustaord s, dwc_v_crm_monate j
-- Abfragezeitpunkt hier: Monatsletzter!
WHERE s.sto_beg <= j.monatsletzter_datum
AND ( s.sto_end >= j.monatsletzter_datum OR s.sto_end IS NULL)
AND j.jahr > DATEPART(yyyy,DATEADD(month, -60, GETDATE()))
AND j.jahr <= DATEPART(yyyy,DATEADD(month, 12, GETDATE()))
AND s.storno = 'F'
;
GO
CREATE VIEW dwc_vk_gnb_adresse_tele
( kunden_uid
, person_uid
, adressgruppe
, adressnummer
, person_nr
, tele_art
, tele_art_bezeichnung
, nummer
, such_nummer
-----------------------------------------------------------------------------------------------------------------
, werbeerlaubnis_teleart
-----------------------------------------------------------------------------------------------------------------
, modified_on)
AS
-----------------------------------------------------------------------------------------------------------------
SELECT
  RTRIM(t.adr_gr) + '/' + LTRIM(STR(t.adr_nr))								kunden_uid
, RTRIM(t.adr_gr) + '/' + LTRIM(STR(t.adr_nr)) + '/' 
                        + LTRIM(STR(t.person_nr))							person_uid
, t.adr_gr																	adressgruppe
, t.adr_nr																	adressnummer
, t.person_nr
, t.tel_art																	tele_art
, (SELECT bez FROM teleart x WHERE x.tel_art = t.tel_art)					tele_art_bezeichnung
, nummer
, such_nummer
-----------------------------------------------------------------------------------------------------------------
, CASE COALESCE(kz_erlaub, '-')
       WHEN 'F' THEN 'nein'
       WHEN 'T' THEN 'ja'
       WHEN 'D' THEN 'Double Opt-in'
       WHEN 'S' THEN 'Single Opt-in'
       WHEN '-' THEN 'nicht angegeben'
       ELSE 'nicht geschlüsselt'
  END																		werbeerlaubnis_teleart
, t.modified_on
-----------------------------------------------------------------------------------------------------------------
FROM  telecom t   LEFT JOIN werbeerl w
ON    t.adr_gr    = w.adr_gr
AND   t.adr_nr    = w.adr_nr
AND   t.person_nr = w.person_nr
AND   t.tel_art   = w.tel_art
AND   w.hist_nr   = 0
AND   w.lfd_nr    = 1
WHERE t.adr_gr IN ('GNB')  -- GNB
;
GO
CREATE VIEW dwc_vk_gnb_adresse_telemailref
( kunden_uid
, person_uid
, tele_art
)
AS
-----------------------------------------------------------------------------------------------------------------
SELECT
  RTRIM(adr_gr) + '/' + LTRIM(STR(adr_nr))									kunden_uid
, RTRIM(adr_gr) + '/' + LTRIM(STR(adr_nr)) + '/' 
                        + LTRIM(STR(person_nr))								person_uid
, MIN(tel_art)																tele_art
-----------------------------------------------------------------------------------------------------------------
FROM  telecom
WHERE adr_gr IN ('GNB')  -- GNB
AND   tel_Art LIKE 'E%'
GROUP BY adr_gr, adr_nr, person_nr
;
GO
CREATE VIEW dwc_vk_gnb_adresskontakte
( kunden_uid
, person_uid
, adressgruppe
, adressnummer
, adresstyp
, personennummer
, name1
, name2
, name3
, anrede_code
, etikett_anrede
, titel_code
, etikett_titel
, namenszusatz
, vorname
, nachname
, namensergaenzung
, position
, abteilung
-----------------------------------------------------------------------------------------------------------------
, strasse
, strasse2
, plz_wohnort
, wohnort
, postfach
, plz_postort
, postort
, land_code
, land_name
, versandadresse
-----------------------------------------------------------------------------------------------------------------
, geburtsdatum
, werbeerlaubnis_brief 
, modified_on )
AS
-----------------------------------------------------------------------------------------------------------------
SELECT
  RTRIM(a.adr_gr) + '/' + LTRIM(STR(a.adr_nr))								kunden_uid
, RTRIM(a.adr_gr) + '/' + LTRIM(STR(a.adr_nr)) + '/' 
                        + LTRIM(STR(p.person_nr))							person_uid
, a.adr_gr																	adressgruppe
, a.adr_nr																	adressnummer
, a_typ																		adresstyp
, p.person_nr																personennummer
, name1
, name2
, name3
, anrede_code
, (SELECT etikett FROM anrede x 
   WHERE x.anrede_code = p.anrede_code and x.sprach_code = 'D')				etikett_anrede
, titel_code
, (SELECT titel_etikett FROM titel x 
   WHERE x.titel_code = p.titel_code)										etikett_titel
, n_zusatz																	namenszusatz
, vorname
, nachname
, n_ergaenz																	namensergaenzung
, position
, abteilung
-----------------------------------------------------------------------------------------------------------------
, strasse
, strasse2
, plz_wohn																	plz_wohnort
, wohnort
, postfach
, plz_post																	plz_postort
, postort
, land_code
, (SELECT land FROM land x 
   WHERE x.land_code = a.land_code)											land_name
, versand_adr																versandadresse
-----------------------------------------------------------------------------------------------------------------
, geb_dat																	geburtsdatum
, COALESCE((SELECT CASE kz_erlaub
          WHEN 'F' THEN 'nein'
          WHEN 'T' THEN 'ja'
          WHEN 'D' THEN 'Double Opt-in'
          WHEN 'S' THEN 'Single Opt-in'
          ELSE 'nicht geschlüsselt'
          END
   FROM  werbeerl x
   WHERE x.adr_gr = p.adr_gr AND x.adr_nr = p.adr_nr AND x.person_nr = 0
   AND   x.hist_nr = 0 AND x.lfd_nr = 1 AND tel_art = 'BRI')
   , 'nicht angegeben')														werbeerlaubnis_brief
, p.modified_on
FROM  anschr a, person p
WHERE a.adr_gr = p.adr_gr
AND   a.adr_nr = p.adr_nr
AND   p.a_typ in ('M','P')
AND   a.adr_gr IN ('GNB')  -- GNB
;
GO
