CREATE VIEW dwd_v_abo_adresse
  ( toplevel, adressgruppe, adressgruppe_bezeichnung, adressgruppe_codebezeichnung, sortierung, landgruppe,
    landgruppe_bezeichnung, adresse, adresse_land_bezeichnung, adresse_land_codebezeichnung )
AS
( SELECT 'Alle Adressen'												toplevel
, RTRIM(adr_gr)															adressgruppe
, RTRIM(ag_name)														adressgruppe_bezeichnung
, RTRIM(adr_gr) + ' - ' + RTRIM(ag_name)								adressgruppe_codebezeichnung
, CASE WHEN land_code='D'            THEN RTRIM(adr_gr) + '/1'
       WHEN land_code IN ('A', 'AT') THEN RTRIM(adr_gr) + '/2'			-- Österreich A oder AT
       WHEN land_code='CH'           THEN RTRIM(adr_gr) + '/3'
       WHEN eg_kz='T'                THEN RTRIM(adr_gr) + '/4'
       WHEN land_gr='E'              THEN RTRIM(adr_gr) + '/5'
       ELSE RTRIM(adr_gr) + '/6'
  END																	sortierung
, CASE WHEN land_code='D'            THEN RTRIM(adr_gr) + '/DACH'
       WHEN land_code IN ('A', 'AT') THEN RTRIM(adr_gr) + '/DACH'		-- Österreich A oder AT
       WHEN land_code='CH'           THEN RTRIM(adr_gr) + '/DACH'
       WHEN eg_kz='T'                THEN RTRIM(adr_gr) + '/Rest-EU'
       WHEN land_gr='E'              THEN RTRIM(adr_gr) + '/Rest-Europa'
       ELSE RTRIM(adr_gr) + '/Rest-Ausland'
  END																	landgruppe
, CASE WHEN land_code='D'            THEN 'D/A/CH'
       WHEN land_code IN ('A', 'AT') THEN 'D/A/CH'						-- Österreich A oder AT
       WHEN land_code='CH'           THEN 'D/A/CH'
       WHEN eg_kz='T'                THEN 'Restliche EU'
       WHEN land_gr='E'              THEN 'Rest-Europa (ohne EU)'
       ELSE 'Restliches Ausland (Welt)'
  END																	landgruppe_bezeichnung
, RTRIM(adr_gr) + '/' + RTRIM(land_code)								adresse
, RTRIM(land)															adresse_land_bezeichnung
, RTRIM(land_code) + ' - ' + RTRIM(land)								adresse_land_codebezeichnung
FROM agruppe, land
-----------------------------------------------------------------------------------------------------
UNION SELECT 'Alle Adressen'											toplevel
, RTRIM(adr_gr)															adressgruppe
, RTRIM(ag_name)														adressgruppe_bezeichnung
, RTRIM(adr_gr) + ' - ' + RTRIM(ag_name)								adressgruppe_codebezeichnung
, RTRIM(adr_gr) + '/9'													sortierung
, RTRIM(adr_gr) + '/unbekannt'											landgruppe
, 'unbekannt'															landgruppe_bezeichnung
, RTRIM(adr_gr) + '/---'												adresse
, 'unbekannt'															adresse_land_bezeichnung
, 'unbekannt'															adresse_land_codebezeichnung
FROM agruppe, land
)
;
GO
