CREATE VIEW dwd_v_abo_heftnummer AS
(
SELECT DISTINCT 
  'Alle Heftnummern'																			Toplevel_fuer_Summe
, jahrzehnt
, CONVERT(char(4),jahr)																			jahr
, heftnummer
, REPLACE(heftnummer,'/','')																	heftnummer_zahl
FROM dwc_t_abo_kalender
WHERE ISNUMERIC(jahr) = 1         -- Jahre, die numerisch sind
--  AND jahr > DATEPART(yyyy,DATEADD(month, -120, GETDATE()))     -- letzte 10 Kalenderjahre
--  AND jahr <= DATEPART(yyyy,DATEADD(month, 72, GETDATE()))      -- nächstes Kalenderjahr
UNION
SELECT
  'Alle Heftnummern'																			Toplevel_fuer_Summe
, 'Jahrestexte'																					jahrzehnt
, RTRIM(jahr)																					jahr
, RTRIM(jahr) + '/' +
  CASE WHEN hnr LIKE '[A-Za-z]%' THEN hnr
       ELSE RIGHT('0' + RTRIM(LEFT(hnr, PATINDEX('%[^0-9]%', hnr + 'x') - 1)), 2) +
            SUBSTRING(RTRIM(hnr), PATINDEX('%[^0-9-]%', hnr + 'x'), 1)
       END																						heftnummer
, CONVERT(char(4),DATEPART(yyyy,COALESCE(versand_soll,versand_ist,edat_soll))) + 
  CASE WHEN hnr LIKE '[A-Za-z]%' THEN hnr
       ELSE RIGHT('0' + RTRIM(LEFT(hnr, PATINDEX('%[^0-9]%', hnr + 'x') - 1)), 2) +
            SUBSTRING(RTRIM(hnr), PATINDEX('%[^0-9-]%', hnr + 'x'), 1)  
       END																						heftnummer_zahl
FROM kalender k
WHERE ISNUMERIC(jahr) = 0         -- Jahre, die nicht numerisch sind
)
;
GO
CREATE VIEW dwd_v_abo_ivwlistrubrik
  (toplevel, summenfeld, summenbezeichnung, ivw_gruppe, ivw_gruppe_bezeichnung, ivw_listrubrik, bezeichnung, code_bezeichnung)
AS
WITH Summenliste AS
    (
    SELECT summe_in
    FROM   ivwlist
    GROUP BY summe_in
    ),
Liste AS
    (
    SELECT 
      ivw_list
    , bezeichnung
    , ivw_gruppe
    , COALESCE(summe_in, ivw_list) Summenfeld
    FROM ivwlist Liste
    WHERE ( NOT EXISTS (SELECT * FROM Summenliste WHERE Liste.ivw_list = Summenliste.summe_in) OR Liste.ivw_list = Liste.summe_in )
    )
(
SELECT 'Alle IVW-Listrubriken'						toplevel
, STR(summenfeld)									summenfeld
, (SELECT bezeichnung 
   FROM ivwlist i
   WHERE (summe_in IS NULL OR summe_in = ivw_list)
   AND i.ivw_list = Liste.Summenfeld)				summenbezeichnung
, STR(ivw_gruppe)									ivw_gruppe
, (SELECT bezeichnung
   FROM ivwlist i
   WHERE (ivw_gruppe IS NULL OR ivw_gruppe = ivw_list)
   AND    i.ivw_list = Liste.ivw_gruppe)			ivw_gruppe_bezeichnung
, STR(ivw_list)										ivw_listrubrik
, TRIM(bezeichnung)									bezeichnung
, STR(ivw_list) + ' - ' + TRIM(bezeichnung)			code_bezeichnung
FROM Liste
UNION SELECT 'Alle IVW-Listrubriken'				toplevel
, '-'												summenfeld
, 'Summe ohne Zuordnung'							summenbezeichnung
, '---'												ivw_gruppe
, 'ohne Zuordnung'									ivw_gruppe_bezeichnung
, '---'												ivw_listrubrik
, 'ohne Zuordnung'									bezeichnung
, '--- (ohne Zuordnung)'							code_bezeichnung
)
;
-------------
GO
CREATE VIEW dwd_v_abo_objekt
  ( toplevel, mandant, mandantenname, mandant_codebezeichnung
  , hauptobjekt, hauptobjekt_name, hauptobjekt_bezeichnung, hauptobjekt_codebezeichnung, hauptobjekt_kurzbezeichnung
  , objekt, objekt_bezeichnung, objekt_codebezeichnung, objekt_kurzbezeichnung, print_online, heft_zeitraum )
AS
(  SELECT 'Alle Objekte'																					toplevel
,  RTRIM(s.e_mandant)																						mandant
,  m_name																									mandantenname
,  RTRIM(s.e_mandant) + ' - ' + m_name																		mandant_codebezeichnung
, (RTRIM(s.e_mandant)) + '/' + s.obj_nr																		hauptobjekt
,  RTRIM(t.objektname)																						hauptobjekt_name
,  RTRIM(s.bezeichnung)																						hauptobjekt_bezeichnung
,  RTRIM(s.obj_nr) + ' - ' + RTRIM(t.objektname)															hauptobjekt_codebezeichnung
,  RTRIM(s.obj_nr)																							hauptobjekt_kurzbezeichnung
, (RTRIM(s.e_mandant)) + '/' + (RTRIM(s.obj_nr) + '/' + RTRIM(s.ausg))										objekt
,  CASE WHEN s.bezeichnung IS NULL
        THEN COALESCE(RTRIM(t.objektname),'-')
        ELSE CASE WHEN RTRIM(s.bezeichnung) = RTRIM(t.objektname)
                  THEN COALESCE(RTRIM(t.objektname),'-')
                  ELSE COALESCE(RTRIM(t.objektname),'-') + ' (' + RTRIM(s.bezeichnung) + ')'
                  END
        END																									objekt_bezeichnung
,  CASE WHEN s.bezeichnung IS NULL
        THEN (RTRIM(s.obj_nr) + '/' + RTRIM(s.ausg)) + ' | ' + COALESCE(RTRIM(t.objektname),'-')
        ELSE CASE WHEN  RTRIM(s.bezeichnung) = RTRIM(t.objektname)
                  THEN (RTRIM(s.obj_nr) + '/' + RTRIM(s.ausg)) + ' | ' + COALESCE(RTRIM(t.objektname),'-')
                  ELSE (RTRIM(s.obj_nr) + '/' + RTRIM(s.ausg)) + ' | ' 
                        + COALESCE(RTRIM(t.objektname),'-') + ' (' + RTRIM(s.bezeichnung) + ')' 
                  END
        END																									objekt_codebezeichnung
, (RTRIM(s.obj_nr) + '/' + RTRIM(s.ausg))																	objekt_kurzbezeichnung
,  CASE WHEN s.kz_online='T'
        THEN 'Online'
        ELSE 'Print' 
        END																									print_online
,  CASE WHEN t.kz_abrech='H'
        THEN 'heftbezogen'
        ELSE 'zeitraumbezogen' 
        END																									heft_zeitraum
FROM mobstamm s 
LEFT JOIN mandant m ON s.e_mandant = m.e_mandant
LEFT JOIN mobjtyp t ON s.e_mandant=t.e_mandant AND s.obj_nr=t.obj_nr
WHERE status='N'
)
;
GO
CREATE VIEW dwd_v_abo_preiskategorie AS
(
SELECT 
  'Alle Preiskategorien'							toplevel
, berechnen
, CASE berechnen
       WHEN 'L' THEN 'Listenpreise'
       WHEN 'N' THEN 'unbezahlte Abos'
       ELSE 'Sonstige Preise'
  END												preisart
, ivw1
, CASE
       WHEN ivw1='18' OR ivw1='19' OR ivw1='20' 
         OR ivw1='21' THEN 'Sonstiger Verkauf'
       WHEN ivw1='23' OR ivw1='24'
         OR ivw1='26' THEN 'Freiabos'
       ELSE 'Bezahlte Abos'
  END												ivw_gruppe
, RTRIM(preis_kat)									preiskategorie
, RTRIM(bezeichnung)								bezeichnung
, RTRIM(preis_kat) + ' - ' + RTRIM(bezeichnung)		code_bezeichnung
FROM preiskat
UNION SELECT 
  'Alle Preiskategorien'							toplevel
, 'S'												berechnen
, 'Sonstige Preise'									preisart
, 18												ivw1
, 'Sonstiger Verkauf'								ivw_gruppe
, '---'												preiskategorie
, 'keine'											bezeichnung
, '--- (keine)'										code_bezeichnung
)
;

GO
CREATE VIEW dwd_v_abo_versandart AS
(
SELECT 
  'Alle Versandarten'								toplevel
, a.versart											versandart
, COALESCE(b.bezeichnung, 
      TRIM(a.versart) + ' (Bezeichnung n. vorh.)')	bezeichnung
, COALESCE(TRIM(a.versart) + ' - ' + b.bezeichnung,
      TRIM(a.versart) + ' (Bezeichnung n. vorh.)')	code_bezeichnung
FROM versart a
LEFT JOIN vartbez b ON a.versart = b.versart
WHERE (sprach_code = 'D' OR sprach_code IS NULL)
-- Dummy-Wert
UNION SELECT 
  'Alle Versandarten'								toplevel
, '---'												versandart
, 'keine'											bezeichnung
, '--- (keine)'										code_bezeichnung
)
;
GO
CREATE VIEW dwd_v_abo_zahlungsart AS
(
SELECT 'Alle Zahlungsarten'												toplevel
, CASE WHEN beschreibung LIKE '%Kreditk%'     THEN 'Kreditkarten'
       WHEN beschreibung LIKE '%Paypal%'      THEN 'Paypal'
       WHEN beschreibung LIKE '%Bank%'        THEN 'Lastschrift'
       WHEN beschreibung LIKE '%Lastschrift%' THEN 'Lastschrift'
       ELSE 'Rechnung'
       END																zahlart_gruppe
, e_mandant
, RTRIM(z_bed)															z_bed
, RTRIM(e_mandant) + '/' + RTRIM(z_bed)									zahlart
, RTRIM(beschreibung)													bezeichnung
, RTRIM(z_bed) + ' - ' + RTRIM(beschreibung)							code_bezeichnung
, skonto_satz
, skonto_tage
, zahl_tage
, kz_online
FROM zahlbed
UNION SELECT 'Alle Zahlungsarten'										toplevel
, 'keine'																zahlart_gruppe
, '---'
, '---'																	z_bed
, '---'																	zahlart
, 'keine'																bezeichnung
, '--- (keine)'															code_bezeichnung
, NULL
, NULL
, NULL
, 'F'
)
;
GO
