create view eaisview
       (adr_gr, adr_nr, auft_nr, auft_hist_nr, dispo_nr, dispo_hist_nr,
        dispopos_nr, e_mandant, obj_nr, ausg, obj_nr_dispo, jahr, hnr, 
        hnr_num, status_dispopos, 
	abrech_id, anzart_id, datum_neu, datum_aend, datum_aend_auft,
        anz_schaltung, farb_id, anz_si, anz_mm,
	anz_eintrag, status, format_id,
	volumen_fa, volumen_mm, volumen_tk, netto_betrag, anzeigen_betrag, 
	wa_prov_betrag, volrab_betrag, wa_prov_basis, mwst_anteil, 
	kombi_rabatt, sonder_rabatt, volumen_rabatt, 
        wa_prov_satz, anz_zeilen, anz_sp, anz_anzeigen, anz_seiten,
        bezirk_id, ums_ant_bezirk, f_typ_bezirk,
        vertreter_id, ums_ant_vert, f_typ_vert, konzern_id,
        haupt_name, haupt_ort, kz_loeschen, kz_einmal_kd, bezirk_id_anschr, 
        waehrung, produkt, produkt_nie, verwend_typ, datum_evt, adr_nr_wa,
        rubrik_id, rub_bezeichnung, rub_anz_belegung, schalt_von, schalt_bis, herkunft_id,
        anz_gramm, anzart_bez, bez_si, plazierungs_id, plaz_ext)
  as
select p.adr_gr, p.adr_nr, p.auft_nr, p.auft_hist_nr, 
        p.dispo_nr, p.dispo_hist_nr, p.dispopos_nr, p.e_mandant, p.obj_nr,
        p.ausg, d.obj_nr, p.jahr, p.hnr, p.hnr_num, p.status, 
	d.abrech_id, d.anzart_id, d.datum_neu, d.datum_aend, g.datum_aend, 
        d.anz_schaltung, d.farb_id, d.anz_si, d.anz_mm, 
        d.anz_eintrag, d.status, d.format_id,
	d.volumen_fa, d.volumen_mm, 0, d.netto_betrag, d.anzeigen_betrag,
        d.wa_prov_betrag, d.volrab_betrag, d.wa_prov_basis, d.mwst_anteil,
	d.kombi_rabatt, d.sonder_rabatt, d.volumen_rabatt, 
        d.wa_prov_satz, d.anz_zeilen, d.anz_sp, d.anz_anzeigen,d.anz_seiten, 
        b.bezirk_id, b.ums_anteil_proz, b.f_typ_nr,
        v.vertreter_id, v.um_ant_proz, v.f_typ_nr, a.konzern_id,
        a.haupt_name, a.haupt_ort, e.kz_loeschen, e.kz_einmal_kd, a.bezirk_id,
        g.waehrung, p.produkt, '', g.verwend_typ, k.datum_evt, g.adr_nr_wa,
        r.rubrik_id, r.bezeichnung, r.anz_belegung, p.schalt_von, p.schalt_bis, d.herkunft_id,
        d.anz_gramm, d.anzart_bez, d.bez_si, p.plazierungs_id, p.plaz_ext
from   dispopos p LEFT OUTER JOIN kalendea k ON
       p.e_mandant = k.e_mandant and p.obj_nr = k.obj_nr and 
       p.ausg = k.ausg and p.jahr = k.jahr and p.hnr = k.hnr
                  LEFT OUTER JOIN adbezirk b ON
       p.adr_gr = b.adr_gr and p.adr_nr = b.adr_nr and p.auft_nr = b.auft_nr and
       p.auft_hist_nr = b.auft_hist_nr and b.dispo_nr = 0 and b.dispo_hist_nr = 0
                  LEFT OUTER JOIN advert v ON
       p.adr_gr = v.adr_gr and p.adr_nr = v.adr_nr and p.auft_nr = v.auft_nr and
       p.auft_hist_nr = v.auft_hist_nr and v.dispo_nr = 0 and v.dispo_hist_nr = 0
                  LEFT OUTER JOIN drubrik r ON
       p.adr_gr = r.adr_gr and p.adr_nr = r.adr_nr and p.auft_nr = r.auft_nr and
       p.auft_hist_nr = r.auft_hist_nr and 
       p.dispo_nr = r.dispo_nr and p.dispo_hist_nr = r.dispo_hist_nr and
       p.dispopos_nr = r.dispopos_nr,
       dispo d, anschr a, person e, auftrag g
where  
       p.adr_gr = d.adr_gr and
       p.adr_nr = d.adr_nr and p.auft_nr = d.auft_nr and
       p.auft_hist_nr = d.auft_hist_nr and p.dispo_nr = d.dispo_nr and
       p.dispo_hist_nr = d.dispo_hist_nr and
       p.adr_gr = a.adr_gr and p.adr_nr = a.adr_nr and
       p.adr_gr = e.adr_gr and p.adr_nr = e.adr_nr and e.person_nr = 0 and
       p.adr_gr = g.adr_gr and p.adr_nr = g.adr_nr and p.auft_nr = g.auft_nr and
       p.auft_hist_nr = g.auft_hist_nr and g.kz_inaktiv='F' and
       p.hnr_num > 2005000

