     (e_mandant,auftrags_nr,man_nr,adr_gr,adr_nr,person_nr,haupt_name,
      name1,ort, adr_nr_obj,haupt_name_obj,  
      erf_dat,fakt_dat,rech_dat,rech_nr,buch_art,r_art,abruf_nr,
