       a.adr_gr, a.adr_nr_re, a.person_nr_re, a.land_code_re, a.eg_kz_re, a.eg_idnr, a.buch_art, a.r_art,
       a.waehrung     ,a.mwst_frei , b.obj_nr, b.ausg, b.fakt_kat, 
       b.steuersatz  ,   c.adr_nr_obj  , c.pnr_obj   , c.abo_nr, c.land_code_he, c.eg_idnr_he, c.btext1, c.btext2, 
