AND    b.e_mandant = c.e_mandant
AND    b.rech_nr   = c.rech_nr
AND    b.re_dat    = c.re_dat
AND    b.abruf_nr  = c.abruf_nr
AND    b.kopie_nr  = c.kopie_nr
AND    b.posnr     = c.posnr

