CREATE VIEW fakuview AS
SELECT a.e_mandant   ,a.rech_nr     ,a.re_dat    ,a.abruf_nr ,
       a.posnr       ,a.uposnr      ,a.adr_gr    ,a.adr_nr_bv,
       a.person_nr_bv,a.adr_nr      ,a.person_nr ,a.auftrags_nr,
       a.obj_nr      ,a.ausg        ,a.u_obj_nr  ,a.u_ausg,
       a.hnr         ,a.jahr        ,a.waehrung  ,a.land_code_re,
       a.fakt_zr     ,a.fakt_kat    ,a.buch_art  ,a.r_art,
       a.sum_betr    ,a.land_code_he,a.buch_monat,a.buch_jahr,
       a.zusbetr     ,a.rabbetr     ,a.w_akt_id  ,a.preis_kat,
       a.abo_nr      ,a.eg_kz_re    ,a.mwst_betr ,a.mwst_satz,
       a.heft_wert   ,a.buchm_wert  ,b.rab_proz  ,b.f_beg_dat_e,
       b.f_ende_dat_e,b.zb_menge, c.kgs_bl, d.ISTATWCODE
FROM   fakustat a, faktupos b, anschr c, mobjtyp d
WHERE  a.e_mandant = b.e_mandant
AND    a.rech_nr   = b.rech_nr
