create view [dbo].[fasuolvi]
       (e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung,
        sum_berechnet, sum_frei, sum_remittend, sum_brutto_betr, sum_partie, sum_netto_betr)
  as
select e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung, 
          sum(sum_berechnet), sum(sum_frei), sum(sum_remittend), sum(sum_brutto_betr),
          sum(sum_partie), sum(sum_netto_betr)
from   bufaksum 
where so_pos_nr = '0'
and (sum_berechnet != 0 or sum_partie != 0 or sum_frei != 0 or sum_remittend != 0 or sum_netto_betr != 0 or sum_brutto_betr != 0)
group by e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung

