create view fasuview 
       (e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung,
        sum_berechnet, sum_frei, sum_remittend, sum_brutto_betr, sum_partie, sum_netto_betr, so_pos_nr, shop_id, preis_kat)
  as
select e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung, 
          sum(sum_berechnet), sum(sum_frei), sum(sum_remittend), sum(sum_brutto_betr),
          sum(sum_partie), sum(sum_netto_betr), so_pos_nr, shop_id, preis_kat
from   bufaksum
where preis_kat != '$NU%' and preis_kat != '$NU&'
group by e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung, so_pos_nr, shop_id, preis_kat

