create view foerdererview (adr_gr, adr_nr, person_nr, e_mandant, obj_nr, ausg, abo_nr,
       abostatus, l_menge, ber_menge, preis_kat,
       haupt_plz, haupt_ort, haupt_name, genfilt_id,
       adr_nr_bv, person_nr_bv, haupt_plz_bv, haupt_ort_bv, haupt_name_bv, genfilt_id_bv,
       s_adnr, s_person_nr, haupt_plz_s, haupt_ort_s, haupt_name_s, genfilt_id_s)
  as select s.adr_gr, s.adr_nr, s.person_nr, s.e_mandant, s.obj_nr, s.ausg, s.abo_nr,
       s.abostatus, v.l_menge, s.ber_menge, s.preis_kat,
       a1.haupt_plz, a1.haupt_ort, a1.haupt_name, a1.genfilt_id,
       s.adr_nr_bv, s.person_nr_bv, a2.haupt_plz, a2.haupt_ort, a2.haupt_name, a2.genfilt_id,
       v.s_adnr, v.s_person_nr, a3.haupt_plz, a3.haupt_ort, a3.haupt_name, a3.genfilt_id
     from abostamm s, abovers v, anschr a1, anschr a2, anschr a3
  where s.adr_gr = v.adr_gr and s.adr_nr = v.adr_nr and s.person_nr = v.person_nr 
    and s.e_mandant = v.e_mandant and s.obj_nr = v.obj_nr and s.ausg = v.ausg and s.abo_nr = v.abo_nr
    and a1.adr_gr = s.adr_gr and a1.adr_nr = s.adr_nr
    and a2.adr_gr = s.adr_gr and a2.adr_nr = s.adr_nr_bv
    and a3.adr_gr = v.adr_gr and a3.adr_nr = v.s_adnr

