CREATE VIEW gggpaview (
      gg_auft_nr, waehrung, kz_sperr, beschreibung, bdatum, binfo, gg_segm_id,
      brutto_volumen, netto_volumen, status, person_nr,
      ber_nachname, ber_vorname, 
      ber_verfasser_id, ber_datum_loe, ber_text_nr,
      adr_gr, adr_nr, haupt_name, haupt_plz, haupt_ort, name1, name2, name3,
      nachname, vorname,
      e_mandant, obj_nr,
      datum_wv)
AS SELECT
      g.gg_auftr_nr, g.waehrung, g.kz_sperr, g.beschreibung, g.bdatum, g.binfo, g.gg_segm_id,
      g.brutto_volumen, g.netto_volumen, g.status, g.person_nr,
      b.nachname, b.vorname, 
      b.verfasser_id, b.datum_loe, b.text_nr,
      a.adr_gr, a.adr_nr, a.haupt_name, a.haupt_plz, a.haupt_ort, a.name1, a.name2, a.name3,
      p.nachname, p.vorname,
      o.e_mandant, o.obj_nr,
      s.datum_wv
FROM
      ggauftr g LEFT OUTER JOIN bericht b ON
            g.erfasser_id   = b.erfasser_id and
            g.datum_akt     = b.datum_akt   and
            g.ber_lfd_nr    = b.lfd_nr
        LEFT OUTER JOIN anschr a ON
            g.adr_gr        = a.adr_gr      and
            g.adr_nr        = a.adr_nr
        LEFT OUTER JOIN person p ON
            g.adr_gr        = p.adr_gr      and
            g.adr_nr        = p.adr_nr      and
            g.person_nr     = p.person_nr
        LEFT OUTER JOIN beriobj o ON
            b.erfasser_id   = o.erfasser_id and
            b.datum_akt     = o.datum_akt   and
            b.lfd_nr        = o.lfd_nr
        LEFT OUTER JOIN briefkas s ON
            b.erfasser_id   = s.erfasser_id and
            b.datum_akt     = s.datum_akt   and
            b.lfd_nr        = s.lfd_nr

GO
create view [dbo].[herkview] (
	herkunft_id, herkunft_typ, beschreibung, gueltig_ab, gueltig_bis,
        b_id_aend, datum_aend)
as

select  h.herkunft_id, h.herkunft_typ, h.beschreibung, h.gueltig_ab, h.gueltig_bis,
        h.b_id_aend, h.datum_aend
from HERKUNFT h

union

select  h.aquell_code, 'ADR', h.herkunft, 
        cast('01.01.2099' as datetime), 
        cast('01.01.2099' as datetime),'      ', 
        cast('01.01.2099' as datetime)
from AQUELLE h

union

select  h.akt_id, 'MAKTIO', h.b_aktid, h.soll_beg, h.soll_ende,
        h.benutzer_id, h.dat_neu
from MHAKTION h

GO
create view [dbo].[hoautueb] (l_titel_nr, autor_nr, adr_gr, adr_nr_aut, person_nr_aut, 
l_ausg_nr, e_mandant, honart_id,verwend_typ_honart, hon_nr, l_aufl_nr, adr_nr_hon, person_nr_hon, kz_pseudo, kz_storno,status, vorschuss, teilabrechnung,dat_neu,
abrech_dat_von, abrech_dat_bis, beleg_nr, beleg_dat, betrag_net, waehrung, artikel_nr)
as select
a.l_titel_nr, a.autor_nr, a.adr_gr, a.adr_nr_aut, a.person_nr_aut,
b.l_ausg_nr, b.e_mandant, b.honart_id, b.verwend_typ_honart, b.hon_nr, b.l_aufl_nr, b.adr_nr, b.person_nr, b.kz_pseudo, b.kz_storno, b.status, b.vorschuss, b.teilabrechnung, b.dat_neu,
b.abrech_dat_von, b.abrech_dat_bis, b.beleg_nr, b.beleg_dat, b.betrag_net, b.waehrung, d.artikel_nr
from buautor a, honorar b, bumanaus d
    where a.l_titel_nr = b.l_titel_nr
    and a.autor_nr = b.autor_nr
    and b.kz_re_ho = 'H'
    and b.l_ausg_nr = d.l_ausg_nr
    and b.e_mandant = d.e_mandant
    and b.kz_zw_abrech = 'F'
union
select
a.l_titel_nr, a.autor_nr, a.adr_gr, a.adr_nr_aut, a.person_nr_aut,
b.l_ausg_nr, b.e_mandant, b.honart_id, e.verwend_typ, 0, null, 0, 0, 'F', 'F', null, null, null, null,
null, null, null, null, null, b.waehrung, d.artikel_nr 
from buautor a, hoautor b, bumanaus d, honart e
    where a.l_titel_nr = b.l_titel_nr
    and a.autor_nr = b.autor_nr
    and b.abr_pro_jahr > 0
    and b.l_ausg_nr = d.l_ausg_nr
    and b.e_mandant = d.e_mandant
    and e.honart_id = b.honart_id
and not exists
(select hon_nr from honorar c
    where b.l_titel_nr = c.l_titel_nr
    and b.l_ausg_nr = c.l_ausg_nr
    and b.autor_nr = c.autor_nr
    and b.honart_id = c.honart_id
    and c.kz_re_ho = 'H'
    and c.kz_zw_abrech = 'F'  
    and b.e_mandant = c.e_mandant)

GO
create view hoautvw (l_titel_nr,autor_nr,l_ausg_nr,e_mandant,honart_id,waehrung,
                     bank_index,adr_gr,adr_nr_aut,person_nr_aut, verwend_typ, abr_pro_jahr, herkunft)
as
select h.l_titel_nr, h.autor_nr, h.l_ausg_nr, h.e_mandant, h.honart_id, h.waehrung,
       h.bank_index, b.adr_gr, b.adr_nr_aut, b.person_nr_aut, a.verwend_typ, h.abr_pro_jahr, g.herkunft
from hoautor h, buautor b, honart a, buausgab g
where h.l_titel_nr = b.l_titel_nr and
      h.l_ausg_nr = g.l_ausg_nr and
      h.autor_nr  = b.autor_nr and
      h.honart_id = a.honart_id and
      not exists (select v.verweistyp from averweis v where
                  v.adr_gr = b.adr_gr and
                  v.adr_nr = b.adr_nr_aut and
                  v.person_nr = b.person_nr_aut and
                  v.verweistyp = 'HONORA' and
                  v.gueltig_ab <= getdate() and 
                  (v.gueltig_bis is null or v.gueltig_bis >= getdate())) 
union
select h.l_titel_nr, h.autor_nr, h.l_ausg_nr, h.e_mandant, h.honart_id, h.waehrung,
       h.bank_index, b.adr_gr, v.adr_nr_verw, v.person_nr_verw, a.verwend_typ, h.abr_pro_jahr, g.herkunft
from hoautor h, buautor b, honart a, averweis v, buausgab g
where h.l_titel_nr = b.l_titel_nr and
      h.l_ausg_nr = g.l_ausg_nr and
      h.autor_nr  = b.autor_nr and
      h.honart_id = a.honart_id and
      v.adr_gr = b.adr_gr and
      v.adr_nr = b.adr_nr_aut and
      v.person_nr = b.person_nr_aut and
      v.verweistyp = 'HONORA' and
      v.gueltig_ab <= getdate() and 
      (v.gueltig_bis is null or v.gueltig_bis >= getdate()) and
      not exists (select w.verweistyp from averweis w where
                  w.adr_gr = b.adr_gr and
                  w.adr_nr = b.adr_nr_aut and
                  w.person_nr = b.person_nr_aut and
                  w.verweistyp = 'HONORA' and
                  w.gueltig_ab <= getdate() and 
                  (w.gueltig_bis is null or w.gueltig_bis >= getdate()) and
                  w.gueltig_ab > v.gueltig_ab)

GO
create view hoburevi
(beleg_nr, beleg_dat, abruf_nr, e_mandant, adr_gr, adr_nr, person_nr, waehrung,
pos_nr, hon_nr, honart_id, verwend_typ_ho, l_titel_nr, l_ausg_nr, l_aufl_nr, autor_nr, 
artikel_nr, titel_such, titel1, beschreibung,
abrech_dat_von, abrech_dat_bis, 
betrag_net_pos, absatz, hon_proz, 
zu_jahr, kz_storno, aufl_dat, n_artikel_nr, prod_typ, grup_id)
as select
a.beleg_nr, a.beleg_dat, a.abruf_nr, a.e_mandant, a.adr_gr, a.adr_nr, a.person_nr, a.waehrung,
b.pos_nr, b.hon_nr, b.honart_id, b.verwend_typ_ho, b.l_titel_nr, b.l_ausg_nr, b.l_aufl_nr, b.autor_nr, 
b.artikel_nr, b.titel_such, b.titel1, b.beschreibung,
b.abrech_dat_von, b.abrech_dat_bis, 
b.betrag_net_pos, b.absatz, b.hon_proz,
coalesce(year(b.abrech_dat_von), year(b.beleg_dat)), c.kz_storno,
coalesce(d.aufl_dat_ist, d.aufl_dat_soll),
isnull(dbo.char2num(b.artikel_nr),0),
e.prod_typ,e.grup_id
from horechn a, horepos b, honorar c, buaufl d, buausgab e
where a.beleg_nr = b.beleg_nr 
and a.beleg_dat = b.beleg_dat 
and a.obj_nr is null 
and b.l_ausg_nr > 0
and c.adr_gr = a.adr_gr
and c.adr_nr = a.adr_nr
and c.person_nr = a.person_nr
and c.hon_nr = b.hon_nr
and d.l_ausg_nr = b.l_ausg_nr
and d.l_aufl_nr = coalesce(b.l_aufl_nr, 0)
and c.kz_pseudo = 'F'
and e.l_ausg_nr = b.l_ausg_nr

GO
