and   a.l_ausg_nr = c.l_ausg_nr
and   a.l_aufl_nr = b.l_aufl_nr
and   b.equip_id  = d.equip_id
and   a.l_ausg_nr = e.l_ausg_nr
and   a.l_aufl_nr = e.l_aufl_nr
and   b.equip_id  = e.equip_id

