CREATE VIEW [dbo].[kondview](lfd_nr, adr_gr, adr_nr, person_nr, e_mandant, obj_nr, ausg, akt_id, abo_kond,
					 a_typ, q_code, q_ausp_code, gueltig_ab, herkunft, 
					 upos_nr, ngruppe, vertreter_id, vertreter_typ, reg_id, reg_code, waehrung,
					 steuer_code, status, landart, betrag, prov_satz, buch_betrag, buch_proz, prov_grp,
					 l_ausg_nr, vertret_auft_typ, kz_sbs_provision, kz_rab_abzug, kz_abo_bringer, kz_mengen_abh)
AS
SELECT 	v.lfd_nr, v.adr_gr, v.adr_nr, v.person_nr, v.e_mandant, v.obj_nr, v.ausg, v.akt_id, v.abo_kond,
		v.a_typ, v.q_code, v.q_ausp_code, v.gueltig_ab, v.herkunft,
		u.upos_nr, u.ngruppe, u.vertreter_id, u.vertreter_typ, u.reg_id, u.reg_code, u.waehrung,
		u.steuer_code, u.status, u.landart, u.betrag, u.prov_satz, u.buch_betrag, u.buch_proz, u.prov_grp,
		u.l_ausg_nr, u.vertret_auft_typ, u.kz_sbs_provision, u.kz_rab_abzug, u.kz_abo_bringer, u.kz_mengen_abh
