create view [dbo].[majobvie]
(jobnr, benutzer_id, jobstatus, jobtyp, hostname, startzeit, jobstart, protokoll,
e_mandant, akt_id, uakt_id)
as select
d.jobnr, d.benutzer_id, d.jobstatus, d.jobtyp, d.hostname, d.startzeit, d.jobstart, d.protokoll,
rtrim(a.wert), rtrim(b.wert), rtrim(c.wert)
from jobtab d
inner join jobparam a on
   a.jobnr = d.jobnr and
   a.lfdnr = 1
inner join jobparam b on
   b.jobnr = d.jobnr and
   b.lfdnr = 7
inner join jobparam c on
   c.jobnr = d.jobnr and
   c.lfdnr = 8
where d.esname = 'VZMA220B'

