create view [dbo].[matnpabo]
(adr_gr, e_mandant, akt_id, uakt_id, adr_nr, person_nr, obj_nr, ausg, abo_nr)
as select  t.adr_gr,t.e_mandant,t.akt_id,t.uakt_id,t.adr_nr,t.person_nr,d.obj_nr,d.ausg,d.abo_nr 
from fdabodat d,fdabruf r, muaktion u, teilnemp t, abostamm a
where u.e_mandant=t.e_mandant and u.akt_id=t.akt_id and u.uakt_id=t.uakt_id
and r.mandant=t.e_mandant and r.w_akt_id=t.akt_id and r.w_uakt_id=t.uakt_id and r.w_start_id=t.start_id
and r.kopie_von_abr=u.fd_abruf_nr
and d.abruf_nr=r.abruf_nr
and ((r.empfaenger = 'L' and d.adr_nr_le= t.adr_nr and d.person_nr_le= t.person_nr) or
     (r.empfaenger = 'R' and d.adr_nr_re= t.adr_nr and d.person_nr_re= t.person_nr) or
     (r.empfaenger = 'P' and d.adr_nr_pr= t.adr_nr and d.person_nr_pr= t.person_nr))
and d.adr_gr=t.adr_gr
and a.e_mandant=t.e_mandant and a.adr_gr=d.adr_gr and a.adr_nr=t.adr_nr and a.person_nr=t.person_nr and a.obj_nr=d.obj_nr and a.ausg=d.ausg and a.abo_nr=d.abo_nr

GO
create view [dbo].[mavbview] (
	e_mandant, akt_id, uakt_id, modul, l_ausg_nr, l_ausg_nr_ma, l_aufl_nr)
as
select e_mandant, akt_id, uakt_id, modul, l_ausg_nr, 0, -1
from MUAKTOBJ o
where l_ausg_nr > 0
union
select e_mandant, akt_id, uakt_id, 'BU', l_ausg_nr_zu, l_ausg_nr, -1
from MHAKTIZU z
union
select v.e_mandant, v.akt_id, v.uakt_id, 'VZ', a.l_ausg_nr, 0, a.l_aufl_nr
from AKTVORB v, AKTVORBA a
where v.e_mandant = a.e_mandant 
and v.akt_id = a.akt_id
and v.obj_nr = a.obj_nr
and v.ausg = a.ausg

