create view [dbo].[mazykvie] 
(haupt_nr,e_mandant, akt_id, uakt_id, kz_aktiv)
as
select a.haupt_nr, substring(b.wert,1,2), substring(c.wert,1,12), substring(d.wert,1,4), 'T'
from zykhaupt a, zykparam b, zykparam c, zykparam d
where a.haupt_nr = b.haupt_nr 
and b.folge_nr = 0
and b.lfdnr = 1
and a.haupt_nr = c.haupt_nr 
and c.folge_nr = 0
and c.lfdnr = 7
and a.haupt_nr = d.haupt_nr
and d.folge_nr = 0
and d.lfdnr = 8
and a.esname = 'VZMA220B'
and ((a.art = 'W' and (so = 'T' or mo = 'T' or di = 'T' or mi = 'T' or do = 'T' or fr = 'T' or sa = 'T'))
     or (a.art = 'M' and (tag is not null or wochentag is not null)))
union
select a.haupt_nr, substring(b.wert,1,2), substring(c.wert,1,12), substring(d.wert,1,4), 'F'
from zykhaupt a, zykparam b, zykparam c, zykparam d
where a.haupt_nr = b.haupt_nr 
and b.folge_nr = 0
and b.lfdnr = 1
and a.haupt_nr = c.haupt_nr 
and c.folge_nr = 0
and c.lfdnr = 7
and a.haupt_nr = d.haupt_nr
and d.folge_nr = 0
and d.lfdnr = 8
and a.esname = 'VZMA220B'
and (not((a.art = 'W' and (so = 'T' or mo = 'T' or di = 'T' or mi = 'T' or do = 'T' or fr = 'T' or sa = 'T'))
     or (a.art = 'M' and (tag is not null or wochentag is not null))) or a.art is null)

