create view [dbo].[menuview] (pos, kopf, ktyp, kbeschreibung,
              ptyp, pbeschreibung, paufruf, plog_es, sortierung)
  as
select pos.knotenid, kopf.knotenid, kopf.knotentyp, kopf.beschreibung,
       pos.knotentyp, pos.beschreibung, pos.aufruf, pos.log_es_name,
       kante.sortierung
  from menue kopf, menuverb kante, menue pos
 where kopf.knotentyp = 'M'
   and kopf.knotenid = kante.menunr
   and kante.menupnr = pos.knotenid
union
select favor.knotenid, -1, 'M', 
       favor.benutzer_id+'                        ',
       m.knotentyp, favor.beschreibung, m.aufruf, m.log_es_name,
       favor.sortierung
  from menufavo favor, menue m
 where favor.knotenid = m.knotenid

