create view [dbo].[mpaktvie] 
(adr_gr, adr_nr, person_nr, 
vorname, nachname, 
land_code, haupt_name, haupt_plz, haupt_ort,
e_mandant, akt_id, uakt_id,l_ausg_nr, l_aufl_nr, gueltig_ab,
l_titel_nr,
artikel_nr,
adr_nr_va, 
land_code_va, haupt_name_va, haupt_plz_va,haupt_ort_va, name1_va, name2_va, name3_va)
as 
select 
b.adr_gr, b.adr_nr_aut, b.person_nr_aut, 
c.vorname, c.nachname, 
d.land_code, d.haupt_name, d.haupt_plz, d.haupt_ort,
a.e_mandant, a.akt_id, a.uakt_id,a.l_ausg_nr, a.l_aufl_nr, a.gueltig_ab,
f.l_titel_nr,
i.artikel_nr,
g.adr_nr,
h.land_code, h.haupt_name, h.haupt_plz, h.haupt_ort,h.name1, h.name2, h.name3
from muaktva a
   inner join buausgab f on
   a.l_ausg_nr = f.l_ausg_nr and
   f.kz_loeschen = 'F'
      left outer join busperr k on
      k.sperr_grund = f.sperr_grund and
      k.sperre_fuer != 'A'
      inner join buautor b on
      b.l_titel_nr = f.l_titel_nr and
      b.kz_hpaut = 'T'
         inner join person c on
         c.adr_gr = b.adr_gr and
         c.adr_nr = b.adr_nr_aut and
         c.person_nr = b.person_nr_aut
            inner join anschr d on
            d.adr_gr = c.adr_gr and
            d.adr_nr = c.adr_nr
   inner join bumanaus i on
   i.l_ausg_nr = a.l_ausg_nr and
   i.e_mandant = a.e_mandant and
   i.kz_loeschen = 'F'
   left outer join buliefer g on
   g.l_ausg_nr = a.l_ausg_nr 
      left outer join anschr h on
      h.adr_gr = g.adr_gr and
      h.adr_nr = g.adr_nr
where not exists 
(select x.l_ausg_nr from
muaktva x where
x.l_ausg_nr = a.l_ausg_nr and
x.l_aufl_nr = a.l_aufl_nr and
x.gueltig_ab > a.gueltig_ab and
x.gueltig_ab <= getdate())

GO
create view [dbo].[muakervi]
(e_mandant, akt_id, uakt_id, b_uaktid, kz_ef, id_vuakt, kz_lwied, n_vakt, soll_start, list_start,
tn_code, kz_alsteu, kz_fortlaufend, soll_ende,
akt_code, b_aktid, soll_beg_h, soll_ende_h, ist_ende_h, modul,
er_code, verwend_typ, verwend_typ_2, bez_er, anz_folgeakt, benutzer_id_h, abruf_art)
as select
u.e_mandant, u.akt_id, u.uakt_id, u.b_uaktid, u.kz_ef, u.id_vuakt, u.kz_lwied, u.n_vakt,
u.soll_start, u.list_start, u.tn_code, u.kz_alsteu, u.kz_fortlaufend, u.soll_ende,
h.akt_code, h.b_aktid, h.soll_beg, h.soll_ende, h.ist_ende, h.modul,
u.er_code, e.verwend_typ, e.verwend_typ_2, e.bez, 
(select count(*) from muaktion f where 
 f.e_mandant = u.e_mandant and
 f.akt_id = u.akt_id and
 f.id_vuakt = u.uakt_id),
h.benutzer_id, u.abruf_art
from muaktion u
  inner join  mhaktion h on
  h.e_mandant = u.e_mandant and
  h.akt_id = u.akt_id
  inner join ereignis e on
  e.er_code = u.er_code
  where u.er_code is not null
union
select
u.e_mandant, u.akt_id, u.uakt_id, u.b_uaktid, u.kz_ef, u.id_vuakt, u.kz_lwied, u.n_vakt,
u.soll_start, u.list_start, u.tn_code, u.kz_alsteu, u.kz_fortlaufend, u.soll_ende,
h.akt_code, h.b_aktid, h.soll_beg, h.soll_ende, h.ist_ende, h.modul,
r.er_code, e.verwend_typ, e.verwend_typ_2, e.bez, 
(select count(*) from muaktion f where 
 f.e_mandant = u.e_mandant and
 f.akt_id = u.akt_id and
 f.id_vuakt = u.uakt_id),
h.benutzer_id, u.abruf_art
from muaktion u
  inner join  mhaktion h on
  h.e_mandant = u.e_mandant and
  h.akt_id = u.akt_id
  inner join respvorg r on
  r.e_mandant = u.e_mandant and
  r.akt_id = u.akt_id and
  r.uakt_id = u.uakt_id
  inner join ereignis e on
  e.er_code = r.er_code
where u.er_code is null

GO
create view [dbo].[muaktivi]
(e_mandant, akt_id, uakt_id, start_id, kz_ef, er_code, adr_gr, adr_nr,person_nr)
as select
u.e_mandant, u.akt_id, u.uakt_id, t.start_id, u.kz_ef, u.er_code, t.adr_gr, t.adr_nr,t.person_nr
from muaktion u
inner join teilnemp t on
  t.e_mandant = u.e_mandant and
  t.akt_id = u.akt_id and
  t.uakt_id = u.uakt_id
where er_code is not null
union
select
u.e_mandant, u.akt_id, u.uakt_id, t.start_id, u.kz_ef, r.er_code, t.adr_gr, t.adr_nr,t.person_nr
from muaktion u
inner join teilnemp t on
  t.e_mandant = u.e_mandant and
  t.akt_id = u.akt_id and
  t.uakt_id = u.uakt_id
  inner join respvorg r on
  r.e_mandant = u.e_mandant and
  r.akt_id = u.akt_id and
  r.f_uakt_id = u.uakt_id
  inner join ereignis e on
  e.er_code = r.er_code
where u.er_code is null and t.start_id <> 9999 and 
  (e.verwend_typ = 'VZ' or 
   e.verwend_typ = 'BU' or 
   ((e.verwend_typ = 'WERBEH') and (e.verwend_typ_2 = 'PH' or e.verwend_typ_2 = 'INTER')) or
   e.verwend_typ = 'SONS')

