create view [dbo].[multipvi] 
(e_mandant, l_ausg_nr, l_aufl_nr, l_titel_nr, autor_nr, adr_gr, adr_nr_aut, person_nr_aut, 
bu_la_id, kz_aufl_best, vertreter_id, sach_grp, adr_nr_li)
as 
select m.e_mandant, a.l_ausg_nr, f.l_aufl_nr, a.l_titel_nr, 
b.autor_nr, b.adr_gr, b.adr_nr_aut, b.person_nr_aut,
a.bu_la_id, a.kz_aufl_best, m.vertreter_id, g.sach_grp, l.adr_nr
from buausgab a
inner join buautor b on
b.l_titel_nr = a.l_titel_nr and
b.kz_hpaut = 'T'
inner join bumanaus m on
m.l_ausg_nr = a.l_ausg_nr
inner join buaufl f on
f.l_ausg_nr = a.l_ausg_nr and
f.l_aufl_nr = 0
left outer join bugruppe g on
g.l_titel_nr = a.l_titel_nr
left outer join buliefer l on
l.l_ausg_nr = a.l_ausg_nr 
where a.herkunft = 'VA' and
a.kz_aufl_best = 'F'
union
select m.e_mandant, a.l_ausg_nr, f.l_aufl_nr, a.l_titel_nr, 
b.autor_nr, b.adr_gr, b.adr_nr_aut, b.person_nr_aut,
a.bu_la_id, a.kz_aufl_best, m.vertreter_id, g.sach_grp, l.adr_nr
from buausgab a
inner join buautor b on
b.l_titel_nr = a.l_titel_nr and
b.kz_hpaut = 'T'
inner join bumanaus m on
m.l_ausg_nr = a.l_ausg_nr
inner join buaufl f on
f.l_ausg_nr = a.l_ausg_nr and
f.l_aufl_nr > 0
left outer join bugruppe g on
g.l_titel_nr = a.l_titel_nr
left outer join buliefer l on
l.l_ausg_nr = a.l_ausg_nr 
where a.herkunft = 'VA' and
a.kz_aufl_best = 'T'

