create view newsview
      (adr_gr, adr_nr, person_nr, tel_art, wm_code, hist_nr, b_id_neu, datum_neu, b_id_aend, datum_aend,
       opt_in, gueltig_ab, gueltig_bis, k_grund, validitaet, eingang_kuend, nummer, verw_id)
