create view portzuvw (e_mandant, portal_id, port_ber_id, port_zugr_nr, port_zugr_ben_nr, gueltig_ab, gueltig_bis, ber_typ, 
              adr_gr, adr_nr, person_nr, obj_nr, ausg, abo_nr, auft_nr, auf_pos, l_titel_nr, beitrag_id, verb_code, 
              uverb_code, beitrag_name, beitrag_url, benutzername, e_mail, ip_von, ip_bis, adr_nr_ben, person_nr_ben, 
              mitglieds_nr, passwort_valg_1, passwort_valg_2, passwort_valg_3, gueltig_bis_ip, kz_agb, kz_passw_aend, kz_bestaet_email)
  as
select r.e_mandant, r.portal_id, r.port_ber_id, r.port_zugr_nr, b.port_zugr_ben_nr, r.gueltig_ab, r.gueltig_bis, r.ber_typ,
       b.adr_gr, r.adr_nr, r.person_nr, r.obj_nr, r.ausg, r.abo_nr, r.auft_nr, r.auf_pos, r.l_titel_nr, r.beitrag_id, r.verb_code, 
       r.uverb_code, r.beitrag_name, r.beitrag_url, b.benutzername, b.e_mail, (case when i.ip_von is Null then '000.000.000.000' else i.ip_von end), 
       (case when i.ip_bis is Null then '000.000.000.000' else i.ip_bis end), b.adr_nr, b.person_nr, 
       b.mitglieds_nr, b.passwort_valg_1, b.passwort_valg_2, b.passwort_valg_3, b.gueltig_bis_ip, b.kz_agb, b.kz_passw_aend, 
       b.kz_bestaet_email
from portzugr r, portal p, portzugb b LEFT OUTER JOIN portzuip i ON
      i.e_mandant    = b.e_mandant and
      i.portal_id    = b.portal_id  and 
      i.port_ber_id  = b.port_ber_id  and 
      i.port_zugr_nr = b.port_zugr_nr and
      i.port_zugr_ben_nr = b.port_zugr_ben_nr
where b.e_mandant    = r.e_mandant and
      b.portal_id    = r.portal_id  and 
      b.port_ber_id  = r.port_ber_id  and 
      b.port_zugr_nr = r.port_zugr_nr and
      r.ber_typ      = 'ABO' and
      b.e_mandant    = p.e_mandant and
      b.portal_id    = p.portal_id  and 
      p.kz_abo = 'T'
union
select r.e_mandant, r.portal_id, r.port_ber_id, r.port_zugr_nr, b.port_zugr_ben_nr, r.gueltig_ab, r.gueltig_bis, r.ber_typ,
       b.adr_gr, r.adr_nr, r.person_nr, r.obj_nr, r.ausg, r.abo_nr, r.auft_nr, r.auf_pos, r.l_titel_nr, r.beitrag_id, r.verb_code, 
       r.uverb_code, r.beitrag_name, r.beitrag_url, b.benutzername, b.e_mail, (case when i.ip_von is Null then '000.000.000.000' else i.ip_von end), 
       (case when i.ip_bis is Null then '000.000.000.000' else i.ip_bis end), b.adr_nr, b.person_nr, 
       b.mitglieds_nr, b.passwort_valg_1, b.passwort_valg_2, b.passwort_valg_3, b.gueltig_bis_ip, b.kz_agb, b.kz_passw_aend, 
       b.kz_bestaet_email
from portzugr r, portal p, portzugb b LEFT OUTER JOIN portzuip i ON
      i.e_mandant    = b.e_mandant and
      i.portal_id    = b.portal_id  and 
      i.port_ber_id  = b.port_ber_id  and 
      i.port_zugr_nr = b.port_zugr_nr and
      i.port_zugr_ben_nr = b.port_zugr_ben_nr
where b.e_mandant    = r.e_mandant and
      b.portal_id    = r.portal_id  and 
      b.port_ber_id  = r.port_ber_id  and 
      b.port_zugr_nr = r.port_zugr_nr and
      r.ber_typ      = 'BUCH' and
      b.e_mandant    = p.e_mandant and
      b.portal_id    = p.portal_id  and 
      p.kz_buch = 'T'
union
select r.e_mandant, r.portal_id, r.port_ber_id, r.port_zugr_nr, b.port_zugr_ben_nr, r.gueltig_ab, r.gueltig_bis, r.ber_typ,
       b.adr_gr, r.adr_nr, r.person_nr, r.obj_nr, r.ausg, r.abo_nr, r.auft_nr, r.auf_pos, r.l_titel_nr, r.beitrag_id, r.verb_code, 
       r.uverb_code, r.beitrag_name, r.beitrag_url, b.benutzername, b.e_mail, (case when i.ip_von is Null then '000.000.000.000' else i.ip_von end), 
       (case when i.ip_bis is Null then '000.000.000.000' else i.ip_bis end), b.adr_nr, b.person_nr, 
       b.mitglieds_nr, b.passwort_valg_1, b.passwort_valg_2, b.passwort_valg_3, b.gueltig_bis_ip, b.kz_agb, b.kz_passw_aend, 
       b.kz_bestaet_email
from portzugr r, portal p, portzugb b LEFT OUTER JOIN portzuip i ON
      i.e_mandant    = b.e_mandant and
      i.portal_id    = b.portal_id  and 
      i.port_ber_id  = b.port_ber_id  and 
      i.port_zugr_nr = b.port_zugr_nr and
      i.port_zugr_ben_nr = b.port_zugr_ben_nr
where b.e_mandant    = r.e_mandant and
      b.portal_id    = r.portal_id  and 
      b.port_ber_id  = r.port_ber_id  and 
      b.port_zugr_nr = r.port_zugr_nr and
      r.ber_typ      = 'MIT' and
      b.e_mandant    = p.e_mandant and
      b.portal_id    = p.portal_id  and 
      p.kz_mitglied = 'T'
union
select r.e_mandant, r.portal_id, r.port_ber_id, r.port_zugr_nr, b.port_zugr_ben_nr, r.gueltig_ab, r.gueltig_bis, r.ber_typ,
       b.adr_gr, r.adr_nr, r.person_nr, r.obj_nr, r.ausg, r.abo_nr, r.auft_nr, r.auf_pos, r.l_titel_nr, r.beitrag_id, r.verb_code, 
       r.uverb_code, r.beitrag_name, r.beitrag_url, b.benutzername, b.e_mail, (case when i.ip_von is Null then '000.000.000.000' else i.ip_von end), 
       (case when i.ip_bis is Null then '000.000.000.000' else i.ip_bis end), b.adr_nr, b.person_nr, 
       b.mitglieds_nr, b.passwort_valg_1, b.passwort_valg_2, b.passwort_valg_3, b.gueltig_bis_ip, b.kz_agb, b.kz_passw_aend, 
       b.kz_bestaet_email
from portzugr r, portal p, portzugb b LEFT OUTER JOIN portzuip i ON
      i.e_mandant    = b.e_mandant and
      i.portal_id    = b.portal_id  and 
      i.port_ber_id  = b.port_ber_id  and 
      i.port_zugr_nr = b.port_zugr_nr and
      i.port_zugr_ben_nr = b.port_zugr_ben_nr
where b.e_mandant    = r.e_mandant and
      b.portal_id    = r.portal_id  and 
      b.port_ber_id  = r.port_ber_id  and 
      b.port_zugr_nr = r.port_zugr_nr and
      r.ber_typ      = 'SONS' and
      b.e_mandant    = p.e_mandant and
      b.portal_id    = p.portal_id  and 
      p.kz_mitglied = 'T'
union
select r.e_mandant, r.portal_id, r.port_ber_id, r.port_zugr_nr, b.port_zugr_ben_nr, r.gueltig_ab, r.gueltig_bis, r.ber_typ,
       b.adr_gr, r.adr_nr, r.person_nr, r.obj_nr, r.ausg, r.abo_nr, r.auft_nr, r.auf_pos, r.l_titel_nr, r.beitrag_id, r.verb_code, 
       r.uverb_code, r.beitrag_name, r.beitrag_url, b.benutzername, b.e_mail, (case when i.ip_von is Null then '000.000.000.000' else i.ip_von end), 
       (case when i.ip_bis is Null then '000.000.000.000' else i.ip_bis end), b.adr_nr, b.person_nr, 
       b.mitglieds_nr, b.passwort_valg_1, b.passwort_valg_2, b.passwort_valg_3, b.gueltig_bis_ip, b.kz_agb, b.kz_passw_aend, 
       b.kz_bestaet_email
from portzugr r, portal p, portzugb b LEFT OUTER JOIN portzuip i ON
      i.e_mandant    = b.e_mandant and
      i.portal_id    = b.portal_id  and 
      i.port_ber_id  = b.port_ber_id  and 
