create view [dbo].[prodview] 
       (produkt, wb_id, hgrp_id, ugrp_id, bez_prod,
        bez_ugrp, verwend_typ, bez_hgrp, bez_wber)
as
select p.produkt, p.wb_id, p.hgrp_id, p.ugrp_id, p.bez,
	 u.bez, u.verwend_typ, h.bez, w.bez
from PRODUKT p, UGRUPPE u, HAUPTGRP h, WBEREICH w
