create view [dbo].[qualview] (adr_gr, adr_nr, person_nr, a_typ, q_code, q_ausp_code,
	herkunft_id, status, datum, fkt_bereich, produkt, wb_id, hgrp_id,
	ugrp_id, adr_nr_wt, suchfeld, bezeichnung)
as
select q.adr_gr, q.adr_nr, q.person_nr, q.a_typ, q.q_code, q.q_ausp_code, q.herkunft_id, q.status,
	coalesce(q.datum_aend,q.datum_neu), '   ', '         ', '   ', '   ', '   ', 0,
	q.q_code+q.q_ausp_code, a.q_auspraeg
from QWERTE q LEFT OUTER JOIN QAUSP a ON
q.adr_gr = a.adr_gr
and   q.a_typ  = a.a_typ
and   q.q_code = a.q_code
and   q.q_ausp_code = a.q_ausp_code
union
select f.adr_gr, f.adr_nr, f.person_nr, 'M', '    ', '        ', '            ', '  ',
	f.datum_neu, f.fkt_bereich, '         ', '   ', '   ', '   ', 0,
      f.fkt_bereich, b.beschreibung
from FKTPERSON f, FKTBER b
where f.fkt_bereich = b.fkt_bereich
union
select wt.adr_gr, wt.adr_nr, 0, pe.a_typ, '    ', '        ',
	wt.herkunft_id, '  ', wt.datum_neu, '   ',
      wt.produkt, p.wb_id, p.hgrp_id, p.ugrp_id, 0, wt.produkt, p.bez
from WTPROD wt, PRODUKT p, PERSON pe
where	wt.produkt   = p.produkt
and 	wt.adr_gr    = pe.adr_gr
and 	wt.adr_nr    = pe.adr_nr
and 	pe.person_nr = 0
and     wt.datum_aend is null
and     (wt.kz_loesch = 'F'
or     wt.kz_loesch is null)
union
select wt.adr_gr, wt.adr_nr, 0, pe.a_typ, '    ', '        ',
	wt.herkunft_id, '  ', wt.datum_aend, '   ',
      wt.produkt, p.wb_id, p.hgrp_id, p.ugrp_id, 0, wt.produkt, p.bez
from WTPROD wt, PRODUKT p, PERSON pe
where	wt.produkt   = p.produkt
and 	wt.adr_gr    = pe.adr_gr
and 	wt.adr_nr    = pe.adr_nr
and 	pe.person_nr = 0
and     wt.datum_aend is not null
and     (wt.kz_loesch = 'F'
or     wt.kz_loesch is null)
union
select wa.adr_gr, wa.adr_nr_wa, 0, pe.a_typ, '    ', '        ',
	wt.herkunft_id, '  ', wt.datum_neu, '   ',
      wa.produkt, p.wb_id, p.hgrp_id, p.ugrp_id, wt.adr_nr, wa.produkt, p.bez
from WAFKTZU wa, PRODUKT p, WTPROD wt, PERSON pe
where	wa.produkt    = p.produkt
and	wa.adr_gr     = wt.adr_gr
and	wa.adr_nr     = wt.adr_nr
and 	wa.produkt    = wt.produkt
and 	wa.adr_gr     = pe.adr_gr
and 	wa.adr_nr_wa  = pe.adr_nr
and 	pe.person_nr = 0
and     wt.datum_aend is null
and     (wt.kz_loesch = 'F'
or     wt.kz_loesch is null)
union
select wa.adr_gr, wa.adr_nr_wa, 0, pe.a_typ, '    ', '        ',
	wt.herkunft_id, '  ', wt.datum_aend, '   ',
      wa.produkt, p.wb_id, p.hgrp_id, p.ugrp_id, wt.adr_nr, wa.produkt, p.bez
from WAFKTZU wa, PRODUKT p, WTPROD wt, PERSON pe
where	wa.produkt    = p.produkt
and	wa.adr_gr     = wt.adr_gr
and	wa.adr_nr     = wt.adr_nr
and 	wa.produkt    = wt.produkt
and 	wa.adr_gr     = pe.adr_gr
and 	wa.adr_nr_wa  = pe.adr_nr
and 	pe.person_nr = 0
and     wt.datum_aend is not null
and     (wt.kz_loesch = 'F'
or     wt.kz_loesch is null)

GO
create view [dbo].[rechview] (
	rech_nr, rech_datum, adr_gr, adr_nr_rech, adr_nr_best, fakt_mandant,
	bereich, rech_typ, vorzeichen, zahl_bed, waehrung,
	netto_betrag, mwst_betrag, rech_betrag, mwst_satz, mwst_satz2,
	vorgang_nr, obj_nr, ausg, etikett_1, etikett_2, etikett_3, etikett_4, 
        etikett_5, etikett_6, etikett_7, etikett_8, etikett_9, etikett_10,
        land_code, ust_id_nr)
as
select 	r.rech_nr, r.re_dat, r.adr_gr, r.adr_nr_re, 0, r.fibu_mandant,
	'VZ', r.buch_art, 1, r.z_bed, r.waehrung,
	abs(r.sum_betr_net), 
	abs(r.summwstb1)+abs(r.summwstb2)+abs(r.summwstb3), 
	abs(r.sum_betr_br), r.mwst_proz1, r.mwst_proz2,
	0, '', '', r.anschr1, r.anschr2, r.anschr3, 
        r.anschr4, r.anschr5, r.anschr6, r.anschr7, r.anschr8,
        r.anschr9, r.anschr10, 
        a.land_code, i.eg_ust_nr
from FAKSTAMM r left OUTER join AINFO i on
      r.kopie_nr=0 and r.buch_art = 'S' and
      r.adr_gr = i.adr_gr and r.adr_nr_re = i.adr_nr,
      ANSCHR a
where r.adr_gr = a.adr_gr and r.adr_nr_re = a.adr_nr
union
select 	r.rech_nr, r.re_dat, r.adr_gr, r.adr_nr_re, 0, r.fibu_mandant,
	'VZ', r.buch_art, -1, r.z_bed, r.waehrung,
	abs(r.sum_betr_net), 
	abs(r.summwstb1)+abs(r.summwstb2)+abs(r.summwstb3), 
	abs(r.sum_betr_br), r.mwst_proz1, r.mwst_proz2,
	0, '', '', r.anschr1, r.anschr2, r.anschr3, 
        r.anschr4, r.anschr5, r.anschr6, r.anschr7, r.anschr8,
        r.anschr9, r.anschr10, 
        a.land_code, i.eg_ust_nr
from FAKSTAMM r left OUTER join AINFO i on
      r.kopie_nr=0 and r.buch_art = 'H' and
      r.adr_gr = i.adr_gr and r.adr_nr_re = i.adr_nr,
      ANSCHR a
where r.adr_gr = a.adr_gr and r.adr_nr_re = a.adr_nr
union
select 	r.rech_nr, r.rech_dat, r.adr_gr, r.adr_nr_e, 0, r.f_mandant,
	'BU', r.rech_typ, 1, r.zahlbed, r.waehrung,
	r.re_netto, r.re_mwst, r.re_brutto, r.mw_proz_1, r.mw_proz_2,
	0, '', '', r.eti_1_e, r.eti_2_e, r.eti_3_e, 
        r.eti_4_e, r.eti_5_e, r.eti_6_e, r.eti_7_e, r.eti_8_e,
        r.eti_9_e, r.eti_10_e, 
        a.land_code, i.eg_ust_nr
from BUFAKST r left OUTER join AINFO i on
      r.rech_typ like 'R%' and not
      (r.rech_typ = 'RO' and r.r_art = 'P') and
      r.adr_gr = i.adr_gr and r.adr_nr_e = i.adr_nr,
      ANSCHR a
where r.adr_gr = a.adr_gr and r.adr_nr_e = a.adr_nr
union
select 	r.rech_nr, r.rech_dat, r.adr_gr, r.adr_nr_e, 0, r.f_mandant,
	'BU', r.rech_typ, -1, r.zahlbed, r.waehrung,
	r.re_netto, r.re_mwst, r.re_brutto, r.mw_proz_1, r.mw_proz_2,
	0, '', '', r.eti_1_e, r.eti_2_e, r.eti_3_e, 
        r.eti_4_e, r.eti_5_e, r.eti_6_e, r.eti_7_e, r.eti_8_e, 
        r.eti_9_e, r.eti_10_e, 
        a.land_code, i.eg_ust_nr
from BUFAKST r left OUTER join AINFO i on
      r.rech_typ like 'G%' and
      r.adr_gr = i.adr_gr and r.adr_nr_e = i.adr_nr,
      ANSCHR a
where r.adr_gr = a.adr_gr and r.adr_nr_e = a.adr_nr
union
select 	r.rech_nr, r.rech_datum, r.adr_gr, r.rech_empf, r.adr_nr, r.f_mandant,
	'EA', r.rech_typ, r.vorzeichen, r.z_bed_id, r.waehrung,
	r.wa_netto_betrag, r.mwst_betrag, r.rech_betrag, r.mwst_satz, 0,
	0, r.obj_nr, r.ausg, r.adresse_1, r.adresse_2, r.adresse_3, 
        r.adresse_4, r.adresse_5, r.adresse_6, r.adresse_7, r.adresse_8,
        '', '', 
        a.land_code, i.eg_ust_nr
from RECHNUNG r left OUTER join AINFO i on
      r.adr_gr = i.adr_gr and r.rech_empf = i.adr_nr,
      ANSCHR a
where r.adr_gr = a.adr_gr and r.rech_empf = a.adr_nr

GO
CREATE VIEW reklview  (erfasser_id, datum_akt, lfd_nr, adr_gr, adr_nr, 
                     person_nr, verfasser_id, betreff, datum_bes, text_nr,
                     datum_wv_verf, reklagrund, status, datum_zwi, datum_erled,
                     kosten, eingangs_art, reaktions_id, vorgang_typ, vorgang_key,
                     vorgang_nr, pos_nr, e_mandant, artikel_nr, auflage_nr, verlags_id)
AS SELECT  r.erfasser_id, r.datum_akt, r.lfd_nr, b.adr_gr, b.adr_nr, 
                     b.person_nr, b.verfasser_id, b.betreff, b.datum_bes, b.text_nr,
                     s.datum_wv, r.reklagrund, r.status, r.datum_zwi, r.datum_erled,
                     r.kosten, r.eingangs_art, r.reaktions_id, r.vorgang_typ, r.vorgang_key,
                     r.vorgang_nr, p.pos_nr, p.e_mandant, p.artikel_nr, p.auflage_nr, p.verlags_id
FROM bericht b LEFT OUTER JOIN briefkas s ON
      b.erfasser_id  = s.erfasser_id and
      b.datum_akt    = s.datum_akt and
      b.lfd_nr       = s.lfd_nr and 
      b.verfasser_id = s.benutzer_id 
      , REKLA r LEFT OUTER JOIN REKLAPOS P ON 
           r.erfasser_id  = p.erfasser_id and
           r.datum_akt    = p.datum_akt and
           r.lfd_nr       = p.lfd_nr
WHERE r.erfasser_id = b.erfasser_id and
               r.datum_akt = b.datum_akt and
               r.lfd_nr = b.lfd_nr

GO
create view [dbo].[respview]  (e_mandant, akt_id, uakt_id, kz_ef, bez_1, er_code, f_uakt_id, bez_2)
as select
a.e_mandant, a.akt_id, a.uakt_id, a.kz_ef, a.b_uaktid, b.er_code, b.f_uakt_id, c.b_uaktid
from  muaktion a
  LEFT OUTER JOIN respvorg b ON
     b.akt_id = a.akt_id and
     b.uakt_id = a.uakt_id
