create view sapcview
(adr_gr,adr_nr, person_nr, haupt_name, haupt_plz, haupt_ort,
       name1, name2, plz_wohn, plz_post, land_code, f_typ,firmkz_id,wohnort,
       kz_loeschen, a_typ, nachname, vorname, titel_code, anrede_code, anz_auft, anz_abo,
       tel_zentrale)
AS
