       a.name1, a.name2, a.plz_wohn, a.plz_post, a.land_code, a.f_typ, a.firmkz_id,
       a.wohnort,p.kz_loeschen, p.a_typ, p.nachname, p.vorname, p.titel_code, p.anrede_code,
       -1, -1, '                                                            '
FROM   anschr a, person p
WHERE  a.adr_gr        = p.adr_gr
AND    a.adr_nr        = p.adr_nr 

