create VIEW sapnview
      (adr_gr,adr_nr, person_nr, haupt_name, haupt_plz, haupt_ort,
       name1, name2, plz_wohn, strasse, hausnr, strasse2, hausnr_zus, 
       plz_post, postfach, postort, land_code, f_typ, firmkz_id, genfilt_id, 
       wohnort, bezirk_id, kz_loeschen, a_typ, 
       nachname, vorname, n_zusatz,
       titel_code, anrede_code, privat_adr_nr,
       anz_auft, anz_fliess, anz_abo, anz_buch, aquell_code, abteilung, kz_dubl,
       plz_gk, gkort, name3, konzern_id, verlber_id, kgs_bl, nielsen_id,
       sprach_code, position, bemerkung, versand_adr)
AS
select a.adr_gr, a.adr_nr, p.person_nr, a.haupt_name, a.haupt_plz, a.haupt_ort,
       a.name1, a.name2, a.plz_wohn, a.strasse, a.hausnr, a.strasse2, a.hausnr_zus, 
       a.plz_post, a.postfach, a.postort, a.land_code, a.f_typ, a.firmkz_id, a.genfilt_id,
       a.wohnort, a.bezirk_id, p.kz_loeschen, p.a_typ, p.nachname, p.vorname, p.n_zusatz,
       p.titel_code, p.anrede_code, p.privat_adr_nr,
       -1 ,-1 , -1, -1, a.aquell_code, p.abteilung, a.kz_dubl, a.plz_gk, a.gkort,
       a.name3, a.konzern_id, a.verlber_id, a.kgs_bl, a.nielsen_id,
       p.sprach_code, p.position, p.bemerkung, a.versand_adr
from   anschr a, person p
where  p.adr_gr            = a.adr_gr
AND    p.adr_nr            = a.adr_nr 

