create view [dbo].[selaspvi] (adr_gr, adr_nr, person_nr, e_mandant,  tabname, 
       asperr_code, asperr_von, asperr_bis)
as
select b.adr_gr, b.adr_nr, 0, b.e_mandant, 'BUKUNDEN',
       b.asperr_code, convert(datetime,'01.01.1900',104), convert(datetime,'31.12.2099',104)
from bukunden b
union
select p.adr_gr, p.adr_nr, p.person_nr, 'P_', 'PERSON',
       p.sperrgrund, convert(datetime,'01.01.1900',104), convert(datetime,'31.12.2099',104)
from person p
union
select a.adr_gr, a.adr_nr, 0, 'A_', 'AINFO',
       a.asperr_code, a.abosperr_von, a.abosperr_bis
from ainfo a

GO
create view [dbo].[selmodvi] (benutzer_id, sel_id, wakt,
	tabname_vors, feldname_vors,
	tabname_filt, feldname_filt, modul)
as
select s.benutzer_id, s.sel_id, s.wakt,
	v.tabellenname, v.feldname,
	f.tabellenname, f.feldname, f.modul
from SELVERWA s, SVORSCHR v LEFT OUTER JOIN SELFILT f ON
		v.tabellenname COLLATE Latin1_General_CI_AS = f.tabellenname
		and v.feldname COLLATE Latin1_General_CI_AS = f.feldname
where s.benutzer_id = v.benutzer_id COLLATE Latin1_General_CI_AS
and   s.sel_id = v.sel_id

