create view tagview 
       (adr_gr, adr_nr, auft_nr, auft_hist_nr, dispo_nr, dispo_hist_nr,
        dispopos_nr, e_mandant, bank_satz_nr, obj_nr, ausg, abrech_id, 
        anzart_id, anzeigen_preis, anz_abo_si, anz_mm, anz_eintrag, anz_si,
        anz_schaltung, anz_sp, anz_zeilen, bdatum, binfo, bzeichen, b_id_aend,
        b_id_neu, druck_id, farb_id, format_id, kombi_rabatt, sonder_rabatt,
        status, volumen_rabatt, wa_prov_satz, aktion, kz_best, versandart,
        prodname, dunterlagen, hnr, jahr, hnr_num, plaz_ext, lfd_nr, anz_belegung,
        bezeichnung, kz_preis_unbekannt, datum_neu, datum_aend, motiv, abw_prod_bez,
        bez_si, dunt_id, status_dispopos, anz_anzeigen)
 as select p.adr_gr, p.adr_nr, p.auft_nr, p.auft_hist_nr, p.dispo_nr, p.dispo_hist_nr,
       p.dispopos_nr, p.e_mandant, d.bank_satz_nr, p.obj_nr, p.ausg, d.abrech_id, 
       d.anzart_id, d.anzeigen_betrag, d.anz_abo_si, d.anz_mm, d.anz_eintrag, 
       d.anz_si, d.anz_schaltung, d.anz_sp, d.anz_zeilen, d.bdatum, d.binfo,
       d.bzeichen, d.b_id_aend, d.b_id_neu, d.druck_id, d.farb_id, d.format_id,
       d.kombi_rabatt, d.sonder_rabatt, d.status, d.volumen_rabatt, d.wa_prov_satz,
       d.aktion, d.kz_best, d.best_art, p.prodname, p.dunterlagen, p.hnr, p.jahr,
       p.hnr_num, p.plaz_ext, r.lfd_nr, r.anz_belegung, r.bezeichnung,
       d.kz_preis_unbekannt, d.datum_neu, d.datum_aend, p.motiv, p.abw_prod_bez,
       d.bez_si, p.druck_id, p.status, d.anz_anzeigen
from   dispo d, dispopos p LEFT OUTER JOIN drubrik r ON	
	p.adr_gr = r.adr_gr and 
	p.adr_nr = r.adr_nr and 
	p.auft_nr = r.auft_nr and
	p.auft_hist_nr = r.auft_hist_nr and 
	p.dispo_nr = r.dispo_nr and 
	p.dispo_hist_nr = r.dispo_hist_nr and 
	p.dispopos_nr = r.dispopos_nr
where	p.adr_gr = d.adr_gr and p.adr_nr = d.adr_nr and p.auft_nr = d.auft_nr and 
	p.auft_hist_nr = d.auft_hist_nr and p.dispo_nr = d.dispo_nr and 
	p.dispo_hist_nr = d.dispo_hist_nr

