create view termview (adr_gr, adr_nr, person_nr, e_mandant, obj_nr, ausg, jahr, hnr_vz, hnr_ea, verwend_typ, 
        akt_id, uakt_id, l_ausg_nr, l_aufl_nr, aufg_id, abteilung, prioritaet, ben_zust, termin_soll, termin_ist, 
        status, waehrung, kosten_soll, kosten_ist, haupt_name, nachname, vorname, erfasser_id, datum_akt, lfd_nr,
        email, tage_gelb, tage_orange, tage_inform, kz_briefkas, adr_nr_extern, person_nr_extern, artikel_nr, titel_such, prod_typ,
        bu_send, kz_meilenstein, sort, termintyp, kz_statistik, aufl_status, l_titel_nr, n_artikel_nr, kz_aufl_best, prod_typ_ausgabe, grup_id, solldauer)
  as
select t.adr_gr, t.adr_nr, t.person_nr, t.e_mandant, t.obj_nr, t.ausg, t.jahr, t.hnr_vz, t.hnr_ea, g.verwend_typ, 
       t.akt_id, t.uakt_id, 0, 0, g.aufg_id, t.abteilung, g.prioritaet, t.ben_zust, g.termin_soll, g.termin_ist, 
       g.status, t.waehrung, t.kosten_soll, t.kosten_ist, an.haupt_name, p.nachname, p.vorname, g.erfasser_id, g.datum_akt, g.lfd_nr,
       t.email, g.termin_soll-t.tage_gelb, g.termin_soll-t.tage_orange, g.termin_soll-t.tage_inform, t.kz_briefkas, t.adr_nr_extern, 
       t.person_nr_extern, null, null, 
       g.prod_typ, null, t.kz_meilenstein, a.sort, a.termintyp, a.kz_statistik, null, 0, 0, null, null, null, 0
from  termaufg g, aufgaben a, termplan t LEFT OUTER JOIN anschr an ON
              t.adr_gr  = an.adr_gr and 
              t.adr_nr  = an.adr_nr
           LEFT OUTER JOIN person p ON
              t.adr_gr  = p.adr_gr and 
              t.adr_nr  = p.adr_nr and 
              t.person_nr  =  p.person_nr
      where   t.erfasser_id = g.erfasser_id and
              t.datum_akt = g.datum_akt and
              t.lfd_nr    = g.lfd_nr and
              a.aufg_id   = g.aufg_id and
              a.verwend_typ = g.verwend_typ and
              a.prod_typ  = g.prod_typ 
union
select t.adr_gr, 0, 0, m.e_mandant, null, null, null, null, 0, g.verwend_typ, 
       null, 0, t.l_ausg_nr, t.l_aufl_nr, g.aufg_id, t.abteilung, g.prioritaet, t.ben_zust, g.termin_soll, g.termin_ist, 
       g.status, t.waehrung, t.kosten_soll, t.kosten_ist, null, null, null,
       g.erfasser_id, g.datum_akt, g.lfd_nr, t.email, g.termin_soll-t.tage_gelb, g.termin_soll-t.tage_orange, g.termin_soll-t.tage_inform, 
       t.kz_briefkas, t.adr_nr, t.person_nr, m.artikel_nr, i.titel_such, g.prod_typ, b.bu_send, t.kz_meilenstein, a.sort, a.termintyp,
       a.kz_statistik, l.status, b.l_titel_nr, dbo.char2num(m.artikel_nr), b.kz_aufl_best, b.prod_typ, b.grup_id, t.solldauer
from  termaufg g, buaufter t, bumanaus m, butitel i, buausgab b, aufgaben a, buaufl l
      where   t.erfasser_id = g.erfasser_id and
              t.datum_akt   = g.datum_akt and
              t.lfd_nr      = g.lfd_nr and
              t.l_ausg_nr   = m.l_ausg_nr   and 
              t.l_ausg_nr   = b.l_ausg_nr and
              b.l_titel_nr  = i.l_titel_nr and
              t.l_ausg_nr   = l.l_ausg_nr and
              t.l_aufl_nr   = l.l_aufl_nr and
              a.aufg_id   = g.aufg_id and
              a.verwend_typ = g.verwend_typ and
              a.prod_typ  = g.prod_typ  and
              not exists (select * from buterext e where t.l_ausg_nr = e.l_ausg_nr and t.l_aufl_nr = e.l_aufl_nr and t.aufg_id = e.aufg_id)
union
select e.adr_gr, 0, 0, m.e_mandant, null, null, null, null, 0, g.verwend_typ, 
       null, 0, t.l_ausg_nr, t.l_aufl_nr, g.aufg_id, t.abteilung, g.prioritaet, t.ben_zust, g.termin_soll, g.termin_ist, 
       g.status, t.waehrung, t.kosten_soll, t.kosten_ist, null, null, null,
       g.erfasser_id, g.datum_akt, g.lfd_nr, e.email, g.termin_soll-t.tage_gelb, g.termin_soll-t.tage_orange, g.termin_soll-t.tage_inform, 
       t.kz_briefkas, e.adr_nr, e.person_nr, m.artikel_nr, i.titel_such, g.prod_typ, b.bu_send, t.kz_meilenstein, a.sort, a.termintyp,
       a.kz_statistik, l.status, b.l_titel_nr, dbo.char2num(m.artikel_nr), b.kz_aufl_best, b.prod_typ, b.grup_id, t.solldauer
from  termaufg g, bumanaus m, butitel i, buausgab b, aufgaben a, buaufl l, buaufter t, buterext e 
      where   t.erfasser_id = g.erfasser_id and
              t.datum_akt   = g.datum_akt and
              t.lfd_nr      = g.lfd_nr and
              t.l_ausg_nr   = m.l_ausg_nr   and 
              t.l_ausg_nr   = b.l_ausg_nr and
              b.l_titel_nr  = i.l_titel_nr and
              t.l_ausg_nr   = l.l_ausg_nr and
              t.l_aufl_nr   = l.l_aufl_nr and
              a.aufg_id   = g.aufg_id and
              a.verwend_typ = g.verwend_typ and
              a.prod_typ  = g.prod_typ and
              t.l_ausg_nr   = e.l_ausg_nr and
              t.l_aufl_nr   = e.l_aufl_nr and
              t.aufg_id   = e.aufg_id       

GO
create view [dbo].[terplavi] (adr_gr,adr_nr,person_nr,e_mandant,obj_nr,ausg,jahr,hnr_vz,hnr_ea,akt_id,uakt_id,verwend_typ)
  as
select p.adr_gr,p.adr_nr,p.person_nr,'XX','XXX','XXXXXXXXXXXX','XXXX','XXXXX',0,'XXXXXXXXXXXX',0,'ADR'
from  person p 
union
select 'XXX',0,0,m.e_mandant,m.obj_nr,m.ausg,'XXXX','XXXXX',0,'XXXXXXXXXXXX',0,'VZO'
from  mobstamm m 
union
select 'XXX',0,0,k.e_mandant,k.obj_nr,k.ausg,k.jahr,k.hnr,0,'XXXXXXXXXXXX',0,'VZH'
from  kalender k 
union
select 'XXX',0,0,a.e_mandant,a.obj_nr,a.ausg,'XXXX','XXXXX',0,'XXXXXXXXXXXX',0,'EAO'
from  eobstamm a 
union
select 'XXX',0,0,e.e_mandant,e.obj_nr,e.ausg,e.jahr,'XXXXX',e.hnr,'XXXXXXXXXXXX',0,'EAH'
from  kalendea e 
union
select 'XXX',0,0,h.e_mandant,'XXX','XXXXXXXXXXXX','XXXX','XXXXX',0,h.akt_id,0,'AK '
from  mhaktion h 
union
select 'XXX',0,0,u.e_mandant,'XXX','XXXXXXXXXXXX','XXXX','XXXXX',0,u.akt_id,u.uakt_id,'AK '
from  muaktion u 
union
select 'XXX',beitrag_nr,0,b.e_mandant,'XXX','XXXXXXXXXXXX','XXXX','XXXXX',0,'XXXXXXXXXXXX',0,'ZR '
from  zrbeitra b 

GO
create view tpwhview
(e_mandant, akt_id, uakt_id, start_id, adr_gr, adr_nr, person_nr, lfd_nr ,datum, kz_erledigt, kz_wh)
as select 
t.e_mandant, t.akt_id, t.uakt_id, t.start_id, t.adr_gr, t.adr_nr, t.person_nr, 0, t.datum, t.kz_erledigt, 'F'
from teilnemp t
union
select 
w.e_mandant, w.akt_id, w.uakt_id, w.start_id, w.adr_gr, w.adr_nr, w.person_nr,w.lfd_nr, w.datum, w.kz_erledigt, 'T'
from werbehis w
where  w.start_id = 0
and w.in_out = 'I'

