create view [dbo].[trabnvie] as
select t.* from trabview t where not exists(
select adr_nr from c2wbest c
where c.adr_gr=t.adr_gr and c.adr_nr=t.adr_nr and c.person_nr=t.person_nr and c.obj_nr=t.obj_nr and c.ausg=t.ausg and c.abo_nr=t.abo_nr
and c.zeitstempel > t.datum_aend+1 )

