create view [dbo].[trabview] 
(e_mandant,adr_gr,adr_nr,person_nr,obj_nr,ausg,abo_nr,adr_nr_bv,person_nr_bv,
transfer_id,kunde,bereich,verwend_typ,
datum_aend)
as select distinct s.e_mandant,s.adr_gr,s.adr_nr,s.person_nr,s.obj_nr,s.ausg,s.abo_nr,s.adr_nr_bv,s.person_nr_bv,
t.transfer_id,t.kunde,t.bereich,t.verwend_typ,
case when (case when coalesce(s.datum_aend,s.datum_neu) > coalesce(pr.datum_aend,pr.datum_neu)
                then coalesce(s.datum_aend,s.datum_neu)
                else coalesce(pr.datum_aend,pr.datum_neu)
                end)
              > coalesce(pl.datum_aend,pl.datum_neu)
     then (case when coalesce(s.datum_aend,s.datum_neu) > coalesce(pr.datum_aend,pr.datum_neu)
                then coalesce(s.datum_aend,s.datum_neu)
                else coalesce(pr.datum_aend,pr.datum_neu)
                end)
     else coalesce(pl.datum_aend,pl.datum_neu)
     end
from trreview t, trabo ta, abostamm s, person pr, person pl
where s.adr_gr=t.adr_gr  and s.adr_nr_bv=t.adr_nr and s.person_nr_bv=t.person_nr 
and   pr.adr_gr=s.adr_gr and pr.adr_nr=s.adr_nr_bv and pr.person_nr=s.person_nr_bv 
and   pl.adr_gr=s.adr_gr and pl.adr_nr=s.adr_nr    and pl.person_nr=s.person_nr
and   ta.transfer_id=t.transfer_id and ta.kunde=t.kunde and ta.verwend_typ=t.verwend_typ and ta.bereich=t.bereich
and   ta.adr_gr=s.adr_gr and ta.adr_nr=s.adr_nr and ta.person_nr=s.person_nr and ta.obj_nr=s.obj_nr and ta.ausg=s.ausg and ta.abo_nr=s.abo_nr 

GO
create view [dbo].[transfvw] (transfer_id, kunde, bereich, verwend_typ, tr_satz_id, tr_pos_nr, 
	vorgang, adr_rolle, abw_tr_satz_id, tr_status, e_mandant, adr_gr, 
	adr_nr_le, person_nr_le, obj_nr, ausg, abo_nr, auft_nr, adr_nr_re, person_nr_re,
	email_1, benutzer_web, gueltig_ab, gueltig_bis, beitrag_id, portal_id, port_ber_id)
as
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, a.tr_pos_nr,
	'VZ', k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr,
	k.adr_nr, k.person_nr, a.obj_nr, a.ausg, a.abo_nr, 0, a.adr_nr_re, a.person_nr_re,
	k.email_1, k.nachsend_firma_ges, a.vbeg_datum, a.vend_datum, null, v.portal_id, v.port_ber_id
from TRABO a, AKTVORB v, PORTAL p, TRKOPF k 
where 	k.transfer_id = a.transfer_id and 
	k.kunde       = a.kunde and     
        k.bereich     = a.bereich and 
	k.verwend_typ = a.verwend_typ and 
	k.tr_satz_id  = a.tr_satz_id and
        k.e_mandant   = v.e_mandant and 
	a.akt_id      = v.akt_id and     
        a.obj_nr      = v.obj_nr and 
  	a.ausg        = v.ausg and 
        p.e_mandant   = k.e_mandant and 
        p.portal_id   = v.portal_id and
        p.kz_abo = 'T'
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, a.tr_pos_nr,
	'VZ', k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr,
	k.adr_nr, k.person_nr, a.obj_nr, a.ausg, a.abo_nr, 0, a.adr_nr_re, a.person_nr_re,
	k.email_1, k.nachsend_firma_ges, a.vbeg_datum, a.vend_datum, null, v.portal_id, v.port_ber_id
from TRABO a, PORTZUOB v, PORTAL p, TRKOPF k 
where 	k.transfer_id = a.transfer_id and 
	k.kunde       = a.kunde and     
        k.bereich     = a.bereich and 
	k.verwend_typ = a.verwend_typ and 
	k.tr_satz_id  = a.tr_satz_id and
        k.e_mandant   = v.e_mandant and 
        a.obj_nr      = v.obj_nr and 
  	a.ausg        = v.ausg and 
        p.e_mandant   = k.e_mandant and 
        p.kz_abo = 'T'
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, b.tr_pos_nr,
	'BU', k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr,
	k.adr_nr, k.person_nr, 'xxx', 'xxxxxxxxxxxx', 0, b.auft_nr, b.adr_nr_re, b.person_nr_re,
	k.email_1, k.nachsend_firma_ges, k.fakt_soll_dat, k.vers_soll_dat, b.beitrag_id, null, null
from TRBUPOS b, TRKOPF k
where 	k.transfer_id = b.transfer_id and 
	k.kunde       = b.kunde and     
        k.bereich     = b.bereich and 
	k.verwend_typ = b.verwend_typ and 
	k.tr_satz_id  = b.tr_satz_id
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, 0,
	'RE', k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr,
	k.adr_nr, k.person_nr, 'xxx', 'xxxxxxxxxxxx', 0, 0, k.adr_nr, k.person_nr,
	k.email_1, k.nachsend_firma_ges, k.zeit_neu, k.vers_soll_dat, null, null, null
from TRKOPF k 
where not exists (select * from trabo a where	
        k.transfer_id = a.transfer_id and 
	k.kunde       = a.kunde and     
        k.bereich     = a.bereich and 
	k.verwend_typ = a.verwend_typ and 
	k.tr_satz_id  = a.tr_satz_id) and 
      not exists (select * from trbupos b where	
        k.transfer_id = b.transfer_id and 
	k.kunde       = b.kunde and     
        k.bereich     = b.bereich and 
	k.verwend_typ = b.verwend_typ and 
	k.tr_satz_id  = b.tr_satz_id) 

GO
create view transuuidview 
        (transfer_id, kunde, bereich, verwend_typ, tr_satz_id, tr_pos_nr, lfd_nr, 
	vorgang, best_datum, adr_rolle, abw_tr_satz_id, tr_status, e_mandant, adr_gr, adr_nr, person_nr, a_typ,
	email_1, email_2, email_rech, firma1, firma2, firma3, firma_ges, vorname, nachname,
	sprach_code, anrede_code, titel_code,
	land_code, strasse, postfach, plz, plz_postfach, nachsend_plz, ort, nachsend_ort, uuid)
as
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, 0, k.lfd_nr,
	'ADR', k.best_datum, k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr, k.adr_nr, k.person_nr, k.a_typ,
	k.email_1, k.email_2, k.email_rech, k.firma1, k.firma2, k.firma3, k.firma_ges, k.vorname, k.nachname,
	k.sprach_code, k.anrede_code, k.titel_code,
	k.land_code, k.strasse, k.postfach, k.plz, k.plz_postfach, k.nachsend_plz, k.ort, k.nachsend_ort, z.uuid_adr
from TRKOPF k, TRKOPFZ z 
where 	z.transfer_id = k.transfer_id and 
	z.kunde       = k.kunde and     
        z.bereich     = k.bereich and 
	z.verwend_typ = k.verwend_typ and 
	z.tr_satz_id  = k.tr_satz_id
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, 0, k.lfd_nr, 
	'AUFT', k.best_datum, k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr, k.adr_nr, k.person_nr, k.a_typ,
	k.email_1, k.email_2, k.email_rech, k.firma1, k.firma2, k.firma3, k.firma_ges, k.vorname, k.nachname,
	k.sprach_code, k.anrede_code, k.titel_code,
	k.land_code, k.strasse, k.postfach, k.plz, k.plz_postfach, k.nachsend_plz, k.ort, k.nachsend_ort, z.uuid_auft
from TRKOPF k, TRKOPFZ z 
where 	z.transfer_id = k.transfer_id and 
	z.kunde       = k.kunde and     
        z.bereich     = k.bereich and 
	z.verwend_typ = k.verwend_typ and 
	z.tr_satz_id  = k.tr_satz_id
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, a.tr_pos_nr, k.lfd_nr, 
	'ABO', k.best_datum, k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr, k.adr_nr, k.person_nr, k.a_typ,
	k.email_1, k.email_2, k.email_rech, k.firma1, k.firma2, k.firma3, k.firma_ges, k.vorname, k.nachname,
	k.sprach_code, k.anrede_code, k.titel_code,
	k.land_code, k.strasse, k.postfach, k.plz, k.plz_postfach, k.nachsend_plz, k.ort, k.nachsend_ort, a.uuid_pos
from TRKOPF k, TRABO a 
where 	a.transfer_id = k.transfer_id and 
	a.kunde       = k.kunde and     
        a.bereich     = k.bereich and 
	a.verwend_typ = k.verwend_typ and 
	a.tr_satz_id  = k.tr_satz_id
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, b.tr_pos_nr, k.lfd_nr, 
	'BUCH', k.best_datum, k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr, k.adr_nr, k.person_nr, k.a_typ,
	k.email_1, k.email_2, k.email_rech, k.firma1, k.firma2, k.firma3, k.firma_ges, k.vorname, k.nachname,
	k.sprach_code, k.anrede_code, k.titel_code,
	k.land_code, k.strasse, k.postfach, k.plz, k.plz_postfach, k.nachsend_plz, k.ort, k.nachsend_ort, b.uuid_pos
from TRKOPF k, TRBUPOS b 
where 	b.transfer_id = k.transfer_id and 
	b.kunde       = k.kunde and     
        b.bereich     = k.bereich and 
	b.verwend_typ = k.verwend_typ and 
	b.tr_satz_id  = k.tr_satz_id

