create view [dbo].[trbuview]
(transfer_id, kunde, bereich, verwend_typ, tr_satz_id, tr_pos_nr, lfd_nr, tr_status, status_reserv,
auft_nr, auf_pos, e_mandant, l_ausg_nr, l_aufl_nr, best_art,lager_mandant, lager_code,
ber_menge, frei_menge, reserviert_menge, kz_best_unabh,
datum_neu_buaufpos, status_buaufpos, storno_buaufpos)
