b.auft_nr, b.auf_pos, b.e_mandant, b.l_ausg_nr, b.l_aufl_nr, b.best_art,b.lager_mandant, b.lager_code,
b.ber_menge, b.frei_menge, b.reserviert_menge, b.kz_best_unabh,
b.datum_neu, b.status, b.storno
from trbupos t, buaufpos b
where t.auft_nr = b.auft_nr
and t.auf_pos = b.auf_pos

