create view [dbo].[trreview]
(adr_gr,adr_nr,person_nr,transfer_id,kunde,bereich,verwend_typ,referenz_typ,
lfd_nr,vorname,nachname,name1,name2,name3,ort,plz,land_code,
strasse,datum_aend,adr_nr_ext)
as select
a.adr_gr,cast(a.adr_nr as INT),cast(p.person_nr as INT),r.transfer_id,r.kunde,r.bereich,r.verwend_typ,r.referenz_typ,
r.lfd_nr,p.vorname,p.nachname,a.name1,a.name2,a.name3,a.haupt_ort,a.haupt_plz,a.land_code,
a.strasse,
case when coalesce(p.datum_aend,p.datum_neu)>coalesce(p0.datum_aend,p0.datum_neu)
     then coalesce(p.datum_aend,p.datum_neu)
     else coalesce(p0.datum_aend,p0.datum_neu)
     end
,r.key_ext_char_3 
from anschr a, person p, person p0, transref r
where a.adr_gr=p.adr_gr and a.adr_nr=p.adr_nr
and r.referenz_typ='EXT_NR_ADR_NR' and r.lfd_nr=(
select max(r2.lfd_nr) from transref r2 
where r2.transfer_id=r.transfer_id and r2.kunde=r.kunde and r2.bereich=r.bereich and r2.verwend_typ=r.verwend_typ
and r2.key_ext_char_3=r.key_ext_char_3
and r2.key_cov_char_3=r.key_cov_char_3 and r2.key_cov_char_4=r.key_cov_char_4 and r2.key_cov_char_5=r.key_cov_char_5
) 
and r.key_cov_char_3=a.adr_gr and cast(r.key_cov_char_4 as INT)=a.adr_nr and r.key_ext_char_2 in ('E','R')
and r.key_cov_char_3=p.adr_gr and cast(r.key_cov_char_4 as INT)=p.adr_nr and cast(r.key_cov_char_5 as INT)=p.person_nr 
and p0.adr_gr=a.adr_gr and p0.adr_nr=a.adr_nr and p0.person_nr=0

