create view [dbo].[verpview] (e_mandant,obj_nr,ausg,abrunr,nummer,bund_nr,zaehler,pzd,
                      eti1,eti2,eti3,eti4,eti5,eti6,eti7,eti8,eti9,eti10,
                      jahr,hnr,adr_gr,adr_nr,person_nr,abo_nr,verseinh,l_menge,
                      pv_kz,versart,preis_kat,verb_code,uverb_code,externe_nr,
                      kz_fremd,plz,adr_nr_9,ort,auftcode,reg_code,rech_nr,
                      strasse,hausnr,hausnr_zus,obj_name,ausg_name,name1,name2,name3,
                      anrede,titel,vorname,nachname,landname,postfach)
as
select p.e_mandant,p.obj_nr,p.ausg,p.abrunr,p.nummer,p.bund_nr,p.zaehler,v.pzd,
       v.eti1,v.eti2,v.eti3,v.eti4, v.eti5,v.eti6,v.eti7,v.eti8,v.eti9,v.eti10, 
       v.jahr,v.hnr,v.adr_gr,v.adr_nr,v.person_nr,
       v.abo_nr,v.verseinh,v.l_menge,v.pv_kz,v.versart,v.preis_kat,v.verb_code,
       v.uverb_code,'','0', v.plz, v.adr_nr, v.ort, v.auftcode,'    ',v.rech_nr,
       v.strasse,v.hausnr,v.hausnr_zus,v.obj_name,v.ausg_name,v.name1,v.name2,v.name3,
       v.anrede,v.titel,v.vorname,v.nachname,v.landname,v.postfach
  from popsort p, versausg v
 where p.e_mandant  = v.e_mandant and
       p.obj_nr     = v.u_obj_nr and
       p.ausg       = v.u_ausg and
       p.abrunr     = v.abrunr and
       p.nummer     = v.lfd_nr 

