create view vlr1view (adr_gr, adr_nr, abo_nr,
       land_code, sprach_code,
       haupt_plz,  haupt_ort, haupt_name, name1, vorname, nachname,adr_nr_bv,
       person_nr, a_typ, anrede_code,
       titel_code,  e_mandant, obj_nr, ausg,
       abostatus,
       ber_menge, preis_kat, name2, name3)
as
select b.adr_gr, b.adr_nr, b.abo_nr,a.land_code, p.sprach_code,
       a.haupt_plz,  a.haupt_ort, a.haupt_name
       ,a.name1, p.vorname, p.nachname, b.adr_nr_bv,
       b.person_nr, p.a_typ, p.anrede_code,
       p.titel_code,  b.e_mandant, b.obj_nr, b.ausg, b.abostatus,
       b.ber_menge,
       b.preis_kat, a.name2, a.name3
  from abostamm b, person p, anschr a
  where b.adr_gr = a.adr_gr and b.adr_nr = a.adr_nr
   and b.adr_gr = p.adr_gr and b.adr_nr = p.adr_nr
   and b.person_nr = p.person_nr
   and b.adr_nr_bv <> b.adr_nr

