create view vls1view (adr_gr, adr_nr, abo_nr,
       land_code, sprach_code, l_menge,
       haupt_plz,  haupt_ort, haupt_name, name1, vorname, nachname,s_adnr,
       person_nr, a_typ, anrede_code,
       titel_code,  e_mandant, obj_nr, ausg,
       abostatus,
       ber_menge, preis_kat, name2, name3 )
as select b.adr_gr, b.adr_nr, b.abo_nr,a.land_code, p.sprach_code,
       v.l_menge, a.haupt_plz,  a.haupt_ort, a.haupt_name
       ,a.name1, p.vorname, p.nachname, v.s_adnr,
       b.person_nr, p.a_typ, p.anrede_code,
       p.titel_code,  b.e_mandant, b.obj_nr, b.ausg, b.abostatus,
       b.ber_menge, b.preis_kat, a.name2, a.name3
  from abovers v, abostamm b, person p, anschr a
 where v.s_adnr is not null and b.adr_gr = v.adr_gr and b.adr_nr = v.adr_nr
   and b.person_nr = v.person_nr and b.e_mandant = v.e_mandant
   and b.obj_nr = v.obj_nr and b.ausg = v.ausg and b.abo_nr = v.abo_nr
   and a.adr_gr = b.adr_gr and a.adr_nr = b.adr_nr
   and p.adr_gr = b.adr_gr and p.adr_nr = b.adr_nr
   and p.person_nr = b.person_nr

