       v.l_menge, a.haupt_plz,  a.haupt_ort, a.haupt_name
       ,a.name1, a.name2, p.vorname, p.nachname, v.s_adnr,
       b.person_nr, p.a_typ, p.anrede_code,
       p.titel_code,  b.e_mandant, b.obj_nr, b.ausg, b.abostatus,
