	0, 0, 0, 0,
	'FR', 'FREIW', 'FREIW', 
	f.e_mandant, f.lfd_nr, ' ', '         ', ' ',
	f.obj_nr, f.ausg, '   ', 0, f.anz_frei,
	'  ', f.datum_ab, f.datum_ab, f.datum_ab, 
	f.empfaenger,
      1000*f.jahr_von + f.heft_von, 1000*f.jahr_bis + f.heft_bis,
	f.datum_ab, f.benutzer_id, f.datum_ab, f.benutzer_id,
	f.kz_manuell, f.kz_privat, f.aktion_id, '', 0
from FREIEINW f
union
select  v.adr_gr, v.adr_nr, v.person_nr,
	0, 0, 0, 0,
	'VE', 'VER  ', 'VERSA', 
	s.e_mandant, v.abo_nr, ' ', v.herkunft, ' ',
	s.obj_nr, s.ausg, '   ', 0, v.l_menge,
	'  ', s.versand_soll, s.versand_soll, s.versand_soll, 
	'                                                            ',
      1000*s.jahr, 1000*s.jahr,
	v.versand_hist, '      ', v.versand_hist, '      ',
	s.status, '', s.hnr, '', 0
from VESTPOOL v, VESTSTAM s
where	v.lfd_nr_vest = s.lfd_nr_vest
and   v.kz_versand  = 'T'
union
select  t.adr_gr, t.adr_nr, t.person_nr,
	0, 0, 0, 0,
	'RD', 'ZRBET', 'AUTOR', 
	r.e_mandant, r.beitrag_nr*(-1), ' ', '            ', ' ',
	h.obj_nr, h.ausg, '   ', 0, 1,
	'  ', r.datum_neu, r.datum_neu, r.datum_neu, 
	t.beteil_typ,
      1000*h.jahr + h.hnr, 1000*h.jahr + h.hnr, 
	r.datum_neu, r.b_id_neu, r.datum_aend, r.b_id_aend,
	'', '', h.seite_von, h.seite_bis, t.anz_belege
from ZRBETEIL t, ZRBEITRA r left OUTER join ZRHEFT h on
	r.beitrag_nr = h.beitrag_nr
where t.beitrag_nr = r.beitrag_nr
union 
select  t.adr_gr, t.adr_nr, t.person_nr,
	d.lfd_nr, t.lfd_nr, d.adr_nr, d.person_nr,
	'RD', 'REDKT', 'REDZB', 
	d.e_mandant, d.beitrag_nr*(-1), ' ', '            ', ' ',
	d.obj_nr, d.ausg, '   ', 0, 1,
	'  ', d.datum_neu, d.datum_neu, d.datum_neu, 
	d.stichwort1,
	d.hnr_num, d.hnr_num,
	d.datum_neu, d.b_id_neu, d.datum_aend, d.b_id_aend,
	'', '', d.art, d.seite, 0
from ZRBETEIL t, RDKTVER d
where t.beitrag_nr = d.beitrag_nr
and t.beteil_typ = 'BELEG'

GO
create view vpaaview (e_mandant, adr_gr, adr_nr, person_nr, obj_nr, ausg,
                      abo_nr, haupt_name, nachname, vorname, wohnort, postort,
                      preis_kat, fakt_zr, fakt_zr_no, vbeg_dat, vbeg_jahr, vbeg_heft,
                      vend_dat, vend_jahr, vend_heft, abostatus, abo_dauer,
                      versart, r_art, r_beg_dat, r_beg_hnr, r_beg_jahr,
                      r_ende_dat, r_ende_hnr, r_ende_jahr, l_rnr,
                      datum_neu,b_id_neu,kz_storno,status,w_akt_id,w_uakt_id,best_datum,
                      PREIS_KAT_NO,VERANLASSER,BEST_WEG,BESTELLG,BER_MENGE,K_GRUND,K_DATUM,L_RDAT,L_RBETRAG,F_ENDE_DAT_E,
                      ADR_NR_BV,PERSON_NR_BV,BEST_NR,auftrags_nr,PLZ_WOHN,PLZ_POST,LAND_CODE,LFD_NR_AKTVORB,IP_ADR,NOTIZ)
as
select b.e_mandant, b.adr_gr, b.adr_nr, p.person_nr, b.obj_nr, b.ausg,
       b.abo_nr, a.haupt_name, p.nachname, p.vorname, a.wohnort, a.postort,
       b.preis_kat, b.fakt_zr, b.fakt_zr_no, b.vbeg_dat, b.vbeg_jahr, b.vbeg_heft,
       b.vend_dat, b.vend_jahr, b.vend_heft, b.abostatus, b.abo_dauer,
       v.versart, b.r_art, b.r_beg_dat, b.r_beg_hnr, b.r_beg_jahr,
       b.r_ende_dat, b.r_ende_hnr, b.r_ende_jahr, f.l_rnr,
       b.datum_neu,b.b_id_neu,b.kz_storno,b.status,b.w_akt_id,b.w_uakt_id,b.best_datum, b.PREIS_KAT_NO,b.VERANLASSER,b.BEST_WEG,b.BESTELLG,b.BER_MENGE,b.K_GRUND,b.K_DATUM,f.L_RDAT,f.L_RBETRAG,f.F_ENDE_DAT_E, b.ADR_NR_BV,b.PERSON_NR_BV, b.BEST_NR, b.auftrags_nr, a.PLZ_WOHN, a.PLZ_POST, a.LAND_CODE, b.LFD_NR_AKTVORB, b.IP_ADR, n.NOTIZ 
from abostamm b LEFT OUTER JOIN abofakt f ON
      b.adr_gr    = f.adr_gr    and b.adr_nr    = f.adr_nr and 
      b.person_nr = f.person_nr and b.e_mandant = f.e_mandant and 
      b.obj_nr    = f.obj_nr    and b.ausg      = f.ausg and 
      b.abo_nr    = f.abo_nr
      LEFT OUTER JOIN abonotiz n ON
      b.adr_gr    = n.adr_gr    and b.adr_nr    = n.adr_nr and 
      b.person_nr = n.person_nr and b.e_mandant = n.e_mandant and 
      b.obj_nr    = n.obj_nr    and b.ausg      = n.ausg and 
      b.abo_nr    = n.abo_nr,
     person p, anschr a, abovers v
where b.adr_gr     = a.adr_gr    and b.adr_nr    = a.adr_nr
   and b.adr_gr    = p.adr_gr    and b.adr_nr    = p.adr_nr
   and b.person_nr = p.person_nr
   and b.adr_gr    = v.adr_gr
   and b.adr_nr    = v.adr_nr    and b.person_nr = v.person_nr
   and b.e_mandant = v.e_mandant and b.obj_nr    = v.obj_nr
   and b.ausg      = v.ausg      and b.abo_nr    = v.abo_nr

GO
create view vparview (e_mandant, adr_gr, adr_nr, person_nr, obj_nr, ausg,
                      abo_nr, haupt_name, nachname, vorname, wohnort, postort,
                      preis_kat, fakt_zr, vbeg_dat, vbeg_jahr, vbeg_heft,
                      vend_dat, vend_jahr, vend_heft, abostatus, abo_dauer,
                      versart, r_art, r_beg_dat, r_beg_hnr, r_beg_jahr,
                      r_ende_dat, r_ende_hnr, r_ende_jahr)
as
select b.e_mandant, b.adr_gr, b.adr_nr, p.person_nr, b.obj_nr, b.ausg,
       b.abo_nr, a.haupt_name, p.nachname, p.vorname, a.wohnort, a.postort,
       b.preis_kat, b.fakt_zr, b.vbeg_dat, b.vbeg_jahr, b.vbeg_heft,
       b.vend_dat, b.vend_jahr, b.vend_heft, b.abostatus, b.abo_dauer,
       v.versart, b.r_art, b.r_beg_dat, b.r_beg_hnr, b.r_beg_jahr,
       b.r_ende_dat, b.r_ende_hnr, b.r_ende_jahr
  from abostamm b, person p, anschr a, abovers v
where b.adr_gr    = a.adr_gr    and (b.adr_nr    = a.adr_nr or b.adr_nr_bv = a.adr_nr)
   and b.adr_gr    = p.adr_gr    and (b.adr_nr    = p.adr_nr or b.adr_nr_bv = p.adr_nr)
   and b.person_nr = p.person_nr and b.adr_gr    = v.adr_gr
   and (b.adr_nr   = v.adr_nr or b.adr_nr_bv = v.adr_nr) and b.person_nr = v.person_nr
   and b.e_mandant = v.e_mandant and b.obj_nr = v.obj_nr
   and b.ausg      = v.ausg      and b.abo_nr = v.abo_nr

