create view [dbo].[vzprview] (
      e_mandant, adr_gr, adr_nr, person_nr, 
      obj_nr, ausg, abo_nr, pos_nr,
      l_ausg_nr, l_aufl_nr,
      preis_kat_pra, einzel_preis,
      w_adr_nr, w_person_nr, r_betrag, kz_sperren,
      adr_nr_bv, person_nr_bv,
      abostatus, kz_storno, waehrung,
      w_akt_id, w_uakt_id, preis_kat, preis_kat_no,
      r_art, ber_menge, best_datum, best_nr,
      vbeg_dat, vbeg_heft, vbeg_jahr,
      vend_dat, vend_heft, vend_jahr,
	r_beg_dat, r_beg_hnr, r_beg_jahr,
      no_ende_dat, no_ende_hnr, no_ende_jahr,
      datum_neu, b_id_neu, datum_aend, b_id_aend,
      aboart, status, bu_ber_menge, frei_menge, gelief_menge, fakt_menge,
      auf_pos, auft_nr, kz_schnupperabo)
as
select a.e_mandant, a.adr_gr, a.adr_nr, a.person_nr,
      a.obj_nr, a.ausg, a.abo_nr, a.pos_nr,
      a.l_ausg_nr, a.l_aufl_nr, 
      a.preiskat, a.einzel_preis,
	a.w_adr_nr, a.w_person_nr, w.r_betrag, w.kz_sperren,
      s.adr_nr_bv, s.person_nr_bv,
	s.abostatus, s.kz_storno, s.waehrung,
      s.w_akt_id, s.w_uakt_id, s.preis_kat, s.preis_kat_no,
	s.r_art, s.ber_menge, s.best_datum, s.best_nr, 
      s.vbeg_dat, s.vbeg_heft, s.vbeg_jahr,
      s.vend_dat, s.vend_heft, s.vend_jahr,
	s.r_beg_dat, s.r_beg_hnr, s.r_beg_jahr,
      s.no_ende_dat, s.no_ende_hnr, s.no_ende_jahr,
	s.datum_neu, s.b_id_neu, s.datum_aend, s.b_id_aend, s.aboart,
      b.status, b.ber_menge, b.frei_menge, b.gelief_menge, b.fakt_menge, b.auf_pos,
      f.auft_nr, a.kz_schnupperabo
from WERBEPRA a, WERBEPR w, ABOSTAMM s, BUAUFTRA f, BUAUFPOS b
where a.adr_gr    = w.adr_gr
and   a.adr_nr    = w.adr_nr
and   a.person_nr = w.person_nr
and   a.e_mandant = w.e_mandant
and   a.obj_nr    = w.obj_nr
and   a.ausg      = w.ausg
and   a.abo_nr    = w.abo_nr
and   a.adr_gr    = s.adr_gr
and   a.adr_nr    = s.adr_nr
and   a.person_nr = s.person_nr
and   a.e_mandant = s.e_mandant
and   a.obj_nr    = s.obj_nr
and   a.ausg      = s.ausg
and   a.abo_nr    = s.abo_nr
and   s.w_akt_id is not null
and   f.adr_gr    = a.adr_gr
and   f.adr_nr_re = a.w_adr_nr
and   f.person_nr_re = a.w_person_nr
and   f.e_mandant = a.e_mandant
and   f.akt_id    = s.w_akt_id
and   f.uakt_id   = s.w_uakt_id
and   b.auft_nr   = f.auft_nr
and   b.obj_nr    = a.obj_nr
and   b.ausg      = a.ausg
and   b.abo_nr    = a.abo_nr
and   b.l_ausg_nr = a.l_ausg_nr
and   (b.l_aufl_nr = a.l_aufl_nr or (b.l_aufl_nr is null and  a.l_aufl_nr is null))
and   b.adr_nr_abo = a.adr_nr
and   b.person_nr_abo = a.person_nr
and   b.akt_id    = s.w_akt_id
and   b.uakt_id   = s.w_uakt_id

