CREATE VIEW [dbo].[VZTYPVIE](e_mandant, vertreter_id, vertreter_typ, akt_id, reg_id, reg_code, kz_standard, 
                     vertreter_art, ebene,
					 adr_gr, adr_nr, person_nr, benutzer_id, bank_satz_nr, rueckbelast_proz, vertragsende, 
					 abrech_rhythmus, ruecklage_betr, ruecklage_behalt_proz, kz_gebiet_pruef
					 )
AS
SELECT  a.e_mandant, a.vertreter_id, a.vertreter_typ, a.akt_id, a.reg_id, a.reg_code, a.kz_standard,
        b.vertreter_art, b.ebene,
		c.adr_gr, c.adr_nr, c.person_nr, c.benutzer_id, c.bank_satz_nr, c.rueckbelast_proz, c.vertragsende, 
		c.abrech_rhythmus, c.ruecklage_betr, c.ruecklage_behalt_proz, c.kz_gebiet_pruef
FROM   	VZTYPTMP a, VZVERTYP b, VZVERTRE c
WHERE	a.vertreter_typ = b.vertreter_typ
and     a.vertreter_id  = c.vertreter_id
and     a.e_mandant     = c.e_mandant

