create view waeview 
       (jobnr, adr_gr, adr_nr, auft_nr, auft_hist_nr, dispo_nr, dispo_hist_nr,
        vorgang_typ, kz_verarb, gruppen_nr, hnr_num, anzart_id, anz_si,
        anz_schaltung, druck_id, farb_id, format_id, e_mandant, obj_nr,
        adr_nr_wa, haupt_name, f_typ_nr, bezirk_id, kz_best, aktion)
  as
select r.jobnr, r.adr_gr, r.adr_nr, r.auft_nr, r.auft_hist_nr, r.dispo_nr, r.dispo_hist_nr,
       r.vorgang_typ, r.kz_verarb, r.gruppen_nr, r.hnr_num, d.anzart_id, d.anz_si,
       d.anz_schaltung, d.druck_id, d.farb_id, d.format_id, d.e_mandant, d.obj_nr,
       a.adr_nr_wa, h.haupt_name, b.f_typ_nr, b.bezirk_id, d.kz_best, d.aktion
from   rechbuch r, dispo d, auftrag a, adbezirk b, anschr h
where  r.adr_gr = d.adr_gr and r.adr_nr = d.adr_nr and r.auft_nr = d.auft_nr and 
       r.auft_hist_nr = d.auft_hist_nr and r.dispo_nr = d.dispo_nr and 
       r.dispo_hist_nr = d.dispo_hist_nr and 
       r.adr_gr = a.adr_gr and r.adr_nr = a.adr_nr and r.auft_nr = a.auft_nr and 
       r.auft_hist_nr = a.auft_hist_nr and
       r.adr_gr = b.adr_gr and r.adr_nr = b.adr_nr and r.auft_nr = b.auft_nr and 
       r.auft_hist_nr = b.auft_hist_nr and
       r.adr_gr = h.adr_gr and r.adr_nr = h.adr_nr

