CREATE VIEW [dbo].[wavaview](adr_gr, adr_nr, person_nr, e_mandant, vertreter_id, obj_nr, ausg, abo_kond, prov_status, kz_prov_schnorrer, prov_menge,
					 akt_id, uakt_id, preis_kat, abo_nr, ber_menge, adr_nr_re, person_nr_re, landart, preis_kat_no, k_grund, best_dat_abo,
					 abrech_rhythmus, kz_gebiet_pruef,
					 kgs, land_code, haupt_plz, plz_wohn, plz_post, plz_gk,
					 prov_kond, prov_std_aktion, kz_abw_prov, kz_prov_genehm,
					 datum_neu_abo, datum_aend_abo, no_ende_dat, no_ende_jahr, no_ende_hnr, k_datum,
					 kz_inaktiv_prov)
AS
SELECT 	w.adr_gr, w.adr_nr, w.person_nr, w.e_mandant, w.vertreter_id, w.obj_nr, w.ausg, w.abo_kond, w.prov_status, w.kz_prov_schnorrer, w.prov_menge,
		a.w_akt_id, a.w_uakt_id, a.preis_kat, a.abo_nr, a.ber_menge, a.adr_nr_bv, a.person_nr_bv, a.inaus, a.preis_kat_no, a.k_grund, a.best_datum,
		v.abrech_rhythmus, v.kz_gebiet_pruef,
		i.kgs, 
		r.land_code, r.haupt_plz, r.plz_wohn, r.plz_post, r.plz_gk,
		m.prov_kond, m.prov_std_aktion, m.kz_abw_prov, m.kz_prov_genehm,
		a.datum_neu, a.datum_aend, a.no_ende_dat, a.no_ende_jahr, a.no_ende_hnr, a.k_datum,
		w.kz_inaktiv_prov
FROM   	werbepr w, vzvertre v, anschr r,
        abostamm a LEFT OUTER JOIN ainfo i  ON
		           a.adr_gr=i.adr_gr and
		           a.adr_nr=i.adr_nr
				   LEFT OUTER JOIN mhaktion m ON
		           a.e_mandant = m.e_mandant and
		           a.w_akt_id  = m.akt_id
WHERE	a.adr_gr=w.adr_gr and
		a.adr_nr=w.adr_nr and
		a.person_nr=w.person_nr and
		a.e_mandant=w.e_mandant and
		a.obj_nr=w.obj_nr and
		a.ausg=w.ausg and
		a.abo_nr  = w.abo_nr and
		a.datum_neu >= '01.01.2011' and
		w.e_mandant=v.e_mandant and
		w.vertreter_id=v.vertreter_id and
		r.adr_gr=w.adr_gr and
		r.adr_nr=w.adr_nr and
		((w.prov_status='P') OR (w.prov_status='K') OR (w.prov_status='Z') or (w.prov_status is NULL))

