create view wbzstammview 
(e_mandant,obj_nr,ausg,lfd_nr_obj,pvkz,vdz_nr_dienstl,lfd_nr_pl_wbz,lfd_nr_wbz,gueltig_ab_hnr,gueltig_ab_jahr,wbz_abg_preis,
lfd_nr_pl_wkz,wkz_schluessel,gueltig_ab_hnr_num_wkz,haftung_anzahl,lfd_nr_wkz,folge_wkz_typ,folge_anzahl,wkz_betrag)
  as
select a.e_mandant, a.obj_nr,a.ausg,a.lfd_nr_obj,a.pv_kz,a.vdz_nr_dienstl,b.lfd_nr_pl,c.lfd_nr,c.gueltig_ab_hnr,c.gueltig_ab_jahr,c.wbz_abg_preis,
d.lfd_nr_pl,d.wkz_schluessel, d.gueltig_ab_hnr_num,d.haftung_anzahl,e.lfd_nr,e.folge_wkz_typ,e.folge_anzahl,e.wkz_betrag
 from mobjwbz a 
 left outer join wbzplgrup b on
      a.e_mandant  = b.e_mandant   and
      a.obj_nr     = b.obj_nr      and
      a.ausg       = b.ausg        and
      a.lfd_nr_obj = b.lfd_nr_obj  
 left outer join wbzplpreis c on
      b.e_mandant  = c.e_mandant   and
      b.obj_nr     = c.obj_nr      and
      b.ausg       = c.ausg        and
      b.lfd_nr_obj = c.lfd_nr_obj  and
      b.lfd_nr_pl  = c.lfd_nr_pl   
 left outer join wkzplist d on
      a.e_mandant  = d.e_mandant   and
      a.obj_nr     = d.obj_nr      and
      a.ausg       = d.ausg        and
      a.lfd_nr_obj = d.lfd_nr_obj  
 left outer join wkzpreis e on
      d.e_mandant  = e.e_mandant   and
      d.obj_nr     = e.obj_nr      and
      d.ausg       = e.ausg        and
      d.lfd_nr_obj = e.lfd_nr_obj  and
      d.lfd_nr_pl  = e.lfd_nr_pl 

GO
create view [dbo].[WEKview] (
        wek_nr, wek_stichtag, hist_typ, mandant, wek_code, 
        akt_id, akt_bez, akt_code, akt_code_bez, akt_wdh_grp, akt_wdh_grp_bez, akt_soll_start, akt_soll_ende, akt_ist_ende, kz_messe, kz_ad,
        uakt_id, uakt_bez, uakt_wek_grp, uakt_wek_grp_bez, erst_folg_akt, vorakt_id, erst_akt_id, erst_akt_bez, massn_code, massn_bez, er_code,
        modul, in_out,
        anz_adr, anz_adr_uakt, anz_adr_eakt, anz_adr_bearb, anz_adr_bearb_uakt, anz_adr_bearb_eakt, 
        soll_ist, betr_kost, betr_kost_cpo, betr_kost_ncpo, betr_erloes,
        betr_kost_cpo_sum, anz_bestell_cpo_sum, cpo,
        artikel_nr, artikel_bez, titel_bez,
        obj_nr, obj_bez,
        aktionskosten, prov_kosten, praem_kosten, zugabe_kosten, anzeige_kosten, akt_erloese,
        anz_abo_voll, anz_aboabs, anz_no2voll, anz_sano2voll, anz_abo_frei, 
        anz_abo_sa, anz_abo_sano, anz_abo_sapo, anz_abo_no, anz_abo_po, anz_abosto,
        anz_probeheft, anz_einzelheft, anz_artikel, anz_sonst, anz_interes, erfolg_proz
        )
as
select  wek.lfd_nr_wek, wek.stichtag, wek.historie_typ, wek.e_mandant, wek.wek_id, 
        wek.akt_id, h.b_aktid, h.akt_code, a.bez, h.wdh_grp, wdh.bez, h.soll_beg, h.soll_ende, h.ist_ende, h.kz_messe, h.kz_ad,
        wek.uakt_id, u.b_uaktid, u.wek_grp, uwg.bez, u.kz_ef, u.id_vuakt, wek.erst_akt_id, u2.b_uaktid, u.mass_code, m.b_mass, r.er_code, 
        wek.modul, wek.in_out,
        wek.anz_adressen, wek.anz_adr_uakt, wek.anz_adr_eakt, wek.anz_adr_bearbeitet, wek.anz_adr_bearb_uakt, wek.anz_adr_bearb_eakt,
        wek.soll_ist, wek.betr_kost, wek.betr_kost_cpo, wek.betr_kost_ncpo, wek.betr_erl_ncpo, 
        wek.betr_kost_cpo_sum, wek.anz_bestell_cpo, wek.cpo,
        bum.artikel_nr, bua.ausg_text, but.titel_such, 
        mob.obj_nr, mob.objektname,
        wek2.betr_kost, wek3.betr_kost, wek4.betr_kost, wek5.betr_kost, wek6.betr_kost, wek7.betr_erl_ncpo,
        wek.anz_abo_voll, wek.anz_aboabs, wek.anz_no2voll, wek.anz_sano2voll, wek.anz_abo_frei, 
        wek.anz_abo_sa, wek.anz_abo_sano, wek.anz_abo_sapo, wek.anz_abo_no, wek.anz_abo_po, wek.anz_abosto,
        wek.anz_probeheft, wek.anz_einzelheft, wek.anz_bestellung, wek.anz_sonst, wek.anz_interes, wek.erfolg_proz
from    WEKSTAT wek
        LEFT OUTER JOIN MHAKTION h ON
		     h.e_mandant                = wek.e_mandant    and
             h.akt_id                   = wek.akt_id
			 LEFT OUTER JOIN MAKTION a ON
			      a.akt_code            = h.akt_code
             LEFT OUTER JOIN MHWDHGRP wdh ON
			      wdh.e_mandant         = h.e_mandant      and
                  wdh.wdh_grp           = h.wdh_grp
		LEFT OUTER JOIN MUAKTION u ON
		     u.e_mandant                = wek.e_mandant    and
             u.akt_id                   = wek.akt_id       and
             u.uakt_id                  = wek.uakt_id
			 LEFT OUTER JOIN MAWEKGRP uwg ON
			      uwg.e_mandant         = u.e_mandant      and
                  uwg.wek_grp           = u.wek_grp
			 LEFT OUTER JOIN MASSNAHM m ON
				  m.mass_code           = u.mass_code
		LEFT OUTER JOIN MUAKTION u2 ON
		     u2.e_mandant               = wek.e_mandant    and
             u2.akt_id                  = wek.akt_id       and
             u2.uakt_id                 = wek.erst_akt_id
		LEFT OUTER JOIN RESPVORG r ON
             r.e_mandant                = wek.e_mandant    and
             r.akt_id                   = wek.akt_id       and
             r.uakt_id                  = wek.id_vuakt     and
             r.f_uakt_id                = wek.uakt_id
		LEFT OUTER JOIN BUMANAUS bum ON
             bum.e_mandant              = wek.e_mandant    and
             bum.l_ausg_nr              = wek.l_ausg_nr
			 LEFT OUTER JOIN BUAUSGAB bua ON
                  bua.l_ausg_nr         = bum.l_ausg_nr
				  LEFT OUTER JOIN BUTITEL but ON
                       but.l_titel_nr   = bua.l_titel_nr
        LEFT OUTER JOIN MOBJTYP mob	ON				   
             mob.e_mandant              = wek.e_mandant    and
             mob.obj_nr                 = wek.obj_nr
        LEFT OUTER JOIN WEKSTAT wek2 ON
             wek2.wek_id                = wek.wek_id       and
             wek2.e_mandant             = wek.e_mandant    and
             wek2.historie_typ          = wek.historie_typ and
             wek2.stichtag              = wek.stichtag     and
             wek2.soll_ist              = wek.soll_ist     and
             wek2.akt_id                = wek.akt_id       and
             wek2.uakt_id               = wek.uakt_id      and
             wek2.lfd_nr_cpo            = wek.lfd_nr_int   and
             wek2.lfd_nr_cpo  is not null                  and
             wek2.verwend_typ           = 'STGR'           and
             wek2.verw_id_stat          = 'AKTKO'
        LEFT OUTER JOIN WEKSTAT wek3 ON
             wek3.wek_id                = wek.wek_id       and
             wek3.e_mandant             = wek.e_mandant    and
             wek3.historie_typ          = wek.historie_typ and
             wek3.stichtag              = wek.stichtag     and
             wek3.soll_ist              = wek.soll_ist     and
             wek3.akt_id                = wek.akt_id       and
             wek3.uakt_id               = wek.uakt_id      and
             wek3.lfd_nr_cpo            = wek.lfd_nr_int   and
             wek3.lfd_nr_cpo  is not null                  and
             wek3.verwend_typ           = 'STGR'           and
             wek3.verw_id_stat          = 'PROVKO'
        LEFT OUTER JOIN WEKSTAT wek4 ON
             wek4.wek_id                = wek.wek_id       and
             wek4.e_mandant             = wek.e_mandant    and
             wek4.historie_typ          = wek.historie_typ and
             wek4.stichtag              = wek.stichtag     and
             wek4.soll_ist              = wek.soll_ist     and
             wek4.akt_id                = wek.akt_id       and
             wek4.uakt_id               = wek.uakt_id      and
             wek4.lfd_nr_cpo            = wek.lfd_nr_int   and
             wek4.lfd_nr_cpo  is not null                  and
             wek4.verwend_typ           = 'STGR'           and
             wek4.verw_id_stat          = 'PRAEKO'
        LEFT OUTER JOIN WEKSTAT wek5 ON
             wek5.wek_id                = wek.wek_id       and
             wek5.e_mandant             = wek.e_mandant    and
             wek5.historie_typ          = wek.historie_typ and
             wek5.stichtag              = wek.stichtag     and
             wek5.soll_ist              = wek.soll_ist     and
             wek5.akt_id                = wek.akt_id       and
             wek5.uakt_id               = wek.uakt_id      and
             wek5.lfd_nr_cpo            = wek.lfd_nr_int   and
             wek5.lfd_nr_cpo  is not null                  and
             wek5.verwend_typ           = 'STGR'           and
             wek5.verw_id_stat          = 'ZUGKO'
        LEFT OUTER JOIN WEKSTAT wek6 ON
             wek6.wek_id                = wek.wek_id       and
             wek6.e_mandant             = wek.e_mandant    and
             wek6.historie_typ          = wek.historie_typ and
             wek6.stichtag              = wek.stichtag     and
             wek6.soll_ist              = wek.soll_ist     and
             wek6.akt_id                = wek.akt_id       and
             wek6.uakt_id               = wek.uakt_id      and
             wek6.lfd_nr_cpo            = wek.lfd_nr_int   and
             wek6.lfd_nr_cpo  is not null                  and
             wek6.verwend_typ           = 'STGR'           and
             wek6.verw_id_stat          = 'ANZKO'
        LEFT OUTER JOIN WEKSTAT wek7 ON
             wek7.wek_id                = wek.wek_id       and
             wek7.e_mandant             = wek.e_mandant    and
             wek7.historie_typ          = wek.historie_typ and
             wek7.stichtag              = wek.stichtag     and
             wek7.soll_ist              = wek.soll_ist     and
             wek7.akt_id                = wek.akt_id       and
             wek7.uakt_id               = wek.uakt_id      and
             wek7.lfd_nr_cpo            = wek.lfd_nr_int   and
             wek7.lfd_nr_cpo  is not null                  and
             wek7.verwend_typ           = 'STGR'           and
             wek7.verw_id_stat          = 'AKTERL'
			 
where   wek.verwend_typ     = 'CPO'

GO
create view [dbo].[wselview] 
     (BENUTZER_ID, SEL_ID, ADR_GR, PRIO_AUFG, ANZ_ADR, ANZ_EX, 
      W_AKT_ID, W_UAKT_ID,W_START_ID, E_MANDANT, OBJ_NR, AUSG, KZ_ERLEDIGT,
      JAHR, HNR, ADR_NR, PERSON_NR, VERWEIS_NR, A_TYP)
as select
      v.BENUTZER_ID, v.SEL_ID, v.ADR_GR, PRIO_AUFG, ANZ_ADR, ANZ_EX, 
      W_AKT_ID, W_UAKT_ID, W_START_ID, E_MANDANT, OBJ_NR, AUSG, KZ_ERLEDIGT,
      JAHR, HNR, ADR_NR, PERSON_NR, VERWEIS_NR, A_TYP
from WERBEVV v, SELPOOL s
where v.benutzer_id = s.benutzer_id
and   v.sel_id      = s.sel_id
and   v.adr_gr      = s.adr_gr

GO
create view wtdpview 
       (adr_gr, adr_nr, auft_nr, dispo_nr, dispopos_nr,
        e_mandant, obj_nr, ausg, jahr, hnr, 
        motiv, farb_id, volumen_mm, objekttyp)
  as
select d.adr_gr, d.adr_nr, d.auft_nr, d.dispo_nr, p.dispopos_nr,
       p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr,
       p.motiv, d.farb_id, d.volumen_mm,  t.objekttyp
from    dispo d, dispopos p, eobjtyp t
where  d.auft_hist_nr = 0 and d.dispo_hist_nr = 0 and
       (d.status='A' or d.status='F' or d.status='R') and
       d.adr_gr=p.adr_gr and d.adr_nr=p.adr_nr and
       d.auft_nr=p.auft_nr and d.auft_hist_nr=p.auft_hist_nr and
       d.dispo_nr=p.dispo_nr and d.dispo_hist_nr=p.dispo_hist_nr and
       d.e_mandant = t.e_mandant and d.obj_nr = t.obj_nr

GO
create view wtdview 
       (adr_gr, adr_nr, e_mandant, obj_nr, ausg,
        jahr, hnr, volumen_fa, volumen_mm, volumen_anz, anz_si)
  as
select p.adr_gr, p.adr_nr,
       p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr,
       sum(d.volumen_fa/d.anz_schaltung), 
       sum(d.volumen_mm/d.anz_schaltung), count(*), sum(d.anz_si)
from   dispopos p, dispo d
where  p.auft_hist_nr = 0 and p.dispo_hist_nr = 0 and
       (d.status='A' or d.status='F' or d.status='R') and
       p.adr_gr=d.adr_gr and p.adr_nr=d.adr_nr and
       p.auft_nr=d.auft_nr and p.auft_hist_nr=d.auft_hist_nr and
       p.dispo_nr=d.dispo_nr and p.dispo_hist_nr=d.dispo_hist_nr
group by p.adr_gr, p.adr_nr, p.e_mandant,
         p.obj_nr, p.ausg, p.jahr, p.hnr

GO
create view wtprview 
       (adr_gr, adr_nr, produkt, kz_loesch, herkunft_id,
        wb_id, hgrp_id, ugrp_id, bez, verwend_typ)
as
select wt.adr_gr, wt.adr_nr, wt.produkt, wt.kz_loesch, wt.herkunft_id,
	 p.wb_id, p.hgrp_id, p.ugrp_id, p.bez, u.verwend_typ
from WTPROD wt, PRODUKT p, UGRUPPE u
where	wt.produkt   = p.produkt and
	p.wb_id      = u.wb_id and
	p.hgrp_id    = u.hgrp_id and
        p.ugrp_id    = u.ugrp_id

