create view [dbo].[wvtpview]
(e_mandant, akt_id, uakt_id, start_id, adr_gr, adr_nr, person_nr, 
obj_nr, ausg, jahr, hnr, kz_erledigt)
as select
t.e_mandant, t.akt_id, t.uakt_id, t.start_id, t.adr_gr, t.adr_nr, t.person_nr,
w.obj_nr, w.ausg, w.jahr, w.hnr, w.kz_erledigt
