create view [dbo].[zrbeivie] (adr_gr, adr_nr, haupt_name, person_nr, 
                     nachname, vorname, beteil_typ, beitrag_id, beitrag_art, beitrag_nr,
                     status, titel, untertitel, such_swort, e_mandant, obj_nr, ausg, hnr, jahr,
                     rubrik_id, rubrik_bez, seite_von, seite_bis, datum_evt)
  as
select b.adr_gr, b.adr_nr, a.haupt_name, b.person_nr, p.nachname, p.vorname,  
       b.beteil_typ, z.beitrag_id, z.beitrag_art, z.beitrag_nr, z.status, z.titel, z.untertitel, s.such_swort,
       h.e_mandant, h.obj_nr, h.ausg, h.hnr, h.jahr, h.rubrik_id, h.rubrik_bez, h.seite_von, h.seite_bis, k.datum_evt
from zrbeitra z 
left outer join (zrbeteil b
inner join anschr a on
	a.adr_gr = b.adr_gr  and 
	a.adr_nr = b.adr_nr
inner join person p on
	p.adr_gr = b.adr_gr and
	p.adr_nr  = b.adr_nr and
	p.person_nr = b.person_nr)
on	b.beitrag_nr = z.beitrag_nr
left outer join (zrheft h 
left outer join kalendea k on
	k.e_mandant = h.e_mandant and
	k.obj_nr  = h.obj_nr and
	k.ausg = h.ausg and
	k.hnr = h.hnr and
	k.jahr = h.jahr)
on	h.beitrag_nr = z.beitrag_nr
left outer join zrstichw s on
	s.beitrag_nr = z.beitrag_nr
union
select r.adr_gr, r.adr_nr, a.haupt_name, r.person_nr, p.nachname, p.vorname,  
       'RDKTVE', z.beitrag_id, z.beitrag_art, z.beitrag_nr, z.status, z.titel, z.untertitel, s.such_swort,
       h.e_mandant, h.obj_nr, h.ausg, h.hnr, h.jahr, h.rubrik_id, h.rubrik_bez, h.seite_von, h.seite_bis, k.datum_evt
from zrbeitra z
inner join (rdktver r
inner join anschr a on
	a.adr_gr = r.adr_gr  and 
	a.adr_nr = r.adr_nr
inner join person p on
	p.adr_gr = r.adr_gr and
	p.adr_nr  = r.adr_nr and
	p.person_nr = r.person_nr)
on	r.beitrag_nr = z.beitrag_nr
left outer join (zrheft h 
left outer join kalendea k on
	k.e_mandant = h.e_mandant and
	k.obj_nr  = h.obj_nr and
	k.ausg = h.ausg and
	k.hnr = h.hnr and
	k.jahr = h.jahr)
on	h.beitrag_nr = z.beitrag_nr
left outer join zrstichw s on
	s.beitrag_nr = z.beitrag_nr

GO
create view [dbo].[zrbelvw] (beitrag_nr, e_mandant, obj_nr, ausg, jahr, hnr,
                    beteil_nr, adr_gr, adr_nr, person_nr, beteil_typ, anz_belege)
  as
select a.beitrag_nr, a.e_mandant, a.obj_nr, a.ausg, a.jahr, a.hnr,
       b.lfd_nr, b.adr_gr, b.adr_nr, b.person_nr, b.beteil_typ, b.anz_belege
from zrheft a, zrbeteil b
where a.beitrag_nr = b.beitrag_nr

