create view zrheftvw (beitrag_nr, e_mandant, obj_nr, ausg, jahr, hnr,
                    beteil_nr, adr_gr, adr_nr, person_nr, beteil_typ, honart_id,anteil_proz, umfang,
		    anz_cm, anteil_proz_bild, verwend_typ, steuer_code)
  as
select a.beitrag_nr, a.e_mandant, a.obj_nr, a.ausg, a.jahr, a.hnr,
       b.lfd_nr, b.adr_gr, b.adr_nr, b.person_nr, b.beteil_typ, 
       b.honart_id, b.anteil_proz, b.umfang, b.anz_cm, b.anteil_proz_bild,
       c.verwend_typ, b.steuer_code
from zrheft a, zrbeteil b, honart c
where a.beitrag_nr = b.beitrag_nr
and b.honart_id = c.honart_id

