create view [dbo].[zrobjvie] (lfd_nr, ab_menge, adr_gr, adr_nr, person_nr, 
                     e_mandant, obj_nr, ausg, jahr, heft, honart_id, 
                     verwend_typ, hon_betrag, abschlag_2, abschlag_3)
  as
select o.lfd_nr, s.ab_menge, o.adr_gr, o.adr_nr, o.person_nr, 
       o.e_mandant, o.obj_nr, o.ausg, o.jahr, o.heft, o.honart_id, 
       a.verwend_typ, s.hon_betrag, s.abschlag_2, s.abschlag_3
from zrobjaut o, zrobjsta s, honart a
where s.lfd_nr = o.lfd_nr and
      o.honart_id = a.honart_id

GO
